window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-027.json"] = [{"name":"黄胸霸鹟","english_name":"Ochre-lored Flatbill","scientific_name":"Tolmomyias flaviventris","overview":"黄胸霸鹟（英文名：Ochre-lored Flatbill，学名：Tolmomyias flaviventris），是雀形目霸鹟科黄绿霸鹟属的鸟类。小型、橄榄黄色的霸鹟科鸟类，分布于中美洲和南美洲北部、东部以及亚马逊雨林的北部和南部，包括巴西东部。其最显著的特征是黄色的喉部和胸部，橙色的脸部，宽大的喙以及明显的翼带。","appearance":"这种鸟约12.7厘米长，体重约11.3克。头部和上体呈橄榄绿色，翅膀和尾巴的羽毛边缘较深，泛着黄色。两道黄色翼带明显。喉咙、胸部和眼环为金色黄色，面部两侧为赭色，腹部为暗黄色。喙侧扁，上黑下白，雌雄相似。不同地区的亚种在颜色上有细微差别，西部亚种较为暗淡，而东部和北部的亚种更亮，带有更多的赭黄色。","call":"其常见叫声是一声尖锐的哨音，单独发出或缓慢连串，偶尔也会发出间隔均匀的粗糙叫声。","habits":"黄胸霸鹟栖息于次生林和轻型林地，通常避开成熟森林的内部。它们在较高的栖木上保持低调，从那里飞出捕捉昆虫。","breeding":"巢由植物纤维制成，通常悬挂在树枝上，靠近黄蜂巢，这可能提供了对捕食者的某种保护。一窝通常有两到三枚奶油白色的蛋，上面有紫色斑点，主要集中在较大的一端。雌鸟孵化大约17天。","identification":"与Olive-faced Flycatcher相似，曾被认为是同一种，称为Yellow-breasted Flycatcher。可通过其更亮的脸部，带有橙色暗示，更明显的翼带以及不同的声音来区分。","distribution":"分布于中美洲和南美洲，范围从哥伦比亚、委内瑞拉向南至秘鲁、玻利维亚和巴西，以及特立尼达和多巴哥。"},{"name":"绿脸霸鹟","english_name":"Olive-faced Flatbill","scientific_name":"Tolmomyias viridiceps","overview":"绿脸霸鹟（英文名：Olive-faced Flatbill，学名：Tolmomyias viridiceps），是雀形目霸鹟科黄绿霸鹟属的鸟类。主要分布于南美洲西部亚马逊雨林地带的次生森林低地和山麓。其特征包括宽大的喙，鲜亮的黄色喉部和胸部，以及翅膀上无明显标记。","appearance":"绿脸霸鹟拥有小型身材，喙部宽阔。它的喉部和胸部呈现出明亮的黄色，脸部缺乏橙色，翅膀上的条纹不甚明显。与之相似的黄胸霸鹟曾被认为是同一物种，统称为黄胸霸鹟。但绿脸霸鹟在面部颜色、翅膀条纹的清晰度以及鸣声上与黄胸霸鹟有所不同。","call":"绿脸霸鹟的典型鸣唱是一系列上升的、间隔开的‘peek’音符，有时会发出尖锐的嘶鸣。","habits":"绿脸霸鹟栖息于亚马逊西部的河流边木地和森林边缘。它们的活动范围和迁徙模式目前记录较少。","identification":"与黄胸霸鹟的区别在于，绿脸霸鹟面部无橙色，翅膀条纹更模糊，且鸣声不同。","distribution":"绿脸霸鹟分布于南美洲西部亚马逊雨林区域，具体包括巴西、秘鲁等地的次生森林低地和山麓。"},{"name":"姬伞鸟","english_name":"Kinglet Calyptura","scientific_name":"Calyptura cristata","overview":"姬伞鸟（英文名：Kinglet Calyptura，学名：Calyptura cristata），是雀形目霸鹟科姬伞鸟属的唯一物种，体型小巧，曾一度被认为是灭绝的物种。仅分布于南美洲巴西东南部的亚热带森林地带，19世纪曾广泛存在，但由于森林砍伐，其生存环境遭受严重威胁。","appearance":"姬伞鸟身长7.5至8厘米，是极其微小的霸鹟科成员，外观类似金冠鸟（Regulus），但具有锥形喙和强烈拱形的上喙，尾部极短。雄鸟拥有黑色边缘的大橙红色冠羽，羽毛略长；背部呈鲜艳橄榄色，臀部黄色；翅膀和尾巴大多灰暗，大覆羽和中覆羽尖端有明显的白色横纹，三级飞羽亦白尖；下体黄色，胸部带有橄榄色斑纹。雌鸟的冠羽斑块较小。幼鸟特征未详述。","call":"姬伞鸟的叫声被描述为短暂、沙哑且令人不悦，对于其体型来说意外地响亮。","habits":"姬伞鸟通常以成对出现，它们在藤蔓上攀爬，根据季节食用昆虫或小型浆果。偏好来自马里安尼拉的果实，这是两种不同的茄科灌木，Acnistus cauliflorus 和 Aureliana lucida。此外，它们也会探索积水的凤梨科植物叶丛。","breeding":"关于姬伞鸟的繁殖信息尚未详细记录。","identification":"姬伞鸟与金冠鸟属（Regulus）的相似性在于体型和部分羽毛颜色，但其独特的锥形喙和冠羽颜色是明显区别点。","protection":"IUCN：CR（极危）","distribution":"姬伞鸟分布于巴西东南部的里约热内卢地区，历史上在圣保罗也有记录，但当前确切的分布范围仅限于里约热内卢州内的少数地点。","other":"自19世纪以来，姬伞鸟因栖息地破坏而面临灭绝威胁，直到1996年在塞拉多斯奥尔加昂国家公园附近再次发现。"},{"name":"桂红冠铲嘴雀","english_name":"Cinnamon-crested Spadebill","scientific_name":"Platyrinchus saturatus","overview":"桂红冠铲嘴雀（英文名：Cinnamon-crested Spadebill，学名：Platyrinchus saturatus），是雀形目霸鹟科铲嘴雀属的鸟类。小型森林底层霸鹟，常见于南美洲的亚马孙雨林，其自然生境为热带湿润低地森林。","appearance":"整体外观较为朴素，上部呈褐色，下部为淡黄色至白色，头顶有一隐蔽的肉桂色冠羽，在野外条件下通常难以察觉。体型小，面部简洁无复杂图案，喙宽大，具有铲嘴雀属的典型特征。","call":"最常听到的叫声为短促且抑扬顿挫的吱吱声，通常在受惊飞离时发出；鸣唱则是一系列令人意外的响亮、刺耳的音符，音量较大。","habits":"栖息于低地热带雨林的下层，常在低矮植被中停歇，作短暂向上扑击以捕食叶片下的昆虫。偶尔会跟随混群鸟群，但更多时候单独行动。","breeding":"繁殖信息未详述。","identification":"与其它铲嘴雀区别在于其朴素的羽色和缺乏鲜明的面部图案。","protection":"IUCN状态未提供。","distribution":"分布于巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉的亚马逊雨林区域。","other":"系统发育历史等其他信息未在本次描述中提供。"},{"name":"短尾铲嘴雀","english_name":"Stub-tailed Spadebill","scientific_name":"Platyrinchus cancrominus","overview":"短尾铲嘴雀（英文名：Stub-tailed Spadebill，学名：Platyrinchus cancrominus），是雀形目霸鹟科铲嘴雀属的鸟类。体型微小可爱，以橄榄棕色上体、鲜明的脸部花纹和极短的尾巴著称。常见于中美洲热带低地雨林中的阴暗地带，尤其在湿润环境中。其独特外观和易于被忽视的特性，使其成为热带森林中的隐秘居民。","appearance":"短尾铲嘴雀长约9-9.5厘米，体重介于9.5-12克。雄鸟具有鲜明的面部特征，包括淡黄色眉纹、眼环、耳斑和拱形的后眼纹，与深黑色的颊部形成对比；头部灰褐色，头顶有半隐藏的黄色冠斑；上体橄榄棕色；翅膀暗色，边缘呈肉桂棕色；尾巴小而短，棕色；喉咙白色，与土黄色或棕色胸部、淡黄色腹部和下尾羽形成对比。虹膜深色；喙宽扁，上喙黑色，下喙淡粉色；腿粉红色。雌鸟缺乏黄色冠斑。幼鸟面部图案较不明显，上体呈棕色，翼上有浅黄色横斑，喉部和胸部为灰白色渐变为白色。","call":"其特有的鸣叫声为响亮的鼻音‘chi-dik’或‘chi-di-dik’，通常在短暂飞行后发出，之后会静止不动，难以被发现。","habits":"短尾铲嘴雀栖息于海拔高达500米的热带干燥雨林或湿润低地，遍及中美洲，从墨西哥东南部至哥斯达黎加西部。它们是杂食性动物，以蜘蛛、甲虫、蚂蚁等节肢动物以及低处的浆果和果实为食。虽然许多个体独居，但成对的短尾铲嘴雀会在深锥形巢穴中共同筑巢，巢由收集到的纤维制成。此外，它们参与多种物种混群觅食，这种行为可能有助于减少被捕食的风险。","breeding":"在繁殖季节，短尾铲嘴雀在哥斯达黎加被观察到收集草和植物纤维，用于建造深锥形的杯状巢，这些巢通常位于低矮的树苗附近。尽管食物来源多样，一些个体可能偏好植物性食物，根据果实或种子的丰度调整饮食。","identification":"短尾铲嘴雀最显著的特征是其极短的尾巴和宽阔扁平的喙，以及头部的显著黄色标记，这使其在同属物种中易于识别。雄鸟的黄色冠斑是与雌鸟的区别之一。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从墨西哥东南部（包括韦拉克鲁斯南部、瓦哈卡、塔巴斯科、恰帕斯和尤卡坦半岛）南至尼加拉瓜和哥斯达黎加西部；最近也在巴拿马西北部（博卡斯德尔托罗群岛）发现。","other":"短尾铲嘴雀于1860年首次科学描述，最初被认为与白喉铲嘴雀相同，后被重新分类为共域物种。"},{"name":"白喉铲嘴雀","english_name":"White-throated Spadebill","scientific_name":"Platyrinchus mystaceus","overview":"白喉铲嘴雀（英文名：White-throated Spadebill，学名：Platyrinchus mystaceus），是雀形目霸鹟科铲嘴雀属的鸟类。体型微小，以异常宽大的喙著称，分布于中美洲至南美洲，包括哥斯达黎加到玻利维亚，南美北部、东部及东南部。具有独特的面部花纹，雄鸟头顶藏有黄色冠羽，常在低层森林中单独或成对活动。","appearance":"白喉铲嘴雀体长9-10厘米，体重7.5-12克。头部大，尾部短，上身橄榄棕色至红棕色，下身淡色，具黑色颊纹。黄色冠羽通常隐蔽，仅在兴奋时展开。喉咙白色，其余下体呈淡黄色至白色。两性相似，但雌鸟冠羽可能较小或缺失。幼鸟缺乏黄色冠羽，上体更偏红棕色。","call":"发出尖锐的单声‘吱’叫，以及上升的颤音。","habits":"栖息于各种生境的下层植被，包括湿润低地、山地森林、干林、画廊森林、高大次生林；有时出现在竹丛或森林边缘的纠结灌木区。海拔高度从海平面至2150米，常见于哥斯达黎加、巴拿马、哥伦比亚、厄瓜多尔等地。","breeding":"繁殖季节在哥斯达黎加为3月至5月，南美北部为5月至7月。雄鸟在兴奋时会展示黄色冠羽，进行飞行表演。巢为锥形杯状，由黑菌丝、枯叶等构成，放置于1-3米高的灌木或幼树的竖直分叉处。每窝产2枚黄白色带红斑的蛋。","identification":"通过其独特的面部图案、宽大扁平的喙以及特定的鸣叫声来辨认。与同属物种的区别在于冠羽的展示方式和色彩差异。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，包括哥斯达黎加至玻利维亚，南美北部、东部及东南部。在巴西的某些保护区较为常见，但受到低地森林砍伐的影响。"},{"name":"金冠铲嘴雀","english_name":"Golden-crowned Spadebill","scientific_name":"Platyrinchus coronatus","overview":"金冠铲嘴雀（英文名：Golden-crowned Spadebill，学名：Platyrinchus coronatus），是雀形目霸鹟科铲嘴雀属的鸟类。小型热带森林鸟类，最显著的特征是拥有宽大的喙，在森林底层难以被忽视。分布于中美洲和南美洲，包括洪都拉斯至厄瓜多尔西北部，以及亚马逊雨林地区。","appearance":"金冠铲嘴雀体型非常小，长度约8.5-9厘米，体重仅8-9克。上体呈橄榄褐色，下体浅黄色，脸颊带有黑色斑纹。喉咙和胸部均匀呈淡黄色，无明显白色喉咙对比。头顶暗红棕色，中央隐藏着金色部分。两性相似，但雌鸟的金色冠羽更偏橙色。幼鸟面部标记较淡，下体颜色也更浅，整个头部为橄榄褐色，翅膀覆羽和飞羽边缘呈赭黄色调。所有亚种极为相似，但superciliaris亚种的下体颜色比指名亚种更亮黄，gumia亚种体型略小，腹部更亮黄。","call":"发出极高音的虫鸣般的颤音。","habits":"金冠铲嘴雀通常单独或成对出现，偏好森林底层环境。它们的行踪隐秘，主要在低海拔的热带湿润森林中活动。","breeding":"繁殖期在中美洲的哥斯达黎加和巴拿马为4月至6月，哥伦比亚西北部为1月至4月，东南部为8月。筑巢时会制作类似蜂鸟的杯状巢，由植物纤维、树蕨鳞片和真菌根状茎构成，用蜘蛛网绑定，内部铺垫细纤维，外表装饰苔藓和蜘蛛卵囊，有时巢底部有杂乱的废弃物。巢置于灌木或幼树的垂直分叉处，高度在1-4米之间。每窝产2枚卵，孵化期约为20-21天。","identification":"通过宽大的扁平喙、鲜明的面部图案和头部橙红棕色的冠羽来识别。雌雄相似，但雌鸟的冠羽颜色更为橙色。幼鸟与成鸟相比，面部标记和下体颜色更淡。","distribution":"分布于中美洲的洪都拉斯至南美洲的厄瓜多尔西北部，以及亚马逊雨林区域。"},{"name":"黄喉铲嘴雀","english_name":"Yellow-throated Spadebill","scientific_name":"Platyrinchus flavigularis","overview":"黄喉铲嘴雀（英文名：Yellow-throated Spadebill，学名：Platyrinchus flavigularis），是雀形目霸鹟科铲嘴雀属的小型鸟类。南美洲特有，分布于委内瑞拉西部至秘鲁东部的安第斯山脉云雾森林中，其独特的外观和罕见性使其成为鸟类观察者的珍稀目标。","appearance":"成年黄喉铲嘴雀拥有一个栗色的冠羽，黄色的下体，橄榄褐色的上体，以及眼睛前方显眼的黄色斑点。喙基部非常宽大，侧面看时可能显得较为常规。头部较大，尾巴较短，整体呈现出上重下轻的外观。它常长时间静止地停栖在森林较低至中层的位置。","call":"最典型的叫声是一种短促而尖锐的哨音，每隔几秒重复一次。其歌声为上升的颤音，有时以一声尖叫结束。","habits":"黄喉铲嘴雀偏好栖息于亚热带或热带湿润的山地森林中，具体可见于南美洲的安第斯山脉区域。这种鸟有静止不动的习性，常在树冠层的低至中层停留。","identification":"与其他铲嘴雀属物种相比，黄喉铲嘴雀的胸部黄色、头部较大的比例以及特殊的喙部形状是其显著的辨识特征。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，主要在委内瑞拉西部至秘鲁东部的安第斯山脉区域。"},{"name":"白冠铲嘴雀","english_name":"White-crested Spadebill","scientific_name":"Platyrinchus platyrhynchos","overview":"白冠铲嘴雀（英文名：White-crested Spadebill，学名：Platyrinchus platyrhynchos），是雀形目霸鹟科铲嘴雀属的鸟类。迷人的小型霸鹟科鸟类，特征为灰色头部与白色喉咙形成鲜明对比，搭配土黄色下体。主要分布于南美洲亚马逊雨林地带，包括巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南、委内瑞拉、玻利维亚等地，偏好生长在亚热带或热带湿润低地森林中。","appearance":"体型较小，拥有独特的外观，头部呈灰色，与白色的喉咙和淡褐色的腹部形成鲜明对比。喙部宽大，是其属名'Platyrinchus'（意为宽嘴）的由来。相较于其他铲嘴雀，白冠铲嘴雀体型略大、体形更厚实，面部特征更为简单。通常单独或成对出现。","call":"其声音特征显著，首先通过尖锐的叫声被察觉；其特有的鸣唱是一段先上升后下降的颤音。","habits":"生活在高大的热带雨林中，数量相对稀少，观察难度较大。常从低矮的栖木上起飞，快速飞向树叶下方捕捉昆虫。活动范围主要集中在森林底层。","breeding":"具体繁殖信息记录较少，一般在适宜季节进行繁殖，营巢于隐蔽处。","identification":"与同属其他铲嘴雀相比，白冠铲嘴雀具有较大的体型、更厚实的体态和较为朴素的面容，头部的灰白色对比明显，是重要的辨识特征。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲亚马逊雨林区域，包括巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南、委内瑞拉和玻利维亚。","other":"系统学历史上，曾被归类于Todus属，后因分类学修订，置于Platyrinchus属中。"},{"name":"黄褐翅铲嘴雀","english_name":"Russet-winged Spadebill","scientific_name":"Platyrinchus leucoryphus","overview":"黄褐翅铲嘴雀（英文名：Russet-winged Spadebill，学名：Platyrinchus leucoryphus），是雀形目霸鹟科铲嘴雀属的小型鸟类，分布于南美的巴拉圭东部、阿根廷东北部和巴西东南部。该鸟种以独特的橄榄褐色冠羽和白色冠斑为显著特征，生活在湿润的森林低地。","appearance":"黄褐翅铲嘴雀体长约12.5厘米，体重约17克，是铲嘴雀中体型最大的。头部橄榄褐色，顶冠处有半隐蔽的白色斑块，脸部图案鲜明，由淡黄色至黄白色的眉纹、眼环、耳下斑点和拱形的眼后条纹构成，与深棕色的额部和眼下的条纹形成对比。背部橄榄褐色，翅膀棕色，翼覆羽和飞羽边缘呈锈色。尾巴长而棕色，喉咙白色，胸部和两侧有橄榄褐色的洗色，腹部淡黄色或白色。虹膜深棕色，喙宽而扁平，上喙黑色边缘黄色，下喙黄色，腿橙色到淡粉色。雌雄相似，幼鸟特征未详述。","call":"鸣叫特征为非常尖锐的口哨声“tchew-tchew”。","habits":"黄褐翅铲嘴雀栖息于湿润森林的下层植被，偏好旧次生林。飞行特点和活动范围尚未详细记录，但已知其对次生林有一定容忍度，可能进行局部迁徙。","breeding":"繁殖信息尚未具体记录。","identification":"与其他铲嘴雀属鸟类相比，黄褐翅铲嘴雀具有更大的体型，独特的橄榄褐色与锈色翅膀组合，以及脸部的鲜明色块，易于区分。","protection":"IUCN：VU（易危）","distribution":"分布于南美洲，具体包括巴西东南部（从帕拉纳和圣保罗东至埃斯皮里图桑托，南至圣卡塔琳娜东北和南里奥格兰德东北）、邻近的巴拉圭东部（从卡因迪尤南至帕拉瓜里、卡萨帕和伊塔普阿）和阿根廷东北极小部分（伊瓜苏国家公园和萨尔托恩坎塔多省级公园，在北米西奥内斯）。"},{"name":"栗红霸鹟","english_name":"Cinnamon Neopipo","scientific_name":"Neopipo cinnamomea","overview":"栗红霸鹟（英文名：Cinnamon Neopipo，学名：Neopipo cinnamomea），是雀形目霸鹟科栗红霸鹟属的唯一物种。这种小鸟身材娇小，容易被忽视，主要栖息在南美洲亚马逊雨林的低地森林中，分布于巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉。","appearance":"体长9.1至9.5厘米，体重约7克。头冠灰暗，带有隐蔽的黄色斑块，通常不明显。头部侧面、颈背呈暗灰色，臀部为赤褐色，翅膀羽毛深色边缘宽广的赤褐色，尾巴赤褐色。喉咙和下体颜色从淡黄到橙赤色，喉咙颜色最浅。眼睛大，虹膜深色，喙细长黑色，下颚基部橙色，腿蓝灰色或暗灰色。雌雄相似，但雌鸟色彩较暗淡，黄色冠斑较小。不同亚种间差异不大。","call":"叫声为短促、嘶哑的哨音“pfééeo”或“weeo”，先升后降。歌声由10至15个音符组成，如“pee pee pa pee… fe-féé-fee-feaa-feaa-feaa-feaa-feaa”，缓慢持续5至6秒，第二个音符最低，第五个最高，后续音符逐渐下降，与鳞胸鹪鹩的歌声相似，但节奏更快。","habits":"主要栖息于高地森林，常出现在白砂土地区的低地。海拔高度从海平面至约1000米，在委内瑞拉可达200米。以昆虫和其他节肢动物为食，通常单独觅食，偶尔加入混合物种群。在中层或更高处的林下层栖息，姿态常显得蜷缩。频繁快速地从栖息处飞向叶子的下方和边缘捕食。","breeding":"关于繁殖信息目前尚无具体资料。","identification":"与红尾霸鹟相比，栗红霸鹟体型较小，尾短，头部圆润，腿为深色，且无触须。近距离观察时，可注意其蓝灰色的腿部。","protection":"IUCN：LC（无危）。在整个分布区内稀少且局部分布，可能经常被忽视。与森林内部的其他小型昆虫食鸟相比，密度较低；在西亚马逊地区记录相对较少，秘鲁境内了解不多。在厄瓜多尔的Cuyabeno保护区和Jatun Sacha生物站，以及巴西的Rio Cristalino森林保护区和Tapajós国家公园内有其分布。尽管在较大范围内，该物种的栖息地状况相对较好，但在发生栖息地破坏的地方数量减少。","distribution":"分布于南美洲亚马逊雨林西部和东北部，包括巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉。"},{"name":"桂红霸鹟","english_name":"Cinnamon Flycatcher","scientific_name":"Pyrrhomyias cinnamomeus","overview":"桂红霸鹟（英文名：Cinnamon Flycatcher，学名：Pyrrhomyias cinnamomeus），是雀形目霸鹟科桂红霸鹟属的唯一物种。这分布于南美洲安第斯山脉亚热带区域的明亮红褐色小鸟，常见于委内瑞拉至阿根廷西北部的地区。具有独特的肉桂色下体、棕色背部和醒目的红褐色翼斑，常成对活动，偏好栖息于云雾林边缘。","appearance":"体长约11-13厘米，体重约10.8克。全身呈现肉桂红褐色，顶冠尖锐。标准种群拥有深棕褐色顶冠，半隐的黄色冠斑，模糊的淡黄眼上方斑块和眼圈；脸颊、颈背和上体橄榄棕色，臀部有一窄条橙色肉桂带（常被遮盖）；翅膀黑色，具两道宽阔的红褐色翼纹，次级飞羽上的红褐色边缘形成一大片区域；尾巴黑色；喉咙、颈部侧面和下体均为肉桂红褐色，腹部略浅；虹膜深色；喙较宽，黑色；腿黑色。幼鸟颜色较暗，无黄色冠斑，背部和尾部有赭色尖端的羽毛。不同亚种在羽毛颜色上有差异，最显著的是圣玛尔塔山（北哥伦比亚）的亚种，全身上下色彩更鲜艳温暖，是所有亚种中最接近肉桂色的。","call":"发出连续的颤音叫声，声音类似“trrrt”、“tr-r-r-r-r-r”、“pti-i-i-i-i”或“pit, pit-pit-pit”，间隔短暂重复，飞行时会发出“tjip tjip”的叫声，也会发出单个“pit”、“tsip”或“chip”的音符。","habits":"栖息于山地森林和木地的空地、边界和道路切割区，海拔600-3550米，通常在1200-3000米之间。在厄瓜多尔，双侧安第斯山脉均有分布，局部高于中央及安第斯山谷间。主要以昆虫为食，偶尔食用浆果。经常成对觅食，虽加入但不跟随混合物种群。从1-15米高的森林边缘裸露的水平枝上搜寻猎物，但不会在树顶活动；站立姿势直立。空中捕食者，通过短暂的飞行捕捉空中猎物，然后突然返回同一位置。","breeding":"繁殖期在委内瑞拉北部为4月至5月。在阿根廷图库曼发现的巢穴中，12月已有蛋。巢为开放的杯状，由苔藓和地衣制成，置于离地面1-5米的岩石裂缝、凹槽或突出处、倒下的原木或树皮中；成对维持一小片永久领地。一窝产2枚蛋，其他信息未知。","identification":"与同属其他物种相比，桂红霸鹟的肉桂色下体、棕色背部和红褐色翼纹使其易于识别。不同亚种在颜色和细节上有所区别，尤其是圣玛尔塔山的亚种颜色更为鲜明。","protection":"IUCN：LC（无危）。在自然保护区中广泛分布，如委内瑞拉的亨利皮蒂尔国家公园、哥伦比亚的坦比托自然保护区以及厄瓜多尔南部至玻利维亚的湿润安第斯山脉所有保护区，还有阿根廷的卡利莱瓜国家公园。适应力较强，即使在部分森林砍伐地区也能生存。","distribution":"分布于南美洲的委内瑞拉至阿根廷西北部，包括哥伦比亚、厄瓜多尔、秘鲁、玻利维亚。在厄瓜多尔，分布于安第斯山脉两侧及局部高于中央及安第斯山谷的区域。"},{"name":"峭壁霸鹟","english_name":"Cliff Flycatcher","scientific_name":"Hirundinea ferruginea","overview":"峭壁霸鹟（英文名：Cliff Flycatcher，学名：Hirundinea ferruginea），是雀形目霸鹟科峭壁霸鹟属的唯一物种。原属中的Swallow Flycatcher被合并为其亚种H. ferruginea bellicosa。原生于南美洲，偏好栖息于靠近亚热带或热带干湿森林、低地森林、山地森林以及重度退化森林边缘的悬崖和峭壁。","appearance":"成年峭壁霸鹟约18.5厘米长，翼展宽广，喙宽而尖，翅膀细长，外观似燕子。上体呈暗褐色，有独特的红褐色臀部和尾基。翼羽尖端深色，其余部分为肉桂红褐色，飞行时尤为明显。下体淡肉桂红褐色，喉部有灰色斑点。","call":"发出类似美国红隼和食蝠隼的高音调叫声，包括‘wheeeyp’、‘killy killy’、‘kaleé kale’或响亮的‘wha-deép wha-deép’声。黎明时的歌声为快速重复的高音‘kit-ti-léé’。","habits":"常单独或成对出现，偏爱在悬崖、岩石露头、峡谷壁、滑坡和陡峭河岸旁的成熟林或次生林附近栖息。低地种群海拔从海平面至2000米；安第斯山脉种群主要位于900至2200米，局部高达2700米。南向种群迁徙，北向种群则为留鸟。","breeding":"几乎未知，但在委内瑞拉有报道在1月发现活跃的巢穴，位于10至12米高的悬崖裂缝或路堑中。巢为开放杯状，主要由草和湿苔藓构成，放置于悬崖或路堑的裂缝或平台上，偶尔在建筑物或人造结构中。每窝产两到三个粉白色带棕色标记的蛋。","identification":"与纹喉丛霸鹟相比，体型更大，喉咙有条纹。在安第斯山脉的种群有更多白色的面部斑点。","protection":"IUCN：LC（无危）。在委内瑞拉分布较为零散，但在巴西东南部较为常见。由于森林砍伐可能正在增加和扩散。","distribution":"仅分布在安第斯山脉以东的南美洲，遍及除智利外的所有南美国家。亚马逊盆地周边的山麓和支流源头的最高海拔，向南延伸至阿根廷中部，越过潘帕斯草原至南部巴西、巴拉圭和乌拉圭，以及亚马逊盆地东南部的巴西高原，直至大西洋和巴西东南部海岸。","other":"近年来首次记录出现在哥伦比亚圣玛尔塔山脉、玻利维亚的诺埃尔肯普夫梅尔卡多国家公园、巴西的卡拉科尔和因特瓦莱斯州立公园等地。"},{"name":"南美纹霸鹟","english_name":"Euler's Flycatcher","scientific_name":"Lathrotriccus euleri","overview":"南美纹霸鹟（英文名：Euler's Flycatcher，学名：Lathrotriccus euleri），是雀形目霸鹟科灰胸纹霸鹟属的小型鸟类。以瑞士鸟类学家Carl Euler命名。分布广泛，主要栖息于南美洲安第斯山脉东侧，从哥伦比亚至阿根廷，包括特立尼达岛，曾经在格林纳达也有分布。","appearance":"平均体长12.7厘米，体重约10-11克。上体橄榄棕色，翼部深棕色，具两道淡黄色条纹。喉部灰色，胸部棕色，腹部呈淡黄色。眼周白色，但无眉纹。两性相似，但不同亚种在颜色上有细微差异。","call":"鸣叫为响亮粗哑的“chee-chi-wi-wi-wi”。","habits":"栖息于森林的低层和中层，偏好隐蔽的灌木丛，以昆虫为食，能短暂悬停以捕捉猎物。","breeding":"在雨季的夏季繁殖，筑巢于树杈，由草叶纤维构成，通常离地面几米高。每窝产2-3枚白底红褐色斑点的蛋，孵化期16-18天，幼鸟约15天后离巢。","identification":"与Empidonax属的某些物种外观相似，但上体更偏棕色，翼条纹更淡黄。不同亚种在上体和下体的颜色上有差异。","protection":"IUCN：LC（无危）。然而，格林纳达亚种可能已经灭绝，原因可能是栖息地破坏和引入的捕食者。","distribution":"南美洲广泛分布，包括哥伦比亚、委内瑞拉、玻利维亚、阿根廷、特立尼达岛。","other":"曾被归入Empidonax属，后因解剖学和分子学证据调整至现属。"},{"name":"灰胸纹霸鹟","english_name":"Grey-breasted Flycatcher","scientific_name":"Lathrotriccus griseipectus","overview":"灰胸纹霸鹟（英文名：Grey-breasted Flycatcher，学名：Lathrotriccus griseipectus），是雀形目霸鹟科灰胸纹霸鹟属的鸟类。南美洲特有的小型飞禽。分布于厄瓜多尔西部和秘鲁北部的干燥与湿润森林地带，具有独特的灰色羽毛和白色翼带。","appearance":"灰胸纹霸鹟拥有灰色为主的羽毛，胸前带有灰色，最显著的特征是白色的眼镜状斑纹和醒目的白色翼带。雌雄鸟在羽毛颜色上相似，幼鸟的特征尚未详细描述。","call":"其典型的叫声柔和而含糊，通常为‘breer, breer’，有时伴随其他音符。","habits":"这种鸟栖息在森林较低层次，偏好在安静处停歇，常通过声音被首次发现。它们的活动范围和迁徙模式尚不完全清楚。","breeding":"繁殖习性知之甚少。在厄瓜多尔西南部，二月份的巢穴中有蛋，巢筑于Ceiba树根的浅洞或附生植物丛中的凤梨科植物叶基之间，巢由死叶、树皮构成，内部稀疏铺有真菌菌丝、深色根须和淡色草茎纤维。每次产2枚蛋，颜色为浅米色，带稀疏的肉桂色和橙褐色斑点，大小约18mm x 13.5mm，新鲜重量约1.8克。孵化期为16天，仅一只成鸟孵卵，但双方共同喂养幼鸟。刚孵化的雏鸟皮肤暗色，背部覆盖淡棕色绒羽，腿和喙黄色，口角边缘亮白，口腔内壁明亮的黄橙色，巢留期约为14天。","identification":"与同属其他物种相比，灰胸纹霸鹟的灰色羽毛和白色翼带是明显的辨识特征。","protection":"IUCN：LC（无危）","distribution":"分布于安第斯山脉西侧的厄瓜多尔西部和秘鲁西北部，包括马腊翁河谷和钦奇佩河谷的东侧。在厄瓜多尔的埃斯梅拉达斯、皮钦查、马纳比、洛斯里奥斯、瓜亚斯、卡纳尔、阿苏艾、埃尔奥罗和洛哈省，以及秘鲁的通贝斯、皮乌拉、兰巴耶克和卡哈马卡省均有记录。"},{"name":"褐胸斑翅霸鹟","english_name":"Tawny-chested Flycatcher","scientific_name":"Aphanotriccus capitalis","overview":"褐胸斑翅霸鹟（英文名：Tawny-chested Flycatcher，学名：Aphanotriccus capitalis），是雀形目霸鹟科褐胸斑翅霸鹟属的鸟类。以独特的灰头、暖褐色胸部、橄榄色背部和翼条为显著特征。分布于中美洲的低地及丘陵地带，从尼加拉瓜东部至哥斯达黎加北部的加勒比斜坡。","appearance":"成年褐胸斑翅霸鹟长约12厘米，重约11克。头部暗灰色，具白色喉部和眼圈。上体橄榄绿色，带有赭色倾向，翅膀暗色，有两道亮赭色的翼条。胸部鲜明的橙赭色，腹部和尾下覆羽黄色。雄雌相似，但雌鸟的头部可能略带橄榄色调。幼鸟特征尚不清楚。","call":"鸣声快速而连贯，通常为“chee chee spt’t cheew”或更复杂的“choot choot choot ch-ch-ch-chttttree’ih”，最后的音节最为响亮。","habits":"栖息于成熟常绿森林和高大的次生林，偏好密集的下层植被环境，如林缘、溪流旁、自然空地或可可种植园。活动范围从海平面到海拔900米，局部可达1050米。以昆虫为食，尤其喜食甲虫、蝽象和蚂蚁。独自或成对觅食，采取固定的觅食路线，利用上升突飞的方式从树叶和树枝的下面捕获猎物。","breeding":"关于繁殖习性的信息有限。已知为洞穴筑巢者，巢穴位于大树或竹子的天然空洞中，高度约6米。巢由雌鸟建造，但对蛋和其他繁殖细节的描述缺失。","identification":"与Empidonax类霸鹟外观相似，但色彩更为鲜艳。识别关键在于其独特的头部颜色组合、亮赭色的胸部和翼条。","protection":"IUCN：VU（易危）。该物种因森林砍伐和碎片化而面临威胁，特别是在哥斯达黎加。虽然在某些保护区如Rincón de la Vieja国家公园、La Selva生物保护区和Rancho Naturalista得到保护，但在尼加拉瓜的分布情况仍需更多研究。","distribution":"分布于中美洲的加勒比斜坡，具体包括尼加拉瓜东部（最近无记录）和哥斯达黎加北部。","other":"在哥斯达黎加的Rancho Naturalista生态旅游旅馆，该物种在其当前管理实践中受到保护。"},{"name":"黑嘴斑翅霸鹟","english_name":"Black-billed Flycatcher","scientific_name":"Aphanotriccus audax","overview":"黑嘴斑翅霸鹟（英文名：Black-billed Flycatcher，学名：Aphanotriccus audax），是雀形目霸鹟科褐胸斑翅霸鹟属的鸟类。小型霸鹟科鸟类，仅分布于中美洲东部巴拿马和南美洲西北部哥伦比亚的部分地区。其自然栖息地为低海拔的热带雨林。","appearance":"该鸟体型较小，上体呈橄榄褐色，胸部为橄榄色，腹部黄色。翅膀深色，有两条淡色翼带。脸部灰白，眼圈模糊白色，喙全黑。","call":"其独特叫声以两个高音符开始，随后滑入更低的喷嚏声。","habits":"栖息于低地森林的林下层，具体活动习性和食物种类尚需进一步研究。","breeding":"关于繁殖习性的详细信息有限，有待更多观察记录。","identification":"通过其独特的橄榄色胸部、黄色腹部、淡色翼带和全黑的喙来识别。","protection":"IUCN：NT（近危）","distribution":"分布于巴拿马（包括Panamá省和Darién）南部至哥伦比亚西北部（Chocó北部和Magdalena河谷中部，北至Santa Marta山脉南坡）。","other":"自首次由美国博物学家Edward William Nelson于1912年描述以来，黑嘴斑翅霸鹟面临着因栖息地丧失而带来的威胁。"},{"name":"暗褐霸鹟","english_name":"Fuscous Flycatcher","scientific_name":"Cnemotriccus fuscatus","overview":"暗褐霸鹟（英文名：Fuscous Flycatcher，学名：Cnemotriccus fuscatus），是雀形目霸鹟科暗褐霸鹟属的唯一成员。分布广泛，从哥伦比亚和委内瑞拉至玻利维亚、巴拉圭、阿根廷，以及特立尼达和多巴哥岛，遍及南美洲北部和东部，包括整个亚马逊盆地和圭亚那，巴西全境除东南部与乌拉圭接壤的极小部分。","appearance":"体长约14.5厘米，体重约11.9克，尾部较长。上体颜色单一呈棕色，翼部深棕色，有两条明显的淡色翼带。眼眉显著，白色，延伸至眼后，与暗色的颊和眼线形成鲜明对比。喉部白色，胸部灰褐色，腹部呈淡黄色。喙黑色，下颚基部淡粉色，腿黑色。雌雄相似，但不同亚种在羽色浓淡、翼带宽度、上体色彩（灰色至棕色）、腹部颜色（白色至黄色）上有所差异。","call":"发出轻柔的'chip'声，鸣唱为'chip-weeti-weeti-weetiyee'，在南部亚种中，黎明时会发出爆发式的变奏叫声'pit-pit-peedit'。","habits":"栖息于林地和灌木丛，筑巢于树叉，巢由枝条和树皮构成，内衬植物纤维，通常放置三枚带有黑色斑点的白色蛋。这种鸟比较隐秘，倾向于在低矮的灌木丛中停留，从那里飞出捕捉昆虫（猎捕）。","breeding":"繁殖期不详，但已知巢穴位于树叉中，由枝条和树皮制成，内里铺垫植物纤维，每次产卵3枚，蛋壳白色，大端有黑色斑点。","identification":"与欧拉霸鹟相似，但具有更为显著的眼眉。不同亚种在羽色上有细微差别，可通过上体和腹部的颜色变化加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲北部和东部，包括整个亚马逊盆地、圭亚那、巴西（除东南部边境地区），以及特立尼达和多巴哥。在哥伦比亚、委内瑞拉、玻利维亚、巴拉圭和阿根廷均有分布。"},{"name":"带霸鹟","english_name":"Belted Flycatcher","scientific_name":"Xenotriccus callizonus","overview":"带霸鹟（英文名：Belted Flycatcher，学名：Xenotriccus callizonus），是雀形目霸鹟科带霸鹟属的鸟类。分布于中美洲墨西哥南部至萨尔瓦多西北部的有限区域。其最显著的特征是头顶上的尖刺状冠羽和横跨胸部的宽橙色带纹。","appearance":"带霸鹟体型较小，雄雌相似。头部两侧、颈背及头侧呈橄榄褐色，具宽阔的白色或淡柠檬色眼环，形成泪滴形状。头顶有一簇黑色或橄榄灰色的尖刺状冠羽。背部橄榄褐色，尾上覆羽淡肉桂棕色。尾羽深褐色，外侧尾羽的外缘呈灰白色。翼羽深褐色，翼覆羽端部广泛肉桂色。翅膀短而圆，具肉桂色三级飞羽边缘和次级飞羽上的面板。喉部黄色，胸部有一条明显的肉桂红棕色带纹，下腹部淡柠檬色。幼鸟外观类似成鸟，但冠羽较短。","habits":"带霸鹟栖息于中美洲的亚热带灌木林，尤其是以橡树为主的干林。它们通常选择隐藏于密集的植被中，偶尔会离开密丛捕食昆虫。带霸鹟通常是孤独生活的，可能实行社会性一夫一妻制。","identification":"带霸鹟非常独特，不易与其他物种混淆。与之相似的有墨西哥霸鹟，但后者整体颜色偏灰，翼纹白色而非肉桂色，胸带颜色也不同。此外，这两种鸟的地理分布并不重叠。领霸鹟外观上有些相似，但其上体颜色更深，下体全部为肉桂色。","protection":"IUCN：LC（无危）","distribution":"带霸鹟主要分布在中美洲的墨西哥南部、危地马拉西南部和萨尔瓦多西北部。"},{"name":"墨西哥霸鹟","english_name":"Pileated Flycatcher","scientific_name":"Xenotriccus mexicanus","overview":"墨西哥霸鹟（英文名：Pileated Flycatcher，学名：Xenotriccus mexicanus），是雀形目霸鹟科带霸鹟属的小型鸟类，分布于墨西哥西南部内陆高地的干燥灌木林地带。其羽毛灰暗，胸部白色，喙部呈黄色，头部顶部有尖锐的灰色羽毛冠。数量受森林砍伐影响，目前估计约有2万至5万只。","appearance":"墨西哥霸鹟体型小巧，羽色较为暗淡，头部具有一簇尖锐的灰色羽毛形成冠状，喙部下方可见明亮的粉橙色。其体羽主要为灰色，胸部为白色，整体外观与几种Empidonax霸鹟（如暗霸鹟）相似，但可通过其独特的冠羽和喙下颜色加以区分。","habits":"栖息于亚热带森林，夏季会进入热带高山灌木丛。主要以昆虫为食，其自然生存环境受到人类活动的威胁，尤其是牧场扩张、咖啡和柑橘种植园的开发。","identification":"与Empidonax属的霸鹟（如暗霸鹟）相比，墨西哥霸鹟拥有更加尖锐的冠羽，喙下部呈亮粉橙色，且叫声不同，缺乏‘whit’声的叫声特征。","protection":"IUCN：LC（无危）。此前曾被认为接近威胁状态。其生境因牧场和农作物种植而受到威胁，保护区域在其小范围内极为有限。","distribution":"分布于墨西哥西南部，从米却肯州和莫雷洛斯州向东至瓦哈卡州（伊斯特穆斯德特胡安特佩克以西）。"},{"name":"灰胸长尾霸鹟","english_name":"Eastern Phoebe","scientific_name":"Sayornis phoebe","overview":"灰胸长尾霸鹟（英文名：Eastern Phoebe，学名：Sayornis phoebe），是雀形目霸鹟科菲比霸鹟属的鸟类。这种小型鸟类以灰褐色的外表和独特的尾部摆动而著称，分布于北美，从加拿大中北部至美国中南部，包括美国东南部和加拿大东南部。灰胸长尾霸鹟的名称可能源于罗马月神狄安娜的别称，但更可能是模仿其鸣叫。","appearance":"灰胸长尾霸鹟拥有中等体型，成年鸟体长可达157毫米左右，雄鸟略大于雌鸟，颜色上雄鸟也稍暗一些。其上身呈灰褐色，头部和尾巴颜色较背部深，下身偏白色，腹部有时带有淡黄色调。冬季羽毛颜色更加橄榄色，腹部黄色调更为明显。幼鸟与成鸟相似，但翼部有红棕色条纹，头部颜色较浅。","call":"灰胸长尾霸鹟的鸣叫特征包括尖锐的'chip'声，以及其名字来源的'fee-bee'叫声。","habits":"灰胸长尾霸鹟适应力强，常见于城市环境中的树林、溪流旁和农田。它们偏好树荫下的隐蔽处，冬季或繁殖季节常在水源丰富的林地边缘活动。它们主要以昆虫为食，但在天气较冷时也会食用果实和浆果。","breeding":"灰胸长尾霸鹟在东部北美的开放林地、农田和郊区繁殖，通常在4月初就开始筑巢活动。巢由泥土基底构成，内衬苔藓和草，建在岩石裂缝或人造结构的隐蔽处，每窝产卵2至6枚。双亲共同喂养幼鸟，一年通常会养育两窝幼鸟。","identification":"与东绿霸鹟外观极其相似，但后者缺乏灰胸长尾霸鹟羽色中的淡黄色调，且具有明显的翼条纹，不会持续摆动尾巴。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于加拿大中部至美国中南部，包括美国东南部和加拿大东南部。冬季迁徙至美国南部和中美洲。","other":"灰胸长尾霸鹟是最早返回繁殖地的鸟类之一，春季迁徙回北方的时间远早于其他飞虫捕食者。"},{"name":"黑长尾霸鹟","english_name":"Black Phoebe","scientific_name":"Sayornis nigricans","overview":"黑长尾霸鹟（英文名：Black Phoebe，学名：Sayornis nigricans），是雀形目霸鹟科菲比霸鹟属的鸟类。中型的霸鹟科鸟类，以深黑色为主色调，腹部洁白。广泛分布于北美西部至南美的阿根廷西北部，常与水体相伴，如河流、湖泊边缘或公园喷泉附近。其筑巢材料依赖于附近的泥源。","appearance":"黑长尾霸鹟体长约16厘米，体重约18克，全身主要为深灰黑色，头、胸及背部色更深，近似黑色；腹部与下尾覆羽为白色，形成独特的倒V字形图案。翼端有淡淡的棕色边缘，尾部快速上下摆动为其显著的行为特征。幼鸟的羽毛边缘呈淡肉桂色，翼上有类似的色带。雄雌两性在外观上相似，仅通过繁殖季节的生殖器官差异可区分。","call":"黑长尾霸鹟的鸣声为重复的‘tee-hee’、‘tee ho’或类似‘sisee’、‘sitsew’的交替叫声，由两性共同发出，但通常雄鸟的叫声更为常见。","habits":"黑长尾霸鹟主要栖息于水源附近，如河流、湖泊和海岸线，偏好有泥源的半永久性水源，用于筑巢。它们主要以昆虫为食，常从低矮的栖木出发，进行短距离飞行捕食。在繁殖季节，它们会表现出强烈的巢址忠诚度，年复一年地重用同一个巢或巢址。","breeding":"黑长尾霸鹟为一夫一妻制，每年繁殖季节可能哺育两窝幼鸟。巢穴通常建在水面上方，固定于垂直墙面并靠近保护性天花板，由泥壳和植物纤维构成。孵化后，雏鸟由雌鸟照料数日，双亲共同喂养，大约18天后离巢。","identification":"黑长尾霸鹟与同属的棕腹长尾霸鹟和灰胸长尾霸鹟相比，前者头部、胸部及背部颜色更深，腹部洁白。而棕腹长尾霸鹟上身呈灰色，下腹橙棕色；灰胸长尾霸鹟下身呈灰白至淡黄色，仅头顶为深灰色。","protection":"IUCN：LC（无危）","distribution":"黑长尾霸鹟繁殖于美国西部至阿根廷西北部，包括北美洲的西南部地区、墨西哥、中美洲直至南美洲的部分地区。","other":"黑长尾霸鹟的北方种群部分迁徙，而南方种群则全年留居于繁殖地。"},{"name":"棕腹长尾霸鹟","english_name":"Say's Phoebe","scientific_name":"Sayornis saya","overview":"棕腹长尾霸鹟（英文名：Say's Phoebe，学名：Sayornis saya），是雀形目霸鹟科菲比霸鹟属的鸟类。广泛分布于北美西部的霸鹟科鸟类，偏好干燥荒凉的环境。其最显著的特征是腹部橙色的洗染效果，上体灰褐色，尾部黑色鲜明，常展现尾部摆动的行为。该鸟种的分布范围广阔，北至阿拉斯加，南达墨西哥中部，遍布美国西部和加拿大西部。","appearance":"棕腹长尾霸鹟体型中等，长约19厘米，体重约21-22克，上体呈淡灰棕色，头部和颈后颜色较深，尾羽黑褐色，翅膀深褐灰色，腹部与尾下覆羽为独特的肉桂色，这一特征在北美的飞虫捕食者中独一无二。雌雄同型，但繁殖季节时，雄鸟会发展出泄殖腔突起，而雌鸟则形成育儿斑。幼鸟外观与成鸟相似，但羽毛更显暗淡，翼羽和飞羽较为狭窄且磨损，翼上有两道明显的肉桂色条纹。","call":"棕腹长尾霸鹟的鸣唱和叫声特点尚未详述。","habits":"这种鸟偏好开放地带，通常栖息于低矮的醒目位置，活动范围覆盖从美国西部到加拿大西部的广大区域，北至阿拉斯加，南至墨西哥中部。它们早春开始迁徙，北方种群秋季向南迁移到美国西南部和墨西哥中部过冬，与南方的留鸟重叠。主要以昆虫为食，包括蜜蜂、黄蜂、苍蝇、甲虫和蚱蜢，通常从距离地面1-2米的高度捕食。","breeding":"棕腹长尾霸鹟表现出强烈的筑巢地点忠诚，一般为一夫一妻制，常两次繁殖。巢建于岩石壁架或其他支撑架下，有时利用人造结构，如废弃建筑中的草原农场和西部牧场。巢由草、茎、苔藓和其他纤维植物材料构成，很少使用泥土。繁殖期从三月中旬的得克萨斯州到五月底的阿拉斯加，雌鸟孵化4或5枚蛋约15天，幼鸟在孵化后约17天离巢。","identification":"与灰胸长尾霸鹟和黑长尾霸鹟相比，棕腹长尾霸鹟的下体呈橙色，上体灰棕色，尾部黑色，翼上有两道肉桂色条纹。成年雌雄难以区分，但繁殖季节时可通过泄殖腔突起和育儿斑识别。幼鸟的翼上有明显的肉桂色翼带。","protection":"IUCN：LC（无危）","distribution":"繁殖区域涵盖从阿拉斯加至南墨西哥的广大地区，非繁殖季节则向南迁移至美国西南部和墨西哥中部。","other":"关于该物种的研究相对较少，特别是在种群动态、生态学、生理学、能量学和营养需求方面。"},{"name":"领霸鹟","english_name":"Northern Tufted Flycatcher","scientific_name":"Mitrephanes phaeocercus","overview":"领霸鹟（英文名：Northern Tufted Flycatcher，学名：Mitrephanes phaeocercus），是雀形目霸鹟科领霸鹟属的鸟类。独特的外观和行为使其在高山区和山脚地带尤为显眼。拥有吸引人的肉桂色下体，明显的羽冠，以及独特的捕食昆虫的方式。","appearance":"领霸鹟长约12厘米，体重约8.5克。上体橄榄绿色，尾羽和翅膀黑色，后者具有两道淡黄色翼带和次级飞羽边缘。胸部橙赭色，逐渐过渡到鲜亮的黄色腹部。性别相似，但幼鸟的上体呈棕色，带有淡黄色边缘，翼带橙色，下体颜色较浅。","call":"发出快速的“weet weet weet weet”叫声。黎明时的鸣唱极为迅速而尖锐，节奏为‘bip-bip-bip-dididiup-bip-bip-bibibiseer’。","habits":"栖息于成熟山林和高大的次生林，尤其偏爱边缘和开阔地带。繁殖季节位于海拔700至3000米间，最常见于1200至2150米。以飞行昆虫为食，常从开放的栖息地捕猎。","breeding":"雌鸟在树枝或藤蔓上建造盘状巢穴，高度4至27米，通常隐藏于蕨类、凤梨科植物和其他附生植物中。雌鸟孵化两个带有褐色斑点的白色蛋，孵化期为15至16天。","identification":"与橄榄色霸鹟相区别，后者分布于秘鲁和玻利维亚。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，从墨西哥西部至厄瓜多尔西北部。","other":"虽然不迁徙，但曾在美国的德克萨斯州大弯国家公园被首次记录为罕见迷鸟，之后在亚利桑那州也有观察记录。"},{"name":"橄榄色霸鹟","english_name":"Olive Tufted Flycatcher","scientific_name":"Mitrephanes olivaceus","overview":"橄榄色霸鹟（英文名：Olive Tufted Flycatcher，学名：Mitrephanes olivaceus），是雀形目霸鹟科领霸鹟属的小型鸟类。亦称: 茶青霸鹟，具有独特的羽色和明显的冠羽。分布于南美洲安第斯山脉东部的秘鲁至玻利维亚西北部的云雾森林中。","appearance":"该鸟体型较小，羽色为淡橄榄褐色，最显著的特点是其头部的明显冠羽。雌雄羽色相似，幼鸟的羽色细节可能有所不同，但总体保持了成鸟的色彩基调。","call":"典型的叫声是一系列柔和的tick音符，随后是一个高音的‘seep’声。歌声由一系列干燥的chipping音符组成，接着是一个穿透力强的下降哨音‘che..chechecheche..SEEUW’。","habits":"栖息于亚热带或热带湿润山地森林，常在显眼的位置停留，兴奋地四处寻找昆虫猎物，容易加入混合物种的鸟群。以捕食昆虫为主。","breeding":"具体繁殖信息未详细提及。","identification":"其小体型、淡橄榄色的羽毛和明显的冠羽在分布范围内是独一无二的，易于与其他鸟类区分开来。","protection":"IUCN状态未知。","distribution":"分布于秘鲁的安第斯山脉中部到玻利维亚西北部的拉巴斯和科恰班巴地区。","other":"属于新大陆特有的捕食昆虫鸟类，与Elaneia（或称茶青霸鹟）有亲缘关系，但属于不同的属。"},{"name":"绿胁绿霸鹟","english_name":"Olive-sided Flycatcher","scientific_name":"Contopus cooperi","overview":"绿胁绿霸鹟（英文名：Olive-sided Flycatcher，学名：Contopus cooperi），是雀形目霸鹟科绿霸鹟属的鸟类。特征为橄榄灰或灰褐色上羽，胸部中央和喉部白色，两侧深灰色，形成似穿着马甲的外观。广泛分布于北美，自阿拉斯加至美国西南部，墨西哥西北部，美国中东部到加拿大东南部繁殖，冬季则迁移至南美北部和中部。","appearance":"绿胁绿霸鹟体长约18-20厘米，体重32-37克，头部显得较大，尾巴较短，喙粗壮。上羽颜色为深橄榄灰或灰褐色，下羽中央白色，两侧橄榄灰，形成鲜明对比，似穿马甲。两翼暗色，仅有隐约的淡灰色翼斑，以及白色的次级飞羽边缘。性别外观相似，但雄鸟的翼长略大于雌鸟。幼鸟上羽更偏棕色，翼斑和次级飞羽边缘泛黄。","call":"鸣唱独特，常被形容为“快速，三杯啤酒”，由三个高音节组成，首音较短，后两音更高更响亮。此外，也有‘pip’声的呼叫。","habits":"栖息于北美的针叶林边缘、沼泽、森林空地等，偏好有开阔空间和高树的环境。以飞行昆虫为主食，采用掠食的方式捕猎。迁徙期间和冬季会在开放的森林间隙停留。","breeding":"繁殖季节通常在春季至夏季，每窝产卵3-4枚，孵化期约15-19天，雏鸟出生后同样需15-19天左右才能离巢。雌鸟选择巢址，多位于针叶树的水平枝上，巢呈杯状，由细枝、草、苔藓等构成。","identification":"与大绿霸鹟、Wood-Pewee等近似种区分，绿胁绿霸鹟体型更大，有明显的马甲状下羽图案，且翼长和尾长较长。叫声和歌声也有所不同。","protection":"IUCN：NT（近危）","distribution":"繁殖于北美，包括美国阿拉斯加州西部至西南部，墨西哥西北部，美国中东部和加拿大东南部。非繁殖季节分布于南美北部和中部。","other":"绿胁绿霸鹟是北美最长距离迁徙的鶲鵙之一，从阿拉斯加至玻利维亚的迁徙距离可达7000英里。"},{"name":"大绿霸鹟","english_name":"Greater Pewee","scientific_name":"Contopus pertinax","overview":"大绿霸鹟（英文名：Greater Pewee，学名：Contopus pertinax），是雀形目霸鹟科绿霸鹟属的鸟类。体型较大的灰褐色飞禽。其最显著的特征是尖刺状的羽冠和橙黄色的下喙，分布于北美西南部至中美洲尼加拉瓜一带。","appearance":"大绿霸鹟身长可达18厘米，体重约27克，全身呈单调的灰褐色，上体颜色略深，具有明显的羽冠，两性外观相似，但雄鸟的翅膀和尾巴平均比雌鸟稍长。幼鸟与成鸟的差异细微，主要通过季节性换羽显现。","call":"大绿霸鹟的鸣唱清晰悠扬，常被描述为“Ho-say ma-ree-ah”，在日间频繁发出，容易识别，尤其在繁殖季节。","habits":"大绿霸鹟栖息于山地松林或松栎混交林，偏好海拔6,500英尺以上的环境，以飞行昆虫为主食，偶尔在较凉月份食用浆果。它们通过从高枝上猛扑的方式捕食昆虫。","breeding":"繁殖期，雌鸟会在针叶树的水平分叉处搭建巢穴，巢由草、杂草构成，内部铺垫细草，外表装饰苔藓。通常产三到四枚带有稀疏或环状棕色和橄榄色斑点的乳白色蛋。","identification":"与绿胁绿霸鹟相比，大绿霸鹟更显暗淡，没有对比鲜明的胸饰，头部有更为突出的羽冠，且下喙为橙黄色，易于区分。","protection":"IUCN：LC（无危）","distribution":"大绿霸鹟在北美西南部至中美洲尼加拉瓜有广泛分布，繁殖区主要在美国西南部至墨西哥中部，非繁殖期可能南迁至更远的中美洲国家。","other":"大绿霸鹟曾被称为Coues's或Coues' Flycatcher，以纪念收集并描述该物种的Elliot Coues医生。"},{"name":"暗绿霸鹟","english_name":"Dark Pewee","scientific_name":"Contopus lugubris","overview":"暗绿霸鹟（英文名：Dark Pewee，学名：Contopus lugubris），是雀形目霸鹟科绿霸鹟属的鸟类。特有于中美洲的塔拉曼卡山脉森林，即哥斯达黎加和巴拿马西部的高海拔地区，分布于1250米至2150米之间。这种大型、暗色的霸鹟以湿山林中的边缘地带和空地为主，也会出现在相邻的半开阔地带。","appearance":"暗绿霸鹟长约26.5厘米，体重约23克。其上身呈烟灰色，冠部尤为深色，具有明显的羽冠。翅膀和尾巴黑色，翼羽边缘略带灰色，形成微弱的翼条纹。喉部为淡灰色，其余下体颜色较背部更浅，呈橄榄灰色，腹部下方转为黄色。两性相似，但幼鸟上体呈棕色，翼羽边缘带有锈红色。","call":"暗绿霸鹟发出持续而响亮的鞭状叫声，以及重复的fred-reek-fear歌声。","habits":"暗绿霸鹟独居，除非在繁殖季节。它常栖息在高处的观察点，从那里飞出捕捉飞行昆虫，之后返回同一暴露的栖息点。它在湿润的山地森林中活动，尤其偏爱森林边缘和空地，以及邻近的半开放区域。","breeding":"繁殖季节从三月持续到六月。巢为宽大的浅杯状，由苔藓、绿苔和地衣构成，内部衬以植物纤维。巢位于离地面4-12米高的树枝上。雌雄双方共同喂养雏鸟。关于暗绿霸鹟的繁殖生物学细节尚不完全清楚。","identification":"与暗绿霸鹟容易混淆的物种有西绿霸鹟、东绿霸鹟、南热带绿霸鹟和绿胁绿霸鹟。区别在于体型、翼条纹的明显程度、喙的颜色和形态。","protection":"IUCN：LC（无危）","distribution":"暗绿霸鹟分布在中美洲的塔拉曼卡山脉森林，具体为哥斯达黎加和巴拿马西部的高海拔地区，范围从1250米至2150米。它在哥斯达黎加的中部火山山脉和塔拉曼卡-奇里基山脉两侧都有分布。","other":"暗绿霸鹟对巢穴的防御非常积极，会对抗包括绿巨嘴鸟在内的较大物种。"},{"name":"烟色绿霸鹟","english_name":"Smoke-colored Pewee","scientific_name":"Contopus fumigatus","overview":"烟色绿霸鹟（英文名：Smoke-colored Pewee，学名：Contopus fumigatus），是雀形目霸鹟科绿霸鹟属的鸟类。中型的霸鹟科鸟类，通体呈灰暗色，头部略具顶冠。广泛分布于南美洲，从委内瑞拉至阿根廷西北部，栖息于云雾森林边缘的中海拔地带。","appearance":"烟色绿霸鹟体型中等，羽毛均匀灰暗，头顶稍隆起形成轻微的顶冠。雄雌相似，喙橙色，基部黑色。成熟个体长约16-17厘米，体重约18-20克。脚趾排列为异趾型，三趾向前一趾向后，这是大多数栖木鸟的典型特征。成年鸟的羽衣统一为灰色，背部和翼尖可能带有橄榄色或浅棕色调。头冠深灰，翼上有两道几乎不可见的浅色翼纹。喉咙、胸腹部颜色略淡。下尾覆羽呈黄白色。幼鸟颜色较浅，偏棕色，颈背有羽边，可见2-3条翼纹，翼纹和腹部略带赭色。","call":"烟色绿霸鹟的鸣叫声多样，最常见的是响亮的‘pip pip pip’声。黎明时会发出‘where-di-WIT… whew’的叫声，还有清晰重复的‘peeew’哨音。偶尔也会发出嘶哑重复的‘zur’声、吹口哨般的‘whueer’声以及短促的‘pjeek pjeek’音。","habits":"烟色绿霸鹟常栖息于中海拔的云雾森林边缘，偏好在显眼的枯枝上停留。它们通过长时间的空中捕捉昆虫，然后返回相同的栖息点，尾巴振动着着陆。在厄瓜多尔东北部，已知它们的食物包括蝉和成年鳞翅目昆虫。","breeding":"烟色绿霸鹟筑杯状巢，由苔藓和地衣构成，通常建在高树的水平枝上。在厄瓜多尔东北部的研究中，九个活跃的巢穴在9月至12月间被发现，每巢产卵2枚，卵壳白色，散布着褐色、肉桂色和薰衣草色斑点。孵卵期约为16天，雏鸟在孵化后21天离巢。巢的构建似乎仅由一只亲鸟，可能是雌鸟，负责，但双方亲鸟都会喂养雏鸟。","identification":"烟色绿霸鹟与近缘种黑绿霸鹟的区别在于体型略大，且常在较高的位置栖息。幼鸟的色彩和纹理也有别于成鸟。","protection":"IUCN：LC（无危）","distribution":"烟色绿霸鹟的地理分布覆盖南美多个国家，包括委内瑞拉、玻利维亚、巴西、哥伦比亚、厄瓜多拉、圭亚那、秘鲁和委内瑞拉。其自然栖息地包括亚热带或热带干燥森林、亚热带或热带湿润山地森林以及重度退化的前森林区域。鸟类多见于海拔1000-2500米之间，安第斯山脉可达3000米，而在西南厄瓜多尔则低至海平面附近。","other":"烟色绿霸鹟在其分布范围内被认为是相当普遍的物种，能容忍一定程度的生境干扰，且在多个国家公园和保护区中都有分布。"},{"name":"赭色绿霸鹟","english_name":"Ochraceous Pewee","scientific_name":"Contopus ochraceus","overview":"赭色绿霸鹟（英文名：Ochraceous Pewee，学名：Contopus ochraceus），是雀形目霸鹟科绿霸鹟属的罕见鸟类。主要分布在中美洲的高海拔地区，具体为哥斯达黎加的高地以及巴拿马西部的山区，海拔大约在2,200至3,000米之间。其显著的外观特征为整体呈淡褐色，腹部颜色较浅，呈现黄色调，翼上有两条棕色条纹，下颚基部橙色，头顶有一撮明显的羽毛形成冠状。","appearance":"赭色绿霸鹟体型中等，全身覆盖着淡褐色的羽毛，腹部颜色偏黄，两翼带有明显的棕色条纹。下颚的下半部分呈现出鲜艳的橙色，头顶有一撮毛发形成小尖顶，非常独特。与相似物种相比，它的体型较大，喙较长。","call":"该鸟会发出尖锐的‘pee-pit！’叫声，以及一系列的pip声，这些声音有助于识别其位置。","habits":"赭色绿霸鹟通常栖息在山地森林边缘，偏好在裸露的枯木上停歇。它们主要生活在哥斯达黎加和巴拿马西部的高海拔地带，这些地方的环境湿润，植被茂密。","breeding":"关于赭色绿霸鹟的繁殖行为细节尚不明确，但一般认为它们会在树洞或岩石缝隙中筑巢。","identification":"赭色绿霸鹟与羽冠飞虫鸟极为相似，但可以通过其较大的体型、较长的喙以及独特的鸣叫声来区分。","protection":"IUCN：LC（无危）","distribution":"赭色绿霸鹟主要分布在中美洲的哥斯达黎加高地以及巴拿马西部的山区，这些地区海拔在2,200至3,000米之间。","other":"这种鸟因其分布范围狭窄而被认为是较为罕见的物种。"},{"name":"西绿霸鹟","english_name":"Western Wood Pewee","scientific_name":"Contopus sordidulus","overview":"西绿霸鹟（英文名：Western Wood Pewee，学名：Contopus sordidulus），是雀形目霸鹟科绿霸鹟属的鸟类。广泛分布于北美西部的森林地带。其外观为灰橄榄色的上体，淡色下体，胸部带有橄榄色斑点，拥有两个翼带，嘴部暗色，下颌基部呈黄色。与东绿霸鹟极其相似，过去曾被认为是同一物种。鸣叫声为响亮的嗡嗡声“peeer”，歌声由三个快速下降的“tsees”音节结束于一个下降的“peeer”。","appearance":"体型小至中等，总长度约14-16厘米，雌鸟略小于雄鸟。成鸟的上体均匀的暗灰褐色，两翼带有模糊的浅色翼带和三级飞羽边缘；下体呈淡白色，胸和侧部转为暗灰色；上喙深色，下喙较浅，尖端或全黑。幼鸟的外观与成鸟类似，但上体带有棕色至肉桂色，翼带明显呈肉桂色。","call":"发出响亮的嗡嗡声“peeer”，歌声包含三个快速下降的“tsees”音节，以一个下降的“peeer”结尾。","habits":"栖息于开放的林地、林缘和河流附近的森林，偏好有大树、开阔的下层植被和立枯木的环境。它们通常在树的中等高度处等待，然后飞出捕食空中飞行的昆虫，也会悬停摘取植物上的昆虫。在繁殖季节，巢建于水平树枝上或树洞内，使用草和其它植物纤维结合蜘蛛网筑巢，外面覆盖苔藓、芽鳞和昆虫皮壳伪装。","breeding":"繁殖期间，雌鸟会在开放林地中选择水平树枝或树洞建造杯状巢，通常产2到3枚蛋。父母双方共同喂养幼鸟。","identification":"与东绿霸鹟难以仅凭外观区分，但西绿霸鹟的翼带较弱，全身颜色更深，最可靠的区别在于鸣叫声的不同。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美洲西部和中美洲，冬季迁徙至南美洲西北部。","other":"与东绿霸鹟及南热带绿霸鹟关系密切，有时被部分分类学家视为超种。"},{"name":"东绿霸鹟","english_name":"Eastern Wood Pewee","scientific_name":"Contopus virens","overview":"东绿霸鹟（英文名：Eastern Wood Pewee，学名：Contopus virens），是雀形目霸鹟科绿霸鹟属的鸟类。一种小型北美洲霸鹟科鸟类，以其哀婉的pee-ah-wee鸣声而知名，广泛分布于东部美国和加拿大南部的森林环境中。这种鸟主要栖息于森林树冠层，筑巢于离地面高达22米的水平树枝上，其巢外表覆盖苔藓，巧妙融入周围环境。其繁殖生境多样，从城市林地到农业区的林块、果园，再到草原、河岸森林和成熟森林的广阔区域都有分布。尽管常见，但近50年来，东绿霸鹟的繁殖种群数量呈现稳定下降趋势。","appearance":"东绿霸鹟体型中等，长约15厘米，重约14克。上体灰橄榄色，下体浅色，胸腹部略带暗色，翼上有两道明显的淡色翼纹。喙上半部深色，下半部橙黄色带暗尖。雌雄外观相似，幼鸟颜色稍深，腹部偏黄。站立时姿态直立，典型飞禽特征，以空中捕食昆虫为主，但不会频繁振翅或摆尾。","call":"最显著的鸣叫为哀婉的pee-ah-wee哨音，重复发出，另有独特的‘PEE-a-weeEEE！’歌声。","habits":"偏好栖息于多种类型的森林环境，包括城市林地、农业区的林块、果园、草原、河岸森林和成熟森林。主要在春季末从南美洲返回繁殖。活动范围广泛，包括北美的落叶林、开放松树林和北方混合硬木针叶林。以昆虫和其他节肢动物为食，常在树中层高度的枝条上等待，然后飞出捕食空中的猎物，有时会悬停以从植被中取食。","breeding":"繁殖期为夏季，在横生的树枝上用蜘蛛网固定草、树皮和苔藓制成的杯状巢。巢高通常介于15至60英尺之间，平均约为30英尺。常见筑巢树种有橡树、松树、桦树和枫树。雌鸟产卵几乎总是三枚（偶尔二枚），卵呈透明白色，带有集中在大端的棕色斑点。雄鸟领地性强，积极保卫巢区，甚至攻击同类或异类入侵者。孵化期12至14天，双亲共同喂养晚成雏鸟。雏鸟在孵化后15至17天离巢，首次飞行可能落地，父母会在附近枝头呼唤并喂食，直到幼鸟能够飞翔。","identification":"与西绿霸鹟极为相似，主要通过鸣声区分，东绿霸鹟的pee-ah-wee鸣声与西绿霸鹟的刺耳peeer鸣声明显不同。与灰胸长尾霸鹟相比，后者缺乏明显的翼纹，经常摆尾，且早于东绿霸鹟到达繁殖地。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美，范围从中南部加拿大至美国中南部和东南部。非繁殖季节迁徙至南美西北部。","other":"东绿霸鹟与西绿霸鹟在大平原西部相遇区域有杂交现象报道。"},{"name":"南热带绿霸鹟","english_name":"Southern Tropical Pewee","scientific_name":"Contopus cinereus","overview":"南热带绿霸鹟（英文名：Southern Tropical Pewee，学名：Contopus cinereus），是雀形目霸鹟科绿霸鹟属的鸟类。小型灰褐色的飞禽。分布于南美洲南部，自巴西东南部至巴拉圭和阿根廷北部，以森林边缘和高树的栽培区为其主要栖息地。","appearance":"该鸟全长约14厘米，重约12克，上体呈暗棕色或灰色，头部黑色，具白色翼纹两条。喉部及胸部中央为白色，腹部淡黄色，侧腹和胸侧为灰褐色。喙短，上喙黑色，下喙橙色。性别相似，但羽色深浅有较大变异，尤其巴西东南部个体接近黑绿霸鹟的颜色。","call":"其鸣声为响亮的三音节颤音，亦会发出尖锐的weeet叫声，但叫声存在地理变异。","habits":"南热带绿霸鹟常栖息于森林边缘或开阔地带，选择高处的枝头作为观察点，从那里飞出捕捉飞行中的昆虫，之后返回同一显著的栖木。这种鸟非常显眼。","breeding":"繁殖季节，雌鸟在树叉或树枝上建造小而开放的杯状巢，巢由纤维和草构成，内部铺草，外表装饰苔藓。雌鸟孵育两枚带红棕色斑点的乳白色蛋，孵化期约为15-16天。","identification":"与其他绿霸鹟相比，南热带绿霸鹟翅膀较短，尾巴较长，且可能在喙眼间有一微小斑点。叫声是最可靠的鉴别特征。","protection":"IUCN状态未知，需查阅最新数据。","distribution":"分布于南美洲，具体包括巴西南部、东南部，延伸至巴拉圭和阿根廷北部。"},{"name":"西热带绿霸鹟","english_name":"Tumbes Pewee","scientific_name":"Contopus punensis","overview":"西热带绿霸鹟（英文名：Tumbes Pewee，学名：Contopus punensis），是雀形目霸鹟科绿霸鹟属的鸟类。小型霸鹟，曾被视为热带绿霸鹟的亚种。该鸟主要分布于厄瓜多尔西部和秘鲁西部的干燥及半湿润森林，体色以灰色为主，具淡色翼斑及小羽冠，部分个体腹部略呈黄色。它是原“热带绿霸鹟”复合体中分布最狭的种类，海拔分布从海平面至秘鲁马拉尼翁谷地的2800米。","appearance":"雌雄同形同色。成鸟上体为橄榄灰色，头顶略深；腰及尾上覆羽偏褐色，腰侧具隐白斑。翼覆羽末端灰白至褐灰色，次级飞羽外缘色浅。眉纹及眼周细白线常不明显；面颊、颈侧、胸及上腹淡灰橄榄色，颏喉白色但羽心灰色；下腹及尾下覆羽白色，后者有时羽缘带白。翼下覆羽及腋羽褐白色。体长13–14厘米，体重约9.3克。幼鸟羽色未详，推测与北热带绿霸鹟相似。","call":"鸣唱为清晰的二音节哨音“tew-tee”，频宽约4–5千赫，常因地域略有变化；在马拉尼翁谷地则发出“chee-wit”或“chee-chee-widit”。叫声包括轻声啁啾；无专属黎明歌。鸣唱多见于晨间及傍晚，自中层裸露枝条发出，具宣示领域功能。","habits":"栖息于干燥至半湿润的落叶林、疏林、林缘、灌丛空地，偶见于红树林及罗汉松林地。留鸟，不迁徙。多在低地及山脚活动，厄瓜多尔通常低于1500米，秘鲁可达2800米。单独或成对活动，从裸露或半开敞的中层栖枝出击捕食昆虫，常返回原枝，落地时尾羽颤动；极少参与混合觅食群。","breeding":"繁殖资料稀少。秘鲁西北部7月见求偶飞行，5月见成鸟带雏；厄瓜多尔1月、3月、12月分别记录到筑巢、产卵及育雏。巢由雌鸟单独构筑，为苔藓、地衣、蛛丝等材料编成的浅杯，距地27米。巢外径约76毫米，内径约42毫米，高约32毫米，深约21毫米。若巢遭捕食，雌鸟可在3–9天内在距原巢约30米处重建。","identification":"与迁徙的东绿霸鹟和西绿霸鹟体型更小、尾显长、喉灰、喙基橙黄范围大，落地时尾颤动，鸣声不同。与同属小型绿霸鹟相比，翼斑暗淡、体色更灰、尾不上翘。易与灰胸纹霸鹟混淆，但后者体型更小，具断裂白眼圈及更显白翼斑，行为亦异。","protection":"IUCN: LC（无危）","distribution":"繁殖区与非繁殖区相同，局限厄瓜多尔西部（从马纳比省至埃斯梅拉达斯省沿海）及秘鲁西部（至利马与万卡韦利卡省），可能延伸至哥伦比亚极西南。","other":"原被视为热带绿霸鹟的亚种之一；分子系统学研究支持将其与北热带绿霸鹟、南热带绿霸鹟分立为三个独立种。"},{"name":"白喉绿霸鹟","english_name":"White-throated Pewee","scientific_name":"Contopus albogularis","overview":"白喉绿霸鹟（英文名：White-throated Pewee，学名：Contopus albogularis），是雀形目霸鹟科绿霸鹟属的小型鸟类。其最显著的特征是拥有明亮的白色喉部斑块，全身其余部分呈现深灰色。该物种主要栖息于南美洲亚马逊雨林的东北部，偏好岩石露头、孤山或铝土矿高原附近的森林环境。","appearance":"白喉绿霸鹟体型小巧，两性皆呈深灰色，唯独喉咙部位有一块醒目的白色斑点。其栖息于雨林冠层或其下方，常单独或成对出现。","call":"发出尖锐的管状鸣叫声，尽管容易被忽视，但它们可能会在一天中的长时间内持续鸣叫。","habits":"白喉绿霸鹟生活在亚热带或热带湿润低地森林中，偏好有岩石出露的区域。它们会从栖息处飞出捕食空中昆虫，之后通常返回同一栖息地。","identification":"与热带绿霸鹟或东西方木绿霸鹟相比，白喉绿霸鹟的颜色更深，且它们的分布范围并不重叠。其他深色绿霸鹟种类的喉咙均无白色标记。","protection":"IUCN：LC（无危）","distribution":"白喉绿霸鹟分布于南美亚马逊雨林东北部，具体包括巴西东北部阿马帕州、法属圭亚那和苏里南东部。"},{"name":"黑绿霸鹟","english_name":"Blackish Pewee","scientific_name":"Contopus nigrescens","overview":"黑绿霸鹟（英文名：Blackish Pewee，学名：Contopus nigrescens），是雀形目霸鹟科绿霸鹟属的鸟类。体型较小、通体深色的鸟类，被发现于南美洲的亚马逊雨林东部、厄瓜多尔和秘鲁等地。以独特的黑色外观和稀少的分布著称。","appearance":"成鸟头部呈黑灰色，脸颊略显灰白，上体统一为暗烟灰色，尾羽和翅膀为深黑色，下体烟灰色，喉部颜色略浅。幼鸟与成鸟相似，但翼上有窄的白色翼纹。喙部上颚黑色，下颚灰肉色，虹膜棕色，跗跖和趾黑色。","call":"发出高音的‘peep’声，类似热带霸鹟，有时会是双音节。","habits":"栖息于湿润森林的树冠层，常见于安第斯山脉东坡的较高海拔，偶尔出现在亚马逊低地的局部区域。偏好在高大的树木顶端竖直站立，通常成对出现。","breeding":"相关信息尚未记录。","identification":"与东绿霸鹟和西绿霸鹟相比，体型更小，颜色更深。比烟色绿霸鹟更小，头部突起不明显，全身颜色更黑。与南美东北部的白喉绿霸鹟在地理上无重叠，后者有白色下巴和上喉。","protection":"IUCN：LC（无危）","distribution":"分布于南美的亚马逊雨林东部、厄瓜多尔和秘鲁，主要栖息在安第斯山脉东侧，海拔400至1500米之间，以及南部圭亚那至巴西帕拉州南部的上地地区。","other":"黑绿霸鹟在大部分分布区被认为是罕见的物种。"},{"name":"大安岛绿霸鹟","english_name":"Cuban Pewee","scientific_name":"Contopus caribaeus","overview":"大安岛绿霸鹟（英文名：Cuban Pewee，学名：Contopus caribaeus），是雀形目霸鹟科绿霸鹟属的鸟类。广泛分布于古巴和巴哈马北部。其最显著的外部特征是眼后部的白色新月状标记，以及上下两色的喙，下颌呈黄色。","appearance":"该鸟体长约15至16.5厘米，体重8.5至13.5克（指名亚种），bahamensis亚种体重稍轻，约10.3至12.2克。指名亚种的冠部为暗橄榄灰色，具羽簇，眼后有明显的白色新月标记，上体橄榄棕色，翅膀暗褐色，翼羽尖端淡棕色至灰白色，形成两个不明显的翼带，次级飞羽外缘白色；尾部暗色，喉部淡灰色，略带淡黄色调；胸部浅灰橄榄色，腹部和臀部更显黄芥末色。虹膜深色，喙宽扁，上喙黑色，下喙橙黄色；腿黑色。幼鸟与成鸟相似，但翼带更宽，下颌颜色较淡。bahamensis亚种比指名亚种灰暗，上体颜色较淡，下体仅轻微带有黄色调。","call":"其特有的叫声为长而下降的哨声，'Tswee-ooooooo'，首部爆炸式，尾部为慵懒的下降哨音。在巴哈马，歌曲常附加两到三个快速音符。叫声为尖锐的'peep-peep-peep'。","habits":"栖息于阔叶林、松林、森林边缘、沼泽、红树林和灌木丛地带，海拔从海平面至1800米，但在高海拔较为罕见。主要以昆虫为食，偶尔摄取果实。从低枝上搜索，突然飞出捕食空中猎物，常返回同一栖息处；着陆时会摇晃或抖动尾巴。","breeding":"繁殖期在巴哈马为2月至3月，在古巴为3月至6月。巢由细根和毛发制成的小杯状，通常位于树或灌木的分叉处或枝条上，覆盖苔藓和地衣。每窝产2至4枚蛋，关于孵化和育雏的详细信息尚不清楚。","identification":"与东绿霸鹟和迁徙型Empidonax属的皮鸟最为相似，但通过眼后的大胆白色新月标记得以区分。","protection":"IUCN：LC（无危）；在古巴的Güira国家公园等地广泛分布。","distribution":"主要分布在古巴和巴哈马北部，从海岸延伸至中等海拔。","other":"曾被与伊岛绿霸鹟和牙买加绿霸鹟合并为单一物种，即Greater Antillean pewee。"},{"name":"拉美绿霸鹟","english_name":"Hispaniolan Pewee","scientific_name":"Contopus hispaniolensis","appearance":"体长约15至16厘米，体重约11.5克。头部和背部呈灰橄榄色，以冠部颜色最深；翅膀和尾巴呈暗褐色，偶尔可见不明显的淡色翼纹（有时缺失）；喉咙灰色，胸部有橄榄棕色的斑块；腹部和下尾羽覆羽混有黄白色和灰色；虹膜深色；喙宽，黑色，基部较浅；腿黑色。雌雄外观相似。幼鸟的冠羽、背部和翅膀覆羽边缘有淡色毛缘。亚种tacitus与指名亚种相似。","call":"叫声较为低调，最常发出的是重复的柔和‘pip’声。黎明时的鸣唱是一连串快速升调的双音节‘shurr, pet-pit, pit-pit, peet-peet’。","habits":"栖息于各种林地环境，包括松树和阔叶林、荫蔽咖啡种植园、果园、森林边缘。海拔高度从海平面至至少1800米。据报道，它会加入松树林中的混合物种群。食物主要包括昆虫，也会吃小果实。从低处的栖木上起飞捕捉空中飞虫，降落时会摇摆尾巴。","breeding":"繁殖期为5月至6月。巢由雌鸟单独构建，使用根须、苔藓和地衣制成杯状，置于离地面3至5米高的枝叉中。每窝产2至4枚蛋；孵化主要由雌鸟负责，雏鸟由双亲共同喂养。","identification":"与憨蝇霸鹟相比，体型较小，无翼纹；与安岛拟霸鹟的区别在于后者有明显的翼纹和暗淡的眼环。伊岛绿霸鹟缺乏显著的野外识别特征，如翼纹和面部标记。","protection":"IUCN：LC（无危）。受地域限制的物种，仅存在于希斯帕尼奥拉岛。普遍且广泛分布，但在海地，森林覆盖率不到国土面积的1.5%，而在多米尼加共和国，约10%的森林仍然存在，但森林持续受到砍伐、刀耕火种农业、木炭生产以及松树种植园取代的威胁。","distribution":"繁殖区域与非繁殖区域一致，主要分布于北美希斯帕尼奥拉岛，包括多米尼加共和国和海地。"},{"name":"牙买加绿霸鹟","english_name":"Jamaican Pewee","scientific_name":"Contopus pallidus","overview":"牙买加绿霸鹟（英文名：Jamaican Pewee，学名：Contopus pallidus），是雀形目霸鹟科绿霸鹟属的鸟类。分布于牙买加。体型较小，羽毛以橄榄褐色为主，上体颜色较深，尤其头部最暗，下体混有灰色，喉部偏灰，胸部和两侧略带橄榄色，尾下覆羽呈淡黄色。其翼条上的淡色条纹有时不明显。","appearance":"牙买加绿霸鹟长约15厘米，重约9.3克。头部及背部为暗橄榄褐色，翅膀深棕色，翼上有狭窄的淡色条纹，可能不显眼；尾巴深棕色，略呈凹状；下体混合了灰色和淡黄色，喉部更偏灰色，胸部和两侧带有橄榄色调，尾下覆羽更黄。眼睛为深棕色，喙部宽大，上喙黑色，下喙橙黄色；腿脚为黑褐色。雌雄相似，幼鸟下体更灰，胸腹部颜色较浅，喙部颜色较淡，翼条上可能有肉桂色条纹。","call":"牙买加绿霸鹟的叫声包括哀婉的'wee-wee'声，第二个音节较响亮，两个音节都呈上升调；类似地哀婉的'uh-weee-oo'声，中间部分上升调；以及略带粗糙的口哨声'weeah'。","habits":"牙买加绿霸鹟常在森林中层的显眼栖木上飞扑捕食，喜欢在着陆时抖动尾巴。它们在牙买加的森林边缘和中海拔地区广泛分布，偶尔出现在高海拔地区，高度可达2000米。在非繁殖季节，它们可能会下到更低的海拔。","breeding":"牙买加绿霸鹟的繁殖期为每年的4月至6月，一季可繁殖两次。它们用细小的植物纤维筑巢，通常建在树杈上。","identification":"与东绿霸鹟相比，牙买加绿霸鹟的初级飞羽相对较短，翼条上的白色条纹不明显，且很少在着陆时抖动尾巴。与安岛拟霸鹟不同，后者翼上有明显的白色条纹和全黑的喙。","protection":"IUCN：LC（Least Concern）","distribution":"牙买加绿霸鹟仅分布于牙买加，主要栖息在森林边缘和中海拔地区。","other":"牙买加绿霸鹟的平均寿命约为3.5年。"},{"name":"小安岛绿霸鹟","english_name":"Lesser Antillean Pewee","scientific_name":"Contopus latirostris","overview":"小安岛绿霸鹟（英文名：Lesser Antillean Pewee，学名：Contopus latirostris），是雀形目霸鹟科绿霸鹟属的鸟类。分布于小安的列斯群岛，包括波多黎各、瓜德罗普、多米尼加、马提尼克和圣卢西亚。三个亚种表现出不同的下体颜色，分别为红肉桂色、暗黄色和更淡的颜色。","appearance":"这种小型的绿霸鹟体长约15厘米，上体呈暗橄榄棕色，有轻微的冠羽，翅膀和尾巴颜色更深。三个亚种的下体颜色各异：圣卢西亚亚种为红肉桂色，波多黎各亚种为暗黄色，而多米尼加、瓜德罗普和马提尼克的亚种颜色更浅。喙部上颚为深褐色至黑色，下颚颜色较浅。","call":"小安岛绿霸鹟的鸣叫包括吹口哨般的“peee-oo”声，随后是低音的颤音“pee-ooooo”，首音节为清晰的哨音，第二音节为低沉的颤音。此外，也会发出尖锐的“pee”声。","habits":"小安岛绿霸鹟通常栖息于山地森林，但在局部地区也可发现它们出现在干燥地带和沿海的红树林。它们的行为特征与同属的其他种类相似。","breeding":"具体繁殖信息未详述。","identification":"与大安岛绿霸鹟外观相似，但可通过下体颜色和特定的鸣叫声加以区分。此外，与波多黎各蝇霸鹟、Empidonax类的鵙鸟和东绿霸鹟也有区别，主要通过大小、下体颜色、翼条纹和眼环的存在与否进行辨识。","protection":"IUCN状态未知。","distribution":"小安岛绿霸鹟分布于北美小安的列斯群岛，包括波多黎各、瓜德罗普、多米尼加、马提尼克和圣卢西亚。","other":"无"},{"name":"北热带绿霸鹟","english_name":"Northern Tropical Pewee","scientific_name":"Contopus bogotensis","overview":"北热带绿霸鹟（英文名：Northern Tropical Pewee，学名：Contopus bogotensis），是雀形目霸鹟科绿霸鹟属的小型鸟类。旧与南热带绿霸鹟及西热带绿霸鹟并为一类统称“热带绿霸鹟”。体型小巧，羽色灰褐，腹微黄，具短冠羽。广布中美洲及南美北部，从墨西哥南部至亚马孙河口，海拔可达二千六百米，栖于林缘、疏林及灌丛。","appearance":"体长12–14厘米，体重8–14克，雌雄同形。成鸟上体暗灰褐，冠羽略尖呈短冠；翅覆羽端灰白，形成两条隐约翼斑；喉白，胸灰橄榄，腹部中央及尾下覆羽淡黄白；尾较长，初级飞羽短于第六枚；喙黑上、橙黄下，腿黑色。幼鸟上体羽缘黄褐，翼覆羽端淡肉桂，下体色淡。","call":"鸣声是可靠鉴别特征。黎明歌为每2–3秒一次的单音“weet”或“wiep”，可持续20分钟；日间常见短颤音“trree-re”及尖锐上扬的“peet”。雄鸟主唱，雌鸟亦发颤音。防御巢区时会发出响亮的喙击声。","habits":"留鸟为主，墨西哥北部个体局部南迁。栖息于干燥至湿润森林边缘、廊道林、咖啡或可可种植园、灌丛及红树林，海拔自海平面至二千六百米。单独或成对活动，常停于裸露枝头，自固定栖点起飞远距扑食昆虫后返回原处，不常混群。主要食物为小型膜翅目、鞘翅目、鳞翅目及双翅目昆虫。","breeding":"繁殖期因地而异：墨西哥3–6月，哥斯达黎加3–6月，巴拿马2–3及6、11月，委内瑞拉3–5月，特立尼达3–7月。雌鸟独建巢，杯状巢置于2–14米高处水平枝或树叉，外层地衣、苔藓、种毛及蛛丝，内衬细草及花序，外径约76毫米，内径42毫米，深21毫米。每窝2–3枚卵，卵白色具棕紫斑，雌鸟单独孵卵15–16天，雄鸟供食。失巢后3–9天内可在30米内重建。育雏期资料缺。","identification":"与过境的东绿霸鹟及西绿霸鹟相比，体型更小更瘦，尾显长，冠色深，喙下橙黄范围大，落枝后常抖尾，鸣声明显不同。易与同属小型绿霸鹟及几种纹霸鹟混淆，但翼斑暗淡、体羽更灰且无尾上翘动作。亚种间差异在色度、大小及喉胸对比，如指名亚种偏暗，苏利南亚种整体较淡。","protection":"IUCN: LC（无危）","distribution":"繁殖区：中美洲自墨西哥南部经危地马拉、伯利兹、洪都拉斯、尼加拉瓜、哥斯达黎加至巴拿马（含珍珠群岛、科伊瓦岛、兰切里亚岛）；南美洲北部哥伦比亚（安第斯山两侧）、委内瑞拉及其博卡斯群岛、特立尼达岛，向东经圭亚那至巴西亚马孙河口及阿马帕州，局部见于厄瓜多尔东南、委内瑞拉西南及巴西北部。非繁殖期：墨西哥北部个体迁至南部及科苏梅尔岛越冬。","other":"分子研究支持本种与西绿霸鹟构成姊妹种，而与南热带绿霸鹟及西热带绿霸鹟亲缘关系较远，证实旧广义“热带绿霸鹟”应拆分为三独立种。"},{"name":"黄腹纹霸鹟","english_name":"Yellow-bellied Flycatcher","scientific_name":"Empidonax flaviventris","overview":"黄腹纹霸鹟（英文名：Yellow-bellied Flycatcher，学名：Empidonax flaviventris），是雀形目霸鹟科纹霸鹟属的鸟类。细小的昆虫食性鸟类，属于霸鹟科。这种鸟在北美广泛分布，其繁殖区域覆盖了加拿大中西部至加拿大东南部和美国东北部。黄腹纹霸鹟的外部特征明显，上体呈绿色，下体黄色，尤其是喉部，胸部有一层暗色的洗染效果。拥有白色或黄色的眼环，翼上有鲜明的白色或淡黄色翼带，喙宽而扁平，尾部相对较短。","appearance":"黄腹纹霸鹟体长约13至15厘米，体重约9至16克。它的头部相对较大，眼环黄色，喉咙和胸部呈现黄色，上体橄榄绿，下体灰黄色，翼带有明显的白色条纹，尾羽棕色，边缘绿色。喙上部深褐色，下部粉红或粉黄，脚暗灰色至棕色，足黑色。雌雄鸟外观相似。","call":"黄腹纹霸鹟的叫声可被描述为粗糙且下降的“tse-berk”，与小纹霸鹟更清脆、音高更均匀的“che-bek”声类似。","habits":"黄腹纹霸鹟栖息于湿冷的北方森林，尤其是在云杉沼泽地带。它们在树的中下部等待，然后飞出捕捉飞行中的昆虫，有时会盘旋于植被之上。它们偶尔也会食用浆果或种子。","breeding":"黄腹纹霸鹟在繁殖季节选择湿润的北方森林，如云杉沼泽，作为栖息地。它们会在地面或接近地面的泥炭苔藓中筑巢。","identification":"与太平洋斜纹霸鹟和科迪纹霸鹟相比，黄腹纹霸鹟的眼环形状和翼带颜色提供了区分点。黄腹纹霸鹟的翼带更为鲜明，眼环完整且无泪滴状延伸。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括加拿大中西部至加拿大东南部和美国东北部的湿冷森林。非繁殖季节迁徙至墨西哥南部及中美洲的热带雨林。","other":"黄腹纹霸鹟是北美最被忽视的鸟类之一，也是最后一个被发现的鸟类之一。"},{"name":"绿纹霸鹟","english_name":"Acadian Flycatcher","scientific_name":"Empidonax virescens","overview":"绿纹霸鹟（英文名：Acadian Flycatcher，学名：Empidonax virescens），是雀形目霸鹟科纹霸鹟属的鸟类。属于霸鹟科，拥有最长的初级飞羽和较大的喙，主要栖息于成熟的落叶林中，尤其偏爱水边环境。其繁殖范围覆盖美国东部和加拿大西南部安大略省，冬季则迁徙至中美洲南部及南美洲西北部。","appearance":"绿纹霸鹟体型较小，上体橄榄绿色，翅膀和尾巴颜色较深，下体白色，胸部带有橄榄色斑点。具有明显的白色眼环和翼带，喙宽而扁，上喙黑色，下喙黄绿色。雄鸟和雌鸟外观相似，幼鸟则有更明显的黄色喉咙和下体，且翼部边缘呈淡黄色。","call":"绿纹霸鹟的鸣声独特，为爆裂式的'ker-chip!'或'peet-sah!'，叫声柔和，类似'peet'。","habits":"绿纹霸鹟偏好在成熟落叶林中栖息，尤其在河流、溪流和沼泽附近。它们以昆虫为主食，通过空中捕捉和悬停掠食的方式觅食。在冬季，它们会迁徙至中美洲和南美洲的热带森林。","breeding":"绿纹霸鹟在树的水平叉枝上筑杯状巢，巢常位于离地面3至9米处。雌鸟负责筑巢、孵化和育雏，双亲共同喂养雏鸟。在一些地区，牛头鸟会寄生在其巢中，但仅有16%的牛头鸟幼鸟能成功离巢。","identification":"与黄腹纹霸鹟相比，绿纹霸鹟体型更大，喙更长，翼展更宽，尾部相对更长。此外，绿纹霸鹟的下颚通常是黄色的，而黄腹纹霸鹟的下颚则为灰色。","protection":"IUCN：LC（无危）","distribution":"绿纹霸鹟繁殖于美国中部和东部，非繁殖季节迁徙至尼加拉瓜至委内瑞拉和厄瓜多尔西部。","other":"绿纹霸鹟的飞行技巧高超，机动性强，能够悬停甚至倒飞。"},{"name":"纹霸鹟","english_name":"Willow Flycatcher","scientific_name":"Empidonax traillii","overview":"纹霸鹟（英文名：Willow Flycatcher，学名：Empidonax traillii），是雀形目霸鹟科纹霸鹟属的鸟类。从北美东部至中部和西部，冬季则迁徙至墨西哥至南美的东北部。","appearance":"纹霸鹟体型较小，长度介于13.3-17.0厘米，重量约11.3-16.4克。上体呈灰褐色至橄榄色，下体较淡，喉部白色，胸部带淡橄榄灰色，腹部略带黄色。翼上有两道白色翼斑，眼环模糊或缺失。喙宽而中等长，上喙深色，下喙橙色或粉色。脚部颜色从棕色至黑色。","call":"其标志性叫声为清脆的'fitz-bew'声，以及简单的干燥'whit'叫声。","habits":"纹霸鹟偏好潮湿的灌木环境，尤其喜欢围绕湿地或河流的柳树林。在西部，它们更倾向于河流林下的灌木层。主要以空中捕食昆虫为食，有时也会在叶片表面悬停捕食或偶尔从地面取食。","breeding":"纹霸鹟为单窝繁殖，通常在5月底至6月筑巢，每窝产卵3至4枚。孵化期为13-14天，幼鸟约在13-15天后离巢。雌雄共同喂养雏鸟，但主要是雌鸟孵卵和照料幼鸟。繁殖季节短暂，约为70-90天。","identification":"纹霸鹟与桤木纹霸鹟非常相似，主要通过声音来区分。纹霸鹟的叫声为'fitz-bew'，而桤木纹霸鹟的叫声为强调的'pip'或'pit'。在视觉上，纹霸鹟比其他小体型纹霸鹟属的鸟更大，头部更大，喙较长，且缺乏明显的眼环。","protection":"IUCN：LC（无危）","distribution":"繁殖区域遍布美国东部、中部和西部，以及加拿大南部。非繁殖季节迁徙至墨西哥西部至南美的东北部，包括厄瓜多尔。","other":"纹霸鹟在繁殖季节结束时会迁徙至冬季栖息地，行程可达1,500-8,000公里。"},{"name":"恺木纹霸鹟","english_name":"Alder Flycatcher","scientific_name":"Empidonax alnorum","appearance":"体长13–17厘米，体重12–14克。上体暗灰橄榄色，头顶略深；翼黑褐色，具两道鲜明白色翼斑；尾羽暗褐带橄榄缘。喉及上胸白色，与胸侧灰带形成对比；胸侧与胁灰，腹部余部淡黄白。眼环细白，有时不显；嘴宽且长，上嘴黑褐，下嘴橙黄或粉红。雌雄同色；幼鸟上体略褐，翼斑淡黄，尾羽较尖。","call":"雄鸟鸣声为粗糙三音节“fee-BEE-o”或“free-BEER”，第二音节重音；遇警时发出清脆“pip”。与柳纹霸鹟的“fitz-bew”明显不同，为野外辨识首要依据。","habits":"繁殖期栖息于湿地灌丛、桤木及柳丛、早期次生林，海拔340–1300米。迁徙时见于灌丛、林缘、农田，南至南美北部低地灌丛。以空中掠飞与叶间啄取方式捕食昆虫为主，偶食浆果。夜迁，春末抵巢域，秋初离境。","breeding":"单窝繁殖。5月下旬至6月初筑巢，雌鸟36小时可完成松散草巢，常悬于湿地灌丛近水面，高30–82厘米。每窝3–4枚卵，卵乳白至淡粉，具褐色环斑。孵化期约11–14天，由双亲轮流担任；雏鸟期约14天。若初次失败可再筑巢一次。","identification":"与纹霸鹟极似，惟鸣声不同；翼略尖，嘴稍短，尾稍长，上体更绿。与小纹霸鹟相比体型更大，翼斑更宽；与黄腹纹霸鹟黄腹纹霸鹟比下体更白。无声个体常难定种。","protection":"IUCN: LC（无危）。","distribution":"繁殖区自阿拉斯加中部、育空、西北领地，经加拿大全境至纽芬兰，向南至大湖区、阿巴拉契亚山脉北缘。越冬区主要在哥伦比亚至玻利维亚的安第斯东坡及亚马孙上游。迁徙时经中美洲、墨西哥，偶见于美国加州等地。","other":"1973年前与纹霸鹟合称“Traill's Flycatcher”。遗传研究显示二者为姐妹种，线粒体DNA差异约5.5%。"},{"name":"白喉纹霸鹟","english_name":"White-throated Flycatcher","scientific_name":"Empidonax albigularis","overview":"白喉纹霸鹟（英文名：White-throated Flycatcher，学名：Empidonax albigularis），是雀形目霸鹟科纹霸鹟属的鸟类。分布于中美洲，包括墨西哥至巴拿马等地。其最显著的特征是白色的喉咙，以及在繁殖季节时独特的沙哑鼻音叫声。","appearance":"白喉纹霸鹟体长约11.3-12.6厘米，整体呈橄榄褐色，白色喉咙与周围较暗的橄榄褐色胸部形成对比。翅膀有浅色的黄褐色翼带，腹部偏黄色，翼下覆羽为黄褐色。喙宽而适中，上喙黑色，下喙基部肉橙色或淡粉色。眼环淡黄褐色，脚趾黑褐色。雌雄外观相似，幼鸟上部颜色更偏棕色，下部更偏黄褐色。","call":"白喉纹霸鹟的典型叫声为尖锐的‘rrrrreah！’，以及嗡嗡的‘shrrt’声。","habits":"这种鸟通常在湿地、半开放地带的灌木丛和树篱中生活，冬季则主要在低地湿地过冬。它会进行短距离迁徙，繁殖期在高地的开阔或半开阔区域，如松树林、湿润草地和溪流附近。主要以昆虫为食。","breeding":"白喉纹霸鹟的繁殖信息不详，但通常在高海拔地区筑巢繁殖。","identification":"与桤木纹霸鹟和纹霸鹟相似，但可通过翼带颜色、喉部颜色和叫声来区分。白喉纹霸鹟的翼带为黄褐色，喉部为白色，叫声独特。","protection":"IUCN：LC（无危）","distribution":"中美洲广泛分布，包括墨西哥、危地马拉、伯利兹、萨尔瓦多、洪都拉斯、尼加拉瓜、哥斯达黎加和巴拿马。","other":"白喉纹霸鹟的迁徙模式为短途迁徙，冬季会在低海拔湿地越冬。"},{"name":"小纹霸鹟","english_name":"Least Flycatcher","scientific_name":"Empidonax minimus","appearance":"小纹霸鹟成鸟上体灰橄榄色，下体白色，腹部略带黄色调，胸部烟灰色。头部圆形，眼圈白色，嘴短，下颌基部黄橙色，尖端暗色。两翼具两道白色翼带，尾巴略呈叉状。喙凸起，宽度4.5至5.5毫米。幼鸟翼带颜色稍深，上体略偏棕色，翼带更接近肉桂色。","call":"鸣声为响亮的“che-BEK, che-BEK”，通常连续爆发，伴有短暂干涩的“whit”叫声。","habits":"栖息于多种林地或灌木丛生的环境，繁殖季节常靠近水源。分布于加拿大西部至美国中北部和东北部，冬季迁徙至中美洲，从墨西哥至巴拿马。集群于落叶林，偶尔出现在针叶林边缘。偏好近开阔地或林缘的繁殖地点，冬季栖息于次生林和森林边缘。","breeding":"繁殖期为春季，集群繁殖，每群2至30个领域。雌鸟编织草细枝筑巢，位于小树或大枝顶端，平均离地12至25英寸。一窝产卵3至5枚，多为4枚，孵化期13至16天。雏鸟出生后12至17天首次飞翔，之后由双亲喂养2至3周。","identification":"与纹霸鹟、桤木纹霸鹟和绿纹霸鹟相比，具有较短的初级飞羽延伸，上体颜色较淡，翼带和眼环更白，尾巴略叉。与哈氏纹霸鹟相比，下颌暗色部分较小，头部和背部颜色一致。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大西部至美国中北部和东北部，包括加拿大东南部。冬季迁徙至中美洲，从墨西哥至巴拿马。","other":"成年鸟在迁徙至越冬地后换羽，幼鸟在秋季迁徙前和期间换羽。"},{"name":"哈氏纹霸鹟","english_name":"Hammond's Flycatcher","scientific_name":"Empidonax hammondii","overview":"哈氏纹霸鹟（英文名：Hammond's Flycatcher，学名：Empidonax hammondii），是雀形目霸鹟科纹霸鹟属的鸟类。小型灰橄榄色的霸鹟科鸟类，以威廉·亚历山大·汉蒙德命名，他曾担任美军医政总长。主要栖息于北美西部的成熟针叶林和混交林，繁殖季节偏好成熟的针叶树环境，冬季迁徙至墨西哥和中美洲的高地森林。","appearance":"哈氏纹霸鹟长约12.5-14.5厘米，体重7.7-12.1克。上体呈灰橄榄色，头部更偏灰色，胸侧和上胸暗灰色，腹部和尾下覆羽颜色从黄到白不等，喉部淡灰色，眼环白色较厚，翼斑窄而白色，幼鸟翼斑较宽且色偏黄褐。喙短而窄，成年鸟下颚基部黄色，幼鸟下颚多橙色。腿黑色。","call":"其叫声包括尖锐的“peek”声和哨音般的“peer”。在迁徙和冬季时不鸣唱，识别时声音是关键。","habits":"哈氏纹霸鹟主要在空中捕食昆虫，偶尔也会从树叶表面或地面觅食。偏好成熟和古老针叶林，一般树龄超过80至90年。繁殖期早期更多从叶面和较高树冠层觅食。","breeding":"繁殖期通常在6月初，筑巢于高大的针叶树水平枝条上，远离主干。每窝产卵3-4枚，卵呈乳白色，有时带有小红棕色斑点。孵化期约15天，幼鸟由双亲喂养，大约16-18天后离巢。","identification":"与灰纹霸鹟和暗纹霸鹟相似，但哈氏纹霸鹟具有较小的喙，较长的翼尖，且在繁殖季节偏好成熟的针叶林。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美，从美国阿拉斯加中部至加拿大西部直至美国西部。非繁殖期分布于美国西南部至洪都拉斯。","other":"由于其繁殖地常位于高树之上，巢穴难以定位，对其自然历史的详细研究资料相对缺乏。"},{"name":"暗纹霸鹟","english_name":"American Dusky Flycatcher","scientific_name":"Empidonax oberholseri","overview":"暗纹霸鹟（英文名：American Dusky Flycatcher，学名：Empidonax oberholseri），是雀形目霸鹟科纹霸鹟属的小型食虫性鸟类，主要分布在北美地区，包括加拿大西部和美国西部。在山地斜坡和丘陵地带的灌木丛和散落的树木中筑巢繁殖。该鸟种以其灰橄榄色的上体和淡色的眼环为显著特征。","appearance":"暗纹霸鹟体长约13至15.2厘米，体重9.3至11.4克。外观呈性单型，繁殖季节中，雄鸟和雌鸟的区别在于泄殖腔突起和孵卵斑。上体颜色为灰橄榄至灰褐色，下体大部分为白色，带有一层变化量的黄色调。喉部为白色，尾羽外侧有白色边缘。眼环明显，有时延伸到眼窝前方，形成类似眼镜的外观。翼条通常为白色且较窄，但在幼鸟和初冬换羽的成鸟中显得更宽且带有奶油色。","call":"其鸣唱为三部分，常见叫声为干燥的\"whit\"声，类似于其他Empidonax属飞禽的叫声。另一种较少见的叫声可能仅由雄鸟发出，听起来像悲伤的\"dew-hic\"。","habits":"暗纹霸鹟偏好在开放的松树林、山地灌木丛、溪边柳树丛和白杨林中筑巢。它们在繁殖季节倾向于低矮的树枝垂直分叉处搭建杯状巢。这种鸟以昆虫为食，常从开阔的栖木上飞出捕捉空中飞行的昆虫，也会悬停在空中从树叶上摘取昆虫。","breeding":"暗纹霸鹟在春季繁殖，雌鸟负责孵卵，而雄鸟经常喂养雌鸟。双亲共同喂养幼鸟，幼鸟大约在18天左右离巢。它们的繁殖地主要位于北美的山地环境中。","identification":"与哈氏纹霸鹟和灰霸鹟相比，暗纹霸鹟具有介于两者之间的特征：比哈氏纹霸鹟尾巴更长，喙更短，颜色更深；而比灰霸鹟尾巴略短，喙更短，颜色更深。在秋季，由于换羽时间的差异，暗纹霸鹟看起来颜色更淡，羽毛磨损，而哈氏纹霸鹟则因新鲜羽毛而显得颜色更深。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要集中在北美，包括加拿大西部和美国西部的山区。非繁殖期，它们会迁徙至美国西南部和墨西哥。","other":"暗纹霸鹟在迁徙途中会在沙漠地区停留，包括美国西南部的莫哈韦沙漠、索诺兰沙漠和奇瓦瓦沙漠。"},{"name":"灰纹霸鹟","english_name":"American Grey Flycatcher","scientific_name":"Empidonax wrightii","overview":"灰纹霸鹟（英文名：American Grey Flycatcher，学名：Empidonax wrightii），是雀形目霸鹟科纹霸鹟属的小型食虫性鸟类，在北美干旱地区广泛分布，尤其是大盆地地区，活跃于各种灌木丛和松树林中，以昆虫为食。","appearance":"体型较小，但比多数Empidonax属的霸鹟稍大，长度约15厘米，翼展22厘米，体重12.5克。成鸟上身呈淡灰色，翅膀和尾巴颜色较深，带有微弱的橄榄色。下身白色，新鲜羽毛带淡黄色。具有白色翼斑和不显眼的白色眼环。喙长而窄，尾长，下颌偏黄或粉红，尖端黑色。幼鸟与成鸟相似，但橄榄色和黄色调更明显，翼斑呈淡褐色。","call":"雄鸟的鸣唱为有力的双音节声，常被描述为“chuwip”或“wilip”。插入较弱、音调更高的“teeap”或“seep”。两性均发出干燥的“pit”或“wit”叫声。","habits":"栖息于干燥的灌木丛、开放林地和森林，偏好裸露的下层环境。迁徙期间，常见于溪流走廊的柳树或棉木地带。冬季在类似的生境中度过，包括干燥的荆棘林和灌木丛。","breeding":"繁殖季节，雄鸟通过鸣叫和展示建立领地，吸引雌鸟。巢由雌鸟建造，通常位于树枝分叉处，紧贴树干。产卵期为5月至6月初，每窝产卵3至4枚，孵化期约为14至16天。幼鸟孵化后约16天离巢。","identification":"与其他Empidonax属的霸鹟相比，灰纹霸鹟有较长的喙和尾，下颌颜色较浅。最显著的区别在于其向下摆动尾羽的独特习性。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大西南部和美国西部，冬季迁至墨西哥南部。","other":"历史上，灰纹霸鹟与暗纹霸鹟在分类上存在混淆，最终通过详细的形态学研究得以区分。"},{"name":"松纹霸鹟","english_name":"Pine Flycatcher","scientific_name":"Empidonax affinis","overview":"松纹霸鹟（英文名：Pine Flycatcher，学名：Empidonax affinis），是雀形目霸鹟科纹霸鹟属的小型飞禽。栖息于中美洲墨西哥和西南部危地马拉的高山热带和亚热带松林及林缘地带。首次在北美洲的记录发生在2016年5月末，一只迷鸟出现在美国亚利桑那州的圣塔丽塔山脉。","appearance":"松纹霸鹟体型较小，常在松林与橡树林交织的高海拔环境中被发现，偏好于开阔地带和果园中的落叶小树。其眼圈明亮，呈泪滴状，颜色淡雅，与哈蒙德霸鹟相似；喙部下方全为淡橙色，这一点类似科迪纹霸鹟，但后者体色更绿，喙部更为宽厚。","call":"其叫声为较为低调的‘pwip’声，与暗灰霸鹟的叫声略有相似，但与哈蒙德霸鹟的叫声明显不同。","habits":"松纹霸鹟与其他几种Empidonax属的飞禽共存，特别是在冬季，与之相伴的是暗灰霸鹟和哈蒙德霸鹟，这二者为迁徙而来的种类。松纹霸鹟偏好在松林边缘的开阔地带和果园中活动，选择有落叶小树的环境。","identification":"在辨别松纹霸鹟时，需注意其明亮的泪滴状眼圈和淡橙色的下喙，这是与暗灰霸鹟和哈蒙德霸鹟的重要区别点。","distribution":"松纹霸鹟主要分布于中美洲的墨西哥，包括其南部和西南部地区。2016年，首次在美国亚利桑那州圣塔丽塔山脉记录到松纹霸鹟的踪迹，这是其在墨西哥北部地区的首次记录。"},{"name":"北美纹霸鹟","english_name":"Western Flycatcher","scientific_name":"Empidonax difficilis","appearance":"北美纹霸鹟体型较小，上体呈现黄橄榄色，翅膀和尾巴颜色较深，下体偏黄。眼环显著，白色并形成泪滴状，向后延伸至耳羽区域。喙小而尖，尾巴较短。雄雌羽毛相似，但幼鸟的上体和下体可能带有淡褐色调，翼斑呈肉桂色到肉桂灰色，腹部颜色较淡或更黄，有时胸部可见模糊的橄榄色到灰色条纹。","call":"北美纹霸鹟的鸣唱包含快速连续的\"pseet\", \"ptsick\", \"seet\"音符，通常一起发出。在太平洋地区的个体中，\"ptsick\"或\"ptik\"音符的第一音节比第二音节音高更高，这是以前认为与科迪纹霸鹟唯一的叫声差异。雄鸟的典型位置叫声是响亮且独特的\"pit pete\"或\"tse-seet\"，但有些个体会发出\"上升的tsweep\"或\"滑音tseeweep\"。","habits":"北美纹霸鹟栖息于针叶林和混合林地，常靠近水源。繁殖期间，它们会在树叉处低矮的水平枝上筑杯状巢，通常选择在靠近溪流的地方。迁徙期间，它们会寻找阴凉密集的栖息地，例如沙漠中的绿洲。在非繁殖季节，它们在墨西哥的蒙特松林、松栎混交林、河岸林、热带落叶林和热带低地常绿林中度过。","breeding":"北美纹霸鹟在春季繁殖，雌鸟会在树叉上筑巢，一般位于较低的水平树枝上。巢呈杯状，由植物材料构成。每窝产卵数量为2到5枚。繁殖行为包括求偶、筑巢、交配、孵化和育雏，但具体细节需进一步研究。","identification":"北美纹霸鹟与其他Empidonax属的霸鹟最明显的区别在于其叫声和繁殖生境。它们的叫声和生境偏好可以用于区分。与黄腹纹霸鹟相比，北美纹霸鹟的上体颜色更深，翼斑与尾羽边缘的对比更明显，下体柠檬黄色，头部相对较小，尾部显得较短。此外，DNA测试确认了一种新的识别特征，涉及次级飞羽的肉桂色边缘程度，可用于可靠地区分此物种与黄腹纹霸鹟。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括加拿大西部和美国西部至墨西哥南部的太平洋海岸森林和山地，以及落基山脉的森林地带。非繁殖季节，大部分个体迁徙至墨西哥西部和中部过冬。","other":"自1989年至2023年，北美纹霸鹟拆分出科迪纹霸鹟，由于缺乏一致的声学、遗传和形态学差异以及广泛的杂交现象，这两个物种有可能被合并为单一物种。"},{"name":"科迪纹霸鹟","english_name":"Cordilleran Flycatcher","scientific_name":"Empidonax occidentalis","overview":"科迪纹霸鹟（英文名：Cordilleran Flycatcher，学名：Empidonax occidentalis），是雀形目霸鹟科纹霸鹟属的鸟类。小型的昆虫食性鸟类，原生于北美西部，繁殖于洛矶山脉和太平洋沿岸森林及山地，范围从加州至阿拉斯加并向南延伸至墨西哥中部；北方种群冬季迁徙至墨西哥。科迪纹霸鹟与北美纹霸鹟外观极其相似，但通过声音和分布区域可区分开。","appearance":"科迪纹霸鹟体型小巧，上体橄榄灰，翼部和尾部颜色更深，下体呈黄色。其特征性的泪滴状白色眼环十分显眼，翅膀上有白色条纹，喙小而尾短。与北美其他Empidonax属的飞虫捕食者相比，它在外观上的差异仅微乎其微，但可以通过声音、繁殖生境和分布范围来区分物种。","call":"其鸣唱包含pseet、ptsick、seet音节，通常快速连续发出。在太平洋地区的鸟类中，ptsick或ptik音节的第一个音节比第二个音节的音调更高——这曾被认为是它们与科迪纹霸鹟叫声的唯一区别。","habits":"科迪纹霸鹟栖息于针叶林或落叶林，进入混交林、道格拉斯冷杉林、红木林、松栎林等多种森林环境，包括河岸林地。它们偏爱靠近流水的生境，筑杯形巢于树杈上，通常位于水平枝的低处。","breeding":"繁殖期间，雌鸟通常会产下两到五个蛋。雄鸟的典型位置叫声响亮而独特，如pit pete或tse-seet，但也有部分个体发出\"上升的tsweep\"或\"滑音的tseeweep\"。","identification":"科迪纹霸鹟与北美纹霸鹟主要通过声音和分布范围区分，前者在叫声中ptsick音节的音调模式为高-低，而后者为低-高。在内部西北地区，两者叫声的某些部分变得更为相似，难以仅凭耳朵区分，需录音分析。","protection":"IUCN：LC（无危）","distribution":"科迪纹霸鹟分布于北美洛矶山脉，向南延伸至墨西哥大部分地区。北美纹霸鹟主要出现在沿海山脉。两种鸟类的分布和物种互动复杂，尤其是在内部西北地区的重叠区域，已报道存在杂交现象。","other":"科迪纹霸鹟的迁徙和越冬生态学研究较少，已知换羽主要发生在越冬地，但确切的越冬分布因存在留鸟和越冬的北美纹霸鹟而未完全解析。"},{"name":"淡黄纹霸鹟","english_name":"Yellowish Flycatcher","scientific_name":"Empidonax flavescens","overview":"淡黄纹霸鹟（英文名：Yellowish Flycatcher，学名：Empidonax flavescens），是雀形目霸鹟科纹霸鹟属的鸟类。常见于中美洲，自墨西哥东南部延伸至巴拿马西部的高海拔森林地带。其上体橄榄绿色，下体黄色调，具有独特的柠檬色眼环，叫声高亢。在高海拔的常绿阔叶林中生活，偶尔出现在松栎混交林。","appearance":"淡黄纹霸鹟长约12.5厘米，体重约12克。头部及上体为橄榄绿色，下体呈黄色，胸部略带赭色。翅膀黑色，带有两道淡色翼斑，眼睛周围有宽大的白色眼环，后方形成小三角。雌雄相似，幼鸟上体较暗，下体淡黄色。喙宽，上喙黑色，下喙橙肉色。","call":"叫声为尖细的'seeep'声，黎明鸣唱为快速重复的'seee seee chit'。","habits":"栖息于海拔800至2500米的凉爽山地森林，偏好林缘、空地、路边和溪流旁，亦见于次生林和灌木牧场。以昆虫、蜘蛛及少量浆果为食，通过短距离飞扑捕食或从地面捡食。","breeding":"深杯状巢由植物纤维和苔藓构成，建于树干裂缝或土坡2.5至4.5米高的地方，常靠近水源。每窝产2至3枚白底带淡红斑点的蛋，孵化期14至15天，雌鸟孵化，幼鸟17天后离巢。有时会接受寄生鸟的卵，成为青铜色牛鹂的寄主。","identification":"与同属迁徙种类如柳莺霸鹟、桤木霸鹟和阿卡迪亚霸鹟相区别，具有更显眼的眼环，比黄腹纹霸鹟下体颜色更黄。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于墨西哥东南部至巴拿马西部，主要栖息于海拔较高的常绿阔叶林。","other":"在北美的冬季，与黄腹纹霸鹟共享栖息地时需仔细区分。"},{"name":"黄胸纹霸鹟","english_name":"Buff-breasted Flycatcher","scientific_name":"Empidonax fulvifrons","appearance":"成年黄胸纹霸鹟体长约11.5至13厘米，体重约8克。上体橄榄灰色，翅膀和尾巴颜色更深，有醒目的白色眼环和翼条。最显著的特征是其橙色的胸部。喙小，尾短。性别差异仅通过雌鸟的抱窝斑点识别。幼鸟可通过淡黄色而非白色的翼条和鲜艳的橙色羽毛来辨别。","call":"其歌声为交替的'PIdew, piDEW'，叫声为响亮而干涩的'pit'。","habits":"栖息于开放的松林和山地橡树林中，偏好有松树和橡树的开阔森林地带。以昆虫为食，常在灌木或低树枝上等待，然后飞出捕食空中飞虫，有时也会悬停在树叶间啄食昆虫。","breeding":"在树叉处筑杯状巢，繁殖季节通常在5月至6月。雌鸟每次产卵2枚，卵色奶油白。","identification":"与羽冠霸鹟（Tufted Flycatcher）相比，黄胸纹霸鹟更小、更紧凑，无羽冠。与其他西部Empidonax物种的区别在于胸部的橙色色调和整体棕色。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于美国西南部至洪都拉斯，冬季会离开美国北部和墨西哥北部的繁殖地。","other":"黄胸纹霸鹟的生态和分类学仍有待深入了解。其数量曾因火灾抑制和牧场过度放牧导致栖息地减少而急剧下降，自1970年以来，美国种群有所恢复，但仍维持在较低水平。"},{"name":"黑顶纹霸鹟","english_name":"Black-capped Flycatcher","scientific_name":"Empidonax atriceps","overview":"黑顶纹霸鹟（英文名：Black-capped Flycatcher，学名：Empidonax atriceps），是雀形目霸鹟科纹霸鹟属的小型鸟类，体长约11.5厘米，重约9克。其头部和颈后呈烟熏黑色，上体橄榄褐色，下体较淡的棕色，喉部接近白色，下腹偏黄。拥有显著的黑色顶冠和宽大的白色眼环，翼部和尾部黑褐色，翼上有两道淡棕色斑纹。性别相似，幼鸟头色更褐，翼纹更淡。叫声为哨音kip，繁殖季节发出响亮的keer keer声。分布于中美洲的高海拔地区，如哥斯达黎加和巴拿马西部。","appearance":"体长11.5厘米，体重9克。头部大部分和颈后呈深黑色，上体橄榄褐色，下体颜色较淡，由棕色渐变为喉部的白色和下腹部的黄色。最显著的特征是黑色的短冠和宽大的白色眼环，眼环在上方中断。翅膀暗色，有两道浅棕色的翼斑，边缘为浅棕色的次级飞羽和三级飞羽；尾部暗色，外侧尾羽的外缘为白色。虹膜深色；上喙黑色，下喙橙黄色，尖端深色；腿黑色。性别相似，幼鸟的黑色顶冠略显暗淡，上体更偏向褐色，翼斑和飞羽边缘呈肉桂色，腹部颜色更浅。","call":"叫声简单，哨音式的'kip'、'chip'或'whit'，在繁殖季节会发出响亮的'keep-keer'声，互动时也会连续发出'keep-keep-keep-keep'。","habits":"栖息于中美洲的山地橡树林（Quercus）、林边、林间空地、灌木丛中的次生植被、牧场和帕拉莫（paramo）边缘。在哥斯达黎加，高度从2450米至3300米，局部低至2100米，雨季高峰期可能降至1850米；在巴拿马主要分布在2100米以上的区域。通常在开阔的栖息地活动，从树冠高处的暴露位置搜寻猎物，也会在低矮的灌木或围栏顶部寻找昆虫，采取空中突袭的方式捕捉猎物后常返回同一栖息点。","breeding":"繁殖期为3月至5月。巢为杯状，由细草和苔藓制成，内部衬以细植物纤维、马毛、小羽毛和熊苔（Usnea），置于2到12米高的地面，要么悬挂在直立的树叉上，要么悬挂在草地下的低矮土堤边缘。一窝产卵2枚，无其他信息。","identification":"与迁徙的Empidonax属的其他种类相比，黑顶纹霸鹟的头部黑色，整体外观较暗，容易区分。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加和巴拿马西部的科迪勒拉山脉。","other":"黑顶纹霸鹟适应了山地环境的破坏，如火灾、伐木和农业转换，常见于烧毁、砍伐和农业转换后的山地森林区域。"},{"name":"猩红霸鹟","english_name":"Scarlet Flycatcher","scientific_name":"Pyrocephalus rubinus","overview":"猩红霸鹟（英文名：Vermilion Flycatcher，学名：Pyrocephalus rubinus），是雀形目霸鹟科朱红霸鹟属的鸟类。亚种obscurus朱红霸鹟曾为独立种，是北美色彩最艳丽、求偶展示最壮观的霸鹟之一。雄鸟具鲜红色羽冠及全身朱红下体，雌鸟呈灰褐上体、胸腹淡粉并具细纹。该鸟繁殖于美国西南部至阿根廷，全球分布约710万平方千米。北美种群冬季南迁至墨西哥及中美洲。2021年前，它与加拉帕戈斯群岛的布鲁霍霸鹟（小朱红霸鹟）被视为同一种。","appearance":"体长13–14厘米，体重11–14克，雌雄异形。雄鸟成鸟：头顶及全身下体鲜红至朱红，眼先、耳羽及后颈连成一条黑褐面罩，其余上体、翼及尾黑褐。雌鸟成鸟：头顶至上背灰褐，额及眉纹灰白，翼覆羽和次级飞羽外缘淡色形成两道隐翼斑；下体白色，胸侧及胁部具灰纹，腹部渐呈淡粉至鲑色。幼鸟：上体褐色具浅色鳞状边缘，下体白而具灰褐卵形斑；部分雄幼鸟胸腹微带粉色。第一年雄鸟羽色介于雌鸟与成雄之间，头及下体呈红或橙红斑杂；第一年雌鸟似成雌，但下腹更黄。","call":"雄鸟鸣唱由5–16种变体组成，平均每次6.55个音节，持续约0.43秒，常被描述为“ching-tink-a-le-tink”或“pit-a-zee”。繁殖期黎明前最活跃，亦在白天及夜间鸣唱。飞行歌：雄鸟在20–30 m高空作起伏飞行并连续鸣唱，声似“t-t-ti-ti-tee-teeur”。联络叫为尖厉“peent”或“pisk”，遇敌时更强硬；交配时雌鸟发出“tjee-tjee-tjee”。","habits":"主要栖息海拔低于3 000 m的干旱灌丛、河岸杨、柳、豆科疏林、农田、公园及高尔夫球场，常近水源。北美种群为短距离候鸟，春季3月返回繁殖地，秋季8–10月南迁；南美南端种群亦为候鸟，冬季北迁至亚马逊巴西。觅食为“坐等突袭”型，从1–10 m高处俯冲捕食空中及地面节肢动物，猎物包括蝴蝶、蚱蜢、甲虫、白蚁、蜘蛛等。领域面积平均约0.88 ha，繁殖期雄鸟频繁巡逻并驱逐入侵者。","breeding":"繁殖期2–7月。雄鸟先于雌鸟抵达，通过巢位展示求偶：雄鸟在水平枝杈上蹲伏、振翅并发出颤音吸引雌鸟。巢由雌鸟主建，为疏松浅杯，外径64–90 mm、高25–51 毫米，由细枝、草、纤维及空茧构成，内衬羽毛、兽毛，外缠蛛丝并饰地衣。巢多置于杨、柳、豆科树水平分叉处，高1–18 米，平均3–5 米。每窝2–4（通常2–3）枚卵，卵白色至乳黄，大端具深褐斑块，孵化期13–15天，仅雌鸟孵卵，雄鸟喂食雌鸟0.7次/小时。雏鸟13–16天离巢，年可育1–3窝。褐头牛鹂寄生率可达20–36%。","identification":"雄成鸟全身鲜红与黑褐上体极具辨识度。雌鸟与体型更大的西氏菲比（棕腹长尾霸鹟）相似，但后者下体一致肉桂色、无白色眉纹且尾与背对比强烈。亚种间差异：北美flammeus雄鸟橙红、雌鸟纹少；mexicanus雄鸟深红；blatteus体型较小、雄鸟红更艳；pinicola雌鸟胸纹更宽；南美obscurus群出现黑变型；rubinus雄鸟背更黑、雌鸟腹少粉且纹多。","protection":"IUCN: LC（无危）。北美西南部因河岸生境破坏、地下水过度抽取导致局部衰退；加州科罗拉多河种群近50年锐减。人工绿地（高尔夫球场、公园）使其在莫哈维沙漠局部扩张，但同时增加牛鹂寄生及巢捕食风险。","distribution":"繁殖区：北美自加州东南部、亚利桑那、新墨西哥、德州西部，经墨西哥、中美洲至巴拿马；南美分为三块——哥伦比亚东北至巴西北部、安第斯山西坡至智利北部、南锥体（玻利维亚、阿根廷、乌拉圭、巴西南部）。非繁殖区：北美种群冬季迁至德州沿岸、加州南部、墨西哥北部及中美洲；南美南端种群冬季北迁至亚马逊巴西、哥伦比亚东南及厄瓜多尔东南。迷鸟记录北至加拿大魁北克、纽芬兰，南至福克兰群岛。","other":"2000年以来北美内陆种群有向北及向东扩张趋势，佛罗里达1940年后记录显著增加。"},{"name":"朱红霸鹟","english_name":"Vermilion Flycatcher","scientific_name":"Pyrocephalus obscurus","overview":"朱红霸鹟（英文名：Vermilion Flycatcher，学名：Pyrocephalus obscurus），是雀形目霸鹟科朱红霸鹟属的鸟类。以其鲜艳的红色羽毛著称，雄鸟拥有明亮的红冠、胸和腹部，而雌鸟则颜色较为暗淡，容易与棕腹长尾霸鹟混淆。广泛分布于北美、中美至南美的智利北部。","appearance":"朱红霸鹟是一种小型鸟类，全长约13-14厘米，翼展可达24-25厘米，体重在11-14克之间。性别二型性明显，雄鸟的头部、胸部和腹部呈鲜艳的红色，耳羽、颈背、翅膀和尾巴为深褐色。雌鸟上体灰色，下体淡红色，腹部桃色，容易被误认为棕腹长尾霸鹟。幼鸟与成年雌鸟相似，但雄鸟幼鸟下体更红，雌鸟幼鸟下体带黄色。","call":"朱红霸鹟的鸣唱被描述为‘pit pit pit pidddrrrreedrr’，富有变化，对于建立领地至关重要。此外，它们还有其他叫声，包括飞行时的‘pt-pt-pre-ee-een’。","habits":"偏好半开放环境，常见于河流旁的树林、灌木丛、农田和沙漠地带，通常靠近水源。它们主要以昆虫为食，通过空中捕食的方式获取食物。在繁殖季节，雄鸟会积极保卫领地。","breeding":"朱红霸鹟通常在3月至6月间繁殖，一季可产两窝，每窝含2-3枚蛋。雌鸟筑巢，雄鸟喂养雌鸟，共同抚养雏鸟。雏鸟出生后15天左右即可离巢。","identification":"雄性朱红霸鹟的独特红色羽毛使其易于识别，而雌鸟则需与棕腹长尾霸鹟区分开来。朱红霸鹟与同属物种在羽毛色彩和饱和度上有差异。","protection":"IUCN：LC（无危）。虽然总体数量庞大，但因栖息地丧失导致数量下降，特别是在加利福尼亚南部变得罕见。","distribution":"分布于北美洲西南部至南美洲北部，包括美国西南部至智利北部。北美种群一般为留鸟，南美种群可能迁徙至巴西亚马逊北部。","other":"朱红霸鹟适应了人类环境，在公园和高尔夫球场筑巢，但面临棕色牛鹂的寄生和巢穴掠食者的威胁。现为猩红霸鹟亚种。"},{"name":"小朱红霸鹟","english_name":"Darwin's Flycatcher","scientific_name":"Pyrocephalus nanus","overview":"小朱红霸鹟（英文名：Brujo Flycatcher，学名：Pyrocephalus nanus），是雀形目霸鹟科朱红霸鹟属的鸟类。是加拉帕戈斯群岛色彩最鲜明的鸟之一，2016 年由北美至南美的“朱红霸鹟”复合体拆分而出，为群岛特有种。雄鸟全身朱红、面罩近黑，雌鸟灰褐上体、腹面淡黄并具细纹。种群受栖息地丧失、外来捕食者和寄生蝇 Philornis downsi 威胁，圣克里斯托瓦尔岛亚种已灭绝，其余岛屿呈下降趋势。","appearance":"体长约 13–14厘米，体重 11–14克，雌雄异形。雄鸟（成鸟）：头至上背、胸腹皆亮朱红至橙红；眼先、耳羽与后颈连成一体的黑褐面罩；其余上体、翼及尾黑褐。雌鸟：头顶与背灰褐，尾色最深；额及隐约眉纹灰白；飞羽及覆羽具淡缘，形成翼斑；喉白，胸腹灰白渐转淡红至鲑色，胸侧及胁具细灰纹。成鸟全年羽色无显著变化。","call":"鸣唱为重复的单音节，每声之间伴随清脆的喙击声。","habits":"留居加拉帕戈斯群岛各主岛（除圣克里斯托瓦尔岛外）。在人居岛主要栖息于较高海拔的森林及林缘；在无居民岛可下降至海岸灌丛。典型的“坐等出击”型捕食者：停于开阔枝头，发现飞虫或陆生节肢动物后迅速俯冲捕获。","breeding":"目前缺乏系统的繁殖生物学资料，亟需研究其求偶、营巢、产卵及育雏行为，以制定保护策略。","identification":"雄鸟色彩鲜明，不易混同；雌鸟淡黄腹面与胸侧细纹是区分要点，但仍需与体型更大、喙更长、无淡眉纹的大嘴蝇霸鹟区别。岛内亚种：指名亚种 P. n. nanus 雌鸟腹面淡黄具细纹；圣克里斯托瓦尔亚种 P. n. dubius 雌鸟腹面无纹、喉部灰黄，该亚种可能已灭绝。","protection":"IUCN: VU（易危）。","distribution":"繁殖区与非繁殖区一致，皆限于加拉帕戈斯群岛。目前已知分布于除圣克里斯托瓦尔岛以外的所有主岛，以及部分无人小岛。","other":"当地人称其为“pájaro brujo”（巫鸟），因而英文名曾用“小朱红霸鹟”；2016 年依据线粒体与核基因研究，以及鸣唱和求偶展示差异，被确立为独立种。"},{"name":"圣岛霸鹟","english_name":"San Cristobal Flycatcher","scientific_name":"Pyrocephalus dubius","overview":"圣岛霸鹟（英文名：San Cristobal Flycatcher，学名：Pyrocephalus dubius），是雀形目霸鹟科朱红霸鹟属的鸟类。最显著的外部特征和分布区域主要集中在南美洲的圣克里斯托巴尔岛（San Cristobal），这里是加拉帕戈斯群岛的一部分。","appearance":"由于缺乏详细的描述，我们未能提供圣岛霸鹟具体的身体形态、羽毛颜色、大小或性别差异的详尽信息。通常，霸鹟科的鸟类具有相对较小的体型，活跃的飞行姿态，以及独特的羽毛色彩。","habits":"圣岛霸鹟的生活习性与其在加拉帕戈斯群岛的独特生态环境紧密相关。它们可能栖息在岛屿的多种生境中，包括灌木丛和森林边缘，但具体的栖息地偏好、食物来源和迁徙模式尚未详细记录。","identification":"与同属其他物种的区别辨识点，包括但不限于体型、羽毛颜色、行为习性和鸣叫声，对于圣岛霸鹟而言，这些信息有待进一步研究确认。","distribution":"圣岛霸鹟的地理分布仅限于南美洲的圣克里斯托巴尔岛（San Cristobal），这是加拉帕戈斯群岛中的一个岛屿。","other":"现为小朱红霸鹟亚种。"},{"name":"棕背小霸鹟","english_name":"Austral Negrito","scientific_name":"Lessonia rufa","overview":"棕背小霸鹟（英文名：Austral Negrito，学名：Lessonia rufa），是雀形目霸鹟科棕背小霸鹟属的鸟类。常见于南美洲南部夏季开阔地带，冬季向北迁徙至玻利维亚、巴西、巴拉圭等地。其独特的黑色外观和锈红色背部使其在繁殖区内无相似物种。雌鸟外表较朴素，但体型、形态及行为特征明显，常与雄鸟一同出现。","appearance":"体长11.5至12.5厘米。雄鸟全身黑色，背部鲜明的锈红色；虹膜深色；喙短黑；腿黑色；后爪异常长，类似鹨鸟。与非常相似的萨氏小霸鹟相比，体型略小，背部颜色更深，飞行羽内侧更暗。雌鸟冠部棕色灰，颈后有深褐色项圈，眼纹及脸颊白色，背部及肩羽淡锈红棕色；翅膀和尾巴黑色，最外侧尾羽外缘呈白色；下方浅黄白色，胸部和两侧有灰色褐色条纹，两胁和腹部淡黄色，腹股沟白色，翼下有一小片肉桂色斑点。幼鸟似雌鸟，但背部更偏红褐色；两个月后换羽至亚成鸟羽毛，六个月后换至成鸟羽毛。","call":"通常沉默；警报声为重复的“tjit-tjit”，联系音为短暂的啾啾声。","habits":"栖息于短草丛的开阔地带，常靠近沼泽、海岸、湖泊和海滩；也出现在牧场。主要生活在海拔1000米以下，局部可达2000米。繁殖后向北迁徙，沿海岸线分散，随后扩散至内陆低地；可能与在智利北部和玻利维亚的南部冬季有所重叠。雄鸟先于仍在照顾幼鸟的雌鸟离开繁殖地；在火地岛，雄鸟12月至1月离境，9月中旬返回；雌鸟和幼鸟2月至3月离境，10月初返回。迁徙期间常见单一性别的小群。已知在福克兰群岛和南极洲的南设得兰群岛出现迷鸟记录，其中南设得兰群岛记录可能是由船只协助到达。食性以小型昆虫为主，基本为陆栖，活跃于地面，常停歇于低矮灌木和围栏上，频繁站立于岩石和小土丘上；紧张时会快速摆动尾巴和翅膀。追捕猎物时奔跑，做短距离突袭。可能跟随牲畜或人类在草地中寻找被惊飞的昆虫。非繁殖季节常形成松散的小群。","breeding":"在智利9月至11月繁殖（火地岛上10月至1月），阿根廷10月至1月，玻利维亚12月；可能产两窝。求偶时，雄鸟向上飞翔至10至15米高。巢为小型开放杯状，由草、小枝或根制成，内衬羽毛，外径6至12厘米，内径5厘米，深度3至5厘米；常建于地面或悬崖边缘，常被悬垂植被覆盖或位于其下。每窝产2至4枚蛋；幼鸟仅由雌鸟照料；其他信息未知。","identification":"雄鸟与萨氏小霸鹟的区别在于体型较小，背部赤褐色更深，飞羽内翈为深色而非白色。雌鸟则可通过头部灰褐色、颈部深棕色项圈以及下体的灰色条纹进行区分。","protection":"IUCN：LC（无危）。在部分范围内相当常见到局部丰盛。在分布区南部逐渐增多。出现在巴塔哥尼亚安第斯山脉沿线的所有国家公园。","distribution":"智利中部（科金博）和阿根廷中部（门多萨、拉潘帕）至火地岛。冬季北迁至智利北部、玻利维亚南部、阿根廷、巴拉圭、巴西东南部和乌拉圭。已知迷鸟记录于福克兰群岛和南极洲的南设得兰群岛。","other":"已记录在南极水域海上观察到的迷鸟。"},{"name":"萨氏小霸鹟","english_name":"Andean Negrito","scientific_name":"Lessonia oreas","overview":"萨氏小霸鹟（英文名：Andean Negrito，学名：Lessonia oreas），是雀形目霸鹟科棕背小霸鹟属的鸟类。这体型微小、地面活动的鵙，主要分布在南美的安第斯山脉高海拔地区，常见于沼泽、湖岸和流溪旁的开阔地带。雄鸟具有亮锈色背部与黑色羽毛，而雌鸟呈现深灰褐色，背部略带锈色。其活动范围涵盖秘鲁至阿根廷西北部。","appearance":"萨氏小霸鹟长约12.5厘米，雄鸟比雌鸟稍大，拥有显著的性二型性。雄鸟的羽毛为黑色，背部呈明亮的锈色，飞行时可见银白色的飞羽内侧。雌鸟上身黑褐色，下身灰黑，背部淡锈色，喉部微白，胸侧带有淡锈色。两性皆有异常长的后爪，类似雀形目的鵙。","call":"萨氏小霸鹟发出的联系叫声为短暂而微弱的‘tyt’声，间隔约0.5秒重复；警报声为极高音的‘zi’声。此外，展示飞行分为三部分：停栖时的‘tsi’音符，斜向飞行时的‘tic’音符，以及转弯下降时的‘trrrrrrrrrr’翼鸣和‘psie’音符。","habits":"栖息于海拔3000至4000米的高山湖泊、溪流和沼泽，偶尔在秘鲁高达4000米以上，智利低至1000米。常以成对或家庭群形式出现，基本在地面活动，频繁停歇于草丛或稍高的栖木上，通过短距离飞行或奔跑追捕近地或地面的小昆虫。","breeding":"在智利北部，繁殖期为10月至次年1月。雄鸟会向上飞翔10至15米进行展示飞行。巢穴通常为隐蔽在草丛中的开放式杯状，每次产卵3至4枚，其余繁殖细节未知。","identification":"萨氏小霸鹟在分布范围内无相似物种，雄鸟特征明显，雌鸟与马来火背鹇相比，体型略小，背部颜色更淡，下身颜色更深。","protection":"IUCN：LC（无危）","distribution":"分布于秘鲁中部至南部、智利西部、玻利维亚西部和阿根廷西北部的安第斯山脉。"},{"name":"灰霸鹟","english_name":"Cinereous Tyrant","scientific_name":"Knipolegus striaticeps","overview":"灰霸鹟（英文名：Cinereous Tyrant，学名：Knipolegus striaticeps），是雀形目霸鹟科黑霸鹟属的中等体型的开放地带霸鹟。灰霸鹟于1837年被命名，其自然栖息地位于南美洲的Gran Chaco地区，偏好亚热带或热带的干燥灌木丛。","appearance":"雄性灰霸鹟与其他黑霸鹟属物种的区别在于其全暗色的翅膀和灰色（而非深黑色）的羽毛。雌鸟则通过其下体上模糊的条纹、棕色的帽状羽冠、锈红色的臀部和暗淡的红褐色虹膜与同属其他雌鸟相区分。成鸟体长约16厘米，翼展略宽。","habits":"灰霸鹟偏好在开阔的荆棘森林、路边、农田和城镇中的显眼栖息处活动。它广泛分布于阿根廷北部、巴拉圭西部、玻利维亚东南部和圣克鲁斯中部至塔里哈东部。","identification":"灰霸鹟的识别要点在于其独特的羽毛色彩和图案，尤其是雄鸟的全暗翅膀和雌鸟的特定下体条纹模式，以及两者共有的棕色帽状羽冠和锈红色臀部。","protection":"IUCN：LC（无危）","distribution":"灰霸鹟主要分布在南美洲，包括玻利维亚东部至阿根廷中部，其分布范围从圣克鲁斯中部南至塔里哈东部，向西至巴拉圭西部，北至阿根廷的胡胡伊和福尔摩萨南部，直至科尔多瓦和圣路易斯北部。"},{"name":"哈氏黑霸鹟","english_name":"Hudson's Black Tyrant","scientific_name":"Knipolegus hudsoni","overview":"哈氏黑霸鹟（英文名：Hudson's Black Tyrant，学名：Knipolegus hudsoni），是雀形目霸鹟科黑霸鹟属的鸟类。以阿根廷-英国鸟类学家威廉·亨利·哈德森命名。在阿根廷中部繁殖，冬季向北迁徙至玻利维亚和巴拉圭。","appearance":"雄鸟光泽黑色，具银色尖端的黑色喙。翅膀下侧有白色斑块，通常在停歇时被遮掩。雌鸟呈棕色和淡黄色，翼上有白色翼条，臀部和尾基部肉桂色，胸部有微弱的斑点。","habits":"栖息于矮林、灌木丛和过度生长的空地。迁徙模式高度迁徙，繁殖季节结束后从阿根廷中央地带向北分散至玻利维亚和巴拉圭，偶尔更远。","identification":"与白翅黑霸鹟极为相似，雌鸟胸部和腹部颜色较浅，但雄鸟在野外几乎无法区分。","distribution":"繁殖区域位于南美阿根廷中部，非繁殖期迁徙至玻利维亚北部。"},{"name":"亚马孙黑霸鹟","english_name":"Amazonian Black Tyrant","scientific_name":"Knipolegus poecilocercus","appearance":"雄性亚马逊黑霸鹟全身呈现光泽的黑色，体型比同类中的滨霸鹟更为小巧，且毛羽更加光亮。雌鸟个体则是暖褐色调，腹部具有条纹，色泽较滨霸鹟更温暖柔和。整体上，它们的色彩饱和度和纹理使其在同类中脱颖而出。","call":"作为飞禽家族的一员，亚马逊黑霸鹟异常安静，很少发出鸣叫。","habits":"亚马逊黑霸鹟偏好生活在低洼的水淹森林环境中，它们在亚马逊河、奥里诺科河及其周边的湿地、森林和灌木丛中活动。以昆虫为主食，通常在近地面或水面附近捕食。这类鸟并不迁徙，展现出在特定栖息地的定居行为。","identification":"亚马逊黑霸鹟与滨霸鹟在外表上有细微差异，尤其是栖息环境的选择上，前者更倾向于水淹森林。","protection":"IUCN：LC（无危）","distribution":"广泛分布于南美洲的亚马孙雨林地区，包括哥伦比亚西部、委内瑞拉南部、圭亚那西部、巴西的亚马逊河流域、秘鲁东北部、厄瓜多尔东北部以及苏里南局部区域。"},{"name":"秘鲁丛霸鹟","english_name":"Jelski's Black Tyrant","scientific_name":"Knipolegus signatus","overview":"秘鲁丛霸鹟（英文名：Jelski's Black Tyrant，学名：Knipolegus signatus），是雀形目霸鹟科黑霸鹟属的鸟类，分布于南美洲安第斯山脉东坡的云雾森林，主要见于秘鲁北部至中部，仅轻微延伸至厄瓜多尔东南部。雄鸟呈深灰黑色，雌鸟为灰橄榄色，翼上有淡色条纹，腹部有模糊的条纹。","appearance":"成年雄性秘鲁丛霸鹟全身羽毛均匀呈煤黑色，眼睛深红或栗色，喙及腿黑色。雌鸟上部暗淡橄榄褐色，尾上覆羽更偏红棕色，两翼有白色至米黄色的翼带，尾部边缘浅肉桂红，下部羽毛广泛带有深灰色橄榄条纹，尤其是胸部，通常显得较为一致，下尾覆羽深黄褐色。幼鸟似雌鸟，但上部略带锈色，翼带白色，翼上有淡黄色面板，下部羽毛的淡色条纹更宽泛，微带淡黄色。","call":"关于其声音和鸣叫行为知之甚少，推测可能像淡嘴黑霸鹟一样通常较为安静。","habits":"栖息地偏好似乎与淡嘴黑霸鹟相似，海拔范围主要在1900至3050米之间，但在某些地方，如北秘鲁的阿布拉帕特里夏（Abra Patricia）附近，可稍低。生活方式为留鸟，饮食和觅食行为可能与秘鲁丛霸鹟相似，会在地面以上约10米处停歇。","breeding":"关于繁殖行为目前尚无确切信息。","identification":"与白翅黑霸鹟的区别在于，雄性秘鲁丛霸鹟颜色更灰，翼上无白色（仅在飞行中可见），而雌鸟则明显较暗，特别是在下部。与铅色黑霸鹟（Plumbeous Black-Tyrant）没有重叠分布。","protection":"IUCN：LC（无危）","distribution":"分布于极端南部的厄瓜多尔（科迪勒拉德尔孔多尔山脊）和秘鲁北部与中部（从亚马逊斯至胡宁省）。","other":"最近记录显示，它在2001年12月和2003年9月首次在厄瓜多尔的科迪勒拉德尔孔多尔被观察到。在秘鲁北部和中部被认为是罕见的，自19世纪末至1970年代初大约100年间未曾有记录。"},{"name":"淡嘴黑霸鹟","english_name":"Plumbeous Tyrant","scientific_name":"Knipolegus cabanisi","overview":"淡嘴黑霸鹟（英文名：Plumbeous Tyrant，学名：Knipolegus cabanisi），是雀形目霸鹟科黑霸鹟属的鸟类。而在玻利维亚西部和阿根廷西北部更为常见。其自然栖息地主要是湿润的山地森林。","appearance":"体型中等，长度约14.5至16.5厘米，重量14至21克。雄鸟羽毛呈较暗的板岩灰色，翅膀和尾巴颜色较暗，翼羽内侧边缘白色，下腹部较浅色，喙蓝灰色，尖端黑色，下颚较浅。雌鸟上体暗褐色，尾覆羽和尾羽边缘亮赤褐色，两道白色翼带，下体乳白色，胸部有灰色橄榄色条纹，喙黑色或灰黑色，尖端黑色。","call":"通常保持安静，雄鸟的叫声为‘tec’或‘tchick’，有时会发出快速低沉的‘chirri’jurriew’声。","habits":"栖息于湿润的山地森林内部，偶尔在边缘地带，偏好靠近河流和溪流的环境。常在光秃的枝条或枯木上停留，然后飞出捕食昆虫。活动范围在海拔700米至至少2700米之间。","breeding":"繁殖期在阿根廷为10月至次年1月，雌鸟在11月中旬处于繁殖状态，12月底有孵卵斑，1月中旬刚结束产卵。雄鸟在2月第三周仍处于繁殖状态。筑巢于小树或灌木的水平枝上，距地面1.5至4米，巢由草和苔藓构成，内衬羽毛，直径约14厘米，高度7.5至12厘米，内径4至6厘米，深度3至4厘米。每窝产1至3枚白色蛋，有栗色标记集中在较大端，蛋尺寸20至23毫米×16至17毫米。已知受到紫辉牛鹂的寄生。","identification":"雄鸟与白翼黑霸鹟的区别在于羽毛更灰暗，光泽较少；与灰霸鹟的区别在于腹部颜色更深。雌鸟与上述物种的区别在于喉部颜色较深而非浅色。","protection":"IUCN：LC（无危）。在秘鲁罕见且了解甚少；在阿根廷和玻利维亚部分地区相当常见。出现在秘鲁的马丘比丘历史保护区，玻利维亚的Pilón Lajas生物圈保护区和Iñao、Tarija和Madidi国家公园，以及阿根廷西北部的Baritú、Calilegua和El Rey国家公园。","distribution":"分布于秘鲁东南部（库斯科东部，普诺北部），玻利维亚东南部（科恰班巴、圣克鲁斯、塔里哈）和阿根廷西北部（胡胡伊南至图库曼和卡塔马卡东南部）。","other":"与秘鲁丛霸鹟有时被视为同种，这种情况下，通常被称为安第斯霸鹟。"},{"name":"蓝嘴黑霸鹟","english_name":"Blue-billed Black Tyrant","scientific_name":"Knipolegus cyanirostris","overview":"蓝嘴黑霸鹟（英文名：Blue-billed Black Tyrant，学名：Knipolegus cyanirostris），是雀形目霸鹟科黑霸鹟属的鸟类。得名于其独特的蓝色喙，主要分布于南美洲的巴西东南部至南部、巴拉圭东部、阿根廷东北部及乌拉圭。该鸟种于1818年被首次命名。","appearance":"蓝嘴黑霸鹟体型较大，头部无羽冠。雄鸟全身大部分呈现光泽的黑色，而雌鸟背部为棕色，臀部呈肉桂色，下体为淡褐色，带有深棕色条纹。雄鸟与雌鸟在羽毛颜色上存在明显差异。","call":"蓝嘴黑霸鹟通常保持沉默，鸣叫声记录有限。","habits":"这种鸟类栖息于湿润森林边缘及画廊林中，偏好接近水源的环境。它们广泛分布于南美的温带森林、亚热带或热带湿润山地森林、亚热带或热带高海拔灌木丛以及严重退化的前森林地带。","breeding":"有关蓝嘴黑霸鹟的繁殖行为的具体信息较为缺乏。","identification":"蓝嘴黑霸鹟的最显著特征为其蓝色的喙，这在同属鸟类中是独一无二的，此外，雌雄鸟在羽毛颜色上有明显的区别。","protection":"IUCN：LC（无危）","distribution":"蓝嘴黑霸鹟的繁殖区域位于南美洲的巴西东南部至南部、巴拉圭东部、阿根廷东北部和乌拉圭。冬季时，南部的种群会向北迁移至巴西的马托格罗索州南部和巴拉圭东部。"},{"name":"棕尾霸鹟","english_name":"Rufous-tailed Tyrant","scientific_name":"Knipolegus poecilurus","overview":"棕尾霸鹟（英文名：Rufous-tailed Tyrant，学名：Knipolegus poecilurus），是雀形目霸鹟科黑霸鹟属的中型飞禽。分布于南美洲的安第斯山脉，自委内瑞拉至秘鲁，以及委内瑞拉和巴西的特普伊山脉。其显著特征为灰褐色的整体色调，红眼，淡肉色腹部，以及肉色或灰褐色翼杠。性别相似。","appearance":"棕尾霸鹟呈中等体型，全身覆盖着灰褐色羽毛，拥有独特的红色眼睛，腹部颜色较浅，呈现淡肉色，翅膀上带有肉色或灰褐色的条纹。雌雄鸟外观相近，难以通过羽毛颜色进行区分。","habits":"栖息于海拔900至2200米的山地森林边缘地带。常见于显眼的栖木上停歇。偏好在活跃的牛牧场边缘的孤立草丛中筑巢。","breeding":"繁殖期记录显示，巢穴通常建在孤立的草丛中，接近牧场边缘。巢为开放式的杯状，由树枝构成，内部衬以柔软的材料。已知蛋为奶油色，带有稀疏的红棕色斑点，尺寸约为22.0mm x 15.0mm。雄鸟的生殖腺在3月至9月间会增大。","protection":"IUCN：LC（无危）。总体而言，分布区内数量稀少至少见，但在某些特定地点如哥伦比亚的La Planada自然保护区和秘鲁的马丘比丘历史保护区较为常见。","distribution":"分布于南美洲，从委内瑞拉西部至秘鲁东部，以及特普伊山脉。"},{"name":"滨霸鹟","english_name":"Riverside Tyrant","scientific_name":"Knipolegus orenocensis","overview":"滨霸鹟（英文名：Riverside Tyrant，学名：Knipolegus orenocensis），是雀形目霸鹟科黑霸鹟属的鸟类。雌鸟上体橄榄灰，下体淡色，胸部有粗犷的橄榄灰色条纹。广泛分布于南美洲亚马逊流域的河流岛屿及周边地区。","appearance":"体长约15.5厘米，体重约19克。雄鸟全身呈均匀的暗黑色，具微小的冠羽，使头部略显圆润。雌鸟上体较雄鸟淡，为橄榄灰色，尾部带锈色，下体淡色，喉部、胸部及侧腹有模糊的橄榄灰色条纹。幼鸟背部褐色，翼覆羽边缘锈色，形成微弱的翼带，下体淡色，有模糊的条纹。","call":"鸣唱为一系列悦耳的音符，以类似打嗝的沙哑音结束，'pwip, pwip, pwip’PI’tjuk'；叫声为柔和的液体声‘pi-weet’或‘pi-pi­weet’，像滴水声。雄鸟展示时，从地面不足1米的高度快速飞升至约4米高，再迅速下降，伴随机械般的啪嗒声。","habits":"栖息于河流沿岸及湖泊附近的半开放灌木丛，尤其偏好季节性洪水泛滥的河岛上的早期次生植被。常在地面以上0.5至4米处单独或成对活动，会突然降落至地面捕食昆虫。活动范围低于海拔300米。","breeding":"繁殖信息极少，已知在9月观察到家庭群，在11月观察到展示行为。雄鸟展示包括垂直向上飞行后急速下降，具体行为细节未知。","identification":"与亚马逊黑霸鹟的雌鸟相似，但后者臀部呈锈色。xinguensis亚种的雄鸟在展示时会在同一栖木上做180度翻转，同时发出‘pip pip’声，尾部突然上翘约60度。","protection":"IUCN：LC（无危）","distribution":"分布于巴西东北部、哥伦比亚东北部、厄瓜多尔东北部、秘鲁东北部至巴西北部，沿亚马逊河和马德拉河东至塔帕若斯河下游。在委内瑞拉南部大草原的Hato El Cedral，11月至3月间可见。","other":"在委内瑞拉的奥里诺科河、阿拉瓜亚河和欣古河及其部分支流中局部存在，较为罕见。"},{"name":"白翅黑霸鹟","english_name":"White-winged Black Tyrant","scientific_name":"Knipolegus aterrimus","overview":"白翅黑霸鹟（英文名：White-winged Black Tyrant，学名：Knipolegus aterrimus），是雀形目霸鹟科黑霸鹟属的鸟类。中型霸鹟，由Kaup于1853年命名。其主要分布在南美洲的中高海拔灌木丛和开阔林地，包括秘鲁至阿根廷中部。曾将巴西黑霸鹟视为其亚种。该鸟种的显著特征是雄鸟的黑色外表和明显的白色翼斑。","appearance":"雄性白翅黑霸鹟呈黑色，飞行时翼下可见鲜明的白色斑纹，由白色翼羽边缘构成。雌鸟则为褐色，带有白色翼纹和尾基部及翅膀上的红棕色斑点。雄鸟比其他黑色霸鹟更暗更闪亮。雌鸟通过白色的翼纹和深色的眼睛帮助区分于相似物种，其体色较浅，红色臀部更为突出。成年雄鸟体型为16-18厘米，体重14.8-24.5克，全身闪亮黑色，翼上有大白色条带；雌鸟背部灰褐色，头顶略深，脸部和眼周有白色斑点，翼上具白色或肉桂色翼纹，臀部和尾基部鲜亮的肉桂红棕色，下体淡黄褐色，胸部颜色最浓，喉咙和腹部中部更白。","call":"鸣叫声知之甚少，通常保持沉默。已知的叫声包括三音节的歌曲，首音下滑，次音略微上升，尾音滑过且中间部分非常嗡嗡作响。此外，雌鸟觅食时会发出“trrie rrhi rrhi”等声音，迁徙时会发出微弱的“tseet”。","habits":"栖息于山地灌木丛和干燥森林，海拔高度在1500-3000米之间，偶尔低至250米或高达3800米。以昆虫为食，通常单独活动，站立时姿态挺直，偶尔在树冠内活动，常摇摆尾巴。从暴露的树枝或岩石突起处捕食昆虫，有时从树叶中获取或落地觅食。迁徙时出现在砾石山坡的开放灌木丛。","breeding":"繁殖季节为10月至次年2月，筑巢于树或灌木低处，偶尔地面，巢为开放杯状，由枝条构成，内衬羽毛和毛发。每窝产2-3枚白色蛋，带有集中在大端的红色斑点，平均尺寸约22mm×16mm。雄鸟在繁殖期间展示飞行，向上短飞后垂直下坠，随后拉起回到栖息地，可能伴随轻微叫声。","identification":"与秘鲁丛霸鹟相比，白翅黑霸鹟的雌鸟上体颜色更深，翼斑更白，下体颜色更浅，尾部颜色更浅（呈肉桂白色）。一年生雄鸟与雌鸟相似，但下体更淡，赭黄色调较重。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的秘鲁至阿根廷中部，包括玻利维亚、智利、巴拉圭、秘鲁和乌拉圭的部分地区。在玻利维亚，常见于马迪迪国家公园和爱德华多阿瓦罗亚保护区；在秘鲁，见于马丘比丘历史保护区，沿着从火车站到遗址的道路。","other":"白翅黑霸鹟的地理分布和生态习性显示它可能主要局限于受严重栖息地丧失影响的马兰翁河谷生物多样性热点区域。尽管如此，该物种的种群被认为相对稳定。"},{"name":"巴西黑霸鹟","english_name":"Sao Francisco Black Tyrant","scientific_name":"Knipolegus franciscanus","overview":"巴西黑霸鹟（英文名：Sao Francisco Black Tyrant，学名：Knipolegus franciscanus），是雀形目霸鹟科黑霸鹟属的鸟类。分布于巴西东部。雄鸟外表光亮呈黑色，翼羽基部有一宽阔的白色带纹，红眼，雌鸟上身褐色，臀部锈色，腹部白色并带有暗色条纹。栖息于干燥森林中的岩石地带。","appearance":"成年巴西黑霸鹟长约16.5厘米，体重约20.5克。雄鸟全身闪亮黑色，翼羽基部有显著的白色横带（仅在飞行时明显可见），虹膜红色，喙黑色或略淡，尖端较深，腿脚暗灰或蓝灰色。雌鸟上体棕色，翼上有相对明显的浅色翼带，由中翼覆羽和大翼覆羽的尖端形成，三级飞羽和最内侧飞羽边缘白色，尾上覆羽红褐色至橙色，臀部和尾基部暗色，其余部分白色，下体重布暗色条纹，胸和下尾覆羽带些许黄褐色。雌鸟的裸露部位主要为暗色，除橙红色眼睛。","call":"关于叫声的出版资料甚少，已知录音显示雄鸟发出极短且音调高的音符。","habits":"栖息于树冠层的干林和半落叶干燥森林，通常与石灰石或砂岩露头（称为lajeiros）相关联。以昆虫为食。行为较为隐蔽，安静地栖息于树冠至地面，偶尔在显眼位置。通常成对或单独活动，偶尔快速摆动尾巴。进行短距离空中捕食，主要针对树枝和叶片上的猎物，偶尔捕捉飞行中的昆虫，通常在树冠或次冠层，但也到地面觅食（非繁殖季节，雌鸟似乎更不显眼，觅食位置低于雄鸟）。有时跟随混合物种觅食群，包括绿䴕雀（亚种reiseri）、纵纹翘嘴雀、黄胸霸鹟、灰喉卡西霸鹟、热带蚋莺、棕眉鵙雀、栗臀锥嘴雀、黑顶唐纳雀和里氏小霸鹟。非繁殖季节，雄鸟会组成小规模的单一性别、单一物种群，暗示雌雄可能在非繁殖期部分隔离。","breeding":"繁殖信息缺乏具体细节。","identification":"雌鸟可能与混淆，因两者可能共享相同的栖息环境，但可通过翼带、尾上覆羽颜色和下体条纹进行区分。","protection":"IUCN：LC（无危）。曾被列为近危。总体而言，物种较为稀少且局部分布，但在某些地区常见，可能能在退化或再生生境中生存。分布范围估计为25,800平方公里，但实际发生范围可能高达约606,100平方公里。在多个保护区被发现，包括Cavernas do Peruaçu国家公园和Mata Seca州立公园（Minas Gerais），以及Serra Geral do Tocantins生态站（Tocantins）；也可能出现在Terra Ronca州立公园（Goiás）。最近（2004年10月）在Tocantins州发现，相信当地种群稳定。在NE Goiás被认为稳定；然而，未来可能面临石灰石露头农业产品开采的威胁。在Bahia州São Felix do Coribe周围，残余干燥森林斑块非常小（全部<200公顷），整个石灰石区域亦是如此。剩余森林主要用于木材，主要是围栏柱子；卫星图像显示Goias的Paranã谷地，1990年至1999年间，干燥森林从区域的15.8%下降至仅5.4%，且<1%的残留碎片大于100公顷，尽管它们占剩余森林的48%。。IUCN：LC（无危）。曾被列为近危。总体而言，物种较为稀少且局部分布，但在某些地区常见，可能能在退化或再生生境中生存。分布范围估计为25,800平方公里，但实际发生范围可能高达约606,100平方公里。在多个保护区被发现，包括Cavernas do Peruaçu国家公园和Mata Seca州立公园（Minas Gerais），以及Serra Geral do Tocantins生态站（Tocantins）；也可能出现在Terra Ronca州立公园（Goiás）。最近（2004年10月）在Tocantins州发现，相信当地种群稳定。在NE Goiás被认为稳定；然而，未来可能面临石灰石露头农业产品开采的威胁。在Bahia州São Felix do Coribe周围，残余干燥森林斑块非常小（全部<200公顷），整个石灰石区域亦是如此。剩余森林主要用于木材，主要是围栏柱子；卫星图像显示Goias的Paranã谷地，1990年至1999年间，干燥森林从区域的15.8%下降至仅5.4%，且<1%的残留碎片大于100公顷，尽管它们占剩余森林的48%。。","distribution":"分布于巴西东部，从Bahia西南部的圣弗朗西斯科河谷和Minas Gerais北部及中部，向西至Tocantins东南部（Serra Geral），Goiás东北部和联邦区。"},{"name":"冠黑霸鹟","english_name":"Crested Black Tyrant","scientific_name":"Knipolegus lophotes","overview":"冠黑霸鹟（英文名：Crested Black Tyrant，学名：Knipolegus lophotes），是雀形目霸鹟科黑霸鹟属的鸟类。体型较大的霸鹟科鸟类，主要分布在南美洲的巴西中部和东南部、乌拉圭以及东北部的巴拉圭。其显著特征是全身光亮的蓝黑色羽毛，头部顶着细长的尖顶状羽冠，红褐色的眼睛，以及飞行时可见的白色翼斑。","appearance":"冠黑霸鹟体长约20-21厘米，羽毛呈光泽的蓝黑色，头部有长长的、纤细的、指向的羽冠。翅膀基部白色（休息时隐藏或大部分隐藏，飞行时显眼）；虹膜颜色为深红色或红棕色；喙和腿均为黑色。雌雄相似，但雌鸟较雄鸟略小。","call":"通常保持沉默，但在夜间的鸣唱被描述为调制的、升降音符伴随短暂的颤音，发出“dewéé-kwirr”的声音。","habits":"栖息于草原、开阔的草地或灌木区，常靠近树丛；海拔高度大多低于1100米。以昆虫为主食，偶尔食用小果实；在巴西米纳斯吉拉斯州的一处地点，Miconia albicans的浆果（Melastomataceae科）似乎占了饮食的重要部分。一般显眼，尽管通常是分散的成对活动。捕食时会突然飞扑向猎物。","breeding":"繁殖信息有限。在巴西的繁殖期大约为9月至11月。两个相邻的领地面积分别为6.5公顷和7.7公顷。巢筑于小平台上，约离地面3.5米高，位于潮湿、隐蔽的阴凉处；巢为开放的圆形，由树枝、根和苔藓构成。","identification":"冠黑霸鹟的识别特征在于其均匀的黑色羽毛和长而细的羽冠，飞行时的白色翼斑。与同属物种相比，其独特的羽冠和全身的黑色羽毛使其易于辨认。","protection":"IUCN：LC（无危）","distribution":"分布于巴西（从中部马托格罗索州东至托坎廷斯州和埃斯皮里图桑托州，南至里奥格兰德杜苏尔州）、乌拉圭东部以及巴拉圭东北部（阿曼拜州）。","other":"在巴西，冠黑霸鹟在当地较为常见，特别是在伊塔蒂亚亚国家公园下方的地区，同时也在卡帕拉奥国家公园、塞拉达卡纳斯特拉国家公园和卡拉察自然遗产特别保护区出现。"},{"name":"柔羽黑霸鹟","english_name":"Velvety Black Tyrant","scientific_name":"Knipolegus nigerrimus","overview":"柔羽黑霸鹟（英文名：Velvety Black Tyrant，学名：Knipolegus nigerrimus），是雀形目霸鹟科黑霸鹟属的鸟类。体型较大的霸鹟，分布于南美洲巴西东部和东南部的山地地区，栖息于温带森林、亚热带湿润山地森林及高海拔灌木丛。","appearance":"全身呈光泽的蓝黑色，具短小的冠羽。飞行中可见白色翼斑。雌鸟个体拥有栗色的下颌。雄雌差异显著，雌鸟的特征尤为独特。","call":"展示飞行时发出短促而尖锐的‘prrrr’叫声，通常在表演飞行中呈现。叫声略显沙哑，为干燥的颤音‘krrr’，有时以高音调‘See.rrrrrr’开始。","habits":"偏好山地草地和岩石裸露的开阔地带，栖息环境多样，包括温带森林、亚热带湿润山地森林及高海拔灌木丛。具体生活习性详情尚待研究。","identification":"与同属其他物种相比，柔羽黑霸鹟的全身蓝黑色光泽和白色翼斑是辨识的关键特征，尤其是雌鸟的栗色下颌。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美巴西东部及东南部，包括温带森林、亚热带湿润山地森林及高海拔灌木丛。"},{"name":"斑眼霸鹟","english_name":"Spectacled Tyrant","scientific_name":"Hymenops perspicillatus","overview":"斑眼霸鹟（英文名：Spectacled Tyrant，学名：Hymenops perspicillatus），是雀形目霸鹟科斑眼霸鹟属的鸟类。雄鸟翅膀上的白色斑块在飞行时尤为显眼。分布于南美洲南部，包括阿根廷、智利、乌拉圭等地，偶尔出现在玻利维亚、巴拉圭和巴西东南部。此鸟偏好湿润草地和沼泽地带。","appearance":"雄性斑眼霸鹟全身黑色，具亮黄眼环和喙，翼上有大白色斑块，飞行时可见。雌鸟褐色，具锈色翼斑，腹部有淡色条纹。雄鸟总长约13-16厘米，平均体重约20.2克；雌鸟稍小，平均体重约19.9克。","call":"斑眼霸鹟的鸣叫特征包括响亮的叫声和空中表演时发出的指弹声。","habits":"斑眼霸鹟常出现在开阔草地、湿地、牧场附近，偏好靠近水体的环境。它们是部分迁徙物种，冬季会从阿根廷南部迁往北面的低地。","breeding":"繁殖期为10月至次年1月，筑巢于草丛中，由雌鸟负责，巢为开放杯状。平均产卵数为2.2枚，孵化期约15.8天，雏鸟喂养期约为14.7天。雌鸟承担全部育儿责任。","identification":"雄性斑眼霸鹟与白翅黑霸鹟相似，但后者具有蓝灰色喙尖和无肉质眼环。雌鸟与其他物种区别在于锈色翼斑和淡色腹部条纹。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲南部，包括阿根廷、智利、乌拉圭等地。在非繁殖季节，也可在多个国家公园和保护区见到。","other":"斑眼霸鹟对高草环境有依赖性，因农田扩张导致栖息地丧失，对其繁殖表现产生负面影响。"},{"name":"淡褐唧霸鹟","english_name":"Drab Water Tyrant","scientific_name":"Ochthornis littoralis","appearance":"淡褐唧霸鹟羽毛呈沙棕色，上部较深，头部和眼区更暗，臀部颜色稍浅，有微弱的白色眉纹；翅膀和尾巴呈暗褐色；下体通常比上体颜色更浅的沙棕色；虹膜深色，喙和腿黑色。性别相似，雌雄外表一致。","call":"通常保持安静；发出微弱的哨声“fwoit”或“fweet”。配偶间通过快速而激动的‘wee-chidle-chee’声合唱，重复4到6次，通常伴随着拍翅。","habits":"栖息于热带河流边缘，尤其靠近陡峭河岸、裸露的树根或垃圾堆旁，始终贴近水面，尤其是大河。海拔高度从海平面至600米。以昆虫为食，通常单独或成对出现，常显得亲近人类，允许近距离接近后再飞往不远处。从水面上方低矮的栖木上出击捕捉猎物，随着水位变化垂直移动，通常保持距水面1米左右的典型栖息高度。","breeding":"繁殖期在秘鲁为4月至10月。巢穴为开放式的草茎、根须和泥巴制成的杯状巢，置于距离河岸3米高的位置，通常位于陡峭河岸的硬泥平台上，或在日志下或悬垂处。每窝产3至4枚蛋。","identification":"与小地霸鹟相似，但后者腹部更浅色，尾羽边缘白色，站立姿势更挺立。","protection":"IUCN：LC（无危）","distribution":"南美洲亚马逊流域，包括南哥伦比亚、委内瑞拉南部（亚马逊州、玻利瓦尔州）、圭亚那南部至厄瓜多尔东部、秘鲁东部、玻利维亚北部和巴西西北部及东北部；亦见于法属圭亚那北部及巴西东北部阿马帕州极北端。"},{"name":"黄眉霸鹟","english_name":"Yellow-browed Tyrant","scientific_name":"Satrapa icterophrys","overview":"黄眉霸鹟（英文名：Yellow-browed Tyrant，学名：Satrapa icterophrys），是雀形目霸鹟科黄眉霸鹟属的唯一物种。这种中等体型的迁徙性飞禽在南美洲的森林边缘和半开放的沼泽地带发现。其最显著的特征是黄色的眉毛和腹部，与橄榄绿色的背部形成鲜明对比，翼羽边缘淡色，面部有深色面纹。雌鸟色彩略显暗淡。","appearance":"黄眉霸鹟具有中等体型，橄榄绿色的背部，鲜明的黄色眉毛和腹部，翼羽边缘呈现淡色，脸部有深色的面纹。雌鸟的颜色比雄鸟稍微暗淡一些。成年个体和幼鸟在羽毛颜色上可能有所差异。","call":"通常保持沉默，鸣叫特征未详述。","habits":"黄眉霸鹟栖息于森林边缘和半开放的沼泽地带，具体分布于委内瑞拉局部地区、玻利维亚北部和东部、巴西中东部至阿根廷北部和东北部、乌拉圭以及南美洲亚马逊盆地的部分地区。在非繁殖季节，南部种群会向北迁移至亚马逊盆地的一部分。","breeding":"关于黄眉霸鹟的繁殖行为和生长周期的具体信息未提供。","identification":"与其他同属物种相比，黄眉霸鹟的黄色眉毛和腹部是其独特的识别特征，特别是在森林边缘和沼泽环境中的辨识。","protection":"IUCN状态未提供。","distribution":"黄眉霸鹟分布于南美洲的委内瑞拉北部、巴西东北部至玻利维亚，阿根廷中部和乌拉圭，以及亚马逊盆地的部分地区。在非繁殖季节，南部种群会向北迁移至亚马逊盆地。","other":"无"},{"name":"小地霸鹟","english_name":"Little Ground Tyrant","scientific_name":"Syrtidicola fluviatilis","overview":"小地霸鹟（英文名：Little Ground Tyrant，学名：Syrtidicola fluviatilis），是雀形目霸鹟科 Syrtidicola 属的唯一物种。分布于南美的亚马逊雨林西南部，包括巴西、秘鲁、玻利维亚的部分区域，以及哥伦比亚和厄瓜多尔的小范围地区。","appearance":"这种小型飞禽主要呈现沙灰色至棕色，上体颜色较深，下体为偏白的色调。具有黑色尾巴，尾羽外侧白色，与内侧黑色形成鲜明对比。喙细长而呈黑褐色，眼睛上方有一条白色眉纹。","call":"小地霸鹟通常很少鸣叫，其叫声特征未详。","habits":"偏好河流沿岸开阔的沙滩和泥滩，而非陡峭河岸。以昆虫为食，常见于河岛上的开阔地带及开阔草地。迁徙习性不详，但在非繁殖季节会出现在各种开放生境。","breeding":"有关小地霸鹟的繁殖习性的具体信息尚未记录。","identification":"与相似且更为常见的淡褐唧霸鹟相比，小地霸鹟的下体颜色更浅，面部无明显图案，尾羽内外颜色对比明显。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲亚马逊盆地的西南部，具体包括秘鲁东部、巴西西部、玻利维亚西北及中部、哥伦比亚东南亚马逊地区以及厄瓜多尔的部分地区。","other":"2020年的一项遗传研究表明，小地霸鹟与地霸鹟的其他成员有显著差异，而是Satrapa属黄眉霸鹟的近亲，因此被移至新设立的Syrtidicola属。"},{"name":"斑嘴地霸鹟","english_name":"Spot-billed Ground Tyrant","scientific_name":"Muscisaxicola maculirostris","overview":"斑嘴地霸鹟（英文名：Spot-billed Ground Tyrant，学名：Muscisaxicola maculirostris），是雀形目霸鹟科地霸鹟属的鸟类。灰顶小霸鹟，1837年被命名。其自然栖息地位于南美洲，具体包括阿根廷、玻利维亚、智利、哥伦比亚、厄瓜多尔和秘鲁的亚热带或热带高海拔灌木丛和牧场。","appearance":"体型相对较小，外观暗淡，主要栖息在安第斯山脉的开阔岩石和碎石斜坡、山谷以及相邻的农业梯田上；在沙漠低地也有局部分布，尤其是在冬季。斑嘴地霸鹟缺乏明显的野外识别特征，羽毛颜色单一，没有强烈的对比色或鲜艳色彩。其体型小巧，胸部有微弱的暗色条纹，翅膀相对较短，喙基部黄色，近距离观察时可见。","habits":"斑嘴地霸鹟偏好在岩石地带和农业梯田环境活动，展现出特定的生境选择。它们在安第斯山脉的高海拔地区筑巢繁殖，同时也适应了沙漠低地的生存条件，尤其是在冬季。","identification":"与其他地霸鹟种类相比，斑嘴地霸鹟通过其较小的体型、模糊的胸部条纹、较短的翅膀和独特的鸣声来区分。此外，其喙基部的黄色在近观时是明显的辨识特征。","protection":"IUCN：LC（无危）","distribution":"斑嘴地霸鹟的分布范围涵盖南美洲的哥伦比亚至智利和阿根廷，包括安第斯山脉的高海拔区域。"},{"name":"灰顶地霸鹟","english_name":"Taczanowski's Ground Tyrant","scientific_name":"Muscisaxicola griseus","overview":"灰顶地霸鹟（英文名：Taczanowski's Ground Tyrant，学名：Muscisaxicola griseus），是雀形目霸鹟科地霸鹟属的鸟类，主要分布于南美的秘鲁和玻利维亚，其自然生境为高海拔的亚热带或热带草原。","appearance":"灰顶地霸鹟是一种灰白色的地霸鹟，具有显著的白色眉纹，这道眉纹延伸至或超过眼睛，为其提供了一个易于识别的特征。它比相似的灰地霸鹟体型更大，站立姿态更为挺拔，给人一种更高大的印象。此外，不同于其他地霸鹟种类，灰顶地霸鹟头部顶部并无明显的斑块。","call":"其叫声被描述为柔和的‘pip’声，间隔重复发出。","habits":"灰顶地霸鹟生活在高海拔的草地和牧场环境中，偏好亚热带或热带的高海拔草原地带。它们的活动范围和觅食方式尚需进一步研究。","breeding":"关于灰顶地霸鹟的繁殖习性的具体信息，目前资料较为有限，需要更多的科学研究来揭示。","identification":"灰顶地霸鹟与灰地霸鹟相比，最明显的区别在于其更长的白色眉纹，以及在头部顶部缺乏斑块，且体型更为庞大，站立时姿态更加挺立。","distribution":"灰顶地霸鹟的分布区域主要集中在南美洲的秘鲁（从Cajamarca向南）和玻利维亚的西北部及中部（包括La Paz和Cochabamba地区）。"},{"name":"高山地霸鹟","english_name":"Puna Ground Tyrant","scientific_name":"Muscisaxicola juninensis","overview":"高山地霸鹟（英文名：Puna Ground Tyrant，学名：Muscisaxicola juninensis），是雀形目霸鹟科地霸鹟属的鸟类。小型陆生霸鹟科鸟类，常见于安第斯山脉高海拔地区的普纳环境，尤其偏爱沼泽地和湖岸周边有岩石和丛草的地方。其体型较白额地霸鹟小，两者常在同一区域内出现。","appearance":"体长约16.5厘米。头部上方略带暗肉桂色，上眼线白色，眉纹淡色但不明显，眼圈断续。背部呈淡褐色，臀部黑色，翅膀灰褐色，尾巴黑色，最外侧尾羽外缘有白色边线。腹部灰色，喉部和腹部接近白色。虹膜深色，喙和腿黑色。成年鸟和幼鸟在外形上相似，幼鸟的翼覆羽边缘带有淡肉桂色，下体呈土黄色。","call":"其歌声尚未被记录。叫声为柔和的高音“peep”，间隔重复。","habits":"主要以昆虫为食，通常在地面短跑和跳跃，然后突然停止站立，偶尔从地面或岩石上飞扑捕食。非繁殖季节经常形成松散的群落。","identification":"与白眉地霸鹟相比，高山地霸鹟外观更偏棕色（而非灰色），眉纹不明显，喙较小。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，从秘鲁中部至南部，智利北部，玻利维亚西南部至阿根廷西北部。"},{"name":"灰地霸鹟","english_name":"Cinereous Ground Tyrant","scientific_name":"Muscisaxicola cinereus","overview":"灰地霸鹟（英文名：Cinereous Ground Tyrant，学名：Muscisaxicola cinereus），是雀形目霸鹟科地霸鹟属的小型鸟类。1864年首次被命名，其名称‘cinereous’即指代其灰烬般的颜色。该物种分布于南美洲的高海拔地带，包括秘鲁、智利北部和阿根廷西北部，栖息在亚热带或热带的高山草原。","appearance":"灰地霸鹟具有朴素而吸引人的外观，头部和背部呈现均匀的蓝灰色，拥有一个短小且稍显白色的眉纹，缺乏色彩鲜艳的头冠标记，喙直且平均长度，尖端略向下弯。翅膀与背部颜色对比不强烈，整体给人一种柔和的视觉印象。","call":"其歌曲尚未被记录。叫声为柔和的‘pip’声，间歇性重复。","habits":"偏好岩石斜坡、山谷和邻近的沼泽环境，常与其他地霸鹟种类混群。南部种群冬季会向北迁徙。","breeding":"关于其繁殖生态的具体细节尚待研究。","identification":"与棕颈地霸鹟相比，灰地霸鹟的眉纹较弱，喙尖下垂，背部与翅膀颜色过渡自然，没有强烈的对比。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲，繁殖区域涵盖秘鲁至智利北部和阿根廷西北部。","other":"已列入《世界自然保护联盟》鸟类名录。"},{"name":"白额地霸鹟","english_name":"White-fronted Ground Tyrant","scientific_name":"Muscisaxicola albifrons","overview":"白额地霸鹟（英文名：White-fronted Ground Tyrant，学名：Muscisaxicola albifrons），是雀形目霸鹟科地霸鹟属的鸟类。地霸鹟中体型最大的一种，以其高大的身材和安第斯山脉的高海拔分布著称。主要分布在南美的秘鲁、玻利维亚西部和智利北部，偏好沼泽和有积水的草甸环境。","appearance":"成年白额地霸鹟的头部呈温暖的灰褐色，额头显著的白色三角形标记延伸到眼上部，形成独特的白色‘V’字图案。背部和颈部为棕色灰色，翅膀和尾巴深棕色，第二级飞羽边缘宽阔的白色，形成闭合翅膀时的白色翼板印象。下体浅灰色，几乎无斑纹。幼鸟与成鸟的区别在于翼覆羽边缘的肉桂色，次级飞羽和内侧初级飞羽边缘的淡黄色，以及额头和眼上部的白色减少且更暗淡。","habits":"白额地霸鹟通常单独或成对出现，活跃于沼泽地带，偶尔也会进入相邻的岩石高地。它们的飞行模式独特，长而宽的翅膀使飞行显得像蛾子般，有助于快速识别。该物种可能是在西半球定期出现的最高海拔鸟类之一，曾在高达5,600米的地方被记录。","breeding":"在秘鲁的Cordillera Vilcanota，白额地霸鹟是仅有的两种在Quelccaya冰川筑巢的物种之一。已知的繁殖巢穴位于冰川边缘的冰洞内，记录的活动巢穴时间在10月至11月间。","identification":"与较小的赭颈地霸鹟最为相似，后者拥有黄色的颈后斑点，当可见时具有诊断意义。赭颈地霸鹟颜色更灰且较淡。与较小的地霸鹟种类如高山地霸鹟相比，白额地霸鹟的翼展和体型特征是最明显的区分点。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美秘鲁至智利北部的Altiplano高原，偏好有积水和垫状植物的沼泽地带。"},{"name":"赭颈地霸鹟","english_name":"Ochre-naped Ground Tyrant","scientific_name":"Muscisaxicola flavinucha","overview":"赭颈地霸鹟（英文名：Ochre-naped Ground Tyrant，学名：Muscisaxicola flavinucha），是雀形目霸鹟科地霸鹟属的鸟类。以灰褐色调的羽毛、白色的前额斑块和鲜明的赭色颈背斑块为显著特征。繁殖于安第斯山脉南部，从秘鲁南部至火地岛西部边缘，冬季迁徙至北部。生活在温带草原和高海拔亚热带草原。","appearance":"赭颈地霸鹟是一种体型较大的陆栖霸鹟，其羽毛呈灰褐色调，头部有明显的白色前额斑块，最独特的特征是颈背部的赭色斑块，这一特征有时因观察角度而难以察觉。雌雄幼鸟的羽毛变化及具体大小信息未详述。","habits":"偏好潮湿环境，如沼泽、溪流旁和其他湿润地带，尤其在开阔的岩石和石质地貌中。迁徙时，也可能出现在低地的田野上。与其它地霸鹟种类共享栖息地。","identification":"通过灰褐色的羽毛、白色的前额斑块和赭色的颈背斑块来识别，尤其是颈背的赭色斑块是辨识关键。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于南美洲的阿根廷和智利境内，非繁殖季节迁徙至秘鲁和玻利维亚西部。"},{"name":"棕颈地霸鹟","english_name":"Rufous-naped Ground Tyrant","scientific_name":"Muscisaxicola rufivertex","overview":"棕颈地霸鹟（英文名：Rufous-naped Ground Tyrant，学名：Muscisaxicola rufivertex），是雀形目霸鹟科地霸鹟属的鸟类。以独特的棕颈和蓝灰色羽毛著称，分布广泛，自1837年命名以来，已成为南美洲特有种。其自然生境涵盖安第斯山脉的高海拔草地和灌木地带。","appearance":"棕颈地霸鹟总体呈现蓝灰色，最显著的特征是其棕颈部斑块，这一特征在南部更显锈色，在中部较为肉桂色，在北部则颜色最深。成鸟的翅膀略暗，尾巴明显更深。头部和上身淡灰，下臀黑色；翅膀呈暗灰色，尾巴暗色，外羽缘白色；下方淡灰色，喉咙和腹部近乎白色。喙长而细，稍向下弯曲，黑色；腿黑色。雌雄相似，幼鸟的冠部斑块较暗，翼覆羽边缘带肉桂色，与成鸟有细微差别。","call":"鸣叫为尖锐上扬但悦耳的‘weet’声，雄鸟展示期间发出薄而高音的‘twee-it’声。","habits":"生活在安第斯山脉的开阔地带，偏好有岩石露头的短草甸，常在较为干旱的地区。栖息于2200至4500米的高海拔，冬季可能降至300至1000米，尤其在秘鲁西南部和智利北部。在繁殖季节，它们主要活动于3350至4350米之间。以昆虫为食，主要在地面捕食，偶尔从地面或岩石上出击。通常独居，非繁殖期会形成小群。","breeding":"繁殖期在11月至1月的阿根廷，9月在智利中部，巢筑于岩石裂缝间，由植物材料构成，内部为小型稻草杯状，衬以羽毛和毛发。每窝产三枚卵，孵化和离巢期未知。受到紫辉牛鹂的寄生。","identification":"与棕颈地霸鹟相比，本种具有更大的体型，栗色冠斑更宽且更为突出，眼纹上方的白色眉纹更宽，尾羽几乎没有浅色边缘。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，自秘鲁至智利中部和阿根廷西部，主要栖息于安第斯山脉的高海拔区域。"},{"name":"暗脸地霸鹟","english_name":"Dark-faced Ground Tyrant","scientific_name":"Muscisaxicola maclovianus","overview":"暗脸地霸鹟（英文名：Dark-faced Ground Tyrant，学名：Muscisaxicola maclovianus），是雀形目霸鹟科地霸鹟属的小型地面活动的鸟类。主要分布于南美洲南部安第斯山脉地区和福克兰群岛，以岩石地带和开阔森林边缘为栖息地。","appearance":"全长约16厘米，雄鸟略大于雌鸟。拥有长腿和直立姿态，上体呈深灰褐色，下体淡灰色，头部为深棕色，面部黑色，臀部和尾巴黑色，尾羽外侧白色。腿和喙均为黑色。福克兰群岛的种群（M. m. maclovianus）比南美洲大陆种群（M. m. mentalis）体型更大，颜色更灰。","call":"发出微弱的啾啾声，既可在地面也可在飞行中鸣唱。","habits":"栖息于从海平面至海拔1500米的开阔地带，冬季部分个体向北迁徙至乌拉圭、阿根廷北部和秘鲁。非繁殖季节会降至低地，访问农田、花园和海滩。","breeding":"巢筑于岩石间，由草和根纤维构成，内衬羊毛或羽毛。产2至3枚白色带红棕色斑点的蛋，可能在一季内育两窝。","identification":"与其他地霸鹟相比，暗脸地霸鹟具有明显的黑脸面具和锈色颈背斑块，福克兰群岛种群体型更大，颜色更灰。","protection":"IUCN状态未知，未列入CITES附录或中国国家重点保护野生动物名录。","distribution":"繁殖区域包括南美洲南部的智利和阿根廷以及福克兰群岛，冬季迁徙至乌拉圭、阿根廷北部和秘鲁沿海。","other":"在1994年9月，有记录显示它曾出现在南乔治亚岛；2011年5月在巴西南里奥格兰德州也有记录。"},{"name":"白眉地霸鹟","english_name":"White-browed Ground Tyrant","scientific_name":"Muscisaxicola albilora","overview":"白眉地霸鹟（英文名：White-browed Ground Tyrant，学名：Muscisaxicola albilora），是雀形目霸鹟科地霸鹟属的鸟类。最显著的特征是长长的白色眉纹。主要分布在南美洲的安第斯山脉，从厄瓜多尔至智利南部和阿根廷西部，海拔介于1,500至4,000米之间。","appearance":"体型约16.5至17厘米，具显著的长而窄的白色眉纹，头顶呈棕褐色逐渐过渡到后冠部的锈色；上体灰褐色，翅膀暗灰色；尾羽黑色，最外侧一对尾羽的外缘呈白色；腹部下方灰淡，腹部白色；眼睛深棕色，喙长而暗色，腿亦呈暗色。雄雌相似，幼鸟整个头部为棕色，三级飞羽和翼覆羽边缘略带暗锈色。","call":"鸣唱时发出激动的‘tstet, tseek, tut, tsk, tchk’声；飞行叫声为‘tseet’，接触叫声为‘tut’；在空中展示时罕见发出‘clet ip’的声音。","habits":"主要以昆虫为食，通常在地面短跑和跳跃追逐猎物，偶尔从地面或岩石上起飞捕捉。通常是独居，迁徙期间会形成松散的群落。","breeding":"繁殖季节在智利为10月至1月；在阿根廷发现筑巢行为发生在11月和2月。空中展示飞行时，缓慢上升，腿下垂，尾巴展开，然后降落至地面。巢穴为草制的开放杯状，内部铺有羽毛，置于岩石裂缝或凹处。一窝产卵2至3枚。","identification":"与高山地霸鹟相比，体型稍大，头顶颜色更深，眉纹更为明显。","distribution":"繁殖于南美洲的安第斯山脉，范围从厄瓜多尔至智利南部和阿根廷西部；迁徙时向北至玻利维亚、哥伦比亚、厄瓜多尔和秘鲁；偶尔出现在福克兰群岛。"},{"name":"淡顶地霸鹟","english_name":"Paramo Ground Tyrant","scientific_name":"Muscisaxicola alpinus","overview":"淡顶地霸鹟（英文名：Paramo Ground Tyrant，学名：Muscisaxicola alpinus），是雀形目霸鹟科地霸鹟属的鸟类。体型略大的陆生霸鹟。其特征为上体呈灰褐色，头顶略带赤褐色，具有一条明显的白色眉纹，下体为灰白色，喉部和腹部颜色更白。该物种主要分布在南美的高海拔地区，如哥伦比亚和厄瓜多尔的安第斯山脉。","appearance":"体长18-19厘米，具有宽阔的白色眉纹延伸过眼，眼下方有小块白色区域；额部暗淡；上体灰褐，头顶微带赤褐色；翅膀较暗，翼羽缘以淡色；尾部黑色，最外侧尾羽边缘白色；下体灰白，喉部和腹部尤为洁白；虹膜深棕色；喙短而细，黑色；腿黑色。幼鸟翼羽和内飞羽尖端和边缘为肉桂色，腹部和臀部带有浅黄色调，下体有白色条纹，头部和背部羽毛顶端有淡淡的暗色点状斑纹。两性相似。","call":"通常沉默，偶尔发出弱小的哀怨声或轻柔的‘tik’音。","habits":"栖息于干燥的高山灌丛、punas和páramos草原，偏好岩石地带，海拔主要在3300至4700米间，偶尔降至800米。常单独活动，非繁殖季节会形成松散的群体，最多可达30只，有时与其他地霸鹟或punas地带的鸟类混群。主要以昆虫为食，地面觅食，突然停止并竖立站立，偶尔从低处的栖木突袭猎物，经常摆动尾巴。","breeding":"繁殖期在哥伦比亚为9月至12月，在厄瓜多尔至少从8月至10月。雄鸟展示时会反复盘旋、停滞和降落。巢由稀疏排列的草和根构成，安置在岩石下的洞穴或裂缝中。每窝产卵4枚，卵壳白色，散布着肉桂色斑点，集中于较大一端。已测量的卵尺寸为27.6mm×18.8mm和27.1mm×18.7mm。","identification":"与灰地霸鹟主要区别在于体型更大，上体颜色更深更偏褐色，白色眉纹略超出眼睛。","protection":"IUCN：LC（无危）。在当地某些地区较为常见，如厄瓜多尔的科托帕克西国家公园；在哥伦比亚相对少见，但在普拉塞国家公园有记录。","distribution":"分布于南美洲的哥伦比亚和厄瓜多尔，主要栖息在安第斯山脉的高海拔地区。","other":"曾被认为与灰顶地霸鹟是同一物种的亚种，但现在通常被视为独立物种。"},{"name":"红腹地霸鹟","english_name":"Cinnamon-bellied Ground Tyrant","scientific_name":"Muscisaxicola capistratus","overview":"红腹地霸鹟（英文名：Cinnamon-bellied Ground Tyrant，学名：Muscisaxicola capistratus），是雀形目霸鹟科地霸鹟属的鸟类，是《世界自然保护联盟》保护的鸟类物种之一。该鸟种主要分布在南美洲的阿根廷南部、智利、秘鲁等地。","appearance":"红腹地霸鹟是一种具有吸引力但数量相对较少且分布较为局限的陆生型霸鹟。其最显著的外部特征在于头部的独特图案以及侧腹和腹部强烈呈现出肉桂色的色调。","habits":"红腹地霸鹟主要栖息在开阔的草原地带、沿海沙丘以及砾石草原，通常在繁殖季节会选择靠近悬崖或岩石露头的地区筑巢。冬季时，它们会迁徙至安第斯山脉的开放环境和沼泽地带。","breeding":"红腹地霸鹟在极端南部的阿根廷和智利以及火地岛北部繁殖，随着南半球冬季的到来，它们会向北迁徙。","identification":"与体型明显更大的赭肛霸鹟相比，红腹地霸鹟在体型上较小，且拥有独特的肉桂色腹部。","protection":"IUCN：LC（无危）","distribution":"红腹地霸鹟的繁殖区域主要集中在南美洲极南端的智利马加兰斯省和阿根廷圣克鲁斯省；冬季时，它们会沿安第斯山脉向北迁徙至秘鲁南部的普诺地区。"},{"name":"黑额地霸鹟","english_name":"Black-fronted Ground Tyrant","scientific_name":"Muscisaxicola frontalis","overview":"黑额地霸鹟（英文名：Black-fronted Ground Tyrant，学名：Muscisaxicola frontalis），是雀形目霸鹟科地霸鹟属的鸟类。在南美安第斯山脉南部的特有鸟类，最显著的特征是头部独特的黑色‘莫霍克’发型，灰烬色的羽毛和下垂的喙尖。繁殖季节主要在智利中部和阿根廷中西部，冬季则迁往北至玻利维亚西部和秘鲁南部。","appearance":"黑额地霸鹟具有独特的灰烬色调羽毛，喙尖下垂，头部呈现出黑色的‘莫霍克’式图案，腹部显得较为圆润，与其它地霸鹟属物种相比，体型略显丰腴。","habits":"栖息于高海拔的安第斯山脉，偏好岩石嶙峋和石质斜坡地带，常出现在沼泽边缘和湖岸附近。以昆虫为主食，冬季在秘鲁时还会食用Cumulopuntia boliviana仙人掌的果实。活动方式主要是地面奔跑和跳跃，偶尔从地面或岩石上起飞捕食。","identification":"与其他地霸鹟属物种相比，黑额地霸鹟拥有更加圆润的腹部，头部的黑色‘莫霍克’发型是其显著的辨识特征。","protection":"IUCN：LC（无危）","distribution":"繁殖于智利中部（从安托法加斯塔至马乌莱）和阿根廷中西部（门多萨西部至里奥内格罗西部），冬季迁徙至北至玻利维亚西部和秘鲁南部（北至安卡什地区）。"},{"name":"黑嘴鵙霸鹟","english_name":"Black-billed Shrike-Tyrant","scientific_name":"Agriornis montanus","overview":"黑嘴鵙霸鹟（英文名：Black-billed Shrike-Tyrant，学名：Agriornis montanus），是雀形目霸鹟科鵙霸鹟属的鸟类。大型霸鹟科鸟类，体长可达23-25厘米（9-10英寸）。广泛分布于安第斯山脉，从哥伦比亚至南美的智利和阿根廷，偶尔飘泊至福克兰群岛。","appearance":"黑嘴鵙霸鹟是一种体型较大的飞禽，其最显著的特征是尾部的白色部分非常显眼，尤其是飞行时更为明显。喙部为全黑色，年轻个体下颚可能略带淡色。眼睛颜色较浅，而在幼鸟中则显得更暗。雄雌外观相似，但在某些亚种中可能存在细微差异。","habits":"偏好开阔和半开阔的生境，从岩石和灌木覆盖的斜坡到沼泽和湖岸都有它们的身影。它们常在村落和滑雪小屋附近活动，甚至在建筑物内部筑巢。经常在显眼的位置停歇，有时会显得相当亲近人，但也能够飞行较长距离。","identification":"在大部分分布区内，通过体型和尾部的白色部分可以轻易识别黑嘴鵙霸鹟。与之相似但数量稀少、体形稍大的白尾鵙霸鹟相比，黑嘴鵙霸鹟具有细长的全黑色喙（年轻个体下颚可能略淡），以及浅色的眼睛（年轻个体的眼睛颜色更深）。","protection":"IUCN：LC（无危）","distribution":"黑嘴鵙霸鹟的分布区域涵盖了南美洲的安第斯山脉，从哥伦比亚南部延伸至智利和阿根廷。在南美洲，它们常见于高海拔的灌木地带和草甸，以及牧场区域。"},{"name":"白尾鵙霸鹟","english_name":"White-tailed Shrike-Tyrant","scientific_name":"Agriornis albicauda","overview":"白尾鵙霸鹟（英文名：White-tailed Shrike-Tyrant，学名：Agriornis albicauda），是雀形目霸鹟科鵙霸鹟属的鸟类。大型霸鹟科鸟类，长度可达25-28厘米，仅次于大鵙霸鹟。其自然栖息地为南美洲安第斯山脉的高海拔灌木丛、草地以及农耕和牧场地带。","appearance":"头部侧面有狭窄的浅色眉纹，上体暗灰褐色，翅膀边缘稍淡。中央尾羽颜色类似背部，其余尾羽白色，尖端带有小黑斑。喉咙白色，带黑色条纹；上胸及两侧灰褐色，下胸、腹部和臀部白色，不规则地染有肉桂色。下颚角质色至黄色，上颚深色，腿黑色。与黑嘴鵙霸鹟相比，体型更大，喙更厚重，喉纹更锐利、更深色。","call":"发出令人惊讶的响亮、悦耳的叫声，如“teeu, tcheeu-tcheeu-tcheeuw!”，有许多变化。雄鸟在空中展示时，外侧两枚初级飞羽产生低音的嗡嗡声。","habits":"栖息于岩石露头或灌木上，主要在地面或空中捕食大型昆虫、小型哺乳动物、蜥蜴、蛙类、其他鸟类的蛋或雏鸟。有时与黑嘴鵙霸鹟共存。","breeding":"在厄瓜多尔西北部，6月时观察到雄鸟进行空中展示，雄鸟交替上升至部分失速状态然后双翼闭合向下俯冲。在厄瓜多尔记录到成鸟喂养雏鸟，具体繁殖信息有限。","identification":"与黑嘴鵙霸鹟相比，可通过更大体型、更厚重的喙、更锐利的喉纹以及下颚的颜色来区分。","protection":"IUCN：VU（易危）。非常罕见且分布局限。近几十年数量明显减少，总数量仅数千只，分布区逐渐碎片化。可能因栖息地破坏和人类活动而受到威胁。","distribution":"分布于南美，从厄瓜多尔至阿根廷西北部。在厄瓜多尔、秘鲁、智利、阿根廷等国的国家公园和保护区有记录，但总体而言分布分散且数量稀少。","other":"历史上曾更常见，但近年来数量显著下降，可能是由于栖息地的改变和人类的干扰导致。"},{"name":"大鵙霸鹟","english_name":"Great Shrike-Tyrant","scientific_name":"Agriornis lividus","overview":"大鵙霸鹟（英文名：Great Shrike-Tyrant，学名：Agriornis lividus），是雀形目霸鹟科鵙霸鹟属的大型飞禽。体型庞大但外表朴素，常见于低地及山麓地带的半开放灌木丛生环境、较轻的林地及干燥农田中的篱笆。通常稀少且分布局限，是南美洲智利及阿根廷南部的特有种。","appearance":"体长26至28厘米，为最大的霸鹟科飞禽。头部深色，耳羽带有肉桂色调，面部有淡白色斑点；上身主要是灰褐色；翅膀颜色更深，翼羽边缘模糊呈淡棕色；尾巴黑色，尖端和外侧羽毛边缘呈浅黄白色；喉咙白色，有黑色条纹；下身略淡的灰褐色，腹部下方和尤其生殖区染有肉桂或肉桂色。虹膜深色；喙厚重且钩状，上喙黑色，下喙角质色并向尖端渐暗；腿黑色。雌雄相似。幼鸟颜色更棕，头部、背部和上胸部有暗色模糊条纹，喉部条纹较少，整个腹部为肉桂色。","call":"通常沉默，叫声为‘t-eek’或‘t-eek-ek’。雄鸟在空中展示时，两个最外侧的初级飞羽会产生低沉、几乎听不见的嗡嗡声。","habits":"居住在半开放的灌木丛和农业区域，避开极端干燥和非常湿润的环境，以及树木茂密或人口稠密的区域。常在亚干旱乡村的大片灌木、浓密灌木丛、仙人掌和凤梨科植物中发现；开阔的平原、周围斜坡上点缀着灌木的牧场，以及过渡性的诺斯福盖斯森林中的树木。海拔从海平面到1800米，主要在1500米以下。高度分散的成对出现，显眼地停在岩石突出物或灌木顶部，大多从地面捕捉猎物，或在空中猎食。","breeding":"在智利，沿海地区繁殖期为10月，内陆为11月。雄鸟有空中展示行为。巢呈杯状，由树枝构成，内部铺以草和羊毛，置于灌木或仙人掌中。每窝产卵2至4枚，通常为3枚。无更多信息。","identification":"最可能被误认为是南美鸫，两者体型和羽毛颜色相似，但南美鸫具有明亮的黄色喙。","protection":"IUCN：LC（无危）。在范围南部变得罕见，但在智利中部（从阿空加瓜到比奥比奥）和巴塔哥尼亚东南部（丘布特和艾森）最为常见。其分布范围内有许多国家公园。","distribution":"分布于南美洲的智利和阿根廷南部。主要在智利中部和巴塔哥尼亚东南部，从海平面到1800米，主要在1500米以下。"},{"name":"灰腹鵙霸鹟","english_name":"Grey-bellied Shrike-Tyrant","scientific_name":"Agriornis micropterus","overview":"灰腹鵙霸鹟（英文名：Grey-bellied Shrike-Tyrant，学名：Agriornis micropterus），是雀形目霸鹟科鵙霸鹟属的鸟类。大型的霸鹟科鵙霸鹟属鸟类，主要分布在南美洲的安第斯山脉和巴塔哥尼亚较干燥地区的半开放和灌木丛生地带。其体型较大，外观较为朴素，常在灌木、树顶或电线上显眼处栖息。","appearance":"该鸟全身羽毛颜色较为暗淡，腹部呈灰色，下体颜色略浅，尾部黑色，喙粗壮有力。雌雄鸟在外观上相似，幼鸟的特征可能略有不同，但具体差异需进一步观察确认。","call":"未提供详细鸣叫特征。","habits":"偏好在干燥区域的半开放和灌木丛生环境中活动，擅长地面奔跑，以追逐小型蜥蜴和其他猎物为食。迁徙模式复杂，南方族群（指名亚种）在南半球冬季（至少6月至10月）向北迁徙，分布范围扩展至阿根廷大部分地区，偶尔可达玻利维亚（科恰班巴）。离开繁殖地的时间大约在2月，非繁殖季节则分布在南玻利维亚、巴拉圭（罕见但规律）、乌拉圭（非常罕见，近期无记录）至科多尔瓦和阿根廷北部布宜诺斯艾利斯。","breeding":"未提供详细繁殖信息。","identification":"与其他类似物种相比，如大鵙霸鹟，灰腹鵙霸鹟在羽毛颜色上更显朴素，腹部和臀部偏灰色，尾部深黑，喙部粗壮，通过这些特征可以将其与其他种类区分开来。","protection":"IUCN：LC（无危）。总体上数量不多，但在某些局部地区较为常见，例如智利的Collacagua谷地和San Pedro de Atacama周边。","distribution":"分布于南美洲的南锥体区域，包括阿根廷、玻利维亚、智利、巴拉圭、秘鲁和乌拉圭。在巴西里约格兰德杜苏尔西部也有记录。","other":"未提供其他信息。"},{"name":"小鵙霸鹟","english_name":"Lesser Shrike-Tyrant","scientific_name":"Agriornis murinus","overview":"小鵙霸鹟（英文名：Lesser Shrike-Tyrant，学名：Agriornis murinus），是雀形目霸鹟科鵙霸鹟属的鸟类。其体型小巧，喙部较小，缺乏典型的鵙霸鹟属中的钩状终端。分布于南美洲南部锥体区域，繁殖于巴塔哥尼亚北部及阿根廷南部蒙特沙漠，包括阿根廷中部的科门钦戈内斯山。在南半球冬季期间，该物种会向北及向海拔较高处分散，进入巴拉圭西部和玻利维亚东南部。","appearance":"小鵙霸鹟的特征在于其小而精致的喙，不同于典型鵙霸鹟的钩状喙端。偏好低矮植被、电线及灌木丛中的暴露栖息点。雌雄及幼鸟的羽毛颜色和大小差异尚未具体描述。","habits":"小鵙霸鹟偏好在低矮植被、电线及灌木丛中活动，以干燥灌木环境为栖息地。其迁徙模式表现为在繁殖季节结束后向北迁移，南半球的冬季（5月至9月）期间，它们广泛分布在阿根廷大部分地区（除东北部）、巴拉圭西部以及玻利维亚中部和南部（北至科恰班巴和西圣克鲁斯）。","identification":"小鵙霸鹟与同属物种的区别在于其较小的体型和喙型，以及其特定的栖息地选择和地理分布。","protection":"IUCN：LC（无危）。小鵙霸鹟数量不多但分布稳定，未发现明显威胁。为了精确确定其繁殖范围，需要进一步的调查工作。","distribution":"繁殖于阿根廷的卡塔马卡、拉里奥哈、科尔多瓦，以及从内乌肯、里奥内格罗和西南部布宜诺斯艾利斯到圣克鲁斯的区域；越冬时北迁至巴拉圭西部和玻利维亚中部及南部（北至科恰班巴和西圣克鲁斯）。"},{"name":"红眼蒙霸鹟","english_name":"Fire-eyed Diucon","scientific_name":"Pyrope pyrope","overview":"红眼蒙霸鹟（英文名：Fire-eyed Diucon，学名：Pyrope pyrope），是雀形目霸鹟科 Pyrope 属的鸟类。以其独特的红宝石般的眼睛命名，主要分布在智利中部和南部、阿根廷西南部以及火地岛。在福克兰群岛也有迷鸟记录。","appearance":"红眼蒙霸鹟是一种大型的霸鹟，身长可达19至21厘米。其上体主要呈灰暗色，翅膀更显黑色，尾巴灰色，外侧尾羽较淡。下体为淡灰白色，喉咙偏白，腹部略带灰色，两性羽毛相似。幼鸟的羽毛边缘呈淡黄色，胸部有模糊的条纹，眼睛颜色为棕色而非红色。","habits":"红眼蒙霸鹟常见于半开放的栖息地，如开阔的林地、农田中的高树和灌木丛、马特拉尔、公园和花园。它们经常单独或成对出现在路边电线和树顶上，表现出不畏惧人类的行为。","identification":"红眼蒙霸鹟在南美洲南部的范围内具有独特的灰色外观和醒目的红眼睛。地霸鹟虽然也是灰色，但更加接近地面，脚更长，头部有浅色眉纹和冠斑，而红眼蒙霸鹟没有这些特征。与之广泛共存的另一种灰色鸟类迪卡雀，体型较小，喙短，尾羽尖端白色，胸部有灰色带，侧面有肉桂色。","protection":"IUCN状态未知","distribution":"红眼蒙霸鹟主要分布于智利中部和南部、阿根廷西南部以及火地岛，福克兰群岛也有迷鸟记录。"},{"name":"灰蒙霸鹟","english_name":"Grey Monjita","scientific_name":"Nengetus cinereus","overview":"灰蒙霸鹟（英文名：Grey Monjita，学名：Nengetus cinereus），是雀形目霸鹟科 Nengetus 属的鸟类。是Nengetus属的唯一物种。广泛分布在南美洲，包括阿根廷、玻利维亚、巴西、巴拉圭、秘鲁、苏里南和乌拉圭等地，偏好干燥草原和季节性湿润的低地草甸环境。","appearance":"这是一种大型的草原和灌木丛中的捕虫鸟，拥有醒目的红眼、白色的眉纹和黑白相间的髭纹。其喉咙和腹部呈白色，胸部和背部为灰色，尾巴黑色，飞行时可见宽阔的白色翼带。雄雌鸟羽色相似。","habits":"灰蒙霸鹟通常成对活动，地面觅食或在显眼处如灌木顶、围栏、电线杆上停栖。它们适应多种生境，包括城市周边，偏好在开阔地带寻找食物。","identification":"与其他同科鸟类相比，灰蒙霸鹟的独特之处在于其红眼、白色眉纹和黑白髭纹，以及飞行时显现的白色翼带。","protection":"IUCN：LC（无危）。虽然在某些地区较为罕见，但在锡帕利维尼草原自然保护区（Surinam）和巴西塞拉多地区（如巴西利亚周边）数量较多。因其对改变后的生境具有耐受性且分布范围广泛，总体上并不受到威胁，但仍需关注南美洲天然草原和塞拉多生境的快速破坏。","distribution":"主要分布于南美洲东部至东南部，具体包括巴西的东部和中部，以及南美东南部的多个国家。"},{"name":"黑顶蒙霸鹟","english_name":"Black-crowned Monjita","scientific_name":"Neoxolmis coronatus","overview":"黑顶蒙霸鹟（英文名：Black-crowned Monjita，学名：Neoxolmis coronatus），是雀形目霸鹟科赭肛霸鹟属的鸟类。广泛分布于南美洲的阿根廷、玻利维亚、巴西、巴拉圭和乌拉圭，其自然生境为亚热带或热带干燥灌木丛。","appearance":"体长约21至22厘米，体重40至53克。头部顶部为黑色，被宽阔的白色额带所包围，眼眉纹和颈背带亦为白色；耳羽黑色；背部灰色或棕灰色；翅膀黑色，翼覆羽具白色尖端和边缘，内侧飞羽边缘泛白，飞行时可见明显的白色条纹沿飞羽基部；尾巴黑色；全身下部全白；虹膜深色；喙和腿黑色。雌雄相似，但雌鸟略小于雄鸟。","habits":"通常在开阔的草地上活动，易于发现，常停栖于围栏、电线、灌木及小树的裸露枝干上，有时也在地面觅食。偏好亚热带或热带干燥灌木环境。","identification":"通过黑色的翅膀和头顶，以及眼与耳羽间暗色线条，可以将其与区域内同属的其他物种区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的阿根廷北部和中部，向北迁徙可达玻利维亚中部（圣克鲁斯西部）、巴拉圭西部和巴西东南部（里奥格兰德州西部）。","other":"曾被归类于Xolmis属，后因2020年发表的分子系统发育研究，被移至Neoxolmis属。"},{"name":"锈背蒙霸鹟","english_name":"Rusty-backed Monjita","scientific_name":"Neoxolmis rubetra","overview":"锈背蒙霸鹟（英文名：Rusty-backed Monjita，学名：Neoxolmis rubetra），是雀形目霸鹟科赭肛霸鹟属的鸟类。主要分布于阿根廷中部。其特征性的锈色背部和条纹下部使其在大部分范围内易于识别，仅在小范围内与盐沼蒙霸鹟有分布重叠。该物种在Monte沙漠和Pampas地区繁殖，非繁殖季节向北扩散。","appearance":"锈背蒙霸鹟拥有醒目的白和锈红色外观，背部呈现明显的锈色，下体带有条纹，这一组合在大部分分布区域内十分独特，仅在有限的区域与盐沼蒙霸鹟有相似之处。它们通常在开阔地带活动，偏好停歇于地面附近的矮灌木或低枝上。","habits":"锈背蒙霸鹟栖息于开阔的乡村地带，尤其偏好干燥的灌木草原和牧场环境。它们在Monte沙漠和Pampas地区繁殖，非繁殖季节会向北扩散至阿根廷北部地区。该物种具有迁徙习性，冬季可北迁至阿根廷北部，包括Tucumán到Entre Ríos一带。","breeding":"锈背蒙霸鹟在Monte沙漠和Pampas地区的特定生境中繁殖，具体繁殖行为和生态细节尚待更多研究。","identification":"锈背蒙霸鹟与盐沼蒙霸鹟在部分重叠分布区内需通过背部颜色和条纹下体进行区分，两者在外形上有细微差异。","protection":"IUCN：LC（无危）","distribution":"锈背蒙霸鹟主要分布于阿根廷中部，从Mendoza南部至Buenos Aires西南部和Santa Cruz东北部。冬季期间，它们向北扩散至阿根廷北部，包括Tucumán至Entre Ríos区域。已记录在巴西极南端Rio Grande do Sul西部有分布记录，同时在智利也有零星记录。"},{"name":"盐沼蒙霸鹟","english_name":"Salinas Monjita","scientific_name":"Neoxolmis salinarum","overview":"盐沼蒙霸鹟（英文名：Salinas Monjita，学名：Neoxolmis salinarum），是雀形目霸鹟科赭肛霸鹟属的鸟类。独特的小型鸟类，仅见于阿根廷中部低地的盐沼地带。其生存状况受到栖息地丧失的威胁。","appearance":"成年雄鸟体长约16.5厘米，特征明显，头顶呈红褐色，背部为红棕色，臀部偏灰白色；翅膀黑色，大翼羽和中翼羽边缘泛灰白，小翼羽带红褐色，三级飞羽边缘白色；尾巴主要为黑色，最外侧尾羽的外缘白色；颈部侧面带有隐约的黑纹，下体白色；虹膜深色，喙和腿黑色。雌鸟颈部条纹更为明显。与锈背蒙霸鹟相比，盐沼蒙霸鹟体型较小，色彩较淡，颈胸条纹较少，两胁的红褐色也较浅。","call":"叫声柔和，通常发出‘pik’声，有时接续以较低沉的鼻音‘eeeuw’，以及旋律优美的‘dewdewdewdew’。互动时会发出升调的‘chebee’或‘chebee..rrrr’叫声。飞行中，会发出柔和的旋律颤音。","habits":"饮食未知，推测主要以昆虫为食。常成对活动，冬季也会形成多达50只的小群。既在地面活动，也在灌木上栖息。","identification":"与锈背蒙霸鹟（X. rubetra）的区别在于体型更小，颜色更淡，颈胸部条纹更少，两胁红褐色较少。","protection":"IUCN：LC（无危）","distribution":"盐沼蒙霸鹟的分布局限于南美洲的阿根廷中北部。","other":"2020年以前，本物种曾被归入Xolmis属，后因分子系统发育研究，被调整至Neoxolmis属。"},{"name":"赭肛霸鹟","english_name":"Chocolate-vented Tyrant","scientific_name":"Neoxolmis rufiventris","overview":"赭肛霸鹟（英文名：Chocolate-vented Tyrant，学名：Neoxolmis rufiventris），是雀形目霸鹟科赭肛霸鹟属的大型陆栖鸟类。栖息于巴塔哥尼亚开阔地带，偏好风吹草低见牛羊的环境，尤其是丛生的草甸和伴有草地斑块的开放灌木草原；冬季会向北迁徙至潘帕斯草原。首次科学描述由Vieillot于1823年提出。","appearance":"通常单独或成对出现，常见于路旁围栏上栖息，或低空掠地飞行。飞行时，其独特的翼纹引人注目：宽大的白色翼缘与翼中部明亮的锈色形成鲜明对比。在地面奔跑时，其姿态似鸫鸟。面部深色，翼板霜白，腹部呈现淡锈色。","habits":"栖息于温带草原，偏好开阔且风大的环境，如巴塔哥尼亚的草甸和灌木草原。冬季迁徙至南美的潘帕斯草原。","identification":"其独特的翼纹和腹部颜色使其易于与其他鸟类区分。飞行时白色翼缘与锈色翼面的对比尤其明显。","protection":"IUCN：LC（无危）","distribution":"分布于南美，从巴西东南部至火地群岛，繁殖季节在阿根廷南部、智利和火地群岛，冬季迁徙至阿根廷东部、乌拉圭和巴西东南部。"},{"name":"白腰蒙霸鹟","english_name":"White-rumped Monjita","scientific_name":"Xolmis velatus","overview":"白腰蒙霸鹟（英文名：White-rumped Monjita，学名：Xolmis velatus），是雀形目霸鹟科蒙霸鹟属的鸟类。主要分布于南美洲，包括巴西中部至玻利维亚和巴拉圭北部。","appearance":"体型较大的飞虫捕食者，栖息于接近水源、散落树木的草原地带。其下体与头部、臀部及上尾羽均为白色。背部呈灰色，翅膀深色而带有白色条带，尾部黑色。常以成对的形式出现，或在地面觅食，或栖息于灌木顶、围栏或电线上。","call":"通常保持沉默，鸣叫特征不详。","habits":"偏好栖息于干燥的草原及牧场环境。活动范围广泛，包括地面觅食及空中捕食。具体食物偏好及捕食者信息尚不明确。","breeding":"关于繁殖行为、筑巢、孵化及育雏的具体信息未详。","identification":"通过其独特的白色臀部、灰色背部、白色翼带及黑色尾部来区分于其他物种。与同属的差异及亚种间的辨识点尚需进一步研究。","protection":"IUCN状态未知。未列入华盛顿公约(CITES)附录或中国国家重点保护野生动物名录。","distribution":"分布于南美洲，具体包括巴西中部至东南部（从亚马逊河下游至马兰豪州，南至巴拉那州，偶见于圣卡塔琳娜州，向西延伸至马托格罗索州南部和马托格罗索杜苏尔州），玻利维亚北部及中部（从贝尼州东部至圣克鲁斯州），以及巴拉圭东北部。","other":"关于白腰蒙霸鹟的分类学地位、种群动态及其他生态学信息有待进一步研究。"},{"name":"白蒙霸鹟","english_name":"White Monjita","scientific_name":"Xolmis irupero","overview":"白蒙霸鹟（英文名：White Monjita，学名：Xolmis irupero），是雀形目霸鹟科蒙霸鹟属的鸟类。分布于南美洲东部及东南部，包括巴西的Caatinga和Pantanal地区，以及阿根廷、玻利维亚、巴拉圭和乌拉圭。这体型较大、引人注目的白色飞禽。","appearance":"成年雄性白蒙霸鹟全身几乎纯白，仅翼端和尾尖呈黑色，眼虹膜深褐色，喙和腿为黑色。雌鸟背部略带灰色。亚种niveus体型稍小，尾部黑带更宽。","call":"通常保持沉默。","habits":"栖息于开阔地带，如草地、牧场及散落树木的区域，常靠近水源，显眼地停栖。偏好亚热带或热带干旱灌木丛及严重退化的前森林地带。","identification":"与相似的黑白蒙霸鹟相比，其羽毛更为洁白。雄鸟纯白，雌鸟背部微灰，易于辨认。","protection":"IUCN状态未知。","distribution":"分布于南美洲东部及东南部，包括巴西的Caatinga和Pantanal地区，以及阿根廷、玻利维亚、巴拉圭和乌拉圭。"},{"name":"黑白蒙霸鹟","english_name":"Black-and-white Monjita","scientific_name":"Heteroxolmis dominicana","overview":"黑白蒙霸鹟（英文名：Black-and-white Monjita，学名：Heteroxolmis dominicana），是雀形目霸鹟科黑白蒙霸鹟属的鸟类。体型较大，身长约20.5厘米，具有修长的身躯和较长的尾巴。雄鸟主要呈白色，翅膀和尾巴为黑色；雌鸟头部和背部呈灰褐色，有明显的白色臀部和翼斑。分布于南美洲的巴西南部、阿根廷东北部和乌拉圭，可能也曾存在于巴拉圭。","appearance":"雄性黑白蒙霸鹟大部分为白色，头部和背部有淡灰色痕迹，翅膀黑色，初级飞羽外侧三分之一为白色；尾巴相对较长，全黑；虹膜深色，喙和腿均为黑色。雌鸟的冠部和背部为褐灰色，有突出的白色肩羽和臀部。幼鸟背部锈色。","call":"通常保持沉默，但在激动时会发出柔和而略带哀怨的“weeyrt”或“wurrt”叫声。","habits":"栖息于湿地和沼泽地带，包括灯心草（Cyperus和Eryngium）丛生的沼泽和新开垦或烧过的草地，偶尔出现在沿海沙丘的内陆一侧。常在邻近的草地上觅食，与橙头黑鹂群相伴，原因未知。海拔一般低于500米，偶尔可达1000米。全年居留，以昆虫为食。","breeding":"筑巢期在巴西东南部（Rio Grande do Sul）为10月至12月，在阿根廷为9月底至12月。巢由干草、粗茎和叶子构成，内部铺有细草、羽毛和羊毛，隐藏在低矮灌木丛中的小型沼泽植被内，或在草丛上。每窝产3-4枚卵，寄生者为紫辉牛鹂。","identification":"与白蒙霸鹟相比，黑白蒙霸鹟体型更大，颜色不那么纯白，翅膀上的黑色更多，尾巴全黑。雌鸟有灰褐色的冠部和背部，白色的肩羽和臀部明显。","protection":"IUCN：VU（易危）。稀少至罕见，分布非常局限。自1850年以来，其种群在其约12万平方公里的范围内经历了灾难性的下降，主要是由于自然草原的排水和农业转化，尤其是用于畜牧业。最近，非本地树种的造林开始取代更多的草原。受火灾破坏巢穴和紫辉牛鹂寄生的威胁。在乌拉圭东南部可能是当前的主栖息地，巴西的Arcos（Minas Gerais）、东南Santa Catarina和东北及东南Rio Grande do Sul，以及阿根廷的Corrientes和Entre Ríos仍相对常见。","distribution":"分布在巴西南部（Paraná、Santa Catarina、Rio Grande do Sul）、乌拉圭西部和阿根廷东北部（Corrientes、东Entre Ríos和东北Buenos Aires）。曾在Paraguay有未经证实的记录，过去分布更广泛。","other":"在多个国家公园和保护区中发现，如阿根廷的Chaco、Mburucuyá和El Palmar国家公园，San Juan de Poriahú和Campos del Tuyú私人保护区，Ribera Norte市政保护区；巴西的Aparados da Serra和São Joaquim国家公园；乌拉圭的Bañados del Este生物圈保护区和Laguna de Castillos、Potrerillo de Santa Teresa和Los Indios保护区。"},{"name":"纹喉丛霸鹟","english_name":"Streak-throated Bush Tyrant","scientific_name":"Myiotheretes striaticollis","overview":"纹喉丛霸鹟（英文名：Streak-throated Bush Tyrant，学名：Myiotheretes striaticollis），是雀形目霸鹟科鸫霸鹟属的鸟类。体型较大的霸鹟以其醒目的橙色腹部和黑白条纹的喉咙而易于识别，广泛分布于南美洲从委内瑞拉西部到阿根廷西北部的地区。","appearance":"纹喉丛霸鹟具有较为明显的外部特征，其橙色腹部和黑白色的喉咙条纹十分醒目。体型比烟色丛霸鹟大，喙部较粗壮。雌雄成鸟和幼鸟的具体羽毛颜色和大小变化尚未详细描述。","habits":"纹喉丛霸鹟通常栖息于开阔地带，常在森林边缘活动。它们以单独或成对的形式出现，有时甚至会停栖在电话线上。具体的食物类型、捕食者信息和活动范围有待进一步观察。","identification":"与烟色丛霸鹟相比，纹喉丛霸鹟体型更大，喙部更粗。此外，其独特的橙色腹部和黑白条纹的喉咙是与其它种类区分的关键特征。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，包括阿根廷、玻利维亚、哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉。在委内瑞拉西部至阿根廷西北部的地区尤为常见，栖息于亚热带或热带湿润山地森林、高海拔灌木丛以及严重退化的前森林区域。"},{"name":"哥伦比亚丛霸鹟","english_name":"Santa Marta Bush Tyrant","scientific_name":"Myiotheretes pernix","overview":"哥伦比亚丛霸鹟（英文名：Santa Marta Bush Tyrant，学名：Myiotheretes pernix），是雀形目霸鹟科鸫霸鹟属的鸟类。其体色深褐，翼部带有两道淡红褐色的翼纹，喉部有微弱的暗色条纹，下腹部呈现深红褐色。栖息于云雾森林的树冠层，为当地特有种。","appearance":"哥伦比亚丛霸鹟体型约为18至21厘米，拥有白色眉纹，上体呈深棕色，翅膀颜色更深，带有两道淡红褐色或肉桂色的翼纹，内侧飞羽边缘呈锈红色，尾部黑色，外侧尾羽边缘锈色或红棕色，喉部白色，狭窄而模糊的暗色条纹，下体深红褐色，胸部略带橄榄色。相较于纹喉丛霸鹟，体型较小，下体颜色更暗，尾部少有肉桂红褐色。雌雄外观相似。","call":"鸣叫特征为短而响亮的下降哨音，重复的\"weeuuu, heeuuu, heeuu\"，音调逐渐下降，可连续重复长达一分钟以上。","habits":"生活在圣玛尔塔山脉的高山森林边缘，海拔高度通常在2100至3300米之间，偶尔可达3580米。通常独居或成对出现，偶尔加入混合种类的鸟群。以昆虫为食，常从灌木或小树顶部长距离飞扑捕食，有时在树冠内部进行飞扑。","breeding":"繁殖信息未知。","identification":"与更广泛的纹喉丛霸鹟相比，喉部条纹不明显且覆盖范围较小，尾部下方基部无肉桂色，鸣叫声更短、更清晰且音调下降更多。","protection":"IUCN：EN（濒危）","distribution":"分布于哥伦比亚北部圣玛尔塔山脉，主要在埃尔多拉多自然保护区的较高区域。"},{"name":"烟色丛霸鹟","english_name":"Smoky Bush Tyrant","scientific_name":"Myiotheretes fumigatus","overview":"烟色丛霸鹟（英文名：Smoky Bush Tyrant，学名：Myiotheretes fumigatus），是雀形目霸鹟科鸫霸鹟属的中等体型鸟类。主要分布于南美洲北部的安第斯山脉区域，自委内瑞拉至秘鲁，栖息于亚热带或热带湿润山地森林。","appearance":"烟色丛霸鹟全身几乎呈巧克力棕色，拥有略淡的眼眉纹和翼带，飞行时可见显眼的肉桂色下翼。雌雄外观相似，无显著差异。其大小介于中等，具体尺寸数据未详述。","habits":"通常单独活动于森林及边缘地带的中上层，高度位于海拔2,000至3,400米之间。有时会明显地停栖。","breeding":"在哥伦比亚，繁殖期为7月至8月，在Sierra de Perijá及北、东安第斯山脉，以及11月在Cundinamarca。筑巢于离地面约2米高的枯木侧边，巢由树蕨鳞片、小枝条和彩色羽毛构成，内衬以树蕨(Cyathea spp.)鳞片为主。每窝产两枚蛋，蛋色以白色为主，散布着少量巧克力棕色斑点，主要集中在大端，尺寸约为24.0 x 18.0毫米和23.0 x 17.5毫米，重量分别为3.6克和3.5克。幼鸟成长期大约为16至17天。","identification":"与纹喉丛霸鹟的区别在于后者具有橙色腹部和喉部条纹。","distribution":"分布于南美，从委内瑞拉西部至秘鲁，覆盖哥伦比亚、厄瓜多尔等地的安第斯山脉。"},{"name":"棕腹丛霸鹟","english_name":"Rufous-bellied Bush Tyrant","scientific_name":"Myiotheretes fuscorufus","overview":"棕腹丛霸鹟（英文名：Rufous-bellied Bush Tyrant，学名：Myiotheretes fuscorufus），是雀形目霸鹟科鸫霸鹟属的鸟类。分布于南美安第斯山脉的东部地带，包括秘鲁南部和玻利维亚西部的高海拔森林区域。该物种在海拔1900至2900米的山地森林和边缘地带活动，较为少见，其自然历史信息尚不充分。","appearance":"成年棕腹丛霸鹟的上体呈棕色，头部具有灰白色的眉纹，翅膀黑色带有两道醒目的红褐色翼斑，内侧飞羽边缘红褐色，下体则为暖色调的红褐色，喉部颜色较浅。雄雌外观相似，而幼鸟的描述目前尚未有详细的记录。","call":"其鸣叫声为一系列短促的弹跳音节，随后是一个突出的结束音符，表现为‘pip-pip-pip, pi-PEW’的模式。","habits":"棕腹丛霸鹟通常单独或成对出现，偏好高海拔的山地森林环境，以昆虫为食，具体生活习性和迁徙行为仍需更多研究。","breeding":"关于棕腹丛霸鹟的繁殖习性，目前资料有限，尚不清楚其具体的繁殖季节、筑巢、产卵等细节。","identification":"与区域内其他霸鹟种类相比，棕腹丛霸鹟在休息时翅膀上可见明显的红褐色，这是其显著的识别特征。与之共存的烟色丛霸鹟全身偏暗棕色，纹喉丛霸鹟体型更大，喉部更白且胸部条纹更为明显，峭壁霸鹟下方羽毛颜色更深，面部有白色霜状斑点，且无红褐色翼斑。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于南美安第斯山脉的秘鲁南部和玻利维亚西部，具体分布在海拔1900至2900米的山地森林。"},{"name":"红腰丛霸鹟","english_name":"Red-rumped Bush Tyrant","scientific_name":"Cnemarchus erythropygius","overview":"红腰丛霸鹟（英文名：Red-rumped Bush Tyrant，学名：Cnemarchus erythropygius），是雀形目霸鹟科红腰丛霸鹟属的独特鸟类。显著特征为灰胸和橙红色腹部，以及明显的白色翼斑。分布于南美洲安第斯山脉，自哥伦比亚北部至玻利维亚中部，栖息于海拔2850至4300米的高山地带。","appearance":"成年红腰丛霸鹟体长约23厘米，头部前冠呈白色，后冠灰色，背部和翅膀为暗灰色，尾部橙红色，尤其在飞行时尤为明显。胸部为灰褐色，腹部则为鲜艳的橙红色。翼上有两道白色条纹，嘴喙细长，脚和趾黑色。","call":"发出尖锐的哨声，可在远距离听到。","habits":"偏好开放的山地环境，常在树梢、电线杆等高处显眼位置停留，从这些位置出击捕食昆虫。分布于南美山地，包括哥伦比亚、厄瓜多尔、秘鲁和玻利维亚的山地。","identification":"红腰丛霸鹟的独特羽色组合使其易于辨认，尤其是橙红色腰部和尾部，以及白色翼斑。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的山地地区，从哥伦比亚北部到玻利维亚中部，常见于安第斯山脉。","other":"红腰丛霸鹟因其独特的分布和鲜明的外观，成为其所在区域的标志性物种之一。"},{"name":"丛霸鹟","english_name":"Rufous-webbed Bush Tyrant","scientific_name":"Cnemarchus rufipennis","overview":"丛霸鹟（英文名：Rufous-webbed Bush Tyrant，学名：Cnemarchus rufipennis），是雀形目霸鹟科红腰丛霸鹟属的鸟类。主要栖息地包括阿根廷、玻利维亚和秘鲁，偶尔在智利也有记录。其最显著的特征是灰白色的腹部和隐藏在休息时、但在飞行中显眼的红棕色翅膀和尾羽。","appearance":"丛霸鹟是一种体型较大的灰色霸鹟，体羽呈现灰褐色，腹部白色。飞行时，其翅膀和尾羽的红棕色斑纹尤为突出，这是它得名的由来。常单独或成对出现，站立时姿态挺直。","call":"它的叫声是一种微弱而尖锐的‘tree’哨音。","habits":"偏好栖息于高处的灌木顶、枯木或岩石上，以俯冲的方式捕捉猎物，有时会悬停在空中。其自然栖息地主要是亚热带或热带湿润的山地森林和高海拔的灌木地带。","identification":"与其他霸鹟科鸟类相比，丛霸鹟的红棕色翅膀和尾羽是其独特的辨识特征。","distribution":"丛霸鹟分布于南美，自秘鲁至阿根廷西北部，偶尔出现在智利。"},{"name":"飘带尾霸鹟","english_name":"Streamer-tailed Tyrant","scientific_name":"Gubernetes yetapa","overview":"飘带尾霸鹟（英文名：Streamer-tailed Tyrant，学名：Gubernetes yetapa），是雀形目霸鹟科飘带尾霸鹟属的鸟类。分布于南美洲的玻利维亚北部、东部以及巴西中部至阿根廷东北部。其最显著的特征是长长的深叉尾羽，全身灰白色调，具有黑色半颈环和眼纹，翅膀上有一块肉桂色斑块。雌鸟个体相较于雄鸟尾部稍短。此鸟种常见于棕榈林、湿地和水边的草甸。","appearance":"体长约35-38厘米，尾部展开可达42厘米。雄鸟拥有浅灰色的前额和眉线，上身主要是淡灰色带有暗棕色的羽轴条纹；翅膀呈黑褐色，基部有一块肉桂红棕色斑块，在飞行中形成显眼的条纹；尾部长而渐尖，深叉状，黑色；喉咙白色，颈部侧面和胸部上方有鲜明的深栗色胸环；胸部和两侧淡灰色，腹部逐渐变为白色。雌鸟体型较小，尾巴略短，颜色略显暗淡。幼鸟色泽更暗淡，背部有棕色斑点，尾巴明显较短。","call":"发出尖锐而悦耳的‘djewp’叫声，其鸣唱表演中，会欢快地上下摆动头部，同时举起尾巴，展开翅膀，发出响亮的‘wurreep’声，重复多次；还有下降音阶的2或3个音符‘jew-jew-jew’；早晨有特定的鸣唱。","habits":"通常成对或小家庭群出现，栖息于灌木丛顶和低矮树木顶端，常位于林缘地带。以昆虫为食，会远距离出击捕捉猎物，尾巴在飞行中鞭打。在沼泽地带低空捕食，偶尔会扑向地面或俯冲到植被中捕捉大型昆虫。","breeding":"繁殖期大约在10月至次年1月，筑巢于离地82厘米高的Saccharum草丛中，巢呈杯状，直径15厘米，高10.5厘米，深6.5厘米，内部铺有细根、草茎和蛇皮。每窝产3枚全白椭圆形蛋，平均重8.9克。","identification":"飘带尾霸鹟的长而深叉的尾羽和独特的叫声是辨识关键。雌雄差异在于雄鸟的尾羽更长。","protection":"IUCN：LC（无危）","distribution":"分布于南美地区的玻利维亚北部（上贝尼河）、巴西南部（马托格罗索州、巴伊亚州南部至里奥格兰德杜苏尔州西部）、巴拉圭东部以及阿根廷东北部（查科、科连特斯、米西奥内斯）。","other":"在一些国家公园和自然保护区较为常见，如玻利维亚的贝尼生物圈保护区、巴拉圭的圣拉斐尔、圣路易斯和伊比库伊国家公园以及巴西的帕特里莫尼奥纳图拉尔多卡拉卡、巴西利亚和塞拉达卡纳斯特拉国家公园。"},{"name":"剪尾灰霸鹟","english_name":"Shear-tailed Grey Tyrant","scientific_name":"Muscipipra vetula","overview":"剪尾灰霸鹟（英文名：Shear-tailed Grey Tyrant，学名：Muscipipra vetula），是雀形目霸鹟科剪尾灰霸鹟属的唯一物种。这种大型黑灰色霸鹟拥有长而分叉的尾巴，活跃于南美洲巴西东南部、巴拉圭东部及阿根廷东北部的山林边缘。其自然栖息地包括亚热带或热带湿润低地森林、湿润山地森林及重度退化的前森林地带。","appearance":"剪尾灰霸鹟的体型较大，主要呈黑灰色调，尾部长而呈明显的叉状。身体大部分为灰色，面罩略显暗淡，翅膀和尾巴颜色深邃。雌雄及幼鸟的羽毛特征相似，但具体细节随年龄略有变化。","call":"通常保持沉默，偶尔会发出低沉的‘puupi-puupi’音节，这成为其特有的声音标记。","habits":"剪尾灰霸鹟在树冠层活动，偏好山地森林边缘和次生林环境。它们的活动范围广泛，包括亚热带或热带湿润森林。飞行技巧高超，以空中捕食为主，食物主要包括昆虫。","breeding":"关于剪尾灰霸鹟的繁殖习性的详细信息较少，但一般而言，霸鹟科的鸟类会在特定季节营巢繁殖，通过精心选择的巢址进行交配、产卵和育雏。","identification":"剪尾灰霸鹟最显著的辨识特征是其长而分叉的尾巴，以及在山地森林边缘活动的生活习性。与其他同属物种相比，这一特征极为突出。","protection":"IUCN：LC（无危）","distribution":"剪尾灰霸鹟的分布区域集中在南美洲的巴西东南部至巴拉圭东部和阿根廷东北部。具体包括巴西的巴伊亚南部、米纳斯吉拉斯中部、埃斯皮里托圣多南部至里奥格兰德杜苏尔，以及巴拉圭东部和阿根廷的米西奥内斯和科连特斯省。","other":"剪尾灰霸鹟于1823年被首次科学命名，自那时起，它就被持续关注并收录于《世界自然保护联盟》鸟类名录中。"},{"name":"斑水霸鹟","english_name":"Pied Water Tyrant","scientific_name":"Fluvicola pica","overview":"斑水霸鹟（英文名：Pied Water Tyrant，学名：Fluvicola pica），是雀形目霸鹟科水霸鹟属的小型鸟类。以黑白相间的羽毛和独特的叫声著称，主要分布于热带南美洲，自巴拿马至玻利维亚一带。在历史上，曾被法国博物学家乔治·路易·勒克莱克首次描述。","appearance":"斑水霸鹟体长约13.5厘米，体重约13克。成鸟主体白色，具有黑色的颈背、翅膀和尾巴。两性相似，雌鸟背部可能略带棕色，幼鸟的黑色部分呈棕色。鼻音叫声为djweeooo。","call":"其鸣叫声为鼻音的djweeooo。","habits":"栖息于沼泽草原和红树林边缘。它们常在低矮的水域植被中寻找昆虫作为主要食物。飞行时有上上下下的摆动，展示出类似蝴蝶的飞翔姿态。","breeding":"巢穴为草和其他植物材料编织的卵形球体，内衬羽毛，侧面有入口，通常建在靠近水面的树枝末端。每次繁殖产两到三个带有少量褐色斑点的奶油色蛋，由两性共同孵化。","identification":"斑水霸鹟的黑白相间羽毛和独特的叫声帮助区分于其他水霸鹟种类。雌鸟的背部可能带有些许棕色。","protection":"IUCN：LC（无全球性威胁）。在某些地区相当常见，甚至可能缓慢扩大其分布范围，例如在巴拿马等地。在哥伦比亚的Tinigua国家公园中也有分布。","distribution":"分布于中美洲和南美洲，从巴拿马至圭亚那和巴西北部，包括特立尼达岛。在哥伦比亚、委内瑞拉、圭亚那、苏里南、法属圭亚那和巴西北部均有记录。","other":"斑水霸鹟的巢穴有时会被寄生鸟如牛鹂所占据。"},{"name":"黑背水霸鹟","english_name":"Black-backed Water Tyrant","scientific_name":"Fluvicola albiventer","overview":"黑背水霸鹟（英文名：Black-backed Water Tyrant，学名：Fluvicola albiventer），是雀形目霸鹟科水霸鹟属的鸟类。主要分布在南美洲的巴西、玻利维亚、巴拉圭、阿根廷北部和乌拉圭西部，以及秘鲁东部。以独特的黑白相间羽毛而引人注目。","appearance":"该鸟体型中等，腹部和脸部主要为白色，与黑色的冠羽和背部形成鲜明对比。拥有白色的臀部和两条明显的白色翼带。尾巴经常从一侧到另一侧明显摆动。","call":"其鸣叫声为尖锐而短暂的‘tic’声。","habits":"常在湿地、湖泊和河流附近地面行走，栖息于沼泽地带。繁殖季节在亚马逊盆地东南部，非繁殖季节会迁移到亚马逊地区的东部秘鲁和北部玻利维亚。","breeding":"具体繁殖信息未详述。","identification":"其黑白分明的体色和独特的尾部摆动动作有助于与其他相似物种区分开来。","protection":"IUCN：LC（无危）","distribution":"在南美洲的巴西（包括亚马逊河下游地区）、玻利维亚东部、巴拉圭、阿根廷北部（至La Rioja、Santa Fe和Buenos Aires）、乌拉圭西部以及秘鲁东部有分布。非繁殖季节也会出现在亚马逊地区的秘鲁东部和玻利维亚北部。","other":"属于《世界自然保护联盟》保护的鸟类之一。"},{"name":"花脸水霸鹟","english_name":"Masked Water Tyrant","scientific_name":"Fluvicola nengeta","overview":"花脸水霸鹟（英文名：Masked Water Tyrant，学名：Fluvicola nengeta），是雀形目霸鹟科水霸鹟属的鸟类。常见于近水地带，甚至在城市区域也能发现其踪迹，表现得相当温顺。最显著的特征是黑色的眼纹和翅膀，与淡色的腹部、头部和背部形成鲜明对比。","appearance":"花脸水霸鹟长约14.5至15厘米，羽毛主要为白色，黑色眼纹与翅膀对比明显，尾巴黑色而尖端白色；背部略带灰褐色；眼睛深色，喙和腿均为黑色。雄鸟和雌鸟外观相似，亚种atripennis的翅膀更黑，三级飞羽边缘白色。","call":"叫声为尖锐响亮的‘kirt！’，飞行时常发出。","habits":"偏好低地半开放的灌木丛生区，靠近淡水，尤其在沼泽地带和稻田附近；也沿河岸、池塘和溪流边活动；偶尔在相邻的开阔地带出现。主要生活在海拔300米以下，局部可达800米，罕见至1300米。以昆虫为食，单独或成对活动，通常显得温顺且显眼；在地面或接近地面的地方觅食，会在漂浮的植被上奔跑；做短暂的空中突袭，快速冲向水面边缘的昆虫。","breeding":"繁殖习性了解不多。展示行为中，鸟儿面对面站立，展开并上下摆动尾巴；雄鸟有时会张开尾巴和翅膀展示黑色的下表面。巢由杂乱的草和茎构成，侧面有入口。一窝产3枚蛋（n=2）；蛋壳白色，带有棕色斑点；仅雌鸟孵卵；孵化期15天。雏鸟由两性共同喂养。一项研究显示，在巴西乌贝兰迪亚市的公园中，7个巢中有3个成功孵化。","identification":"花脸水霸鹟的独特之处在于其黑色眼纹和翅膀，与白色身体形成鲜明对比，以及其尖锐的‘kirt！’叫声。","protection":"IUCN：LC（无危）。相对常见，似乎因森林砍伐而在巴西南部扩散；自1950年代以来，在多个新地点被记录到（例如里约热内卢植物园和动物园、卡特特宫花园和塞南贝蒂巴、马拉姆拜亚等地）。能适应转化的生境，拥有较大分布范围，其中许多国家公园和其他保护区都有其身影。","distribution":"主要分布在南美洲，包括巴西东部和东南部的caatinga和极端东部的cerrado，以及大西洋沿海地区；在南美洲太平洋一侧的厄瓜多尔西部和秘鲁西北部也有较小的分离分布区。自然栖息地为亚热带或热带红树林、湿润灌木林和重度退化的前森林。"},{"name":"白头沼泽霸鹟","english_name":"White-headed Marsh Tyrant","scientific_name":"Arundinicola leucocephala","overview":"白头沼泽霸鹟（英文名：White-headed Marsh Tyrant，学名：Arundinicola leucocephala），是雀形目霸鹟科白头沼泽霸鹟属的鸟类。小型的霸鹟科鸟类，属于Arundinicola属的唯一物种。分布于南美洲热带地区，自哥伦比亚、委内瑞拉和特立尼达岛向南延伸至玻利维亚、阿根廷和巴拉圭。","appearance":"成年白头沼泽霸鹟体长约12.7厘米，体重约15克。雄鸟全身几乎全为棕色至黑色，仅头部及喉部为白色，下颚基部呈黄色。雌鸟上体和翅膀为褐色，尾巴黑色，下体、头部两侧及前额为淡白色。该鸟较为安静。","call":"通常保持沉默，偶尔会发出尖锐的'sedik！'声；在求偶飞行时会重复低沉的'dew-de-lewde'声。","habits":"栖息于湿地草原、芦苇丛和红树林边缘地带，通常在500米以下高度活动。以昆虫为主食，常在水边的显眼枝头等待，短暂飞扑捕捉猎物后立即返回高处栖息。很少像Fluvicola属那样降落地面。","breeding":"繁殖期在委内瑞拉为6月至11月，在特立尼达岛为1月至4月及7月至10月，在哥伦比亚为1月至3月，在巴西为10月至2月，在阿根廷为10月至1月。营巢由两性共同完成，巢为草球状，侧面有入口，隐蔽于灌木或水边的芦苇近顶处，离水面较低。每窝产卵2至4枚，两性共同孵卵和喂养雏鸟，巢寄生现象常见于紫辉牛鹂。","identification":"雄性白头沼泽霸鹟的独特黑白对比羽毛和白色的头部使其容易识别；雌鸟则需通过其灰褐色上体和白色下体与其它类似物种区分。","protection":"IUCN：LC（无危）","distribution":"南美洲广泛分布，北至哥伦比亚、委内瑞拉和特立尼达岛，南至玻利维亚、阿根廷和巴拉圭，东至圭亚那。","other":"虽然局部地区可能因生境退化导致种群数量下降，但总体上该物种不在全球威胁名单之列。"},{"name":"鸡尾霸鹟","english_name":"Cock-tailed Tyrant","scientific_name":"Alectrurus tricolor","overview":"鸡尾霸鹟（英文名：Cock-tailed Tyrant，学名：Alectrurus tricolor），是雀形目霸鹟科异尾霸鹟属的珍稀鸟类。其显著特征为雄鸟黑色上身与白色下身，搭配扇形展开的奇特长尾，而雌鸟则呈斑驳棕色。分布于南美洲北部玻利维亚、巴西东南部、巴拉圭及阿根廷的部分地区。","appearance":"雄性鸡尾霸鹟在繁殖季节可达19厘米，通常体长约12厘米。雄鸟头部至背部黑色，翼上覆羽灰，肩部及次级飞羽白色斑点，尾部中央羽毛异常长，垂直并扇形展开，下身大部分白色，胸部两侧有黑色斑块形成半环状项圈。雌鸟上身斑驳棕色，下身白色或淡黄色，尾部正常且较短。幼鸟外观类似雌鸟。","call":"鸡尾霸鹟大多沉默，少有声音记录。","habits":"栖息于开阔、湿润的高草草原地带，偏好保存完好的环境。群体生活，即使在繁殖季节亦如此。捕食时通过空中捕猎、掠夺草丛或灌木上的昆虫。飞行时翅膀拍打发出嗡嗡声。","breeding":"繁殖期大致在8月至11月，受雨季影响。雄鸟展示时会缓慢升空至5至100米，快速振动翅膀并交替调整尾部姿态。巢为精致的草杯状，隐蔽于地面附近。具体繁殖细节未知。","identification":"雄鸟的特异尾羽形态和黑白对比色是其独特标识，与雌鸟及其它霸鹟科物种明显不同。","protection":"IUCN：VU（易危）","distribution":"分布于南美洲北部玻利维亚、巴西东南部（从马托格罗索州东至米纳斯吉拉斯州，南至巴拉那州）、巴拉圭东部以及阿根廷部分地区。","other":"鸡尾霸鹟面临栖息地丧失的威胁，仅在未受干扰的草地上保持常见，如巴西的Gama-Cabeça de Veado环境保护区、São Miguel野生动物保护区、Emas和Serra da Canastra国家公园等地。"},{"name":"异尾霸鹟","english_name":"Strange-tailed Tyrant","scientific_name":"Alectrurus risora","overview":"异尾霸鹟（英文名：Strange-tailed Tyrant，学名：Alectrurus risora），是雀形目霸鹟科异尾霸鹟属的鸟类。以雄鸟在空中展示其独特尾羽的壮观求偶行为而闻名，这种行为包括雄鸟飞升至高空并反复摆动尾巴。该物种是阿根廷东北部和巴拉圭东部伊贝拉湿地的特有种，偏好未受干扰的高草丛生的泛洪草地。","appearance":"雄鸟在求偶展示中的尾羽摆动极其引人注目，雌鸟可通过其橙色喉部、淡桃色喙和细长尾羽与其它白色霸鹟区分开来。由于缺乏具体描述，体型、羽毛颜色及变化细节未详。","call":"无具体描述。","habits":"异尾霸鹟栖息于泛洪草地，尤其是未受干扰的高草丛生地带，偏好未被牛群放牧的环境。它们在高草中筑巢，巢穴通常位于地面或接近地面的位置。","breeding":"繁殖期在9月至12月间。雌鸟负责筑巢、孵化和喂养幼鸟，巢为开放式的草杯，内部铺垫羽毛，通常建在高草中，离地面约30厘米。每窝产三枚洁白无瑕的蛋，平均孵化期为16至18天。刚孵化的幼鸟体重约2.8克，皮肤呈橙色，头部、背部和腹部覆盖着浓密的绒毛，嘴部橙色带黄色边缘。巢中幼鸟的存活期约为12至14天。","identification":"雄鸟在求偶飞行中展示的独特尾羽摆动是与其他种类区别的关键特征。雌鸟的橙色喉部、淡桃色喙和细长尾羽有助于与相似物种的识别。","protection":"IUCN：VU（易危）","distribution":"主要分布于南美洲巴拉圭南部、阿根廷东北部和乌拉圭，以及巴西南部的几个分散地点。","other":"异尾霸鹟因栖息地丧失而受到威胁，除伊贝拉湿地偶尔可见外，其分布范围已大幅缩减。"},{"name":"通贝斯唧霸鹟","english_name":"Tumbes Tyrant","scientific_name":"Tumbezia salvini","overview":"通贝斯唧霸鹟（英文名：Tumbes Tyrant，学名：Tumbezia salvini），是雀形目霸鹟科通贝斯唧霸鹟属的鸟类。它是一种美丽的小型鵙鸟，主要分布在秘鲁西北部，并刚刚越过边境进入厄瓜多尔西南端。通贝斯唧霸鹟具有独特的羽毛色彩，包括黑色面罩、黄色眉纹和白色翼带。","appearance":"通贝斯唧霸鹟长约13.5厘米。冠羽、眼周和耳羽呈深灰色；有醒目的黄色额带和眉纹，向颈背逐渐变淡至接近白色；背部通常为灰色或灰橄榄色；翅膀为深黑色，带有两道宽阔的白色翼带，次级飞羽和三级飞羽边缘为白色；尾羽深黑，外侧尾羽边缘为白色；喉咙和下体全部为柠檬黄色；虹膜深棕色；喙短而黑；腿也是黑色。雄鸟和雌鸟外观相似。","call":"通贝斯唧霸鹟的叫声包括柔和的哨声和急促的颤音。","habits":"通贝斯唧霸鹟栖息在干燥的林地中，尤其是金合欢（Acacia）或刺槐（Prosopis）林中，经常靠近干涸的河道。它们通常生活在低地，偶尔也会出现在海拔高达1,000米的地方。这种鸟通常以昆虫为食，常成对出现，性格较为亲近人类。它们常在中层树冠停留，有时会摆动尾巴，像树栖鹡鸰一样展开尾巴。","identification":"通贝斯唧霸鹟在其分布范围内几乎不会被误认；其下体和眉纹为黄色，上体主要为灰色到橄榄绿色，具有两条白色翼带，尾巴大部分为深色，两侧有窄的白色边线。","protection":"IUCN: NT（近危）","distribution":"通贝斯唧霸鹟主要分布在秘鲁西北部，从通贝斯向南至拉利伯塔德省；最近在厄瓜多尔西南极端地区也有发现。","other":"最初认为是秘鲁西北部的特有种，但最近的研究表明，通贝斯唧霸鹟可能属于Ochthoeca属而非单独的Tumbezia属。"},{"name":"冠唧霸鹟","english_name":"Crowned Chat-Tyrant","scientific_name":"Silvicultrix frontalis","overview":"冠唧霸鹟（英文名：Crowned Chat-Tyrant，学名：Silvicultrix frontalis），是雀形目霸鹟科黄眉姬霸鹟属的鸟类。南美洲西北部特有，分布于哥伦比亚至玻利维安的安第斯山脉沿线，偏好接近林线的矮树森林环境，如Polylepis林区。该物种具有独特的外观特征，背部呈棕色，翅膀黑色，眉纹白色带黄色，喉部白色，下体灰色，两胁和臀部红褐色。","appearance":"冠唧霸鹟体长约12.5至13厘米。雄鸟指名亚种头顶深棕色，前额带明亮黄色，眉纹向头部后方逐渐变为白色；背部暗棕色，翅膀和尾巴暗色，边缘略带暗棕色；喉部灰白色，腹部下方深灰色，下腹部转为灰白色，臀部和两胁红褐色或红棕色；虹膜深色；喙和腿均为黑色。雌鸟头顶较淡，下体更多呈现红棕色。幼鸟整体更鲜艳，两胁和腹部带有棕色调，眉纹略带黄白色，翅膀上有黄白色的条纹。albidiadema亚种前额和眉纹全白；boliviana亚种背部更灰，臀部白色，通常有一到两条红棕色的翼条；spodionota亚种类似前者但眉纹较短。","call":"通常保持沉默；偶尔发出细而高亢的下降颤音，‘te-tirrrrrrrrrrr’，常常持续数秒。","habits":"昆虫。通常单独行动，很少加入混合物种群。它非常隐蔽，容易被忽视，常在灌木丛中低处栖息。它会飞向树叶和树枝捕捉飞行中的昆虫；经常飞向长满苔藓的树枝而非树叶。","breeding":"在哥伦比亚九月份发现幼鸟，玻利维亚一月份发现幼鸟（科恰班巴）；厄瓜多尔西北部四月份发现幼鸟，秘鲁（Huánuco）十一月份发现幼鸟。巢为开放式的杯状，放置在悬崖洞穴、河岸根部突出处、Espeletia灌木或灌木丛中。没有其他信息。","identification":"与金眉唧霸鹟的区别在于眉纹更白，没有翼斑；与杰氏唧霸鹟的区别在于缺乏红棕色的翼斑。雌鸟头顶颜色较轻，下体更多红棕色。幼鸟整体色彩更鲜亮，两侧和腹部有棕色调，眉纹略带黄白色，翅膀上有黄白色的条纹。","protection":"IUCN: LC（无危）","distribution":"分布于哥伦比亚北部至昆迪纳马卡的安第斯山脉东部；哥伦比亚西部和中部安第斯山脉，厄瓜多尔（两侧）和秘鲁西北部（至La Libertad）。秘鲁中部的Junín，库斯科西部（位于Vilcabamba山脉）及邻近的Ayacucho东北部；秘鲁中部和南部（从San Martín至Huánuco，及库斯科南部的Urubamba山谷）和玻利维亚（从拉巴斯东南至圣克鲁斯西部）。","other":"历史上曾被认为是包含杰氏唧霸鹟和金眉唧霸鹟。北部和南部的亚种形成两个差异显著的群体，可能代表不同的物种。"},{"name":"秘鲁唧霸鹟","english_name":"Kalinowski's Chat-Tyrant","scientific_name":"Silvicultrix spodionota","overview":"秘鲁唧霸鹟（英文名：Kalinowski's Chat-Tyrant，学名：Silvicultrix spodionota），是雀形目霸鹟科黄眉姬霸鹟属的鸟类。主要分布在南美洲的秘鲁和玻利维亚。其自然栖息地为亚热带或热带湿润山地森林。此鸟种曾被认为是冠唧霸鹟的一个亚种，以采集者Jan Kalinowski命名。","appearance":"参照冠唧霸鹟。boliviana亚种上部较灰，尾下覆羽为白色，通常有一到两条红褐色的翅斑；spo­dionota亚种与前者相似，但眉纹较短。","protection":"IUCN状态未知。","distribution":"秘鲁和玻利维亚为主要分布区域，主要栖息在南美的亚热带或热带湿润山地森林。"},{"name":"金眉唧霸鹟","english_name":"Golden-browed Chat-Tyrant","scientific_name":"Silvicultrix pulchella","overview":"金眉唧霸鹟（英文名：Golden-browed Chat-Tyrant，学名：Silvicultrix pulchella），是雀形目霸鹟科黄眉姬霸鹟属的鸟类。生活在南美洲，主要栖息在秘鲁和玻利维亚的Yungas地区的亚热带或热带湿润山地森林中。","appearance":"体型较小，外表吸引人，常见于安第斯山脉东坡的湿润森林中。其最显著的特征是厚实的黄色眉毛，从喙基部延伸至眼后逐渐变为白色，同时具有醒目的锈色翼纹。与冠唧霸鹟的翼纹种族相似，但白色部分的眉毛更短更细。与杰氏唧霸鹟极为相像，但黄色部分略大，不过两者分布区域并不重叠。","call":"典型的鸣声是一串高亢快速的颤音，音调先短暂上扬后稳定下降。","habits":"栖息于森林下层，若非鸣叫时较难察觉。偏好生活在亚热带或热带湿润的山地森林环境中。","identification":"与冠唧霸鹟和杰氏唧霸鹟相比，主要通过眉毛的颜色和形状进行区分，尤其在黄色和白色部分的区别上。","distribution":"分布于南美洲的秘鲁和玻利维亚，主要栖息地为亚热带或热带湿润山地森林。"},{"name":"黄腹唧霸鹟","english_name":"Yellow-bellied Chat-Tyrant","scientific_name":"Silvicultrix diadema","overview":"黄腹唧霸鹟（英文名：Yellow-bellied Chat-Tyrant，学名：Silvicultrix diadema），是雀形目霸鹟科黄眉姬霸鹟属的鸟类。由Hartlaub于1843年命名。主要分布在南美洲，包括哥伦比亚、厄瓜多尔、秘鲁北部等地。这小型飞禽，常见于安第斯山脉的亚热带和温带地带。","appearance":"该鸟长约12.2厘米，体态圆胖，喙短而细。羽毛主要呈暗橄榄色，冠部颜色更深。前额为赭黄色，并延伸成一条狭窄的黄色眉纹。翅膀和尾巴呈灰褐色，腹部和下尾覆羽亮黄色，翼上有两道赤褐色条纹和边缘。","call":"清晨时，其歌声快速、纤细且精致，略有上升趋势，类似手指沿梳子滑动的声音。白天的鸣唱是一段长而嗡嗡的颤音，中间略低沉，结尾上升。还有一种更长的版本，先是缓缓上升，然后在结尾处稍微下降。此外，它还有一种冲突叫声，先逐渐升高，紧接着是缓慢下降的颤音，反复出现，伴有尖锐的争斗声。","habits":"黄腹唧霸鹟偏好生活在亚热带和热带湿润的山地森林及云雾林中，海拔高度通常在1,900至2,300米之间，偶尔可达1,700至3,100米。它们常隐藏在密集的山区灌木丛中，单独或成对活动，以昆虫为食，采用跳跃和突袭的方式在植被中捕猎。","breeding":"繁殖期在哥伦比亚从1月到10月，在厄瓜多尔从3月到12月。它们不迁徙，属于留鸟。筑巢于河岸，巢为苔藓球状，通常含4枚乳白色蛋。","identification":"黄腹唧霸鹟是唯一一种外观主要呈黄色的chat-tyrant，腹部和喉部尤其明亮。可以通过其独特的黄色腹部和长长的黄色眉纹加以辨认，翼上的赤褐色条纹也是其显著特征。","protection":"IUCN：LC（无危）","distribution":"黄腹唧霸鹟主要分布在南美洲的哥伦比亚至秘鲁北部，常见于安第斯山脉的亚热带和温带地带。"},{"name":"杰氏唧霸鹟","english_name":"Jelski's Chat-Tyrant","scientific_name":"Silvicultrix jelskii","overview":"杰氏唧霸鹟（英文名：Jelski's Chat-Tyrant，学名：Silvicultrix jelskii），是雀形目霸鹟科黄眉姬霸鹟属的小型鸟类。主要分布在南美洲的秘鲁和厄瓜多尔南部安第斯山脉地区，其自然栖息地为亚热带或热带湿润山地森林。","appearance":"雄性杰氏唧霸鹟体长约12至12.5厘米，头部呈黑褐色，前额黄色，具明显白色眉纹；背部较头部更红棕色，翅膀暗色，具有两条明显的红棕色翼带；尾巴暗色或棕色；下体灰色，腹部偏白略带淡红棕色，臀部淡黄色；虹膜深色；喙和腿黑色。雌鸟下体更偏黄白色，尤其是下腹部分。","call":"通常较为安静，叫声为高音且尖锐的‘tseeeee’声，有时会变化为‘tseee-krrrr’或‘tse-tsirrekerrr’。","habits":"杰氏唧霸鹟主要以昆虫为食，通常单独活动，偶尔跟随混合物种的鸟群。它们常从低矮的植被或地面突飞出来捕食。","identification":"与冠唧霸鹟相比，杰氏唧霸鹟具有明显的红棕色翼带，上体颜色更偏向棕色，下体颜色更浅灰；与金眉唧霸鹟的区别在于眉纹为白色而非黄色。","distribution":"分布于南美洲的厄瓜多尔西南部和秘鲁西北部。"},{"name":"灰背唧霸鹟","english_name":"Slaty-backed Chat-Tyrant","scientific_name":"Ochthoeca cinnamomeiventris","overview":"灰背唧霸鹟（英文名：Slaty-backed Chat-Tyrant，学名：Ochthoeca cinnamomeiventris），是雀形目霸鹟科唧霸鹟属的鸟类。是南美洲特有。广泛分布于委内瑞拉西南部至秘鲁北部的安第斯山脉云雾森林中，以其独特的白眉和灰栗色羽毛著称。","appearance":"这是一种体型较小而吸引人的霸鹟，其显著特征是明亮的白色眉毛，如同黑暗森林中的车头灯。羽毛以灰色为主，腹部呈温暖的栗色，雌雄成鸟的羽毛颜色基本一致，幼鸟的色彩较为暗淡。","call":"灰背唧霸鹟常发出高亢而嗡嗡的'zwheer'声，即使在溪流湍急的背景下也能被听到。当受到惊扰时，会连续发出'doo-wip'的叫声。","habits":"该物种偏好居住在安第斯山脉云雾森林中靠近湍急溪流的地带。它们的栖息地通常位于海拔较高的山林中，展现出了良好的适应性。","breeding":"关于灰背唧霸鹟的繁殖行为信息有限，但通常在繁殖季节，它们会在树上或灌木丛中筑巢，进行交配和孵化。","identification":"与黑背唧霸鹟和栗腰唧霸鹟相比，灰背唧霸鹟的胸部栗色更为明显，且白眉更加突出。","protection":"IUCN：LC（无危）","distribution":"灰背唧霸鹟的分布范围涵盖南美洲的委内瑞拉西南部至秘鲁北部，主要栖息于安第斯山脉的云雾森林。","other":"之前，灰背唧霸鹟曾被认为与黑背唧霸鹟和栗腰唧霸鹟是同一物种，但现在已确认为独立物种。"},{"name":"黑背唧霸鹟","english_name":"Blackish Chat-Tyrant","scientific_name":"Ochthoeca nigrita","overview":"黑背唧霸鹟（英文名：Blackish Chat-Tyrant，学名：Ochthoeca nigrita），是雀形目霸鹟科唧霸鹟属的小型鸟类，为委内瑞拉安第斯山脉特有种。其通体呈石板灰色，最显著的特征是醒目的白色眉纹，如同在昏暗中闪烁的车灯。该鸟种常栖息于云雾森林中，且几乎总是在湍急的山溪旁被观察到。","appearance":"黑背唧霸鹟体型较小，全身羽毛呈现均匀的石板灰色，最为突出的是其白色眉纹，极为醒目。在不同的光照条件下，这一特征显得尤为耀眼。","call":"其典型鸣叫为短促、下降的摩擦声，每隔几秒重复一次。","habits":"黑背唧霸鹟栖息于云雾缭绕的山林地带，偏好靠近湍急的山溪。它们的活动范围集中在亚热带或热带湿润的山地森林中，以及重度退化的前森林区域。","identification":"与灰背唧霸鹟相比，黑背唧霸鹟的分布范围仅限于委内瑞拉，两者并不重叠。","distribution":"黑背唧霸鹟的自然栖息地位于南美洲东部委内瑞拉西部的山地森林。"},{"name":"栗腰唧霸鹟","english_name":"Maroon-belted Chat-Tyrant","scientific_name":"Ochthoeca thoracica","overview":"栗腰唧霸鹟（英文名：Maroon-belted Chat-Tyrant，学名：Ochthoeca thoracica），是雀形目霸鹟科唧霸鹟属的鸟类。分布于南美洲北部，常见于秘鲁和玻利维亚的亚热带或热带湿润山地森林及严重退化的前森林地带。","appearance":"体型较小的飞捕型鸟类，主要羽毛呈灰色，最显著的特征是胸前有一片栗色斑块，以及在昏暗森林中格外显眼的粗白眉纹。翼展适中，尾部略尖。","call":"最常听到的叫声是一连串拉长的高音‘peeeeeer’，即使在湍急的溪流声中也能辨识。受惊扰时，会发出一系列嘈杂的‘pee-didit’叫声。","habits":"栖息于安第斯山脉云雾森林中的溪流附近，偏好湿润的山地环境。飞行敏捷，善于捕捉空中飞虫。活动范围受限于其特定的生境。","breeding":"关于繁殖行为的详细信息尚不充分，但已知它们在繁殖季节会在树上筑巢。","identification":"与灰背唧霸鹟的区别在于胸带颜色和叫声的不同。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲的秘鲁和玻利维亚，特别是在亚热带或热带湿润山地森林中。","other":"曾被归类为灰背唧霸鹟的一个亚种，后独立为一物种。"},{"name":"棕胸唧霸鹟","english_name":"Rufous-breasted Chat-Tyrant","scientific_name":"Ochthoeca rufipectoralis","overview":"棕胸唧霸鹟（英文名：Rufous-breasted Chat-Tyrant，学名：Ochthoeca rufipectoralis），是雀形目霸鹟科唧霸鹟属的鸟类。分布范围从委内瑞拉延伸至玻利维亚。以其独特的紫红色胸部带和翼条著称，雌雄外观相似，常见于开放林地和边缘。","appearance":"体长约13–14厘米，体重约13克。头部为烟褐色，有明显的白色眉纹；上半身为褐色或烟褐色；翅膀和尾巴为黑色，带有微弱的红褐色或肉桂色边缘，最外侧尾羽边缘白色；下巴和喉咙为灰色，喉咙下部和胸部为深橙红色，腹部为白色；虹膜为暗褐色；喙短且薄，黑色；腿黑色。幼鸟与成鸟相似。不同的亚种在翼纹和下半身颜色上有所变化。","call":"发出急促的‘tjrt-tjrrrrt-tjt-trrrt’、‘chic-chic-chica’或‘ch-brrr, ch-brrr, ch-brrr’声，常重复两次；有时发出轻微的‘cleeoo’声和快速的‘pt’音符序列，以两个‘cleeoo’音符结束；黎明时的歌声为‘tirip, wee-eeuww, tirip, wee­eeuw’等。","habits":"栖息于开放云雾林的边缘，湿润山地和Polylepis森林附近，通常沿着道路分布，海拔高度主要在2000–3600米之间，偶尔可达4100米。主要以昆虫为食，通常单独或成对活动，有时加入混合群鸟中。领土意识强，常以警觉的姿态站立，觅食时活跃。","breeding":"在哥伦比亚，繁殖季节为1月到9月；在厄瓜多尔，4月观察到幼鸟；在秘鲁，10月筑巢（在普诺），11月观察到幼鸟（在胡阿努科）。巢为苔藓杯状，建于岩石的平台上，常被矮树遮蔽。","identification":"与其他几种有粗大白色眉纹的唧霸鹟相似，但通过胸前的紫红色斑块容易区分。亚种间的差异主要体现在翼纹和上半身颜色上。","protection":"IUCN：LC（无危）。在分布范围内多数国家公园中均有发现，但在最湿润的地区较少见。","distribution":"南美洲：从哥伦比亚北部至玻利维亚西部，包括秘鲁、厄瓜多尔等地。","other":"在秘鲁马奇皮丘历史保护区、玻利维亚马迪迪国家公园和厄瓜多尔的多个保护区内都有记录。"},{"name":"褐背唧霸鹟","english_name":"Brown-backed Chat-Tyrant","scientific_name":"Ochthoeca fumicolor","overview":"褐背唧霸鹟（英文名：Brown-backed Chat-Tyrant，学名：Ochthoeca fumicolor），是雀形目霸鹟科唧霸鹟属的鸟类。在南美洲高海拔地区常见的霸鹟。其特征包括淡色眉纹、褐色翼带和肉桂色的下体。分布于哥伦比亚西部、东北部和委内瑞拉西北部至玻利维亚中部。","appearance":"体长14.5至16厘米，体重16至19克。头部扁平，前额和眉纹白色至赭黄色，眼后逐渐加深；冠部温暖的棕色；背部红褐色，臀部更偏红棕色；翅膀暗灰或黑色，两对显著的红褐色翼带，下翼带更为明显；尾巴暗灰至黑色，外侧尾羽具白色边缘；喉咙和下脸灰色；下体肉桂红棕色，尾下覆羽呈淡黄色；虹膜深色；喙黑色；腿黑色。雌鸟下方稍显苍白。幼鸟颜色更暖，缺乏下巴的灰色。不同亚种在胸部和眉纹的肉桂色调上有所差异。","call":"鸣声包括尖锐的吱吱声和尖锐的‘dewit’叫声，常由一对鸟以杂乱的二重唱形式发出。","habits":"栖息于安第斯山脉的高山森林边缘、灌木丛和半湿润的Polylepis林地，高度在2200至4200米之间，偶尔低至1800米，最高可达4400米。通常独居或伴侣分散，经常占据领地。停栖在粗枝上，通常靠近主干，或紧贴主干，也常在树梢和围栏柱上显眼的位置停留。捕食昆虫，从栖息处飞行到地面、树叶或空中捕食，有时返回同一栖息点，有时更换栖息点并移动相当远的距离；偶尔悬停捕食。","breeding":"繁殖季节在哥伦比亚和厄瓜多尔安第斯山脉为2月至9月，12月筑巢（Boyacá地区）；10月中旬在厄瓜多尔南部筑巢；在秘鲁（Huánuco）和玻利维亚（Cochabamba）观察到换羽（推测为产后换羽）。在领地争斗中会做短暂摇晃飞行并发出翼振声。巢穴位于密集藤蔓中，离地约1.5米，深杯状，由苔藓和草构成，内衬Puya纤维，直径12厘米，深8厘米，内杯宽5.5厘米，深4.5厘米。产卵数量为两个，白色，带有少量稀疏的红棕色和深棕色斑点，大小为19.4-20.2毫米×15.1-15.7毫米。","identification":"与棕胸唧霸鹟相似，但肉桂色下体延伸至腹部，不形成明显的胸斑。与O. pectoralis相比，具有更明亮的颜色，红褐色的眉纹和胸部，腹部中心渐变为淡黄色。","protection":"IUCN：LC（Least Concern，无危）","distribution":"主要分布在安第斯山脉西部的委内瑞拉（Trujillo, Mérida, N Táchira）、哥伦比亚、厄瓜多尔、秘鲁北部至中部玻利维亚。","other":"在哥伦比亚和厄瓜多尔的所有国家公园，秘鲁北部的Río Abiseo国家公园，以及秘鲁南部和玻利维亚La Paz和Cochabamba省的所有国家公园均有分布。"},{"name":"南美唧霸鹟","english_name":"D'Orbigny's Chat-Tyrant","scientific_name":"Ochthoeca oenanthoides","overview":"南美唧霸鹟（英文名：D'Orbigny's Chat-Tyrant，学名：Ochthoeca oenanthoides），是雀形目霸鹟科唧霸鹟属的小型鸟类，常见于安第斯山脉的开阔和半开阔灌木丛生环境。其独特的白眉纹和锈色下体是识别它的关键特征。","appearance":"这种吸引人的小型飞禽具有明显的白色眉纹和锈色的下体羽毛，常单独或成对出现在灌木较低到中层位置，偶尔会降落至地面捕食猎物。与北方分布的褐背唧霸鹟相比，其特征更为鲜明。","habits":"南美唧霸鹟偏好居住在岩石山谷和沟壑，以及开放的Polylepis树林中。它们通常安静地栖息在灌木上，伺机从地面捕捉猎物。","identification":"通过其显著的白色眉纹和锈色腹部，可以轻易将其与同属的褐背唧霸鹟区分开来。","distribution":"分布于南美洲，从秘鲁延伸至阿根廷西北部，主要栖息于安第斯山脉的特定生态位。"},{"name":"白眉唧霸鹟","english_name":"White-browed Chat-Tyrant","scientific_name":"Ochthoeca leucophrys","overview":"白眉唧霸鹟（英文名：White-browed Chat-Tyrant，学名：Ochthoeca leucophrys），是雀形目霸鹟科唧霸鹟属的小型鸟类，常见于南美洲安第斯山脉的开放及半开放灌木丛生环境，包括岩石山谷、沟壑及村庄周围的农业梯田。","appearance":"这种小型的霸鹟通常单独或成对出现，安静地栖息于低至中层的灌木丛中，偶尔会突然飞扑到地面捕食猎物。其显著特征包括相对较长的尾巴，常在停栖时向上轻弹。大胆的白色眉纹与整体灰色的羽毛相映成趣，使其外观独特。与体型较小的安第斯唧霸鹟相比，两者在秘鲁部分地区有局部重叠。","habits":"白眉唧霸鹟偏好栖息于南美洲的安第斯山脉地带，尤其在高海拔的灌木丛生环境中。它们的活动范围广泛，包括岩石山谷、沟壑以及人类村落附近的农业梯田。","identification":"与安第斯唧霸鹟的区别在于体型和色彩模式，白眉唧霸鹟具有更长的尾巴和更加明显的白色眉纹，这在整体灰暗的羽毛中尤为突出。","distribution":"分布范围从厄瓜多尔南部延伸至阿根廷西北部，主要栖息于Puna草甸，其自然栖息地为亚热带或热带的高海拔灌木林。"},{"name":"安第斯唧霸鹟","english_name":"Piura Chat-Tyrant","scientific_name":"Ochthoeca piurae","overview":"安第斯唧霸鹟（英文名：Piura Chat-Tyrant，学名：Ochthoeca piurae），是雀形目霸鹟科唧霸鹟属的鸟类。小型霸鹟科鸟类，特有于秘鲁西北部安第斯山脉西侧。其分布范围限于皮乌拉至安卡什，生境为干旱和半湿润灌木斜坡，海拔介于1500至2800米。此物种因栖息地丧失和碎片化被IUCN列为\"近危\"。","appearance":"安第斯唧霸鹟具有鲜明的白色眉纹，背部呈棕色，翼上有两道明显的锈红色条纹。面部灰色，下体浅灰，腹部及臀部近白色。与更广泛的白眉唧霸鹟相比，体型较小，上体颜色更偏褐色。","call":"其典型鸣声为干燥、无调性的颤音，有时带有断音特质。","habits":"栖息于秘鲁西北部的干燥及半湿润森林地带，活动于1500至2800米海拔间。飞行及活动特点尚未详述，但据知以昆虫为食。","identification":"与白眉唧霸鹟的主要区别在于体型更小，上体颜色更丰富，翼上的锈红色条纹更为显著。","protection":"IUCN：LC（无危）","distribution":"南美洲：秘鲁西北部，分布于安卡什至皮乌拉之间。"},{"name":"棕眉唧霸鹟","english_name":"Rufous-browed Chat-Tyrant","scientific_name":"Ochthoeca superciliosa","overview":"棕眉唧霸鹟（英文名：Rufous-browed Chat-Tyrant，学名：Ochthoeca superciliosa），是雀形目霸鹟科唧霸鹟属的鸟类。仅见于委内瑞拉安第斯山脉高海拔地区。其显著特征为亮肉桂色腹部、眉毛及翼纹，通常成对出现在树线附近或之上，栖息于高寒风大的paramos（高山草原）。拥有突出的喙须，上身呈棕色，翼部暗淡带有1至2条醒目的棕红色翼纹，下体明亮的肉桂色，长而宽的棕红色眉纹是其与褐背唧霸鹟区别的关键特征。","appearance":"棕眉唧霸鹟为小型霸鹟，体长约14.5至16厘米，体重约14至15克。雌雄相似，上体棕色，具长而宽的鲜亮肉桂色眉纹，眉纹向后逐渐加宽，与暗色头部两侧形成鲜明对比；翼部和尾部暗淡，具一至两条显眼的棕红色翼纹，由大翼羽和中翼羽的覆羽尖端形成；腹中部及尾下覆羽呈白色；喉部灰白至富橄榄色，其余下体主要为亮丽的肉桂色。幼鸟整体上呈更温暖的棕色调，喉部和腹部颜色较淡，翼纹稍窄且更淡，眉纹更偏赭黄色。","call":"通常较为安静，其叫声为弱而尖锐的吱吱声，常以二重唱形式出现，声音类似“keek-kee-keek”或“keek-tede-keek”，持续约1秒。清晨时，成对的鸟儿会发出节奏感强的、连续的啾啾声，长达12个音节，结尾放慢。","habits":"棕眉唧霸鹟生活在委内瑞拉安第斯山脉的高海拔地区，偏好边界的灌木丛、高山矮林、森林边缘以及半湿润的Polylepis树林，偶尔会在开阔的paramos（高山草原）中见到它们的身影。它们一般独居或成对活动，以昆虫为食，通过在低矮的显眼处如灌木或草丛中栖息，然后飞扑捕捉空中或地面的昆虫。","breeding":"关于棕眉唧霸鹟的繁殖信息有限。已知它们的繁殖季节至少在三月，巢建于河岸凹洞或Espeletia植物死叶形成的空腔中，离地面最低可达20厘米。巢呈开放式杯状，内部铺垫柔软材料如种子绒毛或兔毛。","identification":"与冠唧霸鹟、棕胸唧霸鹟和南美唧霸鹟的区别在于体型、颜色模式和翼纹。与褐背唧霸鹟相比，棕眉唧霸鹟色彩更为鲜艳，具有明显的棕红色眉纹和胸部，腹部中心渐变为肉桂色。","protection":"IUCN：LC（无危）","distribution":"分布于委内瑞拉西部的安第斯山脉，包括特鲁希略州、梅里达州和北部塔奇拉州的高海拔地区。","other":"直到最近，棕眉唧霸鹟还被认为是褐背唧霸鹟的一个亚种，两者在形态和习性上极为相似。"},{"name":"巴塔唧霸鹟","english_name":"Patagonian Tyrant","scientific_name":"Colorhamphus parvirostris","overview":"巴塔唧霸鹟（英文名：Patagonian Tyrant，学名：Colorhamphus parvirostris），是雀形目霸鹟科巴塔唧霸鹟属的唯一物种。这种小鸟在迁徙和冬季广泛出现在花园、公园和开阔的林地中，尤其偏好有浆果灌木的地方。夏季则栖息于温带本土雨林，常居高树，容易被忽视。繁殖季节以单个或成对出现，非繁殖季有时形成小群。","appearance":"外表朴素却颇具吸引力，头部圆润，两颊有暗色斑块，翼上有锈色的翼杠，这些特征使其在同类中独树一帜。体型较小，羽色较为单一，但细节处的色彩变化为其增添了几分魅力。","habits":"巴塔唧霸鹟偏好栖息于温带森林环境，主要以昆虫为食，但也观察到其食用mayten种子和leñadura果实的行为。夏季通常独居或成对活动，冬季则可能形成小群。","identification":"在分布区域内无相似物种，通过其圆头、深色颊斑和锈色翼杠可以轻易识别。","distribution":"繁殖于智利南部（自拉阿劳卡尼亚）和阿根廷西南部（自内乌肯和里奥内格罗）至火地岛；非繁殖季节北至智利中部（科金博）。主要分布于南美洲的智利南部和阿根廷西南部。"},{"name":"长尾霸鹟","english_name":"Long-tailed Tyrant","scientific_name":"Colonia colonus","overview":"长尾霸鹟（英文名：Long-tailed Tyrant，学名：Colonia colonus），是雀形目霸鹟科长尾霸鹟属的鸟类。独特的飞禽。其最显著的特征为雄鸟的超长中央尾羽，比雌鸟更为突出。分布于中美洲至南美洲，从洪都拉斯东南部直至阿根廷东北部。","appearance":"雄性长尾霸鹟长约23-28厘米，重约15-18克，拥有黑色身躯搭配白色背部和眉纹，中央尾羽异常延长，可达13厘米之多，末端稍宽。雌鸟相似但色调更淡，腹部带灰白斑点，背部灰色，冠羽较深，尾羽流苏较短。幼鸟呈烟灰色，腹部灰白，头顶边缘有微弱的白色条纹，中央尾羽较宽，仅轻微超出其余尾羽。不同亚种在头部白色程度、背部白色量及体型大小上有所差异。","call":"发出柔和上升的‘tuweee’或‘wheeet’声，通常在摆动尾羽时鸣叫，有时连续快速叫唤2-3次。雄鸟的歌唱为较长的‘twee-la, twee-la, twee-la’旋律，伴有音乐般的‘druu’声，同时伴随着长尾的鞭打声。互动时会发出尖锐嘶嘶的‘chip’声。求偶追逐时发出‘prrri, bi-bibi’的叫声。","habits":"偏好栖息于开阔地带，如林间空地、边缘或森林边缘，常成对或家族群聚，高居于枯木顶端或开阔树枝上，长时间显眼地停留。以空中突袭方式捕捉昆虫，主要以无刺蜜蜂（汗蜂）为食，擅长捕捉这类猎物。捕食后通常返回原位或附近栖息处。","identification":"长尾霸鹟以其独特的黑白色调和显著的长尾羽区别于其他物种，特别是在雄鸟个体中。不同亚种在头部颜色、背部白色程度和体型上有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲南部至南美洲北部，包括洪都拉斯东南部至阿根廷东北部，遍及巴西、哥伦比亚、秘鲁等国家。"},{"name":"短尾田霸鹟","english_name":"Short-tailed Field Tyrant","scientific_name":"Muscigralla brevicauda","overview":"短尾田霸鹟（英文名：Short-tailed Field Tyrant，学名：Muscigralla brevicauda），是雀形目霸鹟科短尾田霸鹟属的唯一物种。主要分布于南美太平洋沿岸，自厄瓜多尔至智利北部，栖息于海拔1300米以下的荒芜开阔地带。橄榄褐色上身，黑色翅羽具细白翼纹，白色眉纹，极短的黑尾基部呈肉桂色，淡黄色臀部，下体白色。","appearance":"体长11厘米，具独特外形。上体橄榄灰，翼羽深色带薄白翼纹，头顶中央隐匿黄斑。尾短至几乎缺失一半，腿长，足裸露。下体白，侧腹渐变为肉桂色。喙灰，尖端暗，下颌浅黄，虹膜深褐，胫跗骨、跗跖及趾浅黄。","call":"发出柔和而沙哑的连续叫声，伴随其在地上追逐昆虫时的动作。","habits":"主要生活在干旱沙漠和沿海狭窄地带，栖息于地面，也常出现在灌木、岩石、电杆等开放位置。以昆虫为食，奔跑捕食。","breeding":"具体繁殖信息未详述。","identification":"与地霸鹟相比，尾更短，无翼纹及淡色臀部特征。在野外，其独特的外形易于识别。","protection":"IUCN状态未知，未列入华盛顿公约(CITES)或中国国家重点保护野生动物名录。","distribution":"分布于南美洲，从厄瓜多尔南部至智利北部，主要在太平洋沿岸狭窄地带。","other":"无"},{"name":"牛霸鹟","english_name":"Cattle Tyrant","scientific_name":"Machetornis rixosa","overview":"牛霸鹟（英文名：Cattle Tyrant，学名：Machetornis rixosa），是雀形目霸鹟科牛霸鹟属的鸟类。以独特的地面活动习性和跟随放牧动物的行为著称，分布于南美洲的广阔地带，从巴拿马至南美东南部。常在开阔地及牧场中被发现。","appearance":"牛霸鹟长约20厘米，体重介于29至40克之间。成鸟的上体主要为橄榄褐色，腹部黄色鲜明，头部呈灰褐色，冠部带有隐秘的亮橙红色斑块。眼睛周围有淡淡的暗色眼纹，耳羽区带些微的暗褐色或黄褐色调。翅膀橄榄褐色，尾巴黄肉桂色或橄榄褐色，尖端淡而模糊，从下方看更为明显。喉咙白色，下体大部分为鲜黄色，胸部略带橄榄赭色。虹膜深红色，喙细长黑色，腿色深。雌雄相似，但雌鸟可能喉部和胸部有浅黄色洗染，某些文献指出缺乏冠斑。幼鸟特征尚未详细描述。三个亚种中，emflavigularis/em的喉咙更偏黄，emobscurodorsalis/em与前者非常相似。","call":"常见叫声为一系列短暂、尖锐的音符，音高逐渐上升；晨歌为短促重复的颤音口哨声，类似“t’te’te’ree”、“tip-tip, tsi-tsip-tsilíp-tsilíp tsirrrr”或“swee see dee”。黄昏时会发出复杂持续的“tic”音符和短颤音，音高有起伏，与热带王霸鹟的典型叫声相似但更为尖厉。","habits":"偏好干燥的半开放至开放生境，包括稀树草原、散有灌木和树木的牧场、农田、房屋周围的院子、城市公园，偶尔在沙滩上。通常在海拔300米以下的热带低地活动，偶尔可达约1000米高度，曾有在委内瑞拉梅里达3600米高度的迷鸟记录。大部分为留鸟，但在分布南部边缘的指名亚种有迁徙现象。以昆虫为食，常成对或小群在地面快速奔跑觅食，受放牧动物惊扰的昆虫是其主要猎物。也会在树下枝条、矮灌木顶或房屋上栖息。","breeding":"繁殖季在哥伦比亚最早于3月观察到筑巢行为，7月有幼鸟记录；在委内瑞拉，6月至10月间繁殖，5月已有雄鸟处于繁殖状态；阿根廷的繁殖期为10月至次年1月。利用棕额棘雀的大型多室巢穴，或自行构建离地较高的草质球状巢。阿根廷一巢外部直径12厘米，高7.5厘米，内部直径7厘米，深度5厘米。对靠近巢的同类和其他物种表现出一定的攻击性。每窝产3-4枚卵，阿根廷的孵化期为14.5天，幼鸟离巢时间为16天。有时会被紫辉牛鹂寄生。","identification":"与Tyrannus属的鸟类在外观上有相似之处，但其短而圆的翅膀和长腿使其易于区分。牛霸鹟的冠斑、地面活动习性及对放牧动物的依赖也是与其他种类的重要区别点。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲东南部，包括巴拿马至巴西东北端，以及从巴拿马到委内瑞拉、厄瓜多尔东部的区域。在阿根廷北部和玻利维亚也有分布。由于森林砍伐，该物种近期已进入之前未见的地区，如厄瓜多尔东北部。","other":"牛霸鹟能够适应人为改造的环境，广泛存在于国家公园和保护区中。"},{"name":"强霸鹟","english_name":"Piratic Flycatcher","scientific_name":"Legatus leucophaius","appearance":"成年强霸鹟长约15厘米，体重约23克。上体为无条纹的单一褐色，飞行羽具狭窄白色边缘。头部特征包括长长的灰白色眉纹，隐藏的黄色冠纹，以及眼周的暗色面罩。喉部纯白，有一条明显的白色颊纹。下体颜色为白色，带有淡黄色调，胸部和两胁有模糊的棕色条纹。喙短而宽，呈深色。","call":"鸣叫声为上扬的‘weeEEE’，常从高枝发出，持续时间长，有时发出单调的‘weep weep weep’。","habits":"栖息于草原和其他半开放生境中的大树附近。主要食物为水果，如浆果，以及Cecropia的猫须花序和昆虫，如蜻蜓。独居或成对出现，常在树顶显眼处停留。","breeding":"繁殖时不筑巢，而是侵占其他鸟类，尤其是体型远大于它的黄臀鵙鵙或冠鵙鵙的封闭巢穴。一旦成功驱逐原主人，会移除其蛋，雌鸟独自孵化2至4枚，通常为2枚，有黑色条纹的棕色蛋，孵化期16天，幼鸟离巢期18至20天。","identification":"独特的头部条纹，短而粗的喙，以及下体模糊的暗色条纹使其易于辨认。","protection":"IUCN：LC（无危）","distribution":"广泛分布于中美洲至南美洲北部和中部，包括墨西哥南部、特立尼达岛、玻利维亚和阿根廷。"},{"name":"白须短嘴霸鹟","english_name":"White-bearded Flycatcher","scientific_name":"Phelpsia inornata","overview":"白须短嘴霸鹟（英文名：White-bearded Flycatcher，学名：Phelpsia inornata），是雀形目霸鹟科白须短嘴霸鹟属的唯一物种。拥有蓬松圆胖的身躯，酷似短嘴版的霸鹟。该鸟种于1869年被首次命名，主要分布于南美洲的哥伦比亚和委内瑞拉。","appearance":"其特征包括黑色的冠羽和面罩，搭配蓬松的白色喉部和宽阔的白色眉纹，后者在头部后方相连。喙部极短，上体呈橄榄棕色，下体则是鲜艳的黄色。雌雄外观相似，无明显差异。","call":"鸣声独特，容易识别，会发出响亮的‘PU-terr-r, PU-terr-r’叫声，反复鸣唱，通常以二重唱或合唱形式呈现。","habits":"常见于低地的开阔森林、森林边缘及画廊森林，通常以成对或家庭群的形式活动，具有领地性。其栖息地包括次生林和严重退化的森林。","breeding":"关于其繁殖行为的具体细节记录较少，但基于其生态习性推测，可能在树洞或隐蔽处筑巢，具体繁殖季节需进一步研究。","identification":"与社交霸鹟和社会霸鹟、锈缘霸鹟相比较，白须短嘴霸鹟更显圆胖，喙部更短，翅膀无红褐色，黑色的冠羽，以及头颈后部相连的白色条纹。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲北部，具体包括委内瑞拉的Carabobo、Miranda和Cojedes向东至Anzoátegui东北部，向南至Apure和Bolívar北部，以及哥伦比亚东北部的Vichada和Arauca。","other":"尽管在分布区内较为常见，但由于栖息地的持续丧失和退化，其长期生存状况仍值得关注。"},{"name":"锈边短嘴霸鹟","english_name":"Rusty-margined Flycatcher","scientific_name":"Myiozetetes cayanensis","overview":"锈边短嘴霸鹟（英文名：Rusty-margined Flycatcher，学名：Myiozetetes cayanensis），是雀形目霸鹟科短嘴霸鹟属的鸟类。体型中等，羽毛鲜黄，头部黑白相间鲜明。分布于中美洲和南美洲，自巴拿马至巴西东南部，常见于多种开阔林地环境，包括森林边缘和次生林，常靠近水域。该鸟种被列入《世界自然保护联盟》红色名录，但全球并不受威胁。","appearance":"体长16.5-18厘米，体重22-29.5克。头部多呈深灰褐色，具亮黄色至金橙色冠羽（通常隐藏），宽白眉纹连贯前额至颈背。上体橄榄棕色，翼深灰褐，次级飞羽内侧边缘橄榄绿，次级飞羽和初级飞羽尖端有狭窄的锈红或肉桂色边缘。尾羽暗褐色带浅橄榄色边缘。下体鲜黄，喉部白色。虹膜棕，喙短小黑色，腿黑色。雌雄相似，雌鸟平均略小于雄鸟。幼鸟似成鸟，但缺少冠羽，翼和尾羽边缘更宽，偏锈肉桂色。","call":"最常见叫声为细长、哀怨的'peeeeeeeea'或'wheeeeee'，持续2-3秒，有时重复数次。兴奋时发出多样声音，如响亮强调的'puuuuu­reeeéét-éét-éét'或'too-eeéet'，快速滚动的'keé-wit' 'tis-u'或'chew-chewit'系列，有时以二重奏形式发出。","habits":"偏好灌木丛地带、林地空地、半开放区域，也见于农田、受干扰保留树木的环境，以及森林边界和亚马逊地区的牛轭湖旁。通常低于1000米，偶尔可达2100米。常近水，较群栖短嘴霸鹟少出现在居民区，但在后者缺失的地区会频繁光顾牧场、公园和花园，但保持距离住宅。主要以昆虫和水果为食，常成对或小群活动，停歇于开阔处，俯冲至地面或树叶间，或空中捕食昆虫。","breeding":"繁殖期记录在委内瑞拉的3月至8月，巴拿马的3月至4月，哥伦比亚的1月发现幼鸟和筑巢中的雌鸟。巢位于离地2-4米的显眼位置，由干草和小枝构成，侧面入口，多在茂密灌木的外部。每窝产2-3枚蛋，蛋壳呈玫瑰黄色，带褐红色斑点，大小约20-22mm x 15-16mm。","identification":"与群栖短嘴霸鹟相比，头部较不暗沉，背部较不橄榄色。翼和尾羽边缘的锈色更为明显。叫声和行为模式也可用于区分。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲巴拿马至南美洲东南部巴西，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉；以及巴拿马东部。","other":"能容忍改造后的栖息地，广泛存在于其分布范围内多个国家公园和其他保护区。"},{"name":"群栖短嘴霸鹟","english_name":"Social Flycatcher","scientific_name":"Myiozetetes similis","overview":"群栖短嘴霸鹟（英文名：Social Flycatcher，学名：Myiozetetes similis），是雀形目霸鹟科短嘴霸鹟属的鸟类。常见于中美洲及南美洲热带和亚热带地区的鸟类。其体型小巧，头部呈暗灰或棕色，具有隐蔽的红色冠斑，翼和尾部淡褐色，下体黄色，喉部白色。在半开放地带、城镇、花园等地常可见到它们活跃的身影。","appearance":"成年鸟体长16-18.5厘米，体重24-27克。头部主要为暗灰色至棕灰色，拥有鲜亮的红至橙红色冠斑（通常被遮掩），宽大的白色眉纹在前额汇合，并几乎在颈背相连。上体颜色从暗橄榄绿到橄榄棕色，尾羽深灰褐色，下体明亮黄色，喉部白或淡黄色。雄雌相似，雌鸟平均略小。幼鸟外观与成鸟类似，但冠斑较小或缺如，上体更偏向灰棕色，飞羽和尾羽边缘带锈色。","call":"发出尖锐刺耳的叫声，如‘seeá’、‘tcheiit’或‘see-yh!’尖叫，还有各种鼻音或尖锐的快速啾啾声和争吵声，如‘t-cheer-cheer-che-tiqueer’或‘chiir t-chiir t-chirr’。","habits":"偏好湿润至半干旱的半开放低地环境，包括散生灌木和树木、次生林、森林边缘、湖泊和河流边缘、阴凉花园、牧场、农田和居民区。它们通常在海拔1000米以下活动，但在某些地区可高达1700米。以昆虫为主食，偶尔食用蝌蚪，大量摄取小浆果和其他果实。通常成对或小群体活动，会在果树林中聚集。","breeding":"繁殖季节延长，筑巢由雌鸟承担，巢为穹顶状，侧面开口，用干草、稻草、杂草茎等材料构建，经常靠近蜂巢、蚁巢或其它猛禽巢穴。产卵数为2-4枚，孵化期约15-16天，幼鸟离巢期17-21天。每年仅育一窝，但因捕食者威胁，可能尝试多次筑巢。","identification":"与锈边短嘴霸鹟、白须短嘴霸鹟、白环蚊霸鹟和小食蝇霸鹟外观相似，近距离观察才能区分。各亚种在羽毛色泽上有细微差异。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲东北部，从墨西哥至阿根廷东北部，广泛存在于多种半开放生境，包括农业区和住宅区。","other":"在人类改变的环境中也能茁壮成长，如次生林、城市公园和花园。"},{"name":"灰顶短嘴霸鹟","english_name":"Grey-capped Flycatcher","scientific_name":"Myiozetetes granadensis","overview":"灰顶短嘴霸鹟（英文名：Grey-capped Flycatcher，学名：Myiozetetes granadensis），是雀形目霸鹟科短嘴霸鹟属的中型鸟类。以明亮的黄色腹部和较为柔和的头部图案为特征，整体呈灰色，具有白色的喉部和额头。在中美洲至南美洲西部地区广泛分布，从洪都拉斯至北秘鲁、玻利维亚北部和巴西西部。","appearance":"成年灰顶短嘴霸鹟长约16.5至18厘米，体重约26至30克。头部灰色，雄鸟具隐蔽的红色冠纹，眼睛周围有短而弱的眉纹。上体橄榄棕色，翅膀和尾巴为棕色，仅有微弱的红褐色边缘。下体为黄色，喉部白色。幼鸟缺乏冠纹，翼和尾羽边缘为栗色。","call":"其叫声为尖锐的鼻音'kip'，黎明时的歌声为连续的'kip, kip, kip, k’beer'。","habits":"栖息于种植园、牧场和有树木的开阔林地，常单独或成对出现在次生林、森林边缘和花园中，显眼地栖息。以飞行中的昆虫为食，有时也会悬停取食小浆果。","breeding":"繁殖期在2月至6月间，雌鸟在灌木、树上或建筑物上建造大型带屋顶的巢，巢由茎和稻草构成，通常靠近黄蜂、蜜蜂或蚂蚁巢穴，或另一个霸鹟的巢，如社会霸鹟的巢，以获取保护。每窝产2至4枚带有褐色或紫罗兰色斑点的淡白色蛋。","identification":"与社会霸鹟相似，但后者头部黑白条纹明显，灰顶短嘴霸鹟头部图案较不显著，且体型较小，喙也较小。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲西部，从洪都拉斯至厄瓜多尔西部，以及亚马逊雨林西部。"},{"name":"暗胸短嘴霸鹟","english_name":"Dusky-chested Flycatcher","scientific_name":"Myiozetetes luteiventris","overview":"暗胸短嘴霸鹟（英文名：Dusky-chested Flycatcher，学名：Myiozetetes luteiventris），是雀形目霸鹟科短嘴霸鹟属的小型鸟类，主要分布在南美洲的亚马逊雨林地区，包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、法属圭亚那、秘鲁、苏里南和委内瑞拉。栖息于低地的热带森林和沼泽地带。","appearance":"暗胸短嘴霸鹟具有较为朴素的外观，其最显著的特征是灰黄色斑驳的胸部，灰色头部和短小的喙。与黄白喉霸鹟相似，但体型更小，喙部更短。","call":"这种鸟类非常善于发声，通常通过尖锐的喵喵声被首次发现，叫声频繁而响亮。","habits":"暗胸短嘴霸鹟常以成对或小群体的形式出现，有时会跟随混合物种的鸟群，主要以昆虫和果实为食。","breeding":"关于暗胸短嘴霸鹟的繁殖信息较少，但一般而言，它们会在繁殖季节内建立领地，进行求偶和筑巢活动。","identification":"与黄白喉霸鹟相比，暗胸短嘴霸鹟的体型更小，喙部更短，胸部的色彩更加模糊。在识别时，观察其灰黄色的胸部和短喙是关键。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美的亚马逊雨林区域，具体国家包括玻利维亚、巴西、哥伦比亚、厄瓜多尔、法属圭亚那、秘鲁、苏里南和委内瑞拉。"},{"name":"大食蝇霸鹟","english_name":"Great Kiskadee","scientific_name":"Pitangus sulphuratus","overview":"大食蝇霸鹟（英文名：Great Kiskadee，学名：Pitangus sulphuratus），是雀形目霸鹟科大食蝇霸鹟属的鸟类。体型较大、色彩鲜明。广泛分布于中美洲和南美洲，从美国南部至阿根廷中部。其独特的黄色腹部、黑白相间的头部图案以及响亮的‘kis-ka-dee’叫声使其易于识别。","appearance":"大食蝇霸鹟体长约24厘米，体重约74克。头部宽大，黑白条纹分明，冠部黑色，面颊白色，腹部鲜黄。上体呈橄榄褐色，翅膀和尾巴边缘带有赤褐色。喙、腿和脚呈黑色。雌雄相似，仅繁殖季节通过手检可见性别差异。雏鸟似成鸟，但无黄色冠斑，翼羽和尾羽边缘赤褐色更为明显。","call":"发出响亮而富有特色的‘BEE-tee-WEE’叫声，此鸣声为其命名灵感来源之一。","habits":"偏好开放林地，常见于树梢，常近水边或开阔地带。以昆虫为主食，兼食小型脊椎动物、果实等，甚至会访问喂食站。飞行技巧高超，善于捕捉空中猎物。","breeding":"筑巢于树洞或高处，巢呈穹顶状，侧面入口。每次产卵3-4枚，由雌鸟孵化，孵化期16-17天，雏鸟17-18天后离巢。","identification":"与小食蝇霸鹟和船嘴霸鹟的区别在于体型更大、喙较短且厚，翅膀和尾巴的棕色更明显。","protection":"IUCN：LC（无危）","distribution":"分布于北美南部至南美中部，包括美国西南部、墨西哥、中美洲、南美洲北部直至阿根廷中部。在1957年引入百慕大群岛。","other":"被引入百慕大群岛以控制蜥蜴数量，但未能有效控制。"},{"name":"小食蝇霸鹟","english_name":"Lesser Kiskadee","scientific_name":"Philohydor lictor","overview":"小食蝇霸鹟（英文名：Lesser Kiskadee，学名：Philohydor lictor），是雀形目霸鹟科小食蝇霸鹟属的唯一物种。分布于中美洲和南美洲，包括巴西、伯利兹、玻利维亚、阿根廷、哥伦比亚、厄瓜多尔等地，偏好栖息于低地缓慢流动水域附近的亚热带或热带湿润灌木丛和沼泽地带。","appearance":"体长约15-18厘米，体重约25克，上体呈褐色，腹部鲜黄，头部黑白相间。与大食蝇霸鹟相比，小食蝇霸鹟体型更小、身形更瘦长，嘴部更细长且窄，翅膀和尾巴的棕色较浅。雌雄鸟羽毛相似。","call":"发出模糊不清的嗡嗡叫声，有助于在相似物种中进行区分。","habits":"通常单独或成对出现，偏好靠近水面的低地环境，活跃于眼平高度附近。以昆虫为食，善于捕捉飞虫。","breeding":"具体繁殖细节未知，但一般在适宜的季节进行筑巢和繁殖。","identification":"与大食蝇霸鹟的区别在于体型更小、嘴型更细长、翅膀和尾巴的棕色较少。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于中美洲至南美洲东部，包括巴拿马至巴西东南部。","other":"历史上曾被归入Pitangus属，与大食蝇霸鹟同属。"},{"name":"白环蚊霸鹟","english_name":"White-ringed Flycatcher","scientific_name":"Conopias albovittatus","overview":"白环蚊霸鹟（英文名：White-ringed Flycatcher，学名：Conopias albovittatus），是雀形目霸鹟科蚊霸鹟属的中等体型鸟类。以其明亮的黄色腹部、黑白鲜明的头部图案而著称。1862年首次被命名，广泛分布于中美洲至南美洲西北部，包括哥伦比亚、哥斯达黎加、厄瓜多尔、洪都拉斯和巴拿马。其生境主要是亚热带或热带湿润的低地森林，以及重度退化的前森林地带。","appearance":"白环蚊霸鹟具有中等体型，站立姿态挺拔，腹部呈现鲜亮的黄色，头部则以大胆的黑白色调为主，形成独特的视觉效果。其最显著的特征之一是细长的喙，比群栖短嘴霸鹟的喙更长，但比大食蝇霸鹟的喙更细。白色的眉纹环绕至头部后方，形成‘白环’的特色。黑色脸颊明显，不同于灰色，翅膀呈暗淡的棕色而非红褐色。","habits":"白环蚊霸鹟通常栖息于森林边缘较高的位置，其活动高度往往高于其他相似物种。它们的活动范围涵盖了亚热带或热带的湿润低地森林，适应于生活在重度退化后的森林环境中。","identification":"与相似的蚊霸鹟相比，白环蚊霸鹟可通过其特有的‘白环’、非常黑色的颊部、以及较为暗淡的棕色翅膀来辨认。此外，其细长的喙也是识别的重要特征。","protection":"IUCN：LC（无危）","distribution":"白环蚊霸鹟主要分布在中美洲和南美洲，具体包括洪都拉斯东部至厄瓜多尔西北部。"},{"name":"黄喉蚊霸鹟","english_name":"Yellow-throated Flycatcher","scientific_name":"Conopias parvus","overview":"黄喉蚊霸鹟（英文名：Yellow-throated Flycatcher，学名：Conopias parvus），是雀形目霸鹟科蚊霸鹟属的鸟类。其显著特征是整个下体呈黄色，包括喉咙部分。广泛分布于南美洲的低地森林，包括高大的热带雨林和沙土上的矮小森林。","appearance":"黄喉蚊霸鹟体长约15.5厘米，活跃于森林树冠层，通常在混合物种群中边缘活动。其下体全黄，与同类中其他种类明显不同。","call":"鸣声独特，经常发出带有嗡嗡音质的空洞颤音。","habits":"栖息于各种低地森林环境，包括热带湿润森林。活动积极，常以小组形式觅食，偏好在大树叶簇的外侧枝条上停留。","breeding":"关于黄喉蚊霸鹟的繁殖信息暂无具体记载。","identification":"与几种类似大食蝇霸鹟的飞禽相比，黄喉蚊霸鹟的行为和声音有显著差异，辨识时应注意其独特的鸣叫和黄色下体。","protection":"IUCN状态未提及，具体保护级别未知。","distribution":"分布于南美洲北部，包括委内瑞拉、哥伦比亚东部、厄瓜多尔东北部、秘鲁东北部、玻利维亚北部，以及圭亚那、法属圭亚那、苏里南和巴西的亚马逊河以北地区。","other":"在多个南美国家均有记录，是南美热带森林中的特有鸟类之一。"},{"name":"三纹蚊霸鹟","english_name":"Three-striped Flycatcher","scientific_name":"Conopias trivirgatus","overview":"三纹蚊霸鹟（英文名：Three-striped Flycatcher，学名：Conopias trivirgatus），是雀形目霸鹟科蚊霸鹟属的鸟类。偏好森林冠层和边缘地带。该鸟种于1831年被首次命名。","appearance":"三纹蚊霸鹟体型较小，常以直立姿态栖息于显眼的树枝上。其头部特征明显，宽大的白色眉纹与黑色冠羽形成鲜明对比，冠羽上无黄色斑点。拥有明显的面罩。上身主要为橄榄棕色，下身则呈黄色。与群栖短嘴霸鹟相似，但体型更小，缺乏红色冠羽斑块和白色喉部。","call":"其鸣唱为尖锐的“djew-djew”声，反复有力地发出。","habits":"三纹蚊霸鹟偏好湿润的森林环境，常见于森林边界。有时会跟随混合物种群。它在自然栖息地中主要栖息于低地的亚热带或热带湿润森林以及亚热带或热带沼泽中。","identification":"与群栖短嘴霸鹟相比，三纹蚊霸鹟体型更小，没有红色的冠羽斑块和白色的喉部，通过这些特征可以有效区分两者。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的亚马孙雨林和东南部，具体包括阿根廷、玻利维亚、巴西、厄瓜多尔、巴拉圭、秘鲁和委内瑞拉。"},{"name":"黄眉蚊霸鹟","english_name":"Lemon-browed Flycatcher","scientific_name":"Conopias cinchoneti","overview":"黄眉蚊霸鹟（英文名：Lemon-browed Flycatcher，学名：Conopias cinchoneti），是雀形目霸鹟科蚊霸鹟属的鸟类。最显著的外部特征是宽阔的黄色眉毛。分布于南美洲的委内瑞拉西部至秘鲁一带，偏好海拔800-2000米的安第斯山脉低山地带。","appearance":"黄眉蚊霸鹟体型中等偏瘦，全身橄榄褐色，腹部呈黄色，具有鲜明的黄色超眉纹，长度约为6.2英寸。雌雄成鸟在羽毛颜色上较为相似，幼鸟的特征可能有所不同。","habits":"黄眉蚊霸鹟常见于安第斯山脉的山脚和较低的亚热带地带，活动于森林边缘或开阔地带的树冠层。它们在海拔800至2000米之间活动，栖息于湿润的山地森林。","breeding":"繁殖信息有限，可能利用旧的Psarocolius和Cacicus巢穴。曾在厄瓜多尔东南部发现一对黄眉蚊霸鹟在高约18-20米的废弃黄腰酋长鹂巢穴中筑巢。","identification":"黄眉蚊霸鹟的黄色眉毛使其易于识别，与黄喉蚊霸鹟的区别在于其黄色的超眉纹。","protection":"IUCN：LC（无危）。黄眉蚊霸鹟在整个分布区内罕见至局部常见，仅在厄瓜多尔东部相对较多。预计未来11年内，因亚马逊盆地的森林砍伐，其适宜生境将减少30%，种群数量也将下降相同比例。2012年，由于其极小的分布范围和持续的栖息地退化，该物种被列为易危。","distribution":"分布于南美洲，从委内瑞拉西部至秘鲁，包括哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉的部分地区。"},{"name":"金腹大嘴霸鹟","english_name":"Golden-bellied Flycatcher","scientific_name":"Myiodynastes hemichrysus","overview":"金腹大嘴霸鹟（英文名：Golden-bellied Flycatcher，学名：Myiodynastes hemichrysus），是雀形目霸鹟科大嘴霸鹟属的鸟类。体型较大、声音响亮的霸鹟科鸟类，分布于中美洲的哥斯达黎加和巴拿马西部山区云雾森林中。其最显著的特征是黄色腹部、深色面部和白色头部条纹，常被与大食蝇霸鹟混淆，但可通过白色髭纹而非白色喉部加以区分。主要栖息于较高海拔。","appearance":"体长约18-20厘米，体重约41克。冠部和颈背呈暗灰橄榄色或深灰色，有黑色细纹，额部较淡，头顶有半隐藏的黄色斑块。上体橄榄绿色，臀部和尾羽覆羽绿橄榄色，翼部暗灰褐色，初级飞羽和次级飞羽边缘呈肉桂色，翼上覆羽边缘肉桂色或肉桂白色，尾部深灰褐色。下体黄色，喉部更接近金黄色，胸部有模糊的橄榄色条纹。幼鸟缺乏黄色冠斑，上体颜色更偏橄榄绿色，下体较淡，具肉桂红色边缘。","call":"主要鸣声为尖锐而带鼻音的‘syup’、‘seeeik’、‘skeé-eey’或‘skweey’，还有更复杂的‘seek-a-skeeeir’、‘skeé-kit skeé-lit skeé-kit’或‘chwit-chwit-ti-ti-tit-twit’，以及忧郁的‘pee-ah’或‘peeeir’，类似群栖短嘴霸鹟的声音。","habits":"栖息于湿润的山地云雾林的树冠层和边缘，尤其常见于溪流旁和森林空地边缘。主要活动于700-1850米的海拔，最高可达2300米。以水果和昆虫为食，通常成对或小家庭群出现，活跃于繁殖季节后的数月。","breeding":"繁殖季为3月至5月，在哥斯达黎加。巢为浅杯状，由细根和苔藓构成，置于6-30米高的树洞、旧啄木鸟巢穴、蕨类植物丛或悬崖垂直面的植被缝隙中。每窝产卵三枚，颜色为粉红斑点，带有灰色和红棕色斑点。","identification":"与纹大嘴霸鹟和船嘴霸鹟相似，但嘴比前者宽，比后者窄。幼鸟与成鸟相比，颜色更偏向橄榄绿色，黄色冠斑缺失。","protection":"IUCN：LC（无危）","distribution":"繁殖于中美洲哥斯达黎加，自火山Miravalles在Guanacaste山脉南部，至巴拿马西部，最东至Veraguas。在南美洲，分布于哥伦比亚北部，委内瑞拉北部和厄瓜多尔中部。","other":"曾被认为是金顶大嘴霸鹟的同种，但基于形态和分子分析，现已确认为独立物种。"},{"name":"金顶大嘴霸鹟","english_name":"Golden-crowned Flycatcher","scientific_name":"Myiodynastes chrysocephalus","overview":"金顶大嘴霸鹟（英文名：Golden-crowned Flycatcher，学名：Myiodynastes chrysocephalus），是雀形目霸鹟科大嘴霸鹟属的鸟类。特征为头部带有金色冠羽，常见于安第斯山脉的云雾森林中，活跃于较高海拔地区。分布范围自秘鲁东部至阿根廷西北部的安第斯山脉东坡。","appearance":"体型较大的霸鹟，体长19至22厘米，体重约37克。成鸟具有褐色或灰褐色的冠羽，半隐的金色冠斑，宽阔的白色眉纹；头部侧面灰暗，脸颊下方和喉部呈淡黄色；上体颜色较为沉闷，橄榄色；臀部和尾上覆羽绿色橄榄色，尾羽覆羽边缘带有黄褐色或肉桂色；翅膀深色，飞羽和翼覆羽边缘带红棕色或橙黄褐色；尾巴深色，尾羽边缘略带红棕色；下巴白色，喉咙部分变为淡黄色；下体大部分为淡黄色，尤其是下腹部，胸部更偏黄，常被灰色橄榄色的云状花纹或斑点覆盖，胸侧有更明显的橄榄色条纹。","call":"发出尖锐的“de-wit”和“chew-di-wit”叫声，每几秒重复一次。","habits":"栖息于湿润的高山云雾林和潮湿的山地林地边缘，常见于由滑坡或倒木形成的中等大小的开阔地带，或靠近森林的高海拔牧场，通常活动于海拔600至2800米之间，但有时会下降至更低高度。季节性迁徙模式尚不清楚，但在委内瑞拉安第斯山脉，一月至三月期间数量稀少，六月和七月间特别活跃。","breeding":"繁殖习性知之甚少，已知在五月到七月期间处于繁殖状态，八月可见到雏鸟。巢建于树上，位于苔藓或根系缝隙中，也可利用啄木鸟旧巢穴或悬崖上的植被缝隙。巢呈浅而粗糙的杯状，由细根和苔藓构成。每窝产卵2至4枚，蛋壳呈粉红色并有深肉桂色和薰衣草色的斑点。","identification":"与金腹大嘴霸鹟相比，颜色稍淡，头部图案对比度较小，可通过白色胡须纹和缺乏白色喉咙，以及胸部微弱的条纹加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于安第斯山脉东坡，从秘鲁东部延伸至阿根廷西北部，包括哥伦比亚、厄瓜多尔、委内瑞拉等地。","other":"由于分类修订，本物种仅包含在秘鲁马兰翁河以南、玻利维亚和阿根廷发现的个体，北部的个体现归类于金腹大嘴霸鹟中。"},{"name":"比氏大嘴霸鹟","english_name":"Baird's Flycatcher","scientific_name":"Myiodynastes bairdii","overview":"比氏大嘴霸鹟（英文名：Baird's Flycatcher，学名：Myiodynastes bairdii），是雀形目霸鹟科大嘴霸鹟属的鸟类。大型、具有橄榄色背部和黄色腹部的霸鹟科鸟类。主要分布在南美洲的厄瓜多尔西南部和秘鲁西北部的干旱地区，栖息于海拔1000米以下的灌木丛和林地。该物种以其黑色面罩、白色眉纹和灰纹的喉咙为显著特征。","appearance":"比氏大嘴霸鹟体型较大，上体橄榄色，翼部和尾羽呈赤褐色，腹部黄色。头部带有独特的黑色面罩，前额淡沙棕色或近白色，喉部白色并带有轻微的灰色条纹。喙部粗壮，黑色，基部带粉色。虹膜呈栗褐色或灰褐色，跗跖和脚趾黑色或灰色。","call":"比氏大嘴霸鹟有时会发出低沉的三部分叫声。","habits":"该物种偏好在干旱地带的树顶、电线杆等高处栖息。以昆虫为主食，也会摄取水果。飞行时会从高处俯冲捕捉猎物。","identification":"与纹大嘴霸鹟（亚种 chapmani）的区别在于后者背部更偏棕色，腹部更白，且背部和胸部有重条纹。金顶大嘴霸鹟生活在较高海拔的湿润森林，面部图案更为鲜明，上体绿色更深，腹部黄色更浓。","protection":"IUCN：LC（无危）","distribution":"主要分布于南美洲的厄瓜多尔西南部和秘鲁西北部，栖息于海拔1000米以下的干旱地区。","other":"比氏大嘴霸鹟以19世纪自然学家Spencer Fullerton Baird的名字命名。"},{"name":"黄腹大嘴霸鹟","english_name":"Sulphur-bellied Flycatcher","scientific_name":"Myiodynastes luteiventris","overview":"黄腹大嘴霸鹟（英文名：Sulphur-bellied Flycatcher，学名：Myiodynastes luteiventris），是雀形目霸鹟科大嘴霸鹟属的鸟类。大型的霸鹟科飞鸟，以其独特的黄色腹部和粗犷的条纹著称。该物种分布于北美东南部亚利桑那州至哥斯达黎加，冬季迁徙至南美洲亚马逊地区的东部安第斯山麓过冬。繁殖期通常在夏季湿季到来时开始，选择峡谷中的梧桐树（Platanus sp.）作为筑巢场所。","appearance":"黄腹大嘴霸鹟体型中到大，长约18-20厘米，重45-49克，两性相似。头部特征明显，有白色眉纹和髭纹，黑色眼罩和颊纹。下颏黑色或有时白色，喉咙白色，其余下体为硫磺黄色，有深色粗条纹。冠至臀部呈灰色橄榄色，有较暗的条纹和斑点。下臀至尾基部大部分为红褐色，尾羽中央有暗色条纹。翅膀为深棕色，边缘有白色或淡肉桂色。喙结实，宽而黑，下颌基部可能有不明显的淡色区域。幼鸟与成鸟相似，但翼羽边缘更广泛地呈肉桂色，上体略带棕色，头顶黄色较少，最外侧尾羽有较窄的黑色条纹。","call":"其叫声独特，被描述为类似玩具发出的嘶嘶声，具体为“weel-yum weel-yum”（威廉姆斯叫声）或“squeez-ya”。在繁殖季节，叫声通常在迁徙北上时听到。","habits":"黄腹大嘴霸鹟偏好居住在海拔1000至2000米的山区峡谷森林中。它们在树洞或旧啄木鸟洞中筑杯状巢。以飞行昆虫为主要食物，也会吃浆果和种子。它们通常在高处的开放枝干上等待，然后飞出捕捉空中飞行的昆虫。","breeding":"繁殖期在夏季湿季，雌鸟会在树洞或旧啄木鸟洞中产下2至4枚蛋。","identification":"与杂色纹霸鹟和纹大嘴霸鹟区分，后者较小且喙较小，面部图案更鲜明，下体条纹更模糊。纹大嘴霸鹟叫声为鼻音重复的'behk!'，而黄腹大嘴霸鹟叫声为特有的尖锐哨声。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括美国西南部至哥斯达黎加，非繁殖区域位于南美洲亚马逊雨林西部。","other":"该物种于1859年首次正式描述，其在美国的出现最早记录于1874年的亚利桑那州Huachuca山脉。"},{"name":"纹大嘴霸鹟","english_name":"Streaked Flycatcher","scientific_name":"Myiodynastes maculatus","overview":"纹大嘴霸鹟（英文名：Streaked Flycatcher，学名：Myiodynastes maculatus），是雀形目霸鹟科大嘴霸鹟属的鸟类。体型较大的霸鹟科鸟类，广泛分布于中美洲至南美洲的广阔区域，从墨西哥东部至阿根廷。其显著特征为背上有条纹，尾部和头部顶部呈肉桂色。与相似的黄腹大嘴霸鹟相比，纹大嘴霸鹟具有更粗壮的喙和淡黄色的下体。","appearance":"纹大嘴霸鹟的头部呈棕色，头顶有一片隐蔽的黄色斑块，上体为棕色并带有深棕色条纹，翅膀边缘呈红褐色和白色，臀部和尾巴边缘宽阔的栗色。下体为淡黄白色，胸部、两胁和肛周有深色条纹。成年鸟和幼鸟相似，但幼鸟黑色部分为棕色，缺乏黄色顶冠。喙基部下颌呈粉色。","call":"纹大嘴霸鹟发出嘈杂的sqEEE-zip叫声。","habits":"这种鸟类偏好森林和边缘地带，尤其在高大的树木种植园中生活，主要在树冠的中上层活动。它们以大型昆虫（如蝉、蝗虫和甲虫）、蜥蜴和浆果为食，常从高处的观察点飞扑捕食，利用各种空中特技捕捉飞行中的昆虫或从植物上捕捉猎物，偶尔也会从植被中觅食。冬季迁徙的南部群体似乎会摄入大量果实。","breeding":"纹大嘴霸鹟在树洞或有时在凤梨科植物中筑开放式的巢杯，由树枝和草构成。雌鸟负责筑巢和孵化通常为两到三枚乳白色的带红褐色斑点的蛋，孵化期约为16至17天。雏鸟由双亲共同喂养，约在18至21天后离巢。","identification":"与黄腹大嘴霸鹟相比，纹大嘴霸鹟具有更粗的喙，更浅的黄色腹部，下颌基部粉色，超眉线呈奶油色而非白色。","protection":"IUCN：LC（无危）","distribution":"纹大嘴霸鹟分布于中美洲至南美洲，从墨西哥东部至乌拉圭。南部的亚种M. m. solitarius在南半球冬季（3月至9月）期间迁徙至委内瑞拉和圭亚那。"},{"name":"船嘴霸鹟","english_name":"Boat-billed Flycatcher","scientific_name":"Megarynchus pitangua","overview":"船嘴霸鹟（英文名：Boat-billed Flycatcher，学名：Megarynchus pitangua），是雀形目霸鹟科船嘴霸鹟属的唯一物种，分布于中美洲至南美洲东北部，从墨西哥至阿根廷东北部。其最显著的特征是巨大的黑色喙，赋予了它英文和学名。在繁殖季节，常可见于开放的林地带有高树的地方。","appearance":"成年船嘴霸鹟体型庞大，长可达23厘米，重约70克。头部呈黑色，具有一条明显的白色眼纹和隐藏的黄色冠带。上体为橄榄褐色，翅膀和尾巴为棕色，仅微弱的红褐色边缘。下体为黄色，喉部为白色。喙部异常宽大且沉重，黑色，这是与相似的大食蝇霸鹟区分的关键特征。","call":"发出尖锐颤音的‘nya, nya, nya’叫声，声音响亮且略带嘶哑，容易辨认。","habits":"栖息于多种森林和林地环境，从湿润到干旱和落叶林，尤其偏好半开阔地带，如草原、林间空地、种植园或密集覆盖区域的边缘，以及亚马逊地区的河岸和湖畔的várzea树冠。通常在中间至较高层次活动，偶尔在更开放的树上显眼位置停歇。以昆虫为主要食物，尤其是蝉，也会捕食小型脊椎动物，果实和种子。在捕食时，从栖息处飞出，通常在短距离内捕捉猎物，有时短暂悬停，但更常见的是猛烈地撞击树叶以获取猎物。","breeding":"筑巢期在特立尼达岛为2月至6月，哥伦比亚为7月至10月。巢由雌鸟建造，形状为一个较为浅平的杯状，主要由树枝、叶子、草、干藤蔓等材料构成，位于树干水平枝的分叉处，高度约为6至30米。每窝产卵2至3枚，卵为白色，带有大量的棕色斑点。孵化期大约为17至18天，主要由雌鸟负责。幼鸟孵化后约24天离巢。","identification":"通过其巨大的黑色喙和橄榄色的背部，以及缺乏红色的尾翼和翅膀，与大食蝇霸鹟相区别。叫声也有显著差异。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲东北部，从墨西哥至阿根廷东北部，包括特立尼达岛。","other":"在多个国家公园和其他保护区中普遍出现，适应性强，能够忍受生境退化。"},{"name":"黄白喉霸鹟","english_name":"Sulphury Flycatcher","scientific_name":"Tyrannopsis sulphurea","overview":"黄白喉霸鹟（英文名：Sulphury Flycatcher，学名：Tyrannopsis sulphurea），是雀形目霸鹟科黄白喉霸鹟属的唯一物种。这种中型飞禽以橄榄褐色上体、黄色下体的羽色模式让人联想到热带王霸鹟，但其脸部和头部更呈深灰，喉咙鲜明白色。广泛分布于亚马逊雨林及预亚马逊草原地带，尤其在Moriche棕榈树丛中最为常见。","appearance":"黄白喉霸鹟是一种体型相对较大的霸鹟，拥有厚实的喙。其头部主要是暗灰色，冠部有一隐蔽的橙黄色条纹。上体呈暗橄榄褐色，翅膀和尾巴为暗棕色。喉咙白色，带模糊的灰色条纹，上胸部白色，其余下体亮黄色，胸侧带有橄榄灰色的斑纹和晕染，两胁略带橄榄色。雄雌相似。","call":"黄白喉霸鹟的叫声独特且响亮，具有电击般的质感，通常在其现身前就能被听见，帮助人们轻易区分它与其他外观相似的霸鹟。","habits":"黄白喉霸鹟偏好多种森林环境，但在水淹和边缘生境中更为常见，尤其喜欢茂密的棕榈树，如Moriche棕榈。它们一般行动迟缓，成对活动，常在不显眼的枝头停留，然后飞向周围植被捕食昆虫，不同于王鹟类的开放枝头坐姿和空中捕食习惯。","breeding":"黄白喉霸鹟的巢通常位于Moriche棕榈树冠中，为开放式的杯状结构，由枯枝搭建，典型的窝卵数为两枚淡奶油色并带有棕色斑点的蛋。","identification":"与热带王霸鹟相比，黄白喉霸鹟拥有较短的喙和方形尾端，上体颜色更偏向棕色而非橄榄色，上胸部带有橄榄色斑点。与暗胸短嘴霸鹟的区别在于后者体型更小，冠部和头部侧面为棕色，叫声不同，胸侧有模糊的条纹。","protection":"IUCN状态未提供。","distribution":"分布于南美洲亚马逊雨林区域，包括特立尼达、圭亚那、委内瑞拉南部至秘鲁亚马逊地区、玻利维亚北部及巴西。","other":"黄白喉霸鹟的分类位置一度难以确定，分子技术的应用也未能完全阐明其亲缘关系，但因其独特的鸣管解剖特征，目前归于单独的黄白喉霸鹟属（Tyrannopsis）内。"},{"name":"杂色纹霸鹟","english_name":"Variegated Flycatcher","scientific_name":"Empidonomus varius","overview":"杂色纹霸鹟（英文名：Variegated Flycatcher，学名：Empidonomus varius），是雀形目霸鹟科杂色纹霸鹟属的鸟类。是杂色纹霸鹟属唯一现存物种。其体型中等，常见于森林冠层边缘、林地、草原及城市区域，偏好栖息于暴露枝头。","appearance":"头部图案复杂，具黑色眼罩与冠羽，宽阔的白色眉纹和髭纹。黑色冠羽中央有一黄色斑块，通常隐蔽。体羽条纹分明，臀部与尾部呈肉桂色。","call":"发出鼻音似的“pseeeu”叫声。","habits":"栖息于南美洲的多种生境，包括森林、木地、草原及城市环境。偏好在树梢活动。","breeding":"筑巢活动最早可记录至10月中旬，产卵期为11月末至12月，雏鸟出现在12月中旬。巢似扁球状，由小枝条和叶茎构成，内部衬以细根和叶脉，直径约15厘米，高7厘米，内径6厘米，蛋室深2厘米，重约40克。巢置于水平树枝分叉处，高度1至8米。每窝产2-3枚淡黄色带栗褐色和灰色斑点的蛋，尺寸约为20-21.5毫米×15-16毫米。孵化和离巢周期未知，有时巢被紫辉牛鹂寄生。","identification":"与海盗霸鹟相似，但体型更大，色彩更淡，尾部和臀部呈肉桂色，翅膀标记更为醒目。","protection":"IUCN状态未知。","distribution":"广泛分布于阿根廷、玻利维亚、巴西、巴拉圭、乌拉圭和圭亚那地区；偶尔出现在大陆更西北部。北美墨西哥以北地区罕见，仅记录十次：缅因州（1977年）、田纳西州（1984年）、安大略省（1993年、2020年）、华盛顿州（2008年）、佛罗里达州（2013年、2015年、2021年）、得克萨斯州（2016年）和密歇根州（2022年）。"},{"name":"冠灰纹霸鹟","english_name":"Crowned Slaty Flycatcher","scientific_name":"Griseotyrannus aurantioatrocristatus","overview":"冠灰纹霸鹟（英文名：Crowned Slaty Flycatcher，学名：Griseotyrannus aurantioatrocristatus），是雀形目霸鹟科冠灰纹霸鹟属的鸟类。曾以其科学名称长度成为最长鸟名的持有者。中等体型的灰褐色霸鹟，常见于高大森林树冠，迁徙期间大量个体进入亚马逊盆地，成为该地区常见的树冠观察对象。","appearance":"成年冠灰纹霸鹟上体呈灰褐色，具有黑色顶冠和半隐蔽的金黄色冠斑，眼线暗色，脸颊深色，上眉线灰色，下体浅灰色，腹部带黄褐色调。喙和跗蹠黑色。幼鸟与成鸟相似，但翼羽和内侧飞羽边缘有明显的白色边框，尾羽具细窄的红褐色边缘，上眉线颜色较淡且对比更明显。","call":"一般而言，对于一只霸鹟来说，它的鸣叫较为安静；其高音、嗡嗡作响的歌声主要在繁殖地听到。","habits":"繁殖季节偏好落叶和半湿润森林。高度迁徙，冬季主要栖息在亚马逊盆地的低地森林树冠层，觅食时需有足够的开阔空间以捕捉昆虫。","breeding":"在开放的林地中繁殖，最南可达阿根廷中部，常见于蒙特沙漠和查科地区的部分，是那里的常见鸟类之一。繁殖范围向北延伸至巴西中部的干旱地带。","identification":"成年冠灰纹霸鹟不易与其他物种混淆，比灰拟霸鹟体型大且具独特头部图案。幼鸟与杂色纹霸鹟相似，但缺乏后者特有的白色须纹和暗色喉咙侧条纹。","protection":"IUCN：LC（无危）","distribution":"在南美洲亚马逊雨林中南部和东南部繁殖，迁徙时广泛分布于西部和中央亚马逊盆地，除东南部与塞拉多和潘塔纳尔接壤地区外，冬季常驻于此。","other":"冠灰纹霸鹟有记录显示其有迷鸟倾向，已知有在美国路易斯安那州和委内瑞拉的迷鸟记录，以及智利北部的一次记录。"},{"name":"雪喉王霸鹟","english_name":"Snowy-throated Kingbird","scientific_name":"Tyrannus niveigularis","overview":"雪喉王霸鹟（英文名：Snowy-throated Kingbird，学名：Tyrannus niveigularis），是雀形目霸鹟科王霸鹟属的鸟类。分布于南美的哥伦比亚西南部至秘鲁西部。以独特的灰白黄三色外观著称，拥有醒目的白色喉咙和黄色腹部。","appearance":"雪喉王霸鹟的上体呈淡灰色，下体白色渐变为明亮的黄色腹面，头冠为灰色，中央藏有黄色斑块。面部两侧有黑色的面罩，翅膀深色边缘白色，尾巴平截而非叉状。成年个体的两性相似，喙粗壮，虹膜暗色，跗跖和趾暗色。","call":"其叫声尖锐，有时连续发出兴奋的颤音。","habits":"栖息于海拔500米以下的开阔地带和林缘，部分个体具有迁徙习性。雨季在落叶林和灌木丛中繁殖，之后可能分散到更湿润的地区。","breeding":"具体繁殖信息未详述。","identification":"与广泛分布的热带王霸鹟相比，雪喉王霸鹟体型较小，背部颜色较淡，喉咙白色更宽广明显，尾部平截。叫声也有显著差异。","protection":"IUCN状态未提供。","distribution":"繁殖区域位于南美洲，从哥伦比亚西南部延伸至秘鲁西部，主要栖息于亚热带或热带湿润低地森林和亚热带或热带干燥灌木丛。"},{"name":"白喉王霸鹟","english_name":"White-throated Kingbird","scientific_name":"Tyrannus albogularis","overview":"白喉王霸鹟（英文名：White-throated Kingbird，学名：Tyrannus albogularis），是雀形目霸鹟科王霸鹟属的大型鸟类。广泛分布于南美洲东部的亚马逊盆地，包括巴西中部地区。其最显著的特征是拥有灰白色的头部，与深色面罩形成鲜明对比，以及纯净的白色喉咙。","appearance":"体长20至21厘米，体重35至38克。头部大多呈淡灰色，头顶为白色，隐藏着淡橙色或淡黄色的冠斑；面部有从眼窝延伸到耳羽的暗色带，营造出独特的面具外观；背部明亮橄榄绿色，翅膀暗黑褐色，次级飞羽边缘较浅，翼盖边缘亦然；尾巴相对较长，呈叉状，黑色；喉咙纯白；下体鲜黄色，胸部可能隐约可见橄榄色调；虹膜深色；喙大而粗壮，颜色深；腿黑色。","call":"叫声为尖锐的颤音“tic-tic-tic”。","habits":"栖息于各种生境，从森林边缘到开阔地带和牧场，再到林地和城市区域；迁徙期间几乎可以在任何地方出现。其自然栖息地包括亚热带或热带湿润的低地森林和亚热带或热带湿润的灌木丛。","identification":"与热带王霸鹟相似，但头部颜色更淡，面罩和喉咙的对比更明显。雄雌外观相同。","protection":"IUCN状态未知。","distribution":"分布于极端东南委内瑞拉（博利瓦尔州东南部）、圭亚那地区，穿越大部分中巴西（帕拉州、阿马帕州和托坎廷斯州南部至马托格罗索杜苏尔州、圣保罗州、米纳斯吉拉斯州和巴伊亚西部），到达玻利维亚北部（贝尼州、圣克鲁斯州北部）。在非繁殖季节迁徙至亚马逊西部，远至哥伦比亚东南部和秘鲁东部。","other":"在冬季，其分布区会向东扩展至cerrado地区（北部部分为过境迁徙区），并向北进入圭亚那高地，除了沿海区域（向东至马拉若岛）。"},{"name":"热带王霸鹟","english_name":"Tropical Kingbird","scientific_name":"Tyrannus melancholicus","overview":"热带王霸鹟（英文名：Tropical Kingbird，学名：Tyrannus melancholicus），是雀形目霸鹟科王霸鹟属的鸟类。广泛分布于中美洲和南美洲，从美国西南部至阿根廷中部和东部秘鲁，亦见于特立尼达和多巴哥。其黄腹显著，是中南美洲开放森林、森林边缘、灌木丛和农地的常见居民。","appearance":"成年热带王霸鹟长约22厘米（8.7英寸），体重约39克，翼展38至41厘米。头部呈淡灰色，具深色眼罩，橙色冠条不显，喙厚实灰暗。背部橄榄灰色，翅膀和微叉的尾巴棕色。喉咙淡灰色，胸部橄榄色，其余下体黄色。两性相似，但幼鸟翼覆羽边缘呈淡黄褐色。","call":"高音清脆的颤鸣声，\"tree-e-e-e-e-e-e\"，雄鸟黎明时会唱更复杂的版本。","habits":"栖息于半开放地带，如带有树木和灌木的环境，包括花园和路旁。常在高树上显眼的位置观察四周，飞行捕捉空中昆虫，有时悬停以从植被上拾取食物。食物包括甲虫、蜜蜂、黄蜂、白蚁、蝴蝶、蛾、蜻蜓和蚱蜢，也会食用浆果和水果。","breeding":"似乎为一夫一妻制。繁殖期，雌雄共同选择筑巢地点，通常位于树的分叉处。雌鸟用藤蔓、根须、树枝、杂草和草搭建松散的巢，偶尔内衬毛发。每窝产2到4枚蛋，由雌鸟孵化约16天，雏鸟在18至19天后离巢。","identification":"与库氏王霸鹟极为相似，最佳区分方式是通过鸣叫声。比西王霸鹟和卡氏王霸鹟体型更大，喙更长，尾羽颜色更淡。与南美洲的白喉王霸鹟和雪喉王霸鹟也有相似之处，但后者体型较小，面侧更暗，下体黄色较浅。","protection":"IUCN：LC（无危）","distribution":"繁殖区从美国西南部延伸至南美的阿根廷中部和秘鲁东部。非繁殖季节，最北端和最南端的群体迁往温暖地带。","other":"热带王霸鹟在部分范围内全年可见，是当地最知名和最广泛的鸟类之一。"},{"name":"库氏王霸鹟","english_name":"Couch's Kingbird","scientific_name":"Tyrannus couchii","appearance":"成年库氏王霸鹟长约20-24厘米，体重约40克。头部灰色，下巴和喉咙白色，面部有黑色眼罩，其余下部黄色，除胸部略显暗色；背部和肩羽橄榄灰色，翅膀和尾巴黑褐色，尾巴微凹。头部有一个通常隐藏的小红橙色斑块。喙、腿和脚黑色。雄鸟和雌鸟外观相似，全年羽毛相似，但繁殖季节（3月至8月）可通过雄鸟的泄殖腔突起（发育不良）和雌鸟的孵卵斑来区分。初级飞羽6-10的缺口在雄鸟中超过8毫米，在雌鸟中不到8毫米，这一特征在幼鸟的初级飞羽替换后更为明显。幼鸟与成鸟相似，但整体较为暗淡，翼覆羽和上尾覆羽尖端呈肉桂色，眉纹和颊部区域较浅，与深色面罩形成对比，冠部红橙色斑块缺失。","call":"库氏王霸鹟的叫声包括缓慢重复的‘pit’（或‘kip’）和‘pitweeeer’，与热带王霸鹟快速重复的金属质感‘pit’叫声明显不同。","habits":"库氏王霸鹟栖息于轻度森林化地区，如稀疏森林、郊区地带、荆棘林和树木边缘，偏好靠近水源，如河流附近，也常见于道路旁和森林边缘。它主要以昆虫为食，偶尔也吃小浆果和种子。其捕食行为包括在枝头观察环境中的昆虫动态，然后在空中捕捉猎物，或悬停捕食，亦或迅速俯冲捕捉。","breeding":"关于库氏王霸鹟的繁殖行为细节尚不清楚，但据信与热带王霸鹟相似。它们倾向于在轻度森林化的环境中筑巢，常见的巢址树种包括糖刺槐、雪松榆、得克萨斯黑檀和墨西哥白蜡树。巢由雌鸟建造，呈扁平杯状，由树枝、树叶、杂草、苔藓和树皮构成，内部铺垫柔软材料如根须、植物绒毛和西班牙苔藓。巢水平位于离地面8-25英尺的高枝上，由成鸟积极守护，驱赶靠近巢穴的大鸟。孵化期未知，但估计由雌鸟孵化约两周以上。雌鸟每次产卵3-4枚，卵呈粉红色底，带有深棕色和淡紫色斑点。幼鸟出生后约2-3周首次飞行，期间双亲共同喂养。","identification":"库氏王霸鹟与热带王霸鹟在外观上极为相似，但在叫声上有显著区别，库氏王霸鹟的叫声更为复杂且音调多变。此外，库氏王霸鹟更偏好密集的树木生长环境，而热带王霸鹟则偏好更为开阔的环境。与卡氏王霸鹟相比，库氏王霸鹟的胸部颜色更深，喙较小，尾羽末端白色；与西王霸鹟的区别在于后者胸部有一片灰色区域延伸至头部，而库氏王霸鹟没有。","protection":"IUCN：LC（无危）","distribution":"库氏王霸鹟的繁殖区主要在德克萨斯州南部和墨西哥东部，向南延伸至伯利兹。其非繁殖区覆盖了墨西哥东部至伯利兹，以及美国德克萨斯州南部。","other":"库氏王霸鹟最初由Darius N. Couch在1853年发现，之后曾被归类为热带王霸鹟的亚种，直到1979年才重新分类为独立物种。"},{"name":"卡氏王霸鹟","english_name":"Cassin's Kingbird","scientific_name":"Tyrannus vociferans","overview":"卡氏王霸鹟（英文名：Cassin's Kingbird，学名：Tyrannus vociferans），是雀形目霸鹟科王霸鹟属的鸟类。广泛分布于美国西南部和墨西哥西部，以其侵略性的行为和响亮的叫声而闻名。学名反映了其面对潜在天敌和同种竞争者的咄咄逼人性格。这种鸟以明亮的黄色腹部、暗灰色头部和白色髭纹为显著特征，黑色尾巴尖端带有白色。在开阔、干燥的生境中，如高大的灌木丛和树林中，卡氏王霸鹟尤其显眼，偶尔也会出现在山区的空地和草甸上。与西王霸鹟相比，头部颜色对比更鲜明。","appearance":"成年卡氏王霸鹟体型较大，长度约为21-23厘米，体重约45克。头部暗灰，橙红色冠斑隐藏于成年个体中，喙宽而尖。白色下巴与暗灰色头部形成鲜明对比；喉咙和上胸灰色，其余下体黄色，灰黄之间界限分明。背部略淡于长翼（主翼羽10鸣叫特征：发出粗糙的“ch-breer”叫声。生活习性：卡氏王霸鹟偏好干旱地区的开阔生境，常在高大灌木和树木中发现，有时会出现在山区的空地和草甸。它们是部分迁徙的物种，美国和北部墨西哥的个体秋季向南迁移。在中央和南部墨西哥，有一部分种群全年居住于此。卡氏王霸鹟的繁殖海拔高于其他北美王霸鹟种类。它们选择筑巢的大树因地理位置而异，如杨树、柳树、橡树和松树在干旱地区常见。生长繁殖：在迁徙种群中，卡氏王霸鹟每年只抚养一窝幼鸟。雌鸟负责收集巢材、筑巢、孵卵和孵化，而雄鸟则守候附近。两性都参与喂养幼鸟，但雌鸟喂养时间远超雄鸟。区别辨识：与厚嘴王霸鹟、热带王霸鹟、库氏王霸鹟和西王霸鹟等其他黄色腹部王霸鹟容易混淆。卡氏王霸鹟的喙较薄，头部颜色对比鲜明，尾部不呈缺口状，翅膀更长，初级飞羽凹陷不明显，且叫声与其他几种王霸鹟有所不同。保护现状：IUCN：LC（无危）地理分布：繁殖季节分布于美国南部至伯利兹，冬季迁徙至南加州至北中美洲中部。在南中墨西哥为留鸟，主要越冬区域位于加利福尼亚湾西侧的下加利福尼亚州南部，以及东海岸的西墨西哥内陆。其他：卡氏王霸鹟与西王霸鹟在地理和生态位上有重叠，但两者间的竞争似乎较小，尤其是在昆虫丰富的巢穴和觅食环境中。请点击或扫描二维码下载 懂鸟 App，了解更多卡氏王霸鹟的全球分布信息\n\n\n\n\n\n\n\n\n\n\n请使用微信扫描以下二维码进入懂鸟小程序了解更多卡氏王霸鹟的信息：","call":"发出粗糙的“ch-breer”叫声。","habits":"卡氏王霸鹟偏好干旱地区的开阔生境，常在高大灌木和树木中发现，有时会出现在山区的空地和草甸。它们是部分迁徙的物种，美国和北部墨西哥的个体秋季向南迁移。在中央和南部墨西哥，有一部分种群全年居住于此。卡氏王霸鹟的繁殖海拔高于其他北美王霸鹟种类。它们选择筑巢的大树因地理位置而异，如杨树、柳树、橡树和松树在干旱地区常见。","breeding":"在迁徙种群中，卡氏王霸鹟每年只抚养一窝幼鸟。雌鸟负责收集巢材、筑巢、孵卵和孵化，而雄鸟则守候附近。两性都参与喂养幼鸟，但雌鸟喂养时间远超雄鸟。","identification":"与厚嘴王霸鹟、热带王霸鹟、库氏王霸鹟和西王霸鹟等其他黄色腹部王霸鹟容易混淆。卡氏王霸鹟的喙较薄，头部颜色对比鲜明，尾部不呈缺口状，翅膀更长，初级飞羽凹陷不明显，且叫声与其他几种王霸鹟有所不同。","protection":"IUCN：LC（无危）","distribution":"繁殖季节分布于美国南部至伯利兹，冬季迁徙至南加州至北中美洲中部。在南中墨西哥为留鸟，主要越冬区域位于加利福尼亚湾西侧的下加利福尼亚州南部，以及东海岸的西墨西哥内陆。","other":"卡氏王霸鹟与西王霸鹟在地理和生态位上有重叠，但两者间的竞争似乎较小，尤其是在昆虫丰富的巢穴和觅食环境中。"},{"name":"厚嘴王霸鹟","english_name":"Thick-billed Kingbird","scientific_name":"Tyrannus crassirostris","overview":"厚嘴王霸鹟（英文名：Thick-billed Kingbird，学名：Tyrannus crassirostris），是雀形目霸鹟科王霸鹟属的大型飞禽。其最显著的特征是拥有巨大的喙，上体呈暗灰褐色，喉部白色，腹部带有淡黄色。该鸟种常见于棉木林附近的河岸地带，偏爱大梣树和棉木丛生的环境。","appearance":"成鸟体长22-24厘米，体重50-60克，雌雄外观相似。上体深灰褐色，头部稍暗，冠部中央有黄色斑块（通常隐藏）。下体白色，胸腹部带淡灰色，腹部和尾下覆羽带不同程度的淡黄色。幼鸟与成鸟类似，但冠部无黄色，翼覆羽和尾羽边缘红棕色，下体更黄。喙巨大且结实，为该物种最显著特征。","call":"发出尖锐的哨声和啾啾声。","habits":"偏好栖息于干旱或半干旱地区的河岸峡谷，或靠近水源的开阔地带。常见于梣树林边缘。以空中捕食昆虫为主，常从高处的栖息点飞出捕捉飞行中的猎物。","breeding":"繁殖期在树干附近6米以上高度的树枝上筑巢，雌鸟产卵3-5枚。","identification":"与同属其他大型霸鹟相比，厚嘴王霸鹟的喙明显更大更粗壮，上体颜色较暗，下体颜色较浅，且腹下部常带淡黄色。与东王霸鹟相比，体型略小，上体非灰黑色，下体纯白，尾端无白色。","protection":"IUCN：LC（无危）","distribution":"分布于北美和中美洲，从美国西南部至危地马拉。在美国主要见于亚利桑那州东南部和新墨西哥州西南部，以及墨西哥西部沿海山脉，南至危地马拉西部。","other":"在繁殖季节外，美国的个体可能会向南迁徙过冬。"},{"name":"西王霸鹟","english_name":"Western Kingbird","scientific_name":"Tyrannus verticalis","overview":"西王霸鹟（英文名：Western Kingbird，学名：Tyrannus verticalis），是雀形目霸鹟科王霸鹟属的鸟类。体型较大的黄腹霸鹟，常见于北美洲西部，从加拿大西北部和中北部直至墨西哥北部繁殖，冬季迁徙至墨西哥西南部至哥斯达黎加。其显著特征包括淡灰色头部，对比不强烈的白色喉部和胸部，以及柠檬黄色腹部。黑色尾巴边缘呈白色，这一特征在良好状态下较为明显，尤其是在空中飞行时。该鸟种广泛分布于开阔地带，包括树丛和高大灌木，常在电线杆或围栏上显眼地栖息。","appearance":"西王霸鹟拥有较大的体型，身长介于20.3至24.1厘米之间，雄鸟的平均体重约为38.5克，雌鸟则约为37.3克。两性在羽毛颜色上相似，但在雄鸟中，初级飞羽较长，外侧初级飞羽更呈缺刻状。繁殖季节中，雌鸟可通过孵卵斑来识别。头部和胸部呈淡灰色，面部有较暗的灰色面罩，从喙延伸到耳部区域，其余下体部分为硫磺黄色，翅膀为棕黑色，尾巴为黑色，最外侧尾羽边缘为白色，喙为黑色。头顶中部有一小块橙红色羽毛，通常隐藏不见。幼鸟下方的羽毛为较浅的柠檬黄色，上翼覆羽边缘较宽，呈淡色。","call":"西王霸鹟的鸣叫声包括一系列尖锐的、类似玩具吱吱声的歌曲，以及尖锐响亮的“whit”叫声。在日出前偶尔会鸣唱。","habits":"西王霸鹟栖息于开阔地带，包括河流边森林、树林、草原、灌木地、农田（牧场和耕地）、沙漠和城市区域。它们利用开放区域觅食，树木和灌木用于筑巢和栖息；人造结构如电线杆也被用作筑巢场所。主要以昆虫为食，包括蜜蜂、强盗蝇、带翅蚂蚁、蚱蜢和蜘蛛，也会食用浆果、山茱萸/漆树和毒葛种子。这些鸟类会成群迁徙至佛罗里达州和墨西哥南部及中美洲太平洋沿岸。","breeding":"西王霸鹟在树或灌木中建造坚固的杯状巢，有时在电线杆或其他人造结构顶部。每窝产三到五枚白色、奶油色或粉红色的蛋，带有深棕色、黑色或薰衣草色的重斑点，孵化期为12至14天。由于巢穴较小，雏鸟快速成长，大部分雏鸟在羽毛未完全长成之前，因巢内拥挤而被挤出巢外。","identification":"西王霸鹟与卡氏王霸鹟、热带王霸鹟和库氏王霸鹟在外形上有相似之处，但可以通过尾羽最外侧的白色边缘（在良好状态下更为明显）、比热带和库氏王霸鹟更小的喙以及略小于卡氏王霸鹟的体型来区分。此外，卡氏王霸鹟的头部、背部和胸部颜色更深，尾羽尖端为白色或浅灰色，喉咙与头部颜色对比更强烈。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖北美，从加拿大西北部和中北部至墨西哥北部；非繁殖区域则南至墨西哥西南部至哥斯达黎加。","other":"自19世纪末以来，随着人类定居者改变栖息地，西王霸鹟的繁殖范围逐渐扩大。例如，在达科他州和加拿大南部的北部混合草原，由于树木种植，使得该鸟种能够向东扩展。在其他地区，如德克萨斯州，森林清理和电线杆及电线的增生也促进了其范围的扩张。"},{"name":"剪尾王霸鹟","english_name":"Scissor-tailed Flycatcher","scientific_name":"Tyrannus forficatus","overview":"剪尾王霸鹟（英文名：Scissor-tailed Flycatcher，学名：Tyrannus forficatus），是雀形目霸鹟科王霸鹟属的鸟类。以其极长、深叉的尾巴而著称，全身呈淡灰色，翅膀和尾羽较暗，腹部带有鲑鱼色的斑纹。在繁殖季节，常可见它们在德克萨斯州和邻近州的开阔地带活动，尤其喜欢停留在围栏和电线杆上。冬季则主要在墨西哥太平洋沿岸和中美洲聚集。","appearance":"剪尾王霸鹟拥有长而深叉的尾巴，成年鸟整体呈淡灰色，翅膀和尾羽颜色较深，腹部有鲑鱼色的斑纹。雄鸟比雌鸟的尾巴更长，平均而言，雄鸟的尾巴长度比雌鸟长30%左右。幼鸟色彩较淡，尾巴也比成年鸟短。成年鸟体重约39克，不包括尾巴的身长约为11厘米，翼展可达15厘米。","call":"剪尾王霸鹟发出响亮、尖锐且略带嘶哑的叫声，通常在领地防御或求偶时表现得更为明显。","habits":"剪尾王霸鹟偏好开阔地带，如草原、灌木丛、农业区和城市环境，以空中捕食昆虫为主，尤其是蚱蜢和甲虫。它们通过从栖息地向地面俯冲的方式捕食。繁殖季节主要在春季至夏季，非繁殖季节则迁移至南部墨西哥和中美洲。","breeding":"繁殖期为4月至8月。它们在孤立的树木或灌木中筑杯状巢，有时也会利用人造地点，如城镇附近的电话杆。雄鸟会进行壮观的空中求偶展示。雌鸟独自筑巢并孵化，雄鸟参与喂养幼鸟。每窝产3至6枚卵。","identification":"与同属的其他种类相比，剪尾王霸鹟的最显著特征是其极端延长的尾羽。与叉尾王霸鹟相比，剪尾王霸鹟的羽毛色泽更浅，翼下有鲑鱼色的斑纹。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要位于北美的美国中南部至墨西哥东北部。非繁殖期则分布于墨西哥西部至巴拿马。","other":"剪尾王霸鹟是俄克拉荷马州的州鸟，也是FC Tulsa职业足球队徽章上的标志性图案。"},{"name":"叉尾王霸鹟","english_name":"Fork-tailed Flycatcher","scientific_name":"Tyrannus savana","overview":"叉尾王霸鹟（英文名：Fork-tailed Flycatcher，学名：Tyrannus savana），是雀形目霸鹟科王霸鹟属的鸟类。体型较大的霸鹟科鸟类，以极长的分叉尾巴著称，与剪尾王霸鹟共同成为美洲大陆尾巴最长的鸟类种类之一。广泛分布于中美洲和南美洲的开阔地带，从墨西哥南部直至乌拉圭，是该区域内特有的景观。","appearance":"叉尾王霸鹟具有显著的黑头和淡灰色背部，与白色腹部形成鲜明对比。成年雄鸟的尾巴异常长，呈独特的琴弦状，长度甚至超过身体。雌鸟的尾巴较短，而幼鸟的尾巴更短，头部呈烟灰色，背部略带褐色。成年鸟的翼展和尾部特征明显区别于幼鸟和雌鸟。","call":"叉尾王霸鹟发出干涩、嘈杂的叫声，飞行中伴有弱‘tic-note’音调。","habits":"这种鸟偏好栖息在草地、开阔地形和稀树草原等环境，常在围栏、低矮灌木乃至地面歇息。它们的飞行强健有力，尾巴在身后划出优美弧线。部分种群展现高度迁徙行为，偶尔在非传统栖息地被发现，甚至远至加拿大。","breeding":"繁殖季节因亚种和地理位置而异，通常从夏末延续至冬季中期。筑巢地点选择在类似狩猎场的生境中，如河岸森林或草地。每窝产卵1-3枚。","identification":"与东方王霸鹟相比，叉尾王霸鹟的尾部更为延长，且无尾端白色条纹。成鸟在新鲜羽衣状态下的长分叉尾几乎无可混淆。","protection":"IUCN：LC（无危）","distribution":"主要分布于中美洲至南美洲，自墨西哥南部至乌拉圭，覆盖了巴西、玻利维亚、巴拉圭、乌拉圭和阿根廷（南至里奥内格罗省），越冬时向北迁至亚马逊地区，遍及奥里诺科河流域及特立尼达和多巴哥。","other":"在迁徙期间，叉尾王霸鹟展现出群居特性，可能形成多达一万个个体的大型群体。"},{"name":"东王霸鹟","english_name":"Eastern Kingbird","scientific_name":"Tyrannus tyrannus","overview":"东王霸鹟（英文名：Eastern Kingbird，学名：Tyrannus tyrannus），是雀形目霸鹟科王霸鹟属的鸟类。广泛分布于北美地区。其体长介于19至23厘米，重约33至55克。羽毛上部呈现深灰蓝色，下部为洁净的白色，头部略带黑色，尾巴末端显著的白色为其显著特征。繁殖季节活跃于北美各地，冬季则迁徙至南美洲。","appearance":"东王霸鹟体型中等，拥有结实的身体和较大的头部，站立姿态笔直，尾部呈方形且末端带有醒目的白色。上身颜色较深，近似暗灰黑，而下身则为纯白色。头部颜色比背部更黑，尾部黑色并有明显的白色尖端。雄鸟和雌鸟在外表上相似，但雄鸟的两根最外侧初级飞羽（p9和p10）的尖端有更明显的凹陷。雄鸟还倾向于保持稍微竖起的短冠，这在雌鸟中较少见。","call":"东王霸鹟的叫声为高音调的、嗡嗡作响且缺乏音乐性的啾啾声，常被比喻为类似电动围栏发出的声音。","habits":"东王霸鹟偏好开阔地带，如牧场、草地、湿地旁或森林边缘，常在树顶、电线或篱笆上停栖，以捕捉飞行中的昆虫为食。它们具有强烈的领地意识，会积极地保卫巢穴，甚至对抗体型远大于自身的鸟类。迁徙时，它们会成群前往南美洲。","breeding":"东王霸鹟在北美的开放区域筑巢繁殖，巢为坚固的杯状，通常建在树上或灌木丛中，偶尔也会选择树桩或杆子顶部。繁殖期间，雌雄双方共同参与巢的防御，但雌鸟可能会在隐藏得较好的巢中停留更长时间。巢的隐蔽程度影响着雌鸟的警惕行为，以驱赶潜在的捕食者。巢穴可能受到乌鸦、松鼠、攀树蛇和蓝松鸦等的威胁。","identification":"东王霸鹟与厚嘴王霸鹟和灰王霸鹟相似，但可通过体型、颜色差异和尾部白色尖端的存在与否加以区分。厚嘴王霸鹟体型更大，上体灰褐色，下体更灰，喙部更厚重，缺乏白色尾尖。灰王霸鹟也比东王霸鹟大，上体灰白，同样缺乏白色尾尖。","protection":"IUCN：LC（无危）","distribution":"东王霸鹟在北美广泛繁殖，从加拿大南部到美国大部分地区，西至太平洋沿岸的华盛顿州。冬季迁徙至南美洲亚马逊雨林西部。","other":"尽管在某些地区常见，东王霸鹟长期面临人口数量下降的趋势，这一现象在许多空中捕食昆虫的鸟类中普遍存在。"},{"name":"灰王霸鹟","english_name":"Grey Kingbird","scientific_name":"Tyrannus dominicensis","overview":"灰王霸鹟（英文名：Grey Kingbird，学名：Tyrannus dominicensis），是雀形目霸鹟科王霸鹟属的鸟类。常见于南佛罗里达州的红树林沼泽和加勒比海地区。以典型的灰色外观和独特的叫声闻名，常被当地人以拟声词命名。灰王霸鹟主要分布在加勒比海岛屿、美国东南部沿海地区以及中美洲至南美洲北部。","appearance":"灰王霸鹟体型中等，长约23厘米，上体呈均匀的灰色，下体白色，胸部略带灰色调。头部有黑色面罩，翼上有淡色翼斑，尾羽深灰色，无白色边缘。嘴大而黑，基部厚实，尖端钩状。成鸟和幼鸟的区别在于，幼鸟的翼覆羽、臀部和尾羽边缘呈锈红色。","call":"发出响亮滚动的颤音叫声，'pipiri, pipiri'，这一特征也是其多个地方名称的由来，如在西班牙语加勒比海地区被称为pestigre或pitirre，在英语岛屿中称为petchary。","habits":"灰王霸鹟偏好高树和灌木丛，包括稀树草原和沼泽边缘。它们会猛烈地保卫领地，驱赶入侵者，包括哺乳动物和体型较大的鸟类。主要以昆虫为食，偶尔也吃小果实、浆果、蜘蛛和小型蜥蜴。","breeding":"在树上筑造简易的杯状巢，通常由雌鸟孵育两枚带有红棕色斑点的乳白色蛋。","identification":"与东王霸鹟相比，灰王霸鹟上体颜色更浅，喙更大，尾部无白色末端，下体无黄色。与呆头伯劳的区别在于后者有黑色翅膀、尾巴和翅膀上的白色标记。","protection":"IUCN：LC（无危）","distribution":"繁殖于美国东南部，尤其是佛罗里达州，以及整个西印度群岛。非繁殖季节分布于中美洲巴拿马至圭亚那一带。","other":"尽管灰王霸鹟性格显眼，但其生活史的许多方面仍缺乏定量数据。"},{"name":"巨王霸鹟","english_name":"Giant Kingbird","scientific_name":"Tyrannus cubensis","overview":"巨王霸鹟（英文名：Giant Kingbird，学名：Tyrannus cubensis），是雀形目霸鹟科王霸鹟属的鸟类。大型的霸鹟科飞禽，体型庞大，具有明显的黑色冠羽和面部特征，与东方王霸鹟、灰王霸鹟和秃头王霸鹟相似，但其拥有独特的大嘴。分布于古巴，曾广泛存在，现已在巴哈马群岛南部和特克斯和凯科斯群岛灭绝。","appearance":"体长23至26厘米，头部大而圆，扁平外观。上身灰色，翅膀暗灰色，翼羽和翼覆羽边缘白色或灰白色。尾巴略呈凹状，比背部稍暗，有时尾羽尖端较淡。全身下方白色，有时胸部上方带有浅灰色。虹膜深棕色，喙巨大，黑色，腿黑色。雄鸟和雌鸟外观相似，幼鸟类似成年个体，但缺少橙色冠斑。","call":"叫声包括嘶哑的“trrp-bee-bee-bip”、尖锐的“trrree-bip”以及各种啾啾声和叽叽喳喳声。","habits":"栖息于高大的低地森林，尤其是松树森林，河流和沼泽的林木边缘。在旱季，会在相对开放的区域树木和棕榈树中觅食。以大型飞虫为主食，也吃大量果实，偶尔捕食蜥蜴和其它鸟类的幼鸟。成对出现，常在较高的位置，树上的显眼枝条上休息。","breeding":"繁殖季节为3月至6月，巢杯状，由根、干草和小树枝构成，通常建在大树（如Ceiba pentandra）水平枝叉的高处。一窝产2至3枚卵。","identification":"与东方王霸鹟的区别在于后者有明显的白色尾带，而巨王霸鹟没有。与灰王霸鹟相比，巨王霸鹟的头部颜色更深，没有尘土色的面具。与秃头王霸鹟的区别在于后者有灰色的尾带，尾巴形状通常是方形而非凹形。","protection":"IUCN：EN（濒危）","distribution":"古巴东部山区和一些特定地点是其主要分布区，包括Península de Guanahacabibes、Mil Cumbres、Monte de Regino、Sierra de Anafe、El Copey、Trinidad附近、Sierra de Najasa、Cabo Cruz、Macizo de Nipe-Sagua-Baracoa和Moá东南部的云雾林。在Pine Island也有发现。","other":"全球数量不足1000只成熟个体，曾在20世纪中期在松树林中较为常见。"},{"name":"圆头王霸鹟","english_name":"Loggerhead Kingbird","scientific_name":"Tyrannus caudifasciatus","overview":"圆头王霸鹟（英文名：Loggerhead Kingbird，学名：Tyrannus caudifasciatus），是雀形目霸鹟科王霸鹟属的鸟类。广泛分布于大安的列斯群岛，包括巴哈马、开曼群岛、古巴、海地、多米尼加共和国、牙买加、波多黎各以及北美南部的佛罗里达州。其显著特征为黑色头部、橙色或黄色的半隐蔽冠斑、灰色上部和白色下部，尾巴呈方形末端，有淡白色的端带。","appearance":"成年圆头王霸鹟体长约23厘米，重41.3至52克，头部呈黑色，具黄色或淡橙色的半隐蔽冠斑，背部暗灰，翼部主要为深灰色，翼羽覆羽边缘明显白色。尾部钝端，暗灰色，尾羽尖端为淡白色，下体大部分白色，腹部和臀部有黄色晕染。虹膜深色，喙长而厚实，黑色，腿也是黑色。雄雌相似，幼鸟与成鸟相似，但有褐色翼杠，无冠斑。各亚种间差异主要体现在羽毛的黄色程度和尾尖图案上。","call":"其叫声包括各种颤音和叽叽喳喳声。","habits":"圆头王霸鹟栖息于森林、红树林和沼泽边缘，也出现在古巴的低地灌木丛中。在巴哈马群岛、古巴、牙买加和开曼群岛，它在冬季会扩展栖息地至花园、居住区和开阔森林。以飞虫、小果实、浆果和小型蜥蜴为食，通过从低到中高度的栖息处突袭猎物，有时类似啄木鸟的方式觅食。","breeding":"繁殖期主要在2月至7月，偶尔在11月至1月。巢呈杯状，由枝条、根须和毛发构成，通常位于水平树枝分叉处，距离地面2至14米。每窝产卵2至4枚，平均3.1枚，蛋色从白色到浅红色，带有红棕色、棕色、紫色或灰色标记，大小在不同岛屿间有变异性。","identification":"与灰王霸鹟的区别在于其比例较小的喙、更显眼的白色尾尖和头部与背部更鲜明的对比。与巨王霸鹟相比，喙较粗壮，且缺乏白色尾带。","protection":"IUCN：LC（无危）","distribution":"圆头王霸鹟在大安的列斯群岛广泛分布，包括巴哈马群岛、开曼群岛、古巴、海地、多米尼加共和国、牙买加、波多黎各，偶尔出现在美国佛罗里达州南部。在古巴，其分布包括多个国家公园和其他保护区。"},{"name":"灰悲霸鹟","english_name":"Greyish Mourner","scientific_name":"Rhytipterna simplex","overview":"灰悲霸鹟（英文名：Greyish Mourner，学名：Rhytipterna simplex），是雀形目霸鹟科悲霸鹟属的鸟类。中大型的单色调飞禽。主要分布在南美洲的亚马逊雨林区域，包括巴西东部、东南部，以及玻利维亚、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉等地。其自然栖息地为亚热带或热带湿润的低地森林。","appearance":"雄性灰悲霸鹟拥有均匀的灰色羽毛，搭配深红色的眼睛，而雌鸟和幼鸟则呈现出棕色的翼缘和尾巴。整体上，它们的体型较大，色彩相对单一。","call":"灰悲霸鹟的鸣唱独特，是一连串快速而响亮的“tr-tr-tr-chew”声，其中“chew”音节尤为突出，是黎明合唱团中的显著成员。","habits":"它们偏好栖息于湿润森林的中上层，常与其他多种鸟类组成的混群中活动。灰悲霸鹟主要以昆虫为食，偶尔也会摄取水果或小型脊椎动物。","identification":"与尖声伞鸟非常相似，但灰悲霸鹟体型较小，眼睛更偏红褐色。","distribution":"灰悲霸鹟广泛分布于南美洲的亚马逊雨林，包括巴西的东部和东南部，以及邻近的多个国家。"},{"name":"淡腹悲霸鹟","english_name":"Pale-bellied Mourner","scientific_name":"Rhytipterna immunda","overview":"淡腹悲霸鹟（英文名：Pale-bellied Mourner，学名：Rhytipterna immunda），是雀形目霸鹟科悲霸鹟属的鸟类。主要栖息于季节性洪水泛滥的白砂木地和灌木丛生地带。","appearance":"中等体型，外观较为暗淡的霸鹟；与Myiarchus属相似，但嘴较小，头部更圆，胸部与腹部颜色差异不大。具体羽毛颜色和细节需参考专业图鉴。","call":"具有独特的鸣声，是一种丰富而滑音的哨声，其音质类似于Schiffornis，与栖息地内的其他物种截然不同。","habits":"栖息于季节性水淹和灌木林地的白砂区域，行为隐蔽，通常通过声音定位。以昆虫为主食，也会食用果实。可能单独活动或与其它物种松散群居。","identification":"与其他Myiarchus属鸟类的区别在于嘴型、头部形状和胸部与腹部的颜色差异。","protection":"IUCN状态未列出。","distribution":"分布于极端东哥伦比亚、西南委内瑞拉、亚马逊巴西（从上黑河流域向东至马瑙斯地区，向南至罗多尼亚州，东至托坎廷斯州）；同时在玻利维亚东北极端、圭亚那南部、苏里南、法属圭亚那和邻近的巴西东北部（北阿马帕州）也有发现。","other":"关于该物种的分布和生态学信息相对较少，有待更多研究。"},{"name":"棕悲霸鹟","english_name":"Rufous Mourner","scientific_name":"Rhytipterna holerythra","overview":"棕悲霸鹟（英文名：Rufous Mourner，学名：Rhytipterna holerythra），是雀形目霸鹟科悲霸鹟属的鸟类。全身呈红褐色调，下体稍淡，拥有略带粉或角质色基部的黑色喙。分布于中美洲至南美洲西北部的低地热带雨林，从墨西哥南部直至哥伦比亚西部和厄瓜多尔。与同域的棕伞鸟相似，但体型更小。","appearance":"成年棕悲霸鹟的上体为肉桂棕色至赤褐色，头顶比背部略深。中央尾羽较暗，而外侧尾羽为肉桂赤色。翅膀较暗，飞羽边缘呈肉桂赤色。下体明亮的肉桂色至浅赭黄色，胸部颜色较深，喉部和腹部颜色较浅。翼下表面为浅赭黄色。幼鸟与成鸟相似，但上体更赤色，下体更淡的肉桂色。","call":"棕悲霸鹟的叫声为独特的慢速狼哨声——“whee-wheeu”，间隔时间较长，容易模仿。","habits":"棕悲霸鹟栖息于低地和丘陵地带，海拔可达1200米的湿润森林、邻近的旧次生林、半开放区域和阴凉的种植园。通常单独、以家庭群体形式或作为混合物种觅食群的一部分出现。它会从枝条上突然飞出捕食大型昆虫、毛虫以及多种种子和果实，食物通常在空中捕获。","breeding":"筑巢于树洞中，特别是旧啄木鸟的洞穴，也可能在土堤的洞穴中筑巢。","identification":"与棕伞鸟相似，但体型更小，喙较小，喉部颜色较暗，头部形状更为扁平。棕伞鸟头部更圆，站立时姿势更垂直，而棕悲霸鹟常前倾，姿态更水平。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲西北部，从墨西哥南部至哥伦比亚西部和厄瓜多尔。","other":"尽管分布广泛，棕悲霸鹟的自然历史知识相对贫乏。"},{"name":"西利霸鹟","english_name":"Sibilant Sirystes","scientific_name":"Sirystes sibilator","overview":"西利霸鹟（英文名：Sibilant Sirystes，学名：Sirystes sibilator），是雀形目霸鹟科西利霸鹟属的鸟类。广泛分布在南美洲，从巴西东部、西南部到巴拉圭东部以及阿根廷东北部的热带湿润低地森林中。以灰黑色为主调，拥有独特的黑色冠羽和白色翼缘。","appearance":"体型较大，长度约18-18.5厘米，重量介于26.1-27.5克之间。成鸟具有黑色的冠羽，侧头部呈板岩灰色，背部带有橄榄灰色斑点，翅膀和内飞羽边缘宽阔地呈现灰色。尾巴长而方正，颜色深黑。喉咙和胸部为灰色，腹部转为灰白色。虹膜为深红棕色，喙和腿黑色。雄鸟和雌鸟外观相似，但雄鸟的翅膀和尾巴更长。幼鸟全身覆盖着淡黄色的羽毛。阿根廷地区的个体比巴西和巴拉圭的同类拥有更深但较短的喙。","call":"发出响亮而下降的‘pepepew-pepepew’叫声，有时延长成一系列兴奋的音节。","habits":"栖息于森林和成熟次生林的树冠层，包括cerradão、河岸和干燥森林，海拔至少可达1400米。相比其他霸鹟，它需要更大的领地。在极端南部的巴西可能有迁徙现象，但在邻近的巴拉圭东部似乎全年驻留。以较大的昆虫和果实为食，经常成对出现，伴随混合物种的鸟群在森林树冠活动，常扮演领头角色，尤其在巴西东南部的大西洋森林中。偶尔与黄额拾叶雀共享领导地位，从中直接获益。","breeding":"关于繁殖的信息几乎未发表，但在巴西南部（Rio Grande do Sul）的记录显示，8月和10月的鸟群正处于繁殖准备或完全繁殖状态，而成鸟在2月中旬被观察到喂养幼鸟。","identification":"与其他Sirystes种类的区别在于其黑色的冠羽和白色的翼缘，以及独特的鸣叫声。","protection":"IUCN：LC（无危）。在巴西东南部和巴拉圭东部的完好森林中最为常见，但对森林损失和碎片化特别敏感，火灾后会消失。出现在多个国家公园和保护区，如Boa Nova National Park、Augusto Ruschi Biological Reserve、Itatiaia National Park和RPPN Volta Velha。","distribution":"繁殖区域主要集中在南美的巴西东部、西南部至巴拉圭东部和阿根廷东北部。在巴西的分布更为具体，包括Bahia、Espírito Santo、Rio de Janeiro和Santa Catarina等地。","other":"曾经被认为与西部霸鹟、白臀霸鹟和Todd's霸鹟同种，现已确认为独立物种。"},{"name":"白腰西利霸鹟","english_name":"White-rumped Sirystes","scientific_name":"Sirystes albocinereus","overview":"白腰西利霸鹟（英文名：White-rumped Sirystes，学名：Sirystes albocinereus），是雀形目霸鹟科西利霸鹟属的鸟类。独特的黑、灰、白色调。曾被认为是西利霸鹟的同种。该鸟种分布于南美洲，包括委内瑞拉西南部、哥伦比亚东部、厄瓜多尔东部、秘鲁东部、巴西西部以及玻利维亚北部的低地森林。","appearance":"体长约18至19厘米，体重约24至32克。头部黑色，逐渐变为灰色，与灰色的背部形成鲜明对比。拥有明显的白色臀部斑块，翅膀和尾巴为黑色，内侧飞羽边缘为白色，翼覆羽边缘为淡灰色。喉咙和胸部呈淡灰色，腹部白色，大腿部分呈褐色。两性相似，幼鸟描述未知。","call":"其鸣声包括一系列柔和的哨音，例如“p’weer PEW-pu”，叫声包括一系列较长而变化的“pew”音符，以及单独或以杂乱结构发出的较轻的“kew”或“pew”音符。最常见的是一个哨音，紧接着一个短音“wher-péw”，有时是短音“wheer-péwpu”或“p'weer-PEW-pu”。","habits":"栖息于湿润森林的树冠和边界，包括玻利维亚北部的干性和半落叶林，海拔高度通常低于550米，但在秘鲁东部可达700米。饮食可能以大型节肢动物为主。通常单独或成对出现，经常与混合物种群一起，可能在大范围内游荡。站立时姿态挺拔警觉，主要在树枝上悬停捕食，偶尔在不悬停的情况下捕获猎物。","breeding":"在秘鲁东南部的10月初，发现一个活跃的巢穴，里面有成长中的雏鸟。巢位于Calycophyllum树（Rubiaceae科）的垂直“肘部”基部的空洞中，估计离地面32米高。巢穴由一对鸟共同照料，它们会从远至200米的地方捕捉昆虫喂养雏鸟。访问间隔平均为8.6分钟。除此之外，关于繁殖的其他信息未知。","identification":"与西利霸鹟的区别在于其独特的黑白灰相间的羽毛模式和叫声。此外，其地理分布和生境偏好也有所差异。","protection":"IUCN：LC（无危）。在哥伦比亚东部和厄瓜多尔东部非常少见且局部分布，但在厄瓜多尔的Limoncocha附近，靠近哥伦比亚边境，报告称其数量较多。在委内瑞拉西部了解甚少。在秘鲁东部和巴西西部的várzea、过渡和河岸森林中最为丰富，这些地方的大部分栖息地仍保持相对原始的状态。出现在几个国家公园和其他保护区。","distribution":"分布于南美洲，具体包括委内瑞拉西南部（从葡萄牙省东南部到塔奇拉省东南部）、哥伦比亚东部（从阿劳卡省西部到普图马约省）、厄瓜多尔东部、秘鲁东部、巴西西部（亚马逊州西南部、阿克雷州）、玻利维亚北部（南至拉巴斯、科恰班巴和圣克鲁斯北部）。"},{"name":"托氏西利霸鹟","english_name":"Todd's Sirystes","scientific_name":"Sirystes subcanescens","overview":"托氏西利霸鹟（英文名：Todd's Sirystes，学名：Sirystes subcanescens），是雀形目霸鹟科西利霸鹟属的中型灰白相间飞禽，常见于南美洲的热带雨林冠层。以干净的白色下体和对比鲜明的深色头部为显著特征，通常冠羽蓬松。这种鸟在高大的热带雨林中较为罕见，常以成对或小群体的形式出现，往往非常喧闹，喜欢停歇在裸露的树枝上。","appearance":"托氏西利霸鹟体长约18至18.5厘米，体重34至36.5克。其外观与白腰西利霸鹟非常相似，均无橄榄色调，翼覆羽主要呈灰色，无明显的翼斑，拥有大块的白色臀部。喉部和胸部的颜色比白腰西利霸鹟略深，营造出更明显的蓬松外观，上体颜色也较后者更深。虹膜呈深棕色，喙和腿均为黑色或灰色。雌雄两性外表相同。幼鸟特征尚未详细描述。","call":"其鸣声多样而尖锐，包括悠长哀怨的哨音，类似于西利霸鹟，以及一系列快速的短哨音，最后一个音符低沉且持续时间较长。这些叫声易于识别，是发现它的关键。","habits":"托氏西利霸鹟主要栖息在热带雨林的树冠层，以昆虫（已报道其胃内容物中包含直翅目昆虫）为主食，通过短暂的飞翔在树叶间捕食。虽然可能跟随混合物种群，但经常在群外独立活动。其行为和觅食生态与其他西利霸鹟超种相似，但具体细节描述不足。","breeding":"关于繁殖行为的信息未在现有资料中明确提及。","identification":"与西利霸鹟相比，托氏西利霸鹟的下体为白色，鸣叫声更为多样化，听起来更兴奋。与白腰西利霸鹟的区别在于哨音的结构，以及次要鸣叫类型和下行歌曲的音符形状。","protection":"IUCN：LC（无危）。在巴西北部帕拉州被视为极稀有，圭亚那稀缺，苏里南和法属圭亚那不常见，但在巴西亚马逊州部分地区局部常见。出现在多个国家公园和其他保护区。","distribution":"分布于圭亚那和巴西亚马孙雨林东北部，自然栖息地位于亚热带或热带湿润低地森林。","other":"过去曾被认为与响亮西利霸鹟同种。"},{"name":"白翅西利霸鹟","english_name":"Choco Sirystes","scientific_name":"Sirystes albogriseus","overview":"白翅西利霸鹟（英文名：Choco Sirystes，学名：Sirystes albogriseus），是雀形目霸鹟科西利霸鹟属的中等体型鸟类。罕见于中美至南美低地与山脚地带，自巴拿马东部至厄瓜多尔西北部。其外观融合了becard和Myiarchus flycatcher的特征。","appearance":"成鸟拥有暗黑色的冠羽，渐变为头侧的石板灰色，淡灰的颈背、背部与肩羽，白色臀部，深色尾上覆羽边缘灰白，灰黑尾羽尖端灰白，翅膀深黑而具宽阔的白色羽缘，前颈与上胸灰白，其余下体白色。虹膜深棕（偶见报道为红色），喙黑，有时基部略浅，腿黑或深灰。雌雄相似，但雌鸟翼与尾略短。幼鸟全身微泛淡黄褐色。","call":"发出一系列响亮而急促的“prip”或“hrip”音节。白翅西利霸鹟的叫声显著不同于西利霸鹟超物种中的其他成员，其主要叫声类型独特，录音中未出现哨声、叽叽喳喳的歌声或下划音。","habits":"栖息于湿润森林与高大的次生林，常在树冠层活动，偶尔在边缘降低高度。食物包括昆虫与小型果实，已知跟随混种觅食群，突袭捕食昆虫或小果。海拔记录显示在巴拿马可达900米，但在哥伦比亚西部与厄瓜多尔西北部仅限于500米以下。","breeding":"繁殖信息几乎未知，2月在哥伦比亚西部处于繁殖状态，2月至3月在巴拿马东部可能正在筑巢，另有2月在巴拿马中部收集到处于繁殖状态的雄鸟标本。","identification":"与becard相比，身体更修长，尾巴更长。叫声明显区别于西利霸鹟超物种中的其他成员。","protection":"IUCN：LC（无危）。在巴拿马东部较为常见，但在哥伦比亚西部记录稀少，厄瓜多尔西北部罕见且局部分布，被列入厄瓜多尔红名单。","distribution":"分布于中美洲至南美洲，包括巴拿马东部、哥伦比亚西北部以及厄瓜多尔西北部，主要栖息于亚热带或热带湿润低地森林。"},{"name":"棕卡西霸鹟","english_name":"Rufous Casiornis","scientific_name":"Casiornis rufus","overview":"棕卡西霸鹟（英文名：Rufous Casiornis，学名：Casiornis rufus），是雀形目霸鹟科卡西霸鹟属的大型飞禽，主要呈现肉桂色，胸腹颜色较浅。常见于萨凡纳林地和河岸森林，非繁殖季节则可见于查科林地及湿润森林边缘。在南美洲广泛分布，包括玻利维亚、巴西中部和南部、阿根廷北部、乌拉圭东北部等地。","appearance":"该物种体型较大，主要呈肉桂色调，胸部和腹部颜色较为柔和。喙黑色，基部带有粉红色。雄鸟、雌鸟及幼鸟在羽毛颜色上可能略有差异，但总体特征一致。","call":"大部分时间保持沉默，具体鸣叫特征记录较少。","habits":"栖息于萨凡纳林地、河岸森林，非繁殖季节则出现在查科林地和湿润森林边缘。关于其飞行特点、活动范围、觅食方式及食物的具体信息尚待更多研究。","breeding":"繁殖行为、求偶、营巢、交配、产卵、孵化及育雏等详细信息有待进一步观察记录。","identification":"与其他霸鹟科鸟类相比，棕卡西霸鹟具有明显的肉桂色外观，喙的特有色彩是其辨识的关键。","protection":"IUCN：LC（无危）。虽然其栖息地受到农业用途和人工林种植的影响，但在多个国家公园和其他保护区中仍有分布。","distribution":"分布于玻利维亚、巴西中部至南部、阿根廷北部、乌拉圭东北部，以及巴西东南部。在澳大利亚冬季期间，少量个体会出现在巴西北部至秘鲁东南部。","other":"已知其在特定区域内为常见物种，但在更北的亚马逊雨林部分区域偶尔也会被发现。"},{"name":"灰喉卡西霸鹟","english_name":"Ash-throated Casiornis","scientific_name":"Casiornis fuscus","overview":"灰喉卡西霸鹟（英文名：Ash-throated Casiornis，学名：Casiornis fuscus），是雀形目霸鹟科卡西霸鹟属的鸟类。分布于巴西东北部的半干旱森林（Caatinga）中，其自然栖息地为热带或亚热带干燥林地。","appearance":"这种大型的红褐色霸鹟拥有轻微的羽冠，肉桂色背部，暗淡的飞羽以及浅黄色下体。在繁殖季节，它常出现在干燥的灌木森林中；而非繁殖季节，则可见于亚马逊森林、Cerrado草原和轻型林地中。","call":"灰喉卡西霸鹟的鸣唱目前尚未被记录，但其叫声是一连串短暂而果断的“tsip!”声，间歇性重复。","habits":"灰喉卡西霸鹟部分迁徙，干季（4月至10月）期间，它们会从半干旱Caatinga生态系统向西扩张至亚马逊和Cerrado生物群落。栖息地包括亚马逊南部、帕拉伊巴和伯南布哥州，以及马托格罗索州东北部。","breeding":"关于繁殖习性的资料极少，但在一月份于皮奥伊州发现了一个活跃的巢穴，这表明它们可能在此时期进行繁殖活动。","identification":"灰喉卡西霸鹟与棕卡西霸鹟的区别在于后者背部颜色与翅膀相同，呈现红褐色。","protection":"IUCN：LC（无危）。在某些地区，灰喉卡西霸鹟的数量较为稀少，但局部地区相对常见。由于人类活动增加，其栖息地面临压力，尤其是在30年前巴西东北部修建道路后，森林用于牧场和农业开发，无节制的火灾也是一个问题。该物种在米纳斯吉拉斯州的佩鲁阿苏洞穴国家公园和皮奥伊州的塞拉达卡皮瓦拉国家公园有记录。","distribution":"分布于巴西东部，具体区域包括亚马逊河以南的东北巴西，从塔帕若斯河下游向东至贝伦地区，直至帕拉伊巴和伯南布哥州，向南延伸至马托格罗索州东北部的上辛古河流域，戈亚斯州北部和米纳斯吉拉斯州西北部。"},{"name":"棕蝇霸鹟","english_name":"Rufous Flycatcher","scientific_name":"Myiarchus semirufus","overview":"棕蝇霸鹟（英文名：Rufous Flycatcher，学名：Myiarchus semirufus），是雀形目霸鹟科蝇霸鹟属的鸟类。主要分布在秘鲁西北部的干燥低地森林中，特别是在富含刺槐和金合欢的地区。其独特的三色调棕红色羽毛使其在同类中独树一帜。根据《世界自然保护联盟》评估，该物种由原先的最不受关注类别上调至濒危级别。","appearance":"体长17-19厘米，体重21.7-25克。头部和上体呈棕色，尾羽覆羽为红褐色；喉咙和下体几乎均匀的浅肉桂红褐色，翅膀和尾巴主要为红褐色，翼下覆羽为红褐色。两性相似，幼鸟与成鸟外观相近。","call":"黎明时的歌声由交替的“huit”音符和嘶哑的哨声组成，有时插入复杂的喘息音节变化。在防御领地时会发出重复的嘶哑哨声和喘息声。","habits":"生活在热带和亚热带的刺灌丛沙漠、稀树草原和刺槐树林中，海拔高度可达500米。推测为留鸟，食物习性和觅食行为暂无具体数据。","breeding":"繁殖季节记录在12月发现有蛋的巢穴，以及5月观察到的雏鸟。巢穴通常位于地面以上1米的刺槐树丛中，由细软的毛发、纸片、报纸、透明塑料和少量白色羽毛等材料构成。","identification":"其独特的红褐色调和灰顶冠使其易于识别，无其他种类在其范围内具有类似颜色。","protection":"IUCN：VU（易危）","distribution":"秘鲁西北部，从Tumbes向南至Ancash，曾分布至利马北部。","other":"人类活动增加和大规模农业导致栖息地减少，影响了棕蝇霸鹟的生存。"},{"name":"尤卡坦蝇霸鹟","english_name":"Yucatan Flycatcher","scientific_name":"Myiarchus yucatanensis","overview":"尤卡坦蝇霸鹟（英文名：Yucatan Flycatcher，学名：Myiarchus yucatanensis），是雀形目霸鹟科蝇霸鹟属的鸟类。主要分布在墨西哥东北部的尤卡坦半岛以及邻近的贝尔兹和危地马拉北部边界地带。其外观特征包括部分具羽冠的头部，棕色至灰色的背部与头部，红褐色的尾巴以及黄色至淡色的下体。","appearance":"尤卡坦蝇霸鹟具有典型的Myiarchus属特征，部分头顶有羽冠，背部和头部呈棕色到灰色，尾巴呈现红褐色，下体颜色从黄色到淡色不等。与暗顶蝇霸鹟相似，但可通过更宽、较浅灰色的眼周区以及更鲜明的白色翼缘来识别。","habits":"生活在热带林地和边缘地带，主要栖息于树冠中上层，常在果实丰富的树上觅食，尤其是常见的gumbo limbo树。它们在树间飞行灵活，以昆虫为主要食物。","identification":"与暗顶蝇霸鹟、褐冠蝇霸鹟和大冠蝇霸鹟相似，但通过声音最易区分，视觉上主要差异在于眼周区的灰色宽度和翼羽的白色边缘。","distribution":"分布于中美洲的尤卡坦半岛，包括墨西哥东北部，以及北接的贝尔兹和危地马拉的部分地区。"},{"name":"牙买加蝇霸鹟","english_name":"Sad Flycatcher","scientific_name":"Myiarchus barbirostris","overview":"牙买加蝇霸鹟（英文名：Sad Flycatcher，学名：Myiarchus barbirostris），是雀形目霸鹟科蝇霸鹟属的鸟类，仅见于牙买加岛。栖息于低地和山地的湿润森林中，甚至能在严重退化的前森林环境中生存。","appearance":"这种鸟通常安静地栖息在距离地面三至十米高的树上，身体倾向于前倾。它的喙相对较小，翅膀和尾巴上没有锈色。与之相比，憨蝇霸鹟体型更大，喙也较大，且在折叠的初级飞羽上有锈色；而棕尾蝇霸鹟更大，头部和胸部颜色更深，尾巴和折叠的初级飞羽上的锈色更多。","call":"其鸣叫声包括有力的‘pip’声，可以单独发出或快速连续发出，还有口哨般的颤音，以及各种高音的啾啾声和吱吱声；这些叫声常常组合在一起发出。","habits":"牙买加蝇霸鹟生活在低地和山地的湿润森林中，适应于退化森林环境。它们的活动范围和觅食方式未详细描述。","identification":"与憨蝇霸鹟和棕尾蝇霸鹟相比，牙买加蝇霸鹟的体型更小，喙较小，且翅膀和尾巴上缺乏锈色。","protection":"IUCN：LC（无危）。此物种受到栖息地丧失和人为破坏的威胁，尤其是在缺乏资金保护和管理的情况下。自1980年代以来，咖啡种植业的复苏导致大量次生林被清除，飓风破坏、广泛使用杀虫剂、木材移除、故意放火以及持续的小规模农业和城市化也是问题。","distribution":"牙买加岛是牙买加蝇霸鹟的唯一自然分布地，包括低地和山地的湿润森林，以及部分退化森林。"},{"name":"暗顶蝇霸鹟","english_name":"Dusky-capped Flycatcher","scientific_name":"Myiarchus tuberculifer","overview":"暗顶蝇霸鹟（英文名：Dusky-capped Flycatcher，学名：Myiarchus tuberculifer），是雀形目霸鹟科蝇霸鹟属的鸟类。广泛分布于南美洲和中美洲，从美国西南部至阿根廷北部，包括特立尼达岛。其最显著的特征为黑色头部和短小的冠羽，以及明亮的黄色腹部。该物种在大部分范围内为留鸟，但在冬季，美国的繁殖种群会迁至墨西哥。","appearance":"暗顶蝇霸鹟体长约18厘米，体重约20克。上体呈棕色，头顶部深黑色，具有一小簇冠羽。胸部灰色，腹部颜色鲜亮，呈黄色。尾羽和翅膀的棕色部分边缘较淡。两性相似，但幼鸟的翅膀和尾巴边缘具有锈红色的饰边。","call":"该鸟最显著的识别特征之一是其哀伤的、下降的哨音，常被描述为\"peeur\"或\"whee-eu\"。","habits":"暗顶蝇霸鹟栖息于森林和林地，以昆虫为主食，通过在树的中层枝条间飞扑捕食。偶尔也会食用果实，如来自Gumbo-Limbo（Bursera simaruba）和Cymbopetalum mayanum（Annonaceae）的果实，特别是在冬季。","breeding":"筑巢于树洞中，通常产三枚带有褐色斑点的淡黄色蛋，雏鸟在孵化后约13天离巢。","identification":"与其他Myiarchus属鸟类相比，暗顶蝇霸鹟较小，具有黑顶，以及独特的哀伤哨音，是辨别其身份的关键。","protection":"IUCN：LC（无危）","distribution":"分布于北美西南部至南美的亚马逊雨林和巴西东南部，包括美国西南部至阿根廷北部，特立尼达岛。","other":"暗顶蝇霸鹟有13个亚种，亚种之间在头冠颜色和栖息地偏好上有差异，部分亚种在南美洲存在几乎完全的生殖隔离。"},{"name":"斯氏蝇霸鹟","english_name":"Swainson's Flycatcher","scientific_name":"Myiarchus swainsoni","overview":"斯氏蝇霸鹟（英文名：Swainson's Flycatcher，学名：Myiarchus swainsoni），是雀形目霸鹟科蝇霸鹟属的中大型鸟类。以其长而弯曲的喙和小冠羽为显著特征。广泛分布在南美洲的阿根廷、玻利维亚、巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、巴拉圭、秘鲁、苏里南、特立尼达和多巴哥、乌拉圭及委内瑞拉。","appearance":"斯氏蝇霸鹟拥有长而带钩的喙，小而明显的冠羽。其羽色因亚种而异，头部和背部的棕色色调从冷到暖不等，喙的颜色也有变化。所有亚种共有的特征是淡色的胸部、黄色的腹部和平滑的棕色或深色尾巴。","call":"其鸣唱特征为独特的‘pe-tchew, pe-tchew, prrrr’声，这成为区分于相似种类的重要依据。","habits":"斯氏蝇霸鹟栖息于多种林地和森林边缘环境。它们的迁徙模式复杂，部分种群迁至南美洲北部，如哥伦比亚东部至巴西东部，以及亚马逊盆地，而更北的繁殖种群的迁徙状态尚不清楚。","identification":"与其他类似蝇霸鹟的辨识主要依赖于其鸣唱特征，‘pe-tchew, pe-tchew, prrrr’声是独特标志。","protection":"IUCN：LC（无危）。在广泛的范围内，斯氏蝇霸鹟数量普遍较多，至少在十二个国家公园和许多其他保护区中出现，适应多种林木生境，未来短期内无明显威胁。","distribution":"在南美洲广泛分布，涵盖从阿根廷到委内瑞拉的广大区域，包括亚马逊盆地。","other":"斯氏蝇霸鹟的迁徙模式和某些亚种的状态仍需进一步研究。"},{"name":"委内瑞拉蝇霸鹟","english_name":"Venezuelan Flycatcher","scientific_name":"Myiarchus venezuelensis","overview":"委内瑞拉蝇霸鹟（英文名：Venezuelan Flycatcher，学名：Myiarchus venezuelensis），是雀形目霸鹟科蝇霸鹟属的鸟类。曾被视为短冠蝇霸鹟的亚种，但在委内瑞拉两物种存在重叠分布区而不杂交，且叫声有异。主要分布于南美洲东北部的哥伦比亚北部和委内瑞拉北部，以及特立尼达和多巴哥岛。","appearance":"成年委内瑞拉蝇霸鹟长约19厘米，体重约24.4克。上体呈棕色，头部及短冠较背部颜色更深。胸部灰色，腹部黄色。棕色的尾羽和翅膀边缘带有狭窄的红褐色边缘。两性相似，但幼鸟的红褐色边缘更宽。","call":"其特征性的叫声是一种口哨般的'wheeerrrr'，这是区分其与其它类似Myiarchus物种的关键。","habits":"委内瑞拉蝇霸鹟栖息于森林和落叶林地带，常见于哥伦比亚北部和委内瑞拉北部的干燥至湿润森林、河岸森林、树丛稀疏的草原和邻近森林的灌木丛中。它们通常独居。","breeding":"繁殖期间，委内瑞拉蝇霸鹟会在树洞中筑巢。","identification":"与短冠蝇霸鹟的区别在于委内瑞拉蝇霸鹟的喙较为笔直，基部带粉色，叫声不同。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的哥伦比亚北部（从苏克雷省东至瓜希拉省）、委内瑞拉北部（从苏利亚省东至米兰达省，南至阿普雷省）、委内瑞拉东北部和东部（玛格丽塔岛；东北玻利瓦尔州）以及特立尼达和多巴哥岛。可能存在的三个或四个不连续群体。"},{"name":"巴拿马蝇霸鹟","english_name":"Panama Flycatcher","scientific_name":"Myiarchus panamensis","overview":"巴拿马蝇霸鹟（英文名：Panama Flycatcher，学名：Myiarchus panamensis），是雀形目霸鹟科蝇霸鹟属的鸟类。体型相对较大，体长约19厘米，重量在28.1至38.5克之间。其上体呈灰橄榄色，喉部灰白，腹部黄色，背部棕色，具有轻微的冠羽外观，嘴部较大，通常直立栖息。分布于中美洲至南美洲的热带森林地带，包括哥斯达黎加西南部至哥伦比亚。","appearance":"巴拿马蝇霸鹟拥有橄榄色的背部，没有红色尾羽，翼上有微弱的条纹。头顶羽毛较暗形成条纹效果，与背部形成对比。翅膀和背部颜色相似，三级飞羽的外缘呈淡黄白色。尾巴棕色，最外侧尾羽的外缘仅比内缘略浅，通常没有红色（可能仅在新鲜羽毛时可见）。喉咙和胸部灰色，腹部和臀下覆羽黄色，上侧有时带有绿色调，胫部羽毛橄榄棕色。眼睛、喙和腿深色，下颌基部有时稍浅（哥伦比亚上马格达莱纳山谷）。内部口腔橙色。成鸟和幼鸟外观相似，但幼鸟的翼覆羽和尾羽边缘有红色。actiosus亚种上体较灰，腹部比指名亚种更浅。","call":"巴拿马蝇霸鹟的鸣声为一系列下降的哨音：“pee-pee-pee-pee-pee-pee-pee-pee”。在面对同类入侵时会发出重复的抽搐声（通常是双音节）、粗糙的哨声和滚动声。黎明时的歌唱由孤立的、短而缓慢变化的哨声组成，每2至3秒发出一次（这与觅食鸟在白天其他时间发出的频率较低的声音相同）。与短冠蝇霸鹟的叫声差异超过了Myiarchus物种间通常的差异程度。","habits":"巴拿马蝇霸鹟生活在热带落叶林、画廊林、次生林、红树林和干旱低地灌木丛中，也出现在开放的林地和其他半开放的栖息地，如田野边缘、牧场中的散落灌木。特别是在安第斯山脉以西的红树林中发现。海拔高度从海平面到1400米。推测为留鸟，但在哥伦比亚可能有轻微的海拔迁移。以昆虫和果实为食，也会在草地边缘吃草籽。它会从开阔的栖息处捕食飞行中的昆虫，或在地面或红树根部像鸫鸟一样奔跑，然后突然起飞捕捉飞行或休息的昆虫。","breeding":"繁殖期从3月底至6月初，可能在哥伦比亚的上马格达莱纳山谷持续到7月。巢建在树洞中，通常离地面4至12米，用大量根须、藤蔓、叶碎片、植物绒毛、动物毛发和蛇皮填充。也记录到使用鸟巢箱、倾斜设置在地面上直径10厘米的金属管上端、或在道路旁低悬崖上的裂缝中筑巢。每次产卵2至3枚，关于孵化和雏鸟离巢的时间尚无信息。","identification":"与短冠蝇霸鹟极其相似，但一般背部颜色较浅，喉咙颜色较暗且无条纹，腹部颜色更亮，更接近柠檬黄色。与委内瑞拉蝇霸鹟的区别在于喉咙颜色更深且无条纹，初级飞羽上的红色较少，腹部颜色更亮更柠檬黄色。性成熟个体之间相似，仅凭羽毛颜色很难区分。","protection":"IUCN：LC（无危）。在巴拿马东部较为罕见，在哥斯达黎加的Carara生物保护区和Tarcol Lodge以及哥伦比亚的Tambito自然保护区有记录。","distribution":"分布于中美洲至南美洲，具体包括哥斯达黎加西南部至哥伦比亚。自2012年起，在厄瓜多尔北部沿海地区也有报道，可能是新近的移民或过去被忽视的种类。","other":"2020年发表的一项分子遗传学研究发现，巴拿马蝇霸鹟与短冠蝇霸鹟是姐妹种。"},{"name":"短冠蝇霸鹟","english_name":"Short-crested Flycatcher","scientific_name":"Myiarchus ferox","overview":"短冠蝇霸鹟（英文名：Short-crested Flycatcher，学名：Myiarchus ferox），是雀形目霸鹟科蝇霸鹟属的鸟类。广泛分布在南美洲，包括阿根廷、玻利维亚、巴西、哥伦比亚等地。栖息于亚热带或热带湿润的低地森林和严重退化的前森林地带。","appearance":"该鸟体型较大，上部主要呈灰棕色，喉部颜色较浅，腹部为淡黄色。不同亚种的上部色调有所不同，可能偏暖色或冷色，但都具有黑色喙。雄雌幼鸟的特征在文献中未详细描述。","call":"其独特的叫声被描述为短促的‘警官’哨声‘prrrih’，这是区分它与其他类似种类的重要特征。","habits":"短冠蝇霸鹟偏好栖息在稀树草原、半开放的林地和森林边缘。它们的生活习性、迁徙模式、飞行特点等细节尚需更多研究。","breeding":"关于短冠蝇霸鹟的繁殖习性的具体信息未在现有资料中详述。","identification":"通过其特有的叫声‘prrrih’可以最佳地将其与其他相似的蝇霸鹟种类区分开来。","protection":"IUCN状态未知，但鉴于其广泛的分布，目前未被列入濒危名单。","distribution":"南美洲广泛分布，包括但不限于阿根廷、玻利维亚、巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、巴拉圭、秘鲁、苏里南、乌拉圭和委内瑞拉。","other":"历史分类学上，短冠蝇霸鹟最初由Gmelin于1789年描述，曾归入Muscicapa属，现为Myiarchus属的一员，与巴拿马蝇霸鹟关系密切。"},{"name":"尖顶蝇霸鹟","english_name":"Apical Flycatcher","scientific_name":"Myiarchus apicalis","overview":"尖顶蝇霸鹟（英文名：Apical Flycatcher，学名：Myiarchus apicalis），是雀形目霸鹟科蝇霸鹟属的鸟类。无显著特征，属Myiarchus科。仅分布于哥伦比亚的特定干燥林地和灌木丛生环境，海拔低于1700米。","appearance":"整体呈灰橄榄色，上部偏棕色，下部渐变为柠檬黄色腹面。头部冠羽深棕色，尾羽末端白色，为识别关键。雌雄同色，幼鸟翼羽边缘呈锈色。","call":"发出干燥的‘whit’声。","habits":"栖息于热带和温带区的哥伦比亚，常见于干燥森林、半干旱开阔地带、草原及零散树木的田野，偏好河流上游盆地。","breeding":"具体繁殖细节未知。","identification":"尾羽末端的白色为区分于其他Myiarchus种类的关键特征。","protection":"IUCN状态未知。","distribution":"分布于哥伦比亚中西部，包括Cauca河谷、Dagua河上游干旱河谷、Patía河上游、Magdalena河谷等地。"},{"name":"淡边蝇霸鹟","english_name":"Pale-edged Flycatcher","scientific_name":"Myiarchus cephalotes","overview":"淡边蝇霸鹟（英文名：Pale-edged Flycatcher，学名：Myiarchus cephalotes），是雀形目霸鹟科蝇霸鹟属的鸟类。主要分布在南美洲的安第斯云雾森林中，从委内瑞拉到玻利维亚一带，栖息海拔在1100-2400米之间，高于多数相似物种。其特征为上体呈棕色，下体喉部和上胸白色渐变为淡柠檬黄色腹部。","appearance":"成年淡边蝇霸鹟体长18-19厘米，体重在22.5-28克（雄鸟）和20.5-24.5克（雌鸟），具有橄榄棕色的冠羽和略显条纹的外观，上体橄榄绿色，翅膀橄榄棕色，翼覆羽和次级飞羽边缘黄色，尾巴同样橄榄棕色但最外侧尾羽的外缘明显较白。下体喉部和胸部灰色，腹部和尾下覆羽黄色，腿羽橄榄棕色。虹膜、喙和腿深色。两性相似。幼鸟翼覆羽边缘带有锈色，尾羽边缘锈色，上体部分羽毛尖端可能呈现锈棕色。","call":"黎明时会发出一系列间隔至少5秒的尖锐哨声，日间接触叫声类似哨声。","habits":"栖息于安第斯山脉的云雾森林及其边缘，常见于较低或中间层次，偶尔进入树冠层。以昆虫为主食，包括甲虫、黄蜂和毛虫，也会食用浆果种子。捕食方式为从枝叶间悬停觅食，偶尔空中追捕。","identification":"是唯一具有外侧尾羽最外缘苍白黄色的Myiarchus属成员。caribbaeus亚种比指名亚种小，且最外侧尾羽的外缘平均更浅。","protection":"IUCN：LC（无危）","distribution":"南美洲，从委内瑞拉北部至玻利维亚，主要栖息于安第斯山脉的云雾森林。"},{"name":"乌冠蝇霸鹟","english_name":"Sooty-crowned Flycatcher","scientific_name":"Myiarchus phaeocephalus","overview":"乌冠蝇霸鹟（英文名：Sooty-crowned Flycatcher，学名：Myiarchus phaeocephalus），是雀形目霸鹟科蝇霸鹟属的鸟类。主要分布在南美洲的厄瓜多尔西部和秘鲁北部的干燥森林中。其自然栖息地为亚热带或热带的干湿森林。","appearance":"乌冠蝇霸鹟体型较大，具有一顶灰棕色的冠羽（常竖立呈‘蓬松’状），喉咙呈灰色，腹部为黄色。头部颜色较深，有助于将其与类似物种如王鹟区分开来。翅膀和尾巴带有更多栗色。","call":"叫声包括鼻音的尖锐哨声、短促的沙哑声和嘎吱的‘wi-dit’声。","habits":"偏好干燥森林环境，活动范围和栖息地选择上与棕冠蝇霸鹟有所重叠，尤其是在马腊翁河谷。其生活习性包括在树冠层的捕食飞行昆虫。","breeding":"关于其繁殖习性的具体细节尚未充分记录，但通常遵循霸鹟科的繁殖模式。","identification":"与同属其他物种相比，乌冠蝇霸鹟的灰冠和翅膀、尾巴上的栗色为其独特标识。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的厄瓜多尔西部和秘鲁北部，主要栖息在干燥森林和湿润低地森林。","other":"乌冠蝇霸鹟属于《世界自然保护联盟》保护的鸟类种类之一。"},{"name":"灰喉蝇霸鹟","english_name":"Ash-throated Flycatcher","scientific_name":"Myiarchus cinerascens","overview":"灰喉蝇霸鹟（英文名：Ash-throated Flycatcher，学名：Myiarchus cinerascens），是雀形目霸鹟科蝇霸鹟属的鸟类。分布于北美西部至中美洲中部。其特征为橄榄褐色上体，灰喉，淡黄色腹部，以及独特的双翼斑。繁殖季节主要在干燥的灌木丛、河流边森林、牧场和开阔林地。冬季则迁徙至墨西哥南部至洪都拉斯。该物种有时会偏离常规繁殖范围，出现在北美的东海岸。","appearance":"灰喉蝇霸鹟体长约为19至22厘米，翼展约30至32厘米，头部相对较大，带有略尖的顶冠。上体呈橄榄褐色，头部颜色较深，带有短而竖立的顶冠。喉咙呈灰色，腹部非常淡黄。尾巴和翅膀的外缘为红棕色，具有两个模糊的翼斑。雌雄外观相似。","call":"鸣声包括一系列含糊不清的咕噜声和粗糙的叫声。","habits":"主要栖息于干燥的灌木丛、河流边的森林、牧场和开阔林地。迁徙时，它们会离开大部分美国和墨西哥北部，冬季在墨西哥南部至洪都拉斯度过。以昆虫为主要食物，也会捕食一些果实，特别是在冬季昆虫稀缺时。偶尔也会捕杀小型哺乳动物和爬行动物。","breeding":"筑巢于树洞或类似的人造或自然洞穴中，通常一窝产三到四枚蛋。","identification":"与其它Myiarchus属的飞禽通过叫声辨别，尤其是burry kabrick和rough prrt或wheer叫声，全年都能听到。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括美国西南部和墨西哥北部，非繁殖期分布在中美洲，从南部墨西哥至洪都拉斯。","other":"对噪声污染敏感，高噪声水平可能影响其听觉范围，进而影响捕食和防御能力。"},{"name":"淡喉蝇霸鹟","english_name":"Nutting's Flycatcher","scientific_name":"Myiarchus nuttingi","overview":"淡喉蝇霸鹟（英文名：Nutting's Flycatcher，学名：Myiarchus nuttingi），是雀形目霸鹟科蝇霸鹟属的鸟类。得名于美国的动物学家Charles Cleveland Nutting。主要栖息于墨西哥西部至哥斯达黎加西北部的半干旱沙漠灌丛及热带落叶林中。通常全年留居，偶尔会漂泊至美国南部加州和亚利桑那州（东南、中部和西部）。","appearance":"成年淡喉蝇霸鹟体长约18-19厘米，体重约21-23克。上体橄榄棕色，头部颜色较深，有短小的羽冠。胸部呈灰色，腹部为柔和的黄色。尾羽棕色，带有广泛的红褐色边缘，翅膀有红褐色的外缘，翼上有两道暗淡的翼纹。雌雄鸟的外观相似。","call":"其最显著的叫声是一声尖锐的‘weeep’，有助于区分于其他Myiarchus属的近似物种。","habits":"淡喉蝇霸鹟主要以昆虫为食，常在灌木下层捕食飞虫，也会食用浆果。栖息于低地和山麓的干燥灌丛及橡树林，以及从奇瓦瓦州南至中美洲的低地对冲地带和半开放地区。","breeding":"它们在树洞或类似的自然或人造洞穴中筑巢，通常产卵数量为3至5枚。","identification":"与灰喉蝇霸鹟相比，淡喉蝇霸鹟整体颜色略亮，羽冠更蓬松，脸部颜色偏棕。通过其独特的叫声可进行辨别。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，自墨西哥西部至哥斯达黎加西北部，涵盖半干旱沙漠灌丛和热带落叶林。","other":"已知的两个亚种形式，一者生活在低地和山麓的干燥环境，另一者（被称为Ridgway's Flycatcher）栖息于从奇瓦瓦州南至中美洲的低地对冲地带和半开放地区。"},{"name":"大冠蝇霸鹟","english_name":"Great Crested Flycatcher","scientific_name":"Myiarchus crinitus","overview":"大冠蝇霸鹟（英文名：Great Crested Flycatcher，学名：Myiarchus crinitus），是雀形目霸鹟科蝇霸鹟属的大型昆虫食性鸟类鸟类。又名: 大凤头鹟，体长约为17-21厘米，翼展可达34厘米，头部有明显的冠羽，背部呈深橄榄绿色，腹部则为鲜明的黄色，喉咙与胸部为灰色，尾羽带有红棕色。该物种广泛分布于北美的东部和中西部，栖息于落叶林、混合林地和森林边缘。","appearance":"大冠蝇霸鹟的成鸟体长约17-21厘米，翼展约34厘米。其上体为橄榄褐色，腹部明亮黄色，喉部和胸部为灰白色，尾羽和初级飞羽具红棕色。雄雌相似，但雌鸟平均体型略小。成年雄鸟长度为18-21厘米，雌鸟为17-20厘米。","call":"雄鸟会发出三部分组成的歌曲，包含两个短哨音，先是wheerreep，接着是更高音调的whee，最后是柔和低沉的churr。此外，还发出一系列快速上升的huit声，以及最具标志性的响亮whee-eep叫声。","habits":"大冠蝇霸鹟偏好生活在落叶和混合林地，尤其是林地边缘和开阔地带。夏季繁殖于北美东部、中部和东南部，冬季迁徙至墨西哥南部至南美北部。它们主要以昆虫为食，也会摄取少量水果和浆果。","breeding":"繁殖期在春季，通常于4月中旬开始筑巢。它们倾向于在树洞中筑巢，巢由植被、植物纤维、动物毛发、羽毛和人工材料构成。每窝产卵4-8枚，仅雌鸟孵化，孵化期约为两周。雏鸟在巢中停留约两周后离巢。","identification":"与近缘种如褐冠蝇霸鹟和灰喉蝇霸鹟相比，大冠蝇霸鹟具有更重的喙，暗灰色胸部与鲜黄色腹部形成鲜明对比，脸部颜色与橄榄色头顶相近，尾羽内侧大部分或全部为红棕色。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖北美中南部和东南部，包括加拿大中南部和东南部至美国中南部和东南部。非繁殖区域从墨西哥南部延伸至哥伦比亚和委内瑞拉。","other":"大冠蝇霸鹟在某些地区全年可见，如佛罗里达半岛南部。"},{"name":"褐冠蝇霸鹟","english_name":"Brown-crested Flycatcher","scientific_name":"Myiarchus tyrannulus","overview":"褐冠蝇霸鹟（英文名：Brown-crested Flycatcher，学名：Myiarchus tyrannulus），是雀形目霸鹟科蝇霸鹟属的大型霸鹟。分布广泛，从美国西南部至南美的阿根廷北部都有其踪迹。该鸟以橄榄棕色的上体、灰色的胸和柠檬黄色的腹部为显著特征，尾羽内侧边缘呈红褐色。性别相似，体型在18至24厘米之间，平均重量约30至45克。","appearance":"褐冠蝇霸鹟体型较大，头部相对大，有短而蓬松的冠羽和较厚的钩状喙。上体颜色为橄榄棕色，头部颜色更深，背部和颈部侧面呈灰色，喉咙和胸部为淡灰色，腹部和臀部为黄色。翅膀为暗灰棕色，有两条浅色翼带，次级飞羽边缘苍白，初级飞羽边缘红褐色。尾巴也是暗灰棕色，但除了中央一对尾羽，其余尾羽的内侧边缘广泛地带有红褐色。喙、腿和脚通常为黑色，嘴内部颜色为粉红色或暗黄色，虹膜为棕色。","call":"褐冠蝇霸鹟的鸣叫声为粗糙响亮的“come HERE, come HERE”或“whit-will-do, whit-will-do”，是辨别该物种的重要特征。","habits":"栖息于开放林地，包括森林边缘、低地河流旁的灌木丛、柱状仙人掌林地和次生林。在繁殖季节，依赖较大的树木或仙人掌及其相关树洞或自然洞穴用于筑巢。主要捕食昆虫，偶尔食用果实，如“gumbo-limbo”树的果实。在迁徙和冬季，部分个体会摄食水果。","breeding":"繁殖期间，会在树洞或类似自然或人造洞穴中筑巢，每窝产2到3枚带有紫色斑点的乳白色蛋。","identification":"与同属其他物种如灰喉蝇霸鹟和大冠蝇霸鹟的区别在于体型、喙的大小、尾羽的红褐色程度和叫声。较灰喉蝇霸鹟体型更大，喙更厚重，尾羽内侧边缘红褐色更为明显，叫声也不同。","protection":"IUCN：LC（无危）","distribution":"分布于北美、中美和南美地区，从美国西南部至阿根廷北部，几乎遍布巴西全境，除亚马逊雨林南部部分区域外，还包括特立尼达和多巴哥岛。","other":"在繁殖季节结束后，美国境内的个体会迁徙至墨西哥或美国南部佛罗里达过冬。"},{"name":"大嘴蝇霸鹟","english_name":"Galapagos Flycatcher","scientific_name":"Myiarchus magnirostris","overview":"大嘴蝇霸鹟（英文名：Galapagos Flycatcher，学名：Myiarchus magnirostris），是雀形目霸鹟科蝇霸鹟属的鸟类。特有于加拉帕戈斯群岛，或称科隆群岛。是其属内最小的成员，全长约15至16厘米，体重介于12到18.5克之间。在群岛的热带干燥森林与带仙人掌的干旱灌木丛中自由穿梭。","appearance":"大嘴蝇霸鹟呈现出较为单调的灰褐色外观，腹部显现出硫磺黄色，喉咙和上胸部为灰色。翼上有明显的双翼斑，背部橄榄棕至灰棕色，翅膀和尾巴边缘略显淡色，尾羽灰棕色带有红褐色边缘。头部在折叠的冠羽作用下呈现独特的棱角形状，虹膜深棕色，喙部暗棕色至角质色，脚灰色。","habits":"大嘴蝇霸鹟完全不惧人类，常出于好奇接近人类，甚至进入建筑物以寻找昆虫为食。它们活跃地从地面或高处如灌木、仙人掌等位置追逐昆虫，有时甚至会停留在游客的相机镜头上，将反射的影像误认为同类。其栖息地主要为热带干燥森林和干旱的仙人掌灌木丛，海拔可达1000米。","identification":"由于它是加拉帕戈斯群岛内唯一的属种，识别并不困难。尽管与同属其他物种相似，但在其分布范围内无混淆之虞。","protection":"IUCN：LC（无危）","distribution":"南美洲的厄瓜多尔，分布于加拉帕戈斯群岛（科隆群岛）的所有主要岛屿和许多较小岛屿，除达尔文岛、沃尔夫岛和热诺维萨岛北部以外。"},{"name":"格林那达蝇霸鹟","english_name":"Grenada Flycatcher","scientific_name":"Myiarchus nugator","overview":"格林那达蝇霸鹟（英文名：Grenada Flycatcher，学名：Myiarchus nugator），是雀形目霸鹟科蝇霸鹟属的鸟类。开放林地和灌木丛中的中等体型的捕虫高手，偏好接近棕榈树的环境，有时也会出现在城镇。以独特的黄腹和灰胸、喉部形成鲜明对比的褐色背部而著称。","appearance":"这种鸟具有中等大小的身躯，背部呈暗淡的棕色，腹部则是醒目的黄色，与灰色的胸部和喉咙形成鲜明对比。其头部、翅膀和尾巴的色调较为一致，整体外观给人以沉稳的感觉。","call":"鸣叫特征包括一系列缓慢的强调低音‘whip’声，有时会接着一串滚动的‘pit-it-oooo’声。此外，还会发出尖锐的‘whee’声，可单独或连续发出。","habits":"格林那达蝇霸鹟栖息于小安的列斯群岛的亚热带或热带湿润低地森林，以及重度退化的前森林区域。它们倾向于长时间静坐于枝头，伺机捕捉飞过的昆虫。","identification":"与加勒比拟霸鹟类似，但后者体型更小，喙相对较小，具有明显的翼杠，下体颜色较暗，对比度较低。","protection":"IUCN：LC（无危）","distribution":"分布于圣文森特、格林纳丁斯和格林纳达，位于南小安的列斯群岛。","other":"曾被认为是褐冠蝇霸鹟的亚种。"},{"name":"棕尾蝇霸鹟","english_name":"Rufous-tailed Flycatcher","scientific_name":"Myiarchus validus","overview":"棕尾蝇霸鹟（英文名：Rufous-tailed Flycatcher，学名：Myiarchus validus），是雀形目霸鹟科蝇霸鹟属的鸟类。常在树冠下的浓密枝叶间活动，以飞扑捕食的方式觅食。其最显著的特征是亮锈色的尾巴和翅膀上的锈色斑块，头部和胸部呈较深的灰色，与牙买加蝇霸鹟和憨蝇霸鹟相比，体型更大，喙也更粗壮。","appearance":"棕尾蝇霸鹟体长约24厘米，体重约38.6至43.2克。头顶烟褐色，脸部和眼周灰蓝色；上体暗橄榄色，与较暗的头顶形成对比，上尾覆羽微带锈色；翼部的初级和次级飞羽外缘有宽约2毫米的锈色带，三级飞羽外缘有更宽（约3毫米）的锈色带，内缘几乎全被锈色浸染，大翼覆羽和中翼覆羽顶端宽幅锈色（静止时翼部主要呈现锈色）；除中央一对尾羽外，其余尾羽大多锈色，靠近尾轴有一窄带深棕色，中央尾羽外缘较淡，最外侧尾羽除尾轴近端一半处窄带深棕色外几乎全锈色；喉咙和胸部深灰色，腹部和下尾覆羽黄色，但上胸部有强烈的灰白色调（使胸部和腹部的界限不明显）；胫部羽毛橄榄棕色，下翼覆羽锈色；虹膜深色，喙深色，下颚基部较浅，口腔内部鲜橙色，腿深色。性别相似，幼鸟下体白色。","call":"鸣叫声包括略带尖锐、强调的‘or-will’声，口哨般的‘pi-pi-pi-pi-pee-pee-pee-pee’声，以及一系列尖锐的‘pew’声，还有短暂而强调的啾啾声。","habits":"棕尾蝇霸鹟偏好湿润的森林环境，主要栖息于亚热带或热带湿润的低地森林和山地森林，也见于严重退化的旧林地带。它们的飞行特点是突然的飞扑，以捕食昆虫。","breeding":"关于棕尾蝇霸鹟的繁殖信息有限，但一般而言，霸鹟科的鸟会在繁殖季节内营巢、产卵、孵化和育雏。","identification":"与牙买加蝇霸鹟和憨蝇霸鹟相比，棕尾蝇霸鹟具有更大体型和喙，以及明显的锈色尾羽和翅膀。与牙买加蝇霸鹟和憨蝇霸鹟的区别在于更广泛的锈色翅膀和较大的体型。","protection":"IUCN：LC（无危）","distribution":"棕尾蝇霸鹟仅分布于牙买加岛。"},{"name":"拉氏蝇霸鹟","english_name":"La Sagra's Flycatcher","scientific_name":"Myiarchus sagrae","overview":"拉氏蝇霸鹟（英文名：La Sagra's Flycatcher，学名：Myiarchus sagrae），是雀形目霸鹟科蝇霸鹟属的鸟类。小型鸣禽，羽毛由黑色、棕色、白色和灰色组成，色彩较为暗淡，拥有直立的冠羽。该鸟种常见于北美巴哈马和古巴等地，筑巢技艺高超，雏鸟晚成。以昆虫为主要食物。","appearance":"体型约19至22厘米，体重介于14至29克之间。具有独特的前倾姿势和扁平头部外观。头顶烟熏橄榄棕色，前额略浅，与背部、肩部的更橄榄棕色形成对比。上尾覆羽比背部稍带红褐色，翅膀呈棕色，主翼羽外缘薄薄地镶有红褐色边，次级飞羽和三级飞羽外缘呈淡灰白色。腹部灰白，下腹部和尾下覆羽接近白色，胫部羽毛橄榄棕色。两性相似，幼鸟可能有较淡或略带红褐色的翼羽尖端，外侧尾羽外缘更红。","call":"发出快速的‘sweet’声和口哨式的‘whit-it, did-id-oo’叫声。","habits":"栖息于林地，通过声音首次被发现。活跃于巴哈马和古巴，偏好自然林地环境。","breeding":"繁殖信息未详述。","identification":"与大冠蝇霸鹟的区别在于后者胸部颜色更深，腹部更亮黄，喙更厚重，尾巴更锈色。","protection":"IUCN：LC（无危）","distribution":"主要分布在北美巴哈马和古巴，包括开曼群岛、特克斯和凯科斯群岛。","other":"在较小岛屿上，可能受到自然灾害如飓风和人为破坏的影响，导致栖息地丧失。"},{"name":"憨蝇霸鹟","english_name":"Stolid Flycatcher","scientific_name":"Myiarchus stolidus","overview":"憨蝇霸鹟（英文名：Stolid Flycatcher，学名：Myiarchus stolidus），是雀形目霸鹟科蝇霸鹟属的鸟类。主要分布于牙买加，多米尼加和海地的低海拔森林、灌木丛及红树林区域。","appearance":"该鸟种的具体外观描述未提供，通常憨蝇霸鹟具有其属内的典型特征，包括特定的羽色和体型。","call":"憨蝇霸鹟的黎明歌曲是“weeeee-pitit-wee”，首尾音节先升后降。叫声包括上升后下降的‘weee-ee’哨声，有力的颤音‘prrree’，以及喷射状的‘peet-it’，还有其他快速的颤音叫声。","habits":"憨蝇霸鹟是林地物种，常见于低海拔的森林、灌木丛和红树林地带。它们在树林内部捕猎，也会在开阔的栖木上捕食。","breeding":"有关憨蝇霸鹟的繁殖习性的具体信息未提供。","identification":"与之相似的牙买加蝇霸鹟体型较小，喙部更小，缺乏初级飞羽上的锈色，且翼条纹弱或不存在。棕尾蝇霸鹟则更大，头部和胸部颜色更深，喙部更粗壮，尾部有明亮的赤褐色。","protection":"IUCN状态未知，未提及是否列入华盛顿公约(CITES)或中国国家重点保护野生动物名录。","distribution":"憨蝇霸鹟分布于北美地区的牙买加、多米尼加和海地，主要栖息于这些地区的亚热带或热带干燥森林、湿润低地森林、红树林森林以及重度退化的前森林。","other":"关于憨蝇霸鹟的系统学历史和其他有趣的信息未提供。"}];
